def _norm_name(name: str) -> str:
    return re.sub(r"[^0-9a-zA-Z]+", "", str(name).lower())


def _is_percent_like(column_name: str, raw_values: List[str]) -> bool:
    if column_name and "%" in str(column_name):
        return True
    for val in raw_values or []:
        if "%" in str(val):
            return True
    return False


def _coerce_raw_numeric(value: str) -> float | None:
    if value is None:
        return None
    raw = str(value).strip()
    if not raw:
        return None
    raw = raw.replace("%", "")
    raw = re.sub(r"[^0-9,\\.()+-]", "", raw)
    if not raw:
        return None
    neg = False
    if raw.startswith("(") and raw.endswith(")"):
        neg = True
        raw = raw[1:-1]
    if "," in raw and "." in raw:
        if raw.rfind(",") > raw.rfind("."):
            raw = raw.replace(".", "")
            raw = raw.replace(",", ".")
        else:
            raw = raw.replace(",", "")
    elif "," in raw and "." not in raw:
        raw = raw.replace(".", "")
        raw = raw.replace(",", ".")
    try:
        val = float(raw)
    except Exception:
        return None
    return -val if neg else val


def _median(values: List[float]) -> float | None:
    if not values:
        return None
    sorted_vals = sorted(values)
    mid = len(sorted_vals) // 2
    if len(sorted_vals) % 2 == 0:
        return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2
    return sorted_vals[mid]

def _truncate_text(text: str, max_len: int = 18000, head_len: int = 10000, tail_len: int = 6000) -> str:
    if not text:
        return text
    if len(text) <= max_len:
        return text
    safe_head = max(0, min(head_len, max_len))
    safe_tail = max(0, min(tail_len, max_len - safe_head))
    if safe_head + safe_tail == 0:
        return text[:max_len]
    if safe_head + safe_tail < max_len:
        safe_head = max_len - safe_tail
    return text[:safe_head] + "\n...[TRUNCATED]...\n" + text[-safe_tail:]


def _scan_encoding_file(path: str, max_sample: int = 5000) -> Dict[str, Any]:
    payload: Dict[str, Any] = {"path": path, "exists": bool(path and os.path.exists(path))}
    if not payload["exists"]:
        payload["mojibake_score"] = None
        payload["sample"] = ""
        return payload
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as handle:
            text = handle.read()
    except Exception as err:
        payload["error"] = str(err)
        payload["mojibake_score"] = None
        payload["sample"] = ""
        return payload
    score = mojibake_score(text)
    payload["mojibake_score"] = int(score)
    payload["length"] = len(text)
    payload["sample"] = text[:max_sample]
    return payload


def _repair_text_file_inplace(path: str) -> Dict[str, Any]:
    result: Dict[str, Any] = {"path": path, "changed": False, "error": None}
    if not path or not os.path.exists(path):
        result["exists"] = False
        return result
    result["exists"] = True
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as handle:
            original = handle.read()
        repaired = sanitize_text(original or "")
        result["before_score"] = int(mojibake_score(original or ""))
        result["after_score"] = int(mojibake_score(repaired or ""))
        if repaired != original:
            with open(path, "w", encoding="utf-8") as handle:
                handle.write(repaired)
            result["changed"] = True
    except Exception as err:
        result["error"] = str(err)
    return result


def _repair_jsonl_file_inplace(path: str) -> Dict[str, Any]:
    result: Dict[str, Any] = {"path": path, "changed": False, "error": None}
    if not path or not os.path.exists(path):
        result["exists"] = False
        return result
    result["exists"] = True
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as handle:
            original_text = handle.read()
        original_score = int(mojibake_score(original_text or ""))
        lines = original_text.splitlines()
        repaired_lines: List[str] = []
        changed = False
        for line in lines:
            raw_line = str(line or "")
            if not raw_line.strip():
                repaired_lines.append(raw_line)
                continue
            repaired_line = raw_line
            try:
                payload = json.loads(raw_line)
                payload = sanitize_text_payload(payload)
                repaired_line = json.dumps(payload, ensure_ascii=False)
            except Exception:
                repaired_line = sanitize_text(raw_line)
            if repaired_line != raw_line:
                changed = True
            repaired_lines.append(repaired_line)
        repaired_text = "\n".join(repaired_lines)
        if original_text.endswith("\n"):
            repaired_text += "\n"
        repaired_score = int(mojibake_score(repaired_text or ""))
        result["before_score"] = original_score
        result["after_score"] = repaired_score
        if changed:
            with open(path, "w", encoding="utf-8") as handle:
                handle.write(repaired_text)
            result["changed"] = True
    except Exception as err:
        result["error"] = str(err)
    return result


def _persist_encoding_audit(state: Dict[str, Any], report_text: str | None = None) -> Dict[str, Any]:
    run_id = state.get("run_id") if isinstance(state, dict) else None
    run_dir = get_run_dir(run_id) if run_id else None
    event_log = os.path.join(run_dir, "events.jsonl") if run_dir else ""
    translator_response = os.path.join(run_dir, "agents", "translator", "response.txt") if run_dir else ""
    report_path = "data/executive_summary.md"

    report_before = str(report_text or "")
    report_after = sanitize_text(report_before) if report_before else report_before
    report_repaired_runtime = False
    if report_before and report_after != report_before:
        try:
            os.makedirs("data", exist_ok=True)
            with open(report_path, "w", encoding="utf-8") as handle:
                handle.write(report_after)
            report_repaired_runtime = True
        except Exception:
            report_repaired_runtime = False
    _, report_stats = sanitize_text_payload_with_stats({"report": report_before})
    state_objective = str((state or {}).get("business_objective", "") or "")
    objective_before = state_objective
    objective_after = sanitize_text(objective_before) if objective_before else objective_before
    if objective_after != objective_before and isinstance(state, dict):
        state["business_objective"] = objective_after

    repaired_files: List[Dict[str, Any]] = []
    repaired_files.append(_repair_jsonl_file_inplace(event_log))
    repaired_files.append(_repair_text_file_inplace(translator_response))
    repaired_files.append(_repair_text_file_inplace(report_path))

    files = [
        _scan_encoding_file(event_log),
        _scan_encoding_file(translator_response),
        _scan_encoding_file(report_path),
    ]
    flagged_files = [
        item.get("path")
        for item in files
        if isinstance(item, dict) and int(item.get("mojibake_score") or 0) > 0
    ]
    audit = {
        "run_id": run_id,
        "report_repaired": bool((report_after != report_before) or report_repaired_runtime),
        "objective_repaired": bool(objective_after != objective_before),
        "report_mojibake_hits": int(report_stats.get("mojibake_hits", 0)),
        "report_strings_changed": int(report_stats.get("strings_changed", 0)),
        "repaired_files": repaired_files,
        "repaired_files_count": sum(1 for item in repaired_files if isinstance(item, dict) and item.get("changed")),
        "files_checked": files,
        "mojibake_detected": bool(flagged_files),
        "flagged_files": flagged_files,
    }
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/encoding_audit.json", audit)
    except Exception as err:
        print(f"Warning: failed to persist encoding_audit.json: {err}")
    return audit


def _refresh_run_facts_pack(state: Dict[str, Any]) -> None:
    if not isinstance(state, dict):
        return
    try:
        run_facts = build_run_facts_pack(state)
    except Exception as err:
        print(f"Warning: failed to build run_facts_pack: {err}")
        return
    state["run_facts_pack"] = run_facts
    try:
        state["run_facts_block"] = format_run_facts_block(run_facts)
    except Exception:
        state["run_facts_block"] = ""
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/run_facts_pack.json", run_facts)
    except Exception as err:
        print(f"Warning: failed to persist run_facts_pack.json: {err}")
    try:
        run_bundle_dir = state.get("run_bundle_dir")
        src_path = os.path.abspath(os.path.join("data", "run_facts_pack.json"))
        if run_bundle_dir and os.path.exists(src_path):
            dest_path = os.path.join(run_bundle_dir, "artifacts", "run_facts_pack.json")
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            shutil.copy2(src_path, dest_path)
    except Exception as err:
        print(f"Warning: failed to copy run_facts_pack.json into bundle: {err}")


def _freeze_payload(payload: Any) -> Any:
    try:
        return copy.deepcopy(payload)
    except Exception:
        return payload


def _resolve_contract_pair_from_state(state: Dict[str, Any]) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    snapshot = state.get("execution_contract_snapshot")
    if isinstance(snapshot, dict):
        full_snap = snapshot.get("execution_contract")
        if isinstance(full_snap, dict) and full_snap:
            return (
                _freeze_payload(full_snap) if isinstance(full_snap, dict) else {},
                {},
            )
    contract_full = state.get("execution_contract")
    if not isinstance(contract_full, dict) or not contract_full:
        contract_full = _load_json_safe("data/execution_contract.json") or {}
    if not isinstance(contract_full, dict):
        contract_full = {}
    return contract_full, {}


def _resolve_declared_artifact_path_from_state(
    state: Dict[str, Any] | None,
    target: str,
    *,
    owner: str | None = None,
    kind: str | None = None,
    fallback: str = "",
) -> str:
    state_obj = state if isinstance(state, dict) else {}
    contract_full, _ = _resolve_contract_pair_from_state(state_obj)
    resolved = get_declared_artifact_path(contract_full, target, owner=owner, kind=kind)
    if resolved:
        return resolved
    if target == "cleaning_manifest.json":
        state_manifest_path = normalize_artifact_path(state_obj.get("cleaning_manifest_path"))
        if state_manifest_path:
            return state_manifest_path
    target_norm = normalize_artifact_path(target or "")
    target_base = os.path.basename(target_norm.lower()) if target_norm else ""
    state_declared_paths: List[str] = []
    for candidate in (state_obj.get("ml_improvement_output_paths"), state_obj.get("required_outputs")):
        if not isinstance(candidate, list):
            continue
        for item in candidate:
            normalized = normalize_artifact_path(item)
            if normalized and normalized not in state_declared_paths:
                state_declared_paths.append(normalized)
    artifact_index = state_obj.get("artifact_index")
    if isinstance(artifact_index, list):
        for item in artifact_index:
            if not isinstance(item, dict):
                continue
            normalized = normalize_artifact_path(item.get("path"))
            if normalized and normalized not in state_declared_paths:
                state_declared_paths.append(normalized)
    if target_norm and state_declared_paths:
        exact_matches = [path for path in state_declared_paths if path.lower() == target_norm.lower()]
        if exact_matches:
            return exact_matches[0]
        basename_matches = [
            path for path in state_declared_paths if target_base and os.path.basename(path.lower()) == target_base
        ]
        if basename_matches:
            return basename_matches[0]
    return normalize_artifact_path(fallback) if fallback else ""


def _resolve_cleaning_manifest_path_from_state(
    state: Dict[str, Any] | None,
    fallback: str = "",
) -> str:
    state_obj = state if isinstance(state, dict) else {}
    contract_full, _ = _resolve_contract_pair_from_state(state_obj)
    resolved = get_clean_manifest_path(contract_full)
    if resolved:
        return resolved
    state_manifest_path = normalize_artifact_path(state_obj.get("cleaning_manifest_path"))
    if state_manifest_path:
        return state_manifest_path
    return normalize_artifact_path(fallback)


def _load_declared_json_artifact_from_state(
    state: Dict[str, Any] | None,
    target: str,
    *,
    owner: str | None = None,
    kind: str | None = None,
    fallback: str = "",
) -> Tuple[Dict[str, Any], str]:
    path = _resolve_declared_artifact_path_from_state(
        state,
        target,
        owner=owner,
        kind=kind,
        fallback=fallback,
    )
    payload = _load_json_safe(path) if path else {}
    if isinstance(payload, dict):
        return payload, path
    return {}, path


def _resolve_declared_artifact_path_from_contract_or_state(
    contract: Dict[str, Any] | None,
    state: Dict[str, Any] | None,
    target: str,
    *,
    owner: str | None = None,
    kind: str | None = None,
    fallback: str = "",
) -> str:
    contract_obj = contract if isinstance(contract, dict) else {}
    resolved = get_declared_artifact_path(contract_obj, target, owner=owner, kind=kind)
    if resolved:
        return resolved
    if target == "cleaning_manifest.json":
        manifest_path = get_clean_manifest_path(contract_obj)
        if manifest_path:
            return manifest_path
    return _resolve_declared_artifact_path_from_state(
        state,
        target,
        owner=owner,
        kind=kind,
        fallback=fallback,
    )


def _persist_execution_contract_snapshot(
    state: Dict[str, Any],
    contract: Dict[str, Any],
    contract_min: Dict[str, Any] | None,
) -> Dict[str, Any]:
    contract_payload = contract if isinstance(contract, dict) else {}
    iteration_id = int(state.get("iteration_count", 0) or 0) + 1
    run_id = state.get("run_id")
    contract_sig = _hash_json(contract_payload)
    snapshot = {
        "snapshot_schema_version": 1,
        "run_id": run_id,
        "iteration_id": iteration_id,
        "captured_at_utc": datetime.utcnow().isoformat() + "Z",
        "execution_contract_signature": contract_sig,
        "execution_contract_min_signature": None,
        "execution_contract": _freeze_payload(contract_payload),
        "execution_contract_min": {},
    }

    os.makedirs(os.path.join("data", "contracts", "snapshots"), exist_ok=True)
    snapshot_path = os.path.join(
        "data",
        "contracts",
        "snapshots",
        f"contract_snapshot_iter_{iteration_id}.json",
    )
    dump_json(snapshot_path, snapshot)
    latest_path = os.path.join("data", "contract_snapshot_latest.json")
    dump_json(latest_path, snapshot)

    run_bundle_dir = state.get("run_bundle_dir")
    if run_bundle_dir:
        try:
            dest_main = os.path.join(
                run_bundle_dir,
                "artifacts",
                "data",
                "contracts",
                "snapshots",
                os.path.basename(snapshot_path),
            )
            os.makedirs(os.path.dirname(dest_main), exist_ok=True)
            shutil.copy2(os.path.abspath(snapshot_path), dest_main)
            dest_latest = os.path.join(run_bundle_dir, "artifacts", "data", "contract_snapshot_latest.json")
            os.makedirs(os.path.dirname(dest_latest), exist_ok=True)
            shutil.copy2(os.path.abspath(latest_path), dest_latest)
        except Exception as copy_err:
            print(f"Warning: failed to copy contract snapshot into bundle: {copy_err}")

    return {
        "snapshot": snapshot,
        "snapshot_path": snapshot_path,
        "snapshot_latest_path": latest_path,
        "execution_contract_signature": contract_sig,
        "execution_contract_min_signature": None,
        "execution_contract_source": "execution_planner_snapshot",
    }


def _summarize_alignment_requirements(alignment_check: Dict[str, Any]) -> Dict[str, Any]:
    requirements = alignment_check.get("requirements")
    failed: List[Dict[str, Any]] = []
    warned: List[Dict[str, Any]] = []
    if isinstance(requirements, list):
        for item in requirements:
            if not isinstance(item, dict):
                continue
            name = str(item.get("name") or item.get("id") or item.get("gate") or "requirement")
            req_status = str(item.get("status") or "").upper()
            entry = {
                "name": name,
                "status": req_status or "UNKNOWN",
                "evidence": _truncate_text(str(item.get("evidence") or item.get("summary") or ""), max_len=260),
            }
            if req_status == "FAIL":
                failed.append(entry)
            elif req_status == "WARN":
                warned.append(entry)
    return {
        "status": str(alignment_check.get("status") or "").upper() or "UNKNOWN",
        "failure_mode": str(alignment_check.get("failure_mode") or ""),
        "summary": _truncate_text(str(alignment_check.get("summary") or alignment_check.get("notes") or ""), max_len=320),
        "failed_requirements": failed,
        "warn_requirements": warned,
    }


def _metrics_report_has_values(report: Dict[str, Any] | None) -> bool:
    if not isinstance(report, dict):
        return False
    model_perf = report.get("model_performance")
    if isinstance(model_perf, dict) and bool(model_perf):
        return True
    return bool(_extract_metric_like_numbers(report, max_items=80))


def _metric_key_looks_metric_like(name: str) -> bool:
    key = _normalize_metric_key(name)
    if not key:
        return False
    if key in {"value", "score", "metric", "primarymetric", "primarymetricvalue", "cvmean", "mean"}:
        return True
    tokens = (
        "metric",
        "score",
        "auc",
        "gini",
        "logloss",
        "loss",
        "error",
        "rmse",
        "mae",
        "mape",
        "smape",
        "r2",
        "accuracy",
        "acc",
        "precision",
        "recall",
        "f1",
        "spearman",
        "kendall",
        "ndcg",
        "map",
        "mrr",
        "ks",
        "lift",
    )
    return any(token in key for token in tokens)


def _extract_metric_like_numbers(payload: Any, max_items: int = 400) -> Dict[str, float]:
    metrics: Dict[str, float] = {}

    def _coerce_numeric(value: Any) -> float | None:
        if isinstance(value, bool):
            return None
        if isinstance(value, (int, float)):
            try:
                return float(value)
            except Exception:
                return None
        if isinstance(value, str):
            token = value.strip()
            if not token:
                return None
            try:
                return float(token)
            except Exception:
                return None
        return None

    def _walk(node: Any, prefix: str = "", depth: int = 0) -> None:
        if len(metrics) >= max_items or depth > 6:
            return
        if isinstance(node, dict):
            for key, value in node.items():
                key_text = str(key)
                next_prefix = f"{prefix}.{key_text}" if prefix else key_text
                numeric = _coerce_numeric(value)
                if numeric is not None:
                    if _metric_key_looks_metric_like(next_prefix) or _metric_key_looks_metric_like(key_text):
                        metrics[next_prefix] = float(numeric)
                    continue
                if isinstance(value, (dict, list)):
                    _walk(value, next_prefix, depth + 1)
            return
        if isinstance(node, list):
            for idx, item in enumerate(node[:80]):
                list_prefix = f"{prefix}[{idx}]" if prefix else f"[{idx}]"
                if isinstance(item, dict):
                    name = item.get("name") or item.get("metric")
                    metric_value = item.get("value")
                    if metric_value is None:
                        metric_value = item.get("mean")
                    numeric = _coerce_numeric(metric_value)
                    if name and numeric is not None:
                        metric_name = str(name).strip()
                        merged_key = f"{prefix}.{metric_name}" if prefix else metric_name
                        if _metric_key_looks_metric_like(merged_key):
                            metrics[merged_key] = float(numeric)
                    _walk(item, list_prefix, depth + 1)
                else:
                    numeric = _coerce_numeric(item)
                    if numeric is not None and _metric_key_looks_metric_like(prefix):
                        metrics[list_prefix] = float(numeric)
            return

    _walk(payload)
    return metrics


def _is_metrics_like_path(path: str) -> bool:
    text = str(path or "").strip().lower()
    if not text or not text.endswith(".json"):
        return False
    return any(
        token in text
        for token in (
            "metric",
            "evaluation",
            "score",
            "gini",
            "auc",
            "accuracy",
            "precision",
            "recall",
            "f1",
            "rmse",
            "mae",
            "r2",
        )
    )


def _merge_model_performance_entry(model_perf: Dict[str, Any], metric_name: str, value: Any) -> None:
    name = str(metric_name or "").strip()
    if not name:
        return
    num = _coerce_float(value)
    if num is not None:
        model_perf[name] = float(num)
        return
    if not isinstance(value, dict):
        return
    mean = _coerce_float(value.get("mean"))
    if mean is None:
        mean = _coerce_float(value.get("value"))
    if mean is None:
        return
    entry: Dict[str, Any] = {"mean": float(mean)}
    for key in ("ci_lower", "ci_upper", "std", "stdev", "std_dev"):
        if key in value:
            coerced = _coerce_float(value.get(key))
            if coerced is not None:
                entry[key] = float(coerced)
    model_perf[name] = entry


def _normalize_metrics_report_payload(payload: Dict[str, Any] | None) -> Dict[str, Any]:
    if not isinstance(payload, dict) or not payload:
        return {}
    existing_model_perf = payload.get("model_performance")
    if isinstance(existing_model_perf, dict) and bool(existing_model_perf):
        return dict(payload)

    model_perf: Dict[str, Any] = {}

    primary_metric = payload.get("primary_metric")
    if isinstance(primary_metric, dict):
        metric_name = primary_metric.get("name") or primary_metric.get("metric")
        _merge_model_performance_entry(model_perf, str(metric_name or ""), primary_metric.get("value"))

    explicit_primary_name = (
        payload.get("primary_metric_name")
        or (primary_metric if isinstance(primary_metric, str) else None)
    )
    if explicit_primary_name and payload.get("primary_metric_value") is not None:
        _merge_model_performance_entry(
            model_perf,
            str(explicit_primary_name),
            payload.get("primary_metric_value"),
        )

    for block_name in ("cv_summary", "all_metrics", "metrics", "summary"):
        block = payload.get(block_name)
        if not isinstance(block, dict):
            continue
        for metric_name, metric_value in block.items():
            _merge_model_performance_entry(model_perf, str(metric_name), metric_value)

    for list_name in ("metrics_summary", "model_metrics"):
        block = payload.get(list_name)
        if not isinstance(block, list):
            continue
        for item in block:
            if not isinstance(item, dict):
                continue
            metric_name = item.get("metric") or item.get("name")
            if not metric_name:
                continue
            metric_name = str(metric_name)
            if metric_name.lower().startswith("model_performance."):
                metric_name = metric_name.split(".", 1)[1]
            metric_value = item.get("value")
            if metric_value is None:
                metric_value = item.get("mean")
            _merge_model_performance_entry(model_perf, metric_name, metric_value)

    generic_metrics = _extract_metric_like_numbers(payload)
    if generic_metrics:
        for metric_key, metric_value in generic_metrics.items():
            _merge_model_performance_entry(model_perf, metric_key, metric_value)

    if not model_perf:
        return {}
    normalized = dict(payload)
    normalized["model_performance"] = model_perf
    return normalized


def _resolve_output_contract_report_for_facts(state: Dict[str, Any]) -> Dict[str, Any]:
    current = state.get("output_contract_report")
    if not isinstance(current, dict):
        current = _load_json_safe("data/output_contract_report.json")
    if not isinstance(current, dict):
        current = {}

    best = state.get("best_attempt_output_contract_report")
    if not isinstance(best, dict):
        best = {}

    last_success = state.get("last_successful_output_contract_report")
    if not isinstance(last_success, dict):
        last_success = {}

    current_missing = [str(x) for x in (current.get("missing") or []) if x] if isinstance(current, dict) else []
    current_status = str(current.get("overall_status") or "").lower() if isinstance(current, dict) else ""

    def _is_clean(report: Dict[str, Any]) -> bool:
        if not isinstance(report, dict) or not report:
            return False
        missing = [str(x) for x in (report.get("missing") or []) if x]
        status = str(report.get("overall_status") or "").lower()
        return not missing and status != "error"

    if (current_missing or current_status == "error") and _is_clean(best):
        return best
    if (current_missing or current_status == "error") and _is_clean(last_success):
        return last_success
    if current:
        return current
    if best:
        return best
    if last_success:
        return last_success
    return {}


def _resolve_metrics_report_for_facts(state: Dict[str, Any]) -> Dict[str, Any]:
    candidates: List[tuple[Dict[str, Any], str]] = []
    metric_round_active = bool(state.get("ml_improvement_round_active"))
    state_metrics = state.get("metrics_report")
    state_metrics_snapshot = state.get("metrics_artifact_snapshot")
    snapshot_is_fresh = _metrics_snapshot_matches_active_attempt(state, state_metrics_snapshot)
    snapshot_role = (
        str(state_metrics_snapshot.get("role") or "").strip().lower()
        if isinstance(state_metrics_snapshot, dict)
        else ""
    )
    if isinstance(state_metrics, dict) and state_metrics and (
        (not metric_round_active) or (snapshot_role == "candidate" and snapshot_is_fresh)
    ):
        candidates.append((state_metrics, "state.metrics_report"))

    if not metric_round_active and isinstance(state_metrics_snapshot, dict):
        snapshot_payload = (
            state_metrics_snapshot.get("metrics_payload")
            if isinstance(state_metrics_snapshot.get("metrics_payload"), dict)
            else {}
        )
        if snapshot_payload:
            snapshot_source = str(
                state_metrics_snapshot.get("source")
                or state_metrics_snapshot.get("path")
                or "state.metrics_artifact_snapshot"
            ).strip()
            candidates.append((snapshot_payload, snapshot_source))
    elif (
        metric_round_active
        and isinstance(state_metrics_snapshot, dict)
        and snapshot_role == "candidate"
        and snapshot_is_fresh
    ):
        snapshot_payload = (
            state_metrics_snapshot.get("metrics_payload")
            if isinstance(state_metrics_snapshot.get("metrics_payload"), dict)
            else {}
        )
        if snapshot_payload:
            snapshot_source = str(
                state_metrics_snapshot.get("source")
                or state_metrics_snapshot.get("path")
                or "state.metrics_artifact_snapshot"
            ).strip()
            candidates.append((snapshot_payload, snapshot_source))

    insights = _load_json_safe("data/insights.json")
    if not metric_round_active and isinstance(insights, dict) and insights:
        candidates.append((insights, "data/insights.json"))

    for payload, source in candidates:
        normalized = _normalize_metrics_report_payload(payload)
        if _metrics_report_has_values(normalized):
            normalized.setdefault("source", source)
            return normalized

    artifact_paths: List[str] = []
    seen_paths: set[str] = set()

    def _add_path(path: Any) -> None:
        if not isinstance(path, str):
            return
        rel = path.strip().replace("\\", "/")
        if not rel or rel in seen_paths:
            return
        seen_paths.add(rel)
        artifact_paths.append(rel)

    artifact_index = state.get("artifact_index")
    if not isinstance(artifact_index, list):
        artifact_index = state.get("produced_artifact_index")
    if not isinstance(artifact_index, list):
        artifact_index = _load_json_safe("data/produced_artifact_index.json")
    if isinstance(artifact_index, list):
        for entry in reversed(artifact_index):
            if isinstance(entry, dict):
                path = entry.get("path")
                if isinstance(path, str):
                    _add_path(path)
            elif isinstance(entry, str):
                _add_path(entry)

    for path in artifact_paths:
        if not _is_metrics_like_path(path):
            continue
        payload = _load_json_safe(path)
        normalized = _normalize_metrics_report_payload(payload if isinstance(payload, dict) else {})
        if _metrics_report_has_values(normalized):
            normalized.setdefault("source", f"artifact:{path}")
            return normalized

    metrics_path = _resolve_declared_artifact_path_from_state(
        state,
        "metrics.json",
        kind="metrics",
    )
    file_metrics = _load_json_safe(metrics_path) if metrics_path else {}
    if isinstance(file_metrics, dict) and file_metrics:
        normalized = _normalize_metrics_report_payload(file_metrics)
        if _metrics_report_has_values(normalized):
            normalized.setdefault("source", metrics_path)
            return normalized

    oc_report = _resolve_output_contract_report_for_facts(state)
    if isinstance(oc_report, dict):
        for path in oc_report.get("present", []) or []:
            _add_path(path)

    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    for path in _resolve_required_outputs(contract, state):
        _add_path(path)

    for path in artifact_paths:
        if not _is_metrics_like_path(path):
            continue
        payload = _load_json_safe(path)
        normalized = _normalize_metrics_report_payload(payload if isinstance(payload, dict) else {})
        if _metrics_report_has_values(normalized):
            normalized.setdefault("source", f"artifact:{path}")
            return normalized

    return {}


def _coerce_optional_bool(value: Any) -> bool | None:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        if value == 1:
            return True
        if value == 0:
            return False
        return None
    token = str(value or "").strip().lower()
    if token in {"1", "true", "yes", "y", "higher", "maximize", "max"}:
        return True
    if token in {"0", "false", "no", "n", "lower", "minimize", "min"}:
        return False
    return None


def _resolve_metric_from_entry(entry: Any, source: str) -> Dict[str, Any] | None:
    if not isinstance(entry, dict):
        return None
    keys_in_priority = [
        "competition_metric",
        "leaderboard_metric",
        "kaggle_metric",
        "primary_metric",
    ]
    for key in keys_in_priority:
        raw = entry.get(key)
        metric_name = ""
        higher_is_better: bool | None = None
        if isinstance(raw, dict):
            metric_name = str(
                raw.get("name")
                or raw.get("metric")
                or raw.get("id")
                or raw.get("value")
                or ""
            ).strip()
            higher_is_better = _coerce_optional_bool(
                raw.get("higher_is_better")
                if raw.get("higher_is_better") is not None
                else raw.get("maximize")
            )
        elif isinstance(raw, str):
            metric_name = raw.strip()
        if not metric_name:
            continue
        if higher_is_better is None:
            higher_is_better = _coerce_optional_bool(entry.get(key + "_higher_is_better"))
        if higher_is_better is None and key == "primary_metric":
            higher_is_better = _coerce_optional_bool(entry.get("higher_is_better"))
        return {
            "name": metric_name,
            "canonical_name": metric_eval_canonicalize_metric_name(metric_name),
            "higher_is_better": higher_is_better,
            "source": source + "." + key,
        }
    return None


def _metric_canonical_name(metric_name: Any) -> str:
    return metric_eval_canonicalize_metric_name(str(metric_name or ""))


def _load_primary_metric_state(state: Dict[str, Any] | None = None) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    payload = state.get("primary_metric_state")
    if isinstance(payload, dict) and payload:
        return dict(payload)
    loaded = _load_json_safe("data/metric_state.json")
    if isinstance(loaded, dict) and loaded:
        return loaded
    snapshot = state.get("primary_metric_snapshot")
    if isinstance(snapshot, dict) and snapshot:
        return dict(snapshot)
    return {}


def _persist_primary_metric_state(
    metric_state: Dict[str, Any] | None,
    *,
    existing_index: Any = None,
) -> List[Dict[str, Any]]:
    metric_state = metric_state if isinstance(metric_state, dict) else {}
    if not metric_state:
        return existing_index if isinstance(existing_index, list) else []
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/metric_state.json", metric_state)
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(["data/metric_state.json"], None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        return merged_index
    except Exception as metric_err:
        print(f"Warning: failed to persist metric_state.json: {metric_err}")
        return existing_index if isinstance(existing_index, list) else []


def _load_metric_loop_state(
    state: Dict[str, Any] | None = None,
    contract: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    payload = state.get("metric_loop_state")
    if isinstance(payload, dict) and payload:
        return dict(payload)
    loaded = _load_json_safe("data/metric_loop_state.json")
    if isinstance(loaded, dict) and loaded:
        return loaded
    return _derive_metric_loop_state_from_legacy(
        state,
        contract if isinstance(contract, dict) else (
            state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
        ),
    )


def _persist_metric_loop_state(
    metric_loop_state: Dict[str, Any] | None,
    *,
    existing_index: Any = None,
) -> List[Dict[str, Any]]:
    metric_loop_state = metric_loop_state if isinstance(metric_loop_state, dict) else {}
    if not metric_loop_state:
        return existing_index if isinstance(existing_index, list) else []
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/metric_loop_state.json", metric_loop_state)
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(["data/metric_loop_state.json"], None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        return merged_index
    except Exception as metric_err:
        print(f"Warning: failed to persist metric_loop_state.json: {metric_err}")
        return existing_index if isinstance(existing_index, list) else []


def _load_declared_artifact_payload(
    contract: Dict[str, Any] | None,
    state: Dict[str, Any] | None,
    artifact_name: str,
    *,
    kind: str | None = None,
) -> Tuple[Dict[str, Any], str | None]:
    contract = contract if isinstance(contract, dict) else {}
    state = state if isinstance(state, dict) else {}
    path = _resolve_declared_artifact_path_from_contract_or_state(
        contract,
        state,
        artifact_name,
        kind=kind,
    )
    payload = _load_json_safe(path) if path else {}
    if kind == "metrics" and (not isinstance(payload, dict) or not payload):
        metric_candidates: List[str] = []

        def _add_metric_candidate(candidate_path: Any) -> None:
            normalized = normalize_artifact_path(candidate_path)
            if (
                normalized
                and normalized not in metric_candidates
                and _is_metrics_like_path(normalized)
            ):
                metric_candidates.append(normalized)

        _add_metric_candidate(path)
        for candidate_path in get_required_outputs(contract):
            _add_metric_candidate(candidate_path)
        artifact_requirements = get_artifact_requirements(contract)
        if isinstance(artifact_requirements, dict):
            required_files = artifact_requirements.get("required_files")
            if isinstance(required_files, list):
                for item in required_files:
                    if isinstance(item, dict):
                        _add_metric_candidate(item.get("path"))
                    else:
                        _add_metric_candidate(item)
            file_schemas = artifact_requirements.get("file_schemas")
            if isinstance(file_schemas, dict):
                for schema_path in file_schemas.keys():
                    _add_metric_candidate(schema_path)
        for candidate_group in (
            state.get("ml_improvement_output_paths"),
            state.get("required_outputs"),
        ):
            if not isinstance(candidate_group, list):
                continue
            for item in candidate_group:
                _add_metric_candidate(item)
        artifact_index = state.get("artifact_index")
        if isinstance(artifact_index, list):
            for item in artifact_index:
                if isinstance(item, dict):
                    _add_metric_candidate(item.get("path"))

        for candidate_path in metric_candidates:
            candidate_payload = _load_json_safe(candidate_path)
            if isinstance(candidate_payload, dict) and candidate_payload:
                payload = candidate_payload
                path = candidate_path
                break
    return (payload if isinstance(payload, dict) else {}), path


def _load_metric_snapshot_payload(
    snapshot_dir: Any,
    artifact_paths: List[str] | None,
) -> Tuple[Dict[str, Any], str | None]:
    snapshot_root = str(snapshot_dir or "").strip()
    if not snapshot_root:
        return {}, None
    candidates: List[str] = []
    for item in artifact_paths or []:
        normalized = normalize_artifact_path(item)
        if normalized and normalized not in candidates:
            candidates.append(normalized)
    for rel_path in candidates:
        candidate_path = Path(snapshot_root) / Path(rel_path)
        if not candidate_path.exists():
            continue
        payload = _load_json_safe(str(candidate_path))
        if isinstance(payload, dict) and payload:
            return payload, normalize_artifact_path(rel_path)
    return {}, None


def _metrics_snapshot_payload(snapshot: Dict[str, Any] | None) -> Dict[str, Any]:
    if not isinstance(snapshot, dict):
        return {}
    payload = snapshot.get("metrics_payload")
    return copy.deepcopy(payload) if isinstance(payload, dict) and payload else {}


def _build_metrics_artifact_snapshot(
    *,
    state: Dict[str, Any] | None,
    role: str,
    metrics_payload: Dict[str, Any] | None,
    path: str | None = None,
    source: str | None = None,
    metric_name: str | None = None,
    higher_is_better: bool | None = None,
    round_id: Any = None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    payload = copy.deepcopy(metrics_payload) if isinstance(metrics_payload, dict) else {}
    normalized_path = normalize_artifact_path(path)
    resolved_metric = _resolve_metric_payload(
        payload,
        metric_name,
        source_hint=str(source or normalized_path or "metrics_snapshot"),
    )
    try:
        normalized_round_id = int(round_id) if round_id is not None else None
    except Exception:
        normalized_round_id = None
    snapshot = {
        "schema_version": "v1",
        "role": str(role or "").strip() or "unknown",
        "run_id": str(state.get("run_id") or "").strip() or None,
        "iteration_id": int(state.get("iteration_count", 0) or 0) + 1 if isinstance(state, dict) else None,
        "attempt_id": int(state.get("execution_attempt", 0) or 0) if isinstance(state, dict) else None,
        "round_id": normalized_round_id,
        "path": normalized_path or None,
        "source": str(source or normalized_path or "").strip() or None,
        "payload_hash": _hash_json(payload) if payload else "",
        "metrics_payload": payload,
        "primary_metric_name": None,
        "primary_metric_canonical_name": None,
        "primary_metric_value": None,
        "higher_is_better": bool(higher_is_better) if isinstance(higher_is_better, bool) else None,
    }
    if isinstance(resolved_metric, dict) and resolved_metric.get("value") is not None:
        snapshot["primary_metric_name"] = str(
            resolved_metric.get("name")
            or resolved_metric.get("matched_key")
            or metric_name
            or ""
        ).strip() or None
        snapshot["primary_metric_canonical_name"] = str(
            resolved_metric.get("canonical_name")
            or _metric_canonical_name(snapshot.get("primary_metric_name"))
        ).strip() or None
        snapshot["primary_metric_value"] = float(resolved_metric.get("value"))
    return snapshot


def _resolve_metrics_snapshot_from_state(
    state: Dict[str, Any] | None,
    *,
    preferred_roles: List[str] | None = None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    role_order = [str(item or "").strip().lower() for item in (preferred_roles or []) if str(item or "").strip()]
    candidates: List[Dict[str, Any]] = []

    explicit_snapshot = state.get("metrics_artifact_snapshot")
    if isinstance(explicit_snapshot, dict) and (
        _metrics_snapshot_payload(explicit_snapshot) or explicit_snapshot.get("path")
    ):
        candidates.append(copy.deepcopy(explicit_snapshot))

    loop_state = (
        state.get("metric_loop_state")
        if isinstance(state.get("metric_loop_state"), dict)
        else {}
    )
    if not loop_state:
        loaded_loop_state = _load_json_safe("data/metric_loop_state.json")
        if isinstance(loaded_loop_state, dict):
            loop_state = loaded_loop_state

    artifacts_block = loop_state.get("artifacts") if isinstance(loop_state.get("artifacts"), dict) else {}
    snapshots_block = artifacts_block.get("snapshots") if isinstance(artifacts_block.get("snapshots"), dict) else {}
    for value in snapshots_block.values():
        if isinstance(value, dict) and (_metrics_snapshot_payload(value) or value.get("path")):
            candidates.append(copy.deepcopy(value))

    round_payload = loop_state.get("round") if isinstance(loop_state.get("round"), dict) else {}
    loop_entries = {
        "final": loop_state.get("final"),
        "candidate": loop_state.get("candidate"),
        "incumbent": loop_state.get("incumbent"),
        "round_baseline": round_payload.get("baseline"),
    }
    for role_name, entry in loop_entries.items():
        if not isinstance(entry, dict):
            continue
        snapshot = entry.get("artifact_snapshot") if isinstance(entry.get("artifact_snapshot"), dict) else {}
        if not snapshot:
            payload = entry.get("metrics_payload") if isinstance(entry.get("metrics_payload"), dict) else {}
            path = entry.get("path")
            if payload or path:
                snapshot = _build_metrics_artifact_snapshot(
                    state=state,
                    role=role_name,
                    metrics_payload=payload,
                    path=str(path or ""),
                    source=str(entry.get("source") or ""),
                    metric_name=str(entry.get("metric_name") or ""),
                    round_id=entry.get("round_id"),
                )
        if snapshot and (_metrics_snapshot_payload(snapshot) or snapshot.get("path")):
            candidates.append(snapshot)

    if not candidates:
        return {}
    if role_order:
        for role in role_order:
            for snapshot in candidates:
                if str(snapshot.get("role") or "").strip().lower() == role:
                    return copy.deepcopy(snapshot)
    return copy.deepcopy(candidates[0])


def _metrics_snapshot_matches_active_attempt(
    state: Dict[str, Any] | None,
    snapshot: Dict[str, Any] | None,
) -> bool:
    state = state if isinstance(state, dict) else {}
    snapshot = snapshot if isinstance(snapshot, dict) else {}
    if not snapshot or not bool(state.get("ml_improvement_round_active")):
        return True

    current_attempt = _coerce_nonnegative_int(state.get("execution_attempt"), default=0)
    snapshot_attempt = _coerce_nonnegative_int(snapshot.get("attempt_id"), default=0)
    if current_attempt > 0 and snapshot_attempt > 0 and snapshot_attempt != current_attempt:
        return False

    current_round = _coerce_nonnegative_int(state.get("ml_improvement_current_round_id"), default=0)
    snapshot_round = _coerce_nonnegative_int(snapshot.get("round_id"), default=0)
    if current_round > 0 and snapshot_round > 0 and snapshot_round != current_round:
        return False

    return True


def _metric_loop_controller(loop_state: Dict[str, Any] | None) -> Dict[str, Any]:
    return (
        loop_state.get("controller")
        if isinstance(loop_state, dict) and isinstance(loop_state.get("controller"), dict)
        else {}
    )


def _metric_loop_is_closed_for_routing(state: Dict[str, Any] | Any) -> bool:
    state_obj = state if isinstance(state, dict) else {}
    if bool(state_obj.get("ml_improvement_loop_complete")):
        return True
    loop_state = _load_metric_loop_state(state_obj, None)
    if not isinstance(loop_state, dict) or not loop_state:
        return False
    controller = _metric_loop_controller(loop_state)
    selection = loop_state.get("selection") if isinstance(loop_state.get("selection"), dict) else {}
    round_payload = loop_state.get("round") if isinstance(loop_state.get("round"), dict) else {}
    try:
        round_id = int(round_payload.get("round_id") or 0)
    except Exception:
        round_id = 0
    active = (
        bool(controller.get("active"))
        if isinstance(controller.get("active"), bool)
        else bool(state_obj.get("ml_improvement_round_active"))
    )
    continue_round = (
        bool(controller.get("continue_round"))
        if isinstance(controller.get("continue_round"), bool)
        else bool(state_obj.get("ml_improvement_continue"))
    )
    selected_label = str(selection.get("selected_label") or "").strip()
    return bool((not active) and (not continue_round) and round_id > 0 and selected_label)


def _metric_loop_artifacts(loop_state: Dict[str, Any] | None) -> Dict[str, Any]:
    return (
        loop_state.get("artifacts")
        if isinstance(loop_state, dict) and isinstance(loop_state.get("artifacts"), dict)
        else {}
    )


def _resolve_metric_loop_value(
    metric_name: str | None,
    metrics_payload: Dict[str, Any] | None,
    fallback_value: Any = None,
) -> float | None:
    payload = metrics_payload if isinstance(metrics_payload, dict) else {}
    metric_name = str(metric_name or "").strip()
    if metric_name and payload:
        resolved = _resolve_metric_payload(payload, metric_name, source_hint="metric_loop_state")
        if isinstance(resolved, dict) and resolved.get("value") is not None:
            return float(resolved.get("value"))
    return _coerce_float(fallback_value)


def _build_metric_loop_entry(
    *,
    label: str,
    metric_name: str,
    canonical_name: str,
    metrics_payload: Dict[str, Any] | None,
    fallback_value: Any = None,
    path: str | None = None,
    source: str | None = None,
    round_id: Any = None,
    status: str | None = None,
    review_verdict: str | None = None,
    artifact_snapshot: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    payload = metrics_payload if isinstance(metrics_payload, dict) else {}
    metric_value = _resolve_metric_loop_value(metric_name, payload, fallback_value)
    try:
        round_id_int = int(round_id) if round_id is not None else None
    except Exception:
        round_id_int = None
    return {
        "label": str(label or "").strip() or "unknown",
        "metric_name": str(metric_name or "").strip() or None,
        "canonical_name": str(canonical_name or _metric_canonical_name(metric_name)).strip() or None,
        "metric_value": float(metric_value) if metric_value is not None else None,
        "metrics_payload": copy.deepcopy(payload) if payload else {},
        "path": str(path or "").strip() or None,
        "source": str(source or "").strip() or None,
        "round_id": round_id_int,
        "status": str(status or "").strip() or None,
        "review_verdict": str(review_verdict or "").strip() or None,
        "artifact_snapshot": (
            copy.deepcopy(artifact_snapshot)
            if isinstance(artifact_snapshot, dict) and artifact_snapshot
            else {}
        ),
    }


def _metric_loop_value_is_better(
    candidate_value: Any,
    incumbent_value: Any,
    higher_is_better: bool,
) -> bool:
    candidate = _coerce_float(candidate_value)
    incumbent = _coerce_float(incumbent_value)
    if candidate is None:
        return False
    if incumbent is None:
        return True
    if higher_is_better:
        return float(candidate) > float(incumbent)
    return float(candidate) < float(incumbent)


def _resolve_metric_loop_higher_is_better(
    metric_name: str | None,
    *,
    metric_target: Dict[str, Any] | None = None,
    loop_target: Dict[str, Any] | None = None,
    primary_metric_state: Dict[str, Any] | None = None,
) -> bool:
    metric_target = metric_target if isinstance(metric_target, dict) else {}
    loop_target = loop_target if isinstance(loop_target, dict) else {}
    primary_metric_state = primary_metric_state if isinstance(primary_metric_state, dict) else {}

    for source in (metric_target, loop_target, primary_metric_state):
        higher_is_better = source.get("higher_is_better")
        if isinstance(higher_is_better, bool):
            return bool(higher_is_better)
    return bool(_metric_higher_is_better(str(metric_name or "")))


def _has_metric_loop_legacy_evidence(state: Dict[str, Any] | None) -> bool:
    state = state if isinstance(state, dict) else {}
    if not state:
        return False
    if any(
        bool(state.get(key))
        for key in (
            "ml_improvement_round_active",
            "ml_improvement_continue",
            "ml_improvement_loop_complete",
            "ml_improvement_attempted",
        )
    ):
        return True
    for key in (
        "ml_improvement_round_count",
        "ml_improvement_current_round_id",
        "ml_improvement_no_improve_streak",
        "ml_improvement_best_round",
    ):
        try:
            if int(state.get(key) or 0) > 0:
                return True
        except (TypeError, ValueError):
            continue
    for key in (
        "ml_improvement_round_baseline_metrics",
        "ml_improvement_baseline_metrics",
        "ml_improvement_hypothesis_packet",
        "ml_improvement_critique_packet",
        "ml_improvement_candidate_critique_packet",
    ):
        payload = state.get(key)
        if isinstance(payload, dict) and payload:
            return True
    return False


def _build_metric_loop_state(
    *,
    state: Dict[str, Any],
    contract: Dict[str, Any] | None,
    round_id: int,
    rounds_allowed: int,
    patience: int,
    no_improve_streak: int,
    min_delta: float,
    active: bool,
    incumbent_metrics_payload: Dict[str, Any] | None,
    incumbent_fallback_value: Any = None,
    incumbent_path: str | None = None,
    incumbent_source: str = "round_baseline",
    baseline_review_verdict: str | None = None,
    candidate_metrics_payload: Dict[str, Any] | None = None,
    candidate_fallback_value: Any = None,
    candidate_path: str | None = None,
    candidate_source: str | None = None,
    candidate_status: str | None = None,
    best_observed_value: Any = None,
    best_observed_label: str | None = None,
    best_observed_source: str | None = None,
    final_label: str | None = None,
    final_metrics_payload: Dict[str, Any] | None = None,
    final_fallback_value: Any = None,
    final_path: str | None = None,
    final_source: str | None = None,
    selection: Dict[str, Any] | None = None,
    output_paths: List[str] | None = None,
    snapshot_dir: str | None = None,
    review_mode: str | None = None,
    continue_round: bool | None = None,
    force_finalize_reason: str | None = None,
) -> Dict[str, Any]:
    contract = contract if isinstance(contract, dict) else {}
    metric_target = _resolve_contract_metric_target(state if isinstance(state, dict) else {}, contract)
    prior_loop_target = (
        state.get("metric_loop_state", {}).get("target")
        if isinstance(state.get("metric_loop_state"), dict)
        and isinstance(state.get("metric_loop_state", {}).get("target"), dict)
        else {}
    )
    primary_metric_state = _load_primary_metric_state(state if isinstance(state, dict) else {})
    metric_name = str(
        metric_target.get("name")
        or prior_loop_target.get("name")
        or primary_metric_state.get("target_metric_name")
        or primary_metric_state.get("primary_metric_name")
        or state.get("ml_improvement_primary_metric_name")
        or ""
    ).strip()
    canonical_name = str(
        metric_target.get("canonical_name")
        or prior_loop_target.get("canonical_name")
        or primary_metric_state.get("target_metric_canonical_name")
        or primary_metric_state.get("primary_metric_canonical_name")
        or _metric_canonical_name(metric_name)
    ).strip()
    higher_is_better = _resolve_metric_loop_higher_is_better(
        metric_name,
        metric_target=metric_target,
        loop_target=prior_loop_target,
        primary_metric_state=primary_metric_state,
    )

    incumbent = _build_metric_loop_entry(
        label="incumbent",
        metric_name=metric_name,
        canonical_name=canonical_name,
        metrics_payload=incumbent_metrics_payload,
        fallback_value=incumbent_fallback_value,
        path=incumbent_path,
        source=incumbent_source,
        round_id=round_id,
        status="active" if active else "stable",
        review_verdict=baseline_review_verdict,
    )
    incumbent_payload_for_snapshot = (
        incumbent.get("metrics_payload")
        if isinstance(incumbent.get("metrics_payload"), dict)
        else {}
    )
    incumbent["artifact_snapshot"] = _build_metrics_artifact_snapshot(
        state=state,
        role="incumbent",
        metrics_payload=incumbent_payload_for_snapshot,
        path=str(incumbent.get("path") or ""),
        source=str(incumbent.get("source") or ""),
        metric_name=metric_name,
        higher_is_better=bool(higher_is_better),
        round_id=round_id,
    )
    round_baseline = copy.deepcopy(incumbent)
    round_baseline["label"] = "round_baseline"
    round_baseline["artifact_snapshot"] = _build_metrics_artifact_snapshot(
        state=state,
        role="round_baseline",
        metrics_payload=round_baseline.get("metrics_payload") if isinstance(round_baseline.get("metrics_payload"), dict) else {},
        path=str(round_baseline.get("path") or ""),
        source=str(round_baseline.get("source") or ""),
        metric_name=metric_name,
        higher_is_better=bool(higher_is_better),
        round_id=round_id,
    )

    candidate = _build_metric_loop_entry(
        label="candidate",
        metric_name=metric_name,
        canonical_name=canonical_name,
        metrics_payload=candidate_metrics_payload,
        fallback_value=candidate_fallback_value,
        path=candidate_path,
        source=candidate_source,
        round_id=round_id,
        status=candidate_status or ("pending" if active else None),
        review_verdict=None,
    )
    candidate["artifact_snapshot"] = _build_metrics_artifact_snapshot(
        state=state,
        role="candidate",
        metrics_payload=candidate.get("metrics_payload") if isinstance(candidate.get("metrics_payload"), dict) else {},
        path=str(candidate.get("path") or ""),
        source=str(candidate.get("source") or ""),
        metric_name=metric_name,
        higher_is_better=bool(higher_is_better),
        round_id=round_id,
    )

    best_value = _coerce_float(best_observed_value)
    if best_value is None:
        best_value = incumbent.get("metric_value")
    best_label = str(best_observed_label or ("incumbent" if best_value == incumbent.get("metric_value") else "")).strip() or "incumbent"
    best_source = str(best_observed_source or ("round_baseline" if best_label == "incumbent" else "")).strip() or "round_baseline"

    final_entry = {}
    if final_label or final_metrics_payload or final_fallback_value is not None:
        final_entry = _build_metric_loop_entry(
            label=str(final_label or "final").strip() or "final",
            metric_name=metric_name,
            canonical_name=canonical_name,
            metrics_payload=final_metrics_payload,
            fallback_value=final_fallback_value,
            path=final_path,
            source=final_source,
            round_id=round_id,
            status="selected" if final_label else None,
            review_verdict=None,
        )
        final_role = str(final_entry.get("label") or "final").strip() or "final"
        final_entry["artifact_snapshot"] = _build_metrics_artifact_snapshot(
            state=state,
            role=final_role,
            metrics_payload=final_entry.get("metrics_payload") if isinstance(final_entry.get("metrics_payload"), dict) else {},
            path=str(final_entry.get("path") or ""),
            source=str(final_entry.get("source") or ""),
            metric_name=metric_name,
            higher_is_better=bool(higher_is_better),
            round_id=round_id,
        )

    normalized_output_paths: List[str] = []
    for item in output_paths or []:
        normalized = normalize_artifact_path(item)
        if normalized and normalized not in normalized_output_paths:
            normalized_output_paths.append(normalized)

    return {
        "schema_version": "v1",
        "target": {
            "name": metric_name or None,
            "canonical_name": canonical_name or None,
            "higher_is_better": bool(higher_is_better),
            "min_delta": float(min_delta),
            "source": str(metric_target.get("source") or primary_metric_state.get("target_metric_source") or "metric_loop_state").strip(),
        },
        "round": {
            "round_id": int(round_id),
            "rounds_allowed": int(rounds_allowed),
            "patience": int(patience),
            "no_improve_streak": int(no_improve_streak),
            "status": "active" if active else "complete",
            "baseline": round_baseline,
        },
        "incumbent": incumbent,
        "candidate": candidate,
        "best_observed": {
            "label": best_label,
            "metric_name": metric_name or None,
            "canonical_name": canonical_name or None,
            "metric_value": float(best_value) if best_value is not None else None,
            "round_id": int(round_id),
            "source": best_source,
        },
        "final": final_entry,
        "selection": copy.deepcopy(selection) if isinstance(selection, dict) else {},
        "controller": {
            "active": bool(active),
            "status": "active" if active else "complete",
            "continue_round": (
                bool(continue_round)
                if isinstance(continue_round, bool)
                else None
            ),
            "review_mode": str(review_mode or "").strip() or None,
            "baseline_review_verdict": str(baseline_review_verdict or "").strip() or None,
            "force_finalize_reason": str(force_finalize_reason or "").strip() or None,
        },
        "artifacts": {
            "metrics_path": normalize_artifact_path(final_path or candidate_path or incumbent_path),
            "output_paths": normalized_output_paths[:16],
            "snapshot_dir": str(snapshot_dir or "").strip() or None,
            "snapshots": {
                "round_baseline": copy.deepcopy(round_baseline.get("artifact_snapshot") or {}),
                "incumbent": copy.deepcopy(incumbent.get("artifact_snapshot") or {}),
                "candidate": copy.deepcopy(candidate.get("artifact_snapshot") or {}),
                "final": copy.deepcopy(final_entry.get("artifact_snapshot") or {}),
            },
        },
    }


def _derive_metric_loop_state_from_legacy(
    state: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    contract = contract if isinstance(contract, dict) else {}
    if not _has_metric_loop_legacy_evidence(state):
        return {}
    metric_state = _load_primary_metric_state(state)
    current_metrics_payload, metric_path = _load_declared_artifact_payload(
        contract,
        state,
        "metrics.json",
        kind="metrics",
    )
    round_baseline_metrics = (
        state.get("ml_improvement_round_baseline_metrics")
        if isinstance(state.get("ml_improvement_round_baseline_metrics"), dict)
        else {}
    )
    baseline_metrics = (
        round_baseline_metrics
        if round_baseline_metrics
        else (
            state.get("ml_improvement_baseline_metrics")
            if isinstance(state.get("ml_improvement_baseline_metrics"), dict)
            else {}
        )
    )
    output_paths = state.get("ml_improvement_output_paths") if isinstance(state.get("ml_improvement_output_paths"), list) else []
    snapshot_dir = str(state.get("ml_improvement_snapshot_dir") or "").strip()
    if not baseline_metrics and bool(state.get("ml_improvement_round_active")):
        baseline_metrics, _ = _load_metric_snapshot_payload(
            snapshot_dir,
            ([metric_path] if metric_path else []) + list(output_paths),
        )
    round_id = int(
        state.get("ml_improvement_current_round_id")
        or state.get("ml_improvement_round_count")
        or 0
        or 0
    )
    rounds_allowed = int(state.get("ml_improvement_rounds_allowed", 1) or 1)
    patience = int(state.get("ml_improvement_patience", 2) or 2)
    no_improve_streak = int(state.get("ml_improvement_no_improve_streak", 0) or 0)
    min_delta = float(state.get("ml_improvement_min_delta", 0.0005) or 0.0005)
    active = bool(state.get("ml_improvement_round_active"))
    incumbent_payload = baseline_metrics if baseline_metrics else (current_metrics_payload if not active else {})
    incumbent_fallback_value = (
        state.get("ml_improvement_incumbent_metric")
        if state.get("ml_improvement_incumbent_metric") not in (None, "")
        else (
            state.get("ml_improvement_round_baseline_metric")
            if state.get("ml_improvement_round_baseline_metric") not in (None, "")
            else metric_state.get("baseline_value")
        )
    )
    candidate_payload = current_metrics_payload if active else {}
    candidate_fallback_value = metric_state.get("primary_metric_value") if active else None
    legacy_best_round = _coerce_nonnegative_int(state.get("ml_improvement_best_round"), default=0)
    legacy_best_label = str(state.get("ml_improvement_best_label") or "").strip() or None
    legacy_best_metric = (
        state.get("ml_improvement_best_metric")
        if legacy_best_round > 0 or legacy_best_label
        else None
    )
    return _build_metric_loop_state(
        state=state,
        contract=contract,
        round_id=round_id,
        rounds_allowed=rounds_allowed,
        patience=patience,
        no_improve_streak=no_improve_streak,
        min_delta=min_delta,
        active=active,
        incumbent_metrics_payload=incumbent_payload,
        incumbent_fallback_value=incumbent_fallback_value,
        incumbent_path=metric_path,
        incumbent_source="legacy_round_state" if active else "legacy_current_outputs",
        baseline_review_verdict=str(state.get("ml_improvement_baseline_review_verdict") or "").strip() or None,
        candidate_metrics_payload=candidate_payload,
        candidate_fallback_value=candidate_fallback_value,
        candidate_path=metric_path if active else None,
        candidate_source="legacy_current_outputs" if active else None,
        candidate_status="pending" if active else None,
        best_observed_value=legacy_best_metric,
        best_observed_label=legacy_best_label or "incumbent",
        best_observed_source="legacy_best_metric",
        final_label=state.get("ml_improvement_kept"),
        output_paths=output_paths,
        snapshot_dir=snapshot_dir,
        review_mode=state.get("ml_improvement_review_mode"),
        continue_round=_coerce_optional_bool(state.get("ml_improvement_continue")),
        force_finalize_reason=str(state.get("ml_improvement_force_finalize_reason") or "").strip() or None,
        selection=state.get("opt_incumbent_selection") if isinstance(state.get("opt_incumbent_selection"), dict) else {},
    )


def _build_metric_loop_prompt_snapshot(
    metric_loop_state: Dict[str, Any] | None,
    *,
    current_metric_value: Any = None,
    current_metric_name: str | None = None,
) -> Dict[str, Any]:
    loop_state = metric_loop_state if isinstance(metric_loop_state, dict) else {}
    target = loop_state.get("target") if isinstance(loop_state.get("target"), dict) else {}
    round_payload = loop_state.get("round") if isinstance(loop_state.get("round"), dict) else {}
    round_baseline = round_payload.get("baseline") if isinstance(round_payload.get("baseline"), dict) else {}
    incumbent = loop_state.get("incumbent") if isinstance(loop_state.get("incumbent"), dict) else {}
    candidate = loop_state.get("candidate") if isinstance(loop_state.get("candidate"), dict) else {}
    best_observed = loop_state.get("best_observed") if isinstance(loop_state.get("best_observed"), dict) else {}
    final_entry = loop_state.get("final") if isinstance(loop_state.get("final"), dict) else {}
    controller = _metric_loop_controller(loop_state)
    current_metric = _coerce_float(current_metric_value)
    if current_metric is None:
        current_metric = _coerce_float(candidate.get("metric_value"))
    metric_name = str(
        current_metric_name
        or target.get("name")
        or round_baseline.get("metric_name")
        or ""
    ).strip()
    return {
        "primary_metric_name": metric_name or None,
        "primary_metric_canonical_name": str(target.get("canonical_name") or _metric_canonical_name(metric_name)).strip() or None,
        "baseline_metric": _coerce_float(round_baseline.get("metric_value")),
        "incumbent_metric": _coerce_float(incumbent.get("metric_value")),
        "candidate_metric": _coerce_float(candidate.get("metric_value")),
        "current_metric": current_metric,
        "best_metric_so_far": _coerce_float(best_observed.get("metric_value")),
        "higher_is_better": (
            bool(target.get("higher_is_better"))
            if isinstance(target.get("higher_is_better"), bool)
            else bool(_metric_higher_is_better(metric_name))
        ),
        "min_delta": _coerce_float(target.get("min_delta")),
        "round_id": round_payload.get("round_id"),
        "rounds_allowed": round_payload.get("rounds_allowed"),
        "round_status": controller.get("status") or round_payload.get("status"),
        "selected_label": (
            final_entry.get("label")
            or (
                (loop_state.get("selection") or {}).get("selected_label")
                if isinstance(loop_state.get("selection"), dict)
                else None
            )
        ),
    }


def _sync_metric_loop_legacy_fields(
    state: Dict[str, Any],
    metric_loop_state: Dict[str, Any] | None,
) -> None:
    if not isinstance(state, dict):
        return
    loop_state = metric_loop_state if isinstance(metric_loop_state, dict) else {}
    if not loop_state:
        return
    target = loop_state.get("target") if isinstance(loop_state.get("target"), dict) else {}
    round_payload = loop_state.get("round") if isinstance(loop_state.get("round"), dict) else {}
    round_baseline = round_payload.get("baseline") if isinstance(round_payload.get("baseline"), dict) else {}
    incumbent = loop_state.get("incumbent") if isinstance(loop_state.get("incumbent"), dict) else {}
    best_observed = loop_state.get("best_observed") if isinstance(loop_state.get("best_observed"), dict) else {}
    final_entry = loop_state.get("final") if isinstance(loop_state.get("final"), dict) else {}
    controller = _metric_loop_controller(loop_state)
    artifacts = _metric_loop_artifacts(loop_state)
    selection = loop_state.get("selection") if isinstance(loop_state.get("selection"), dict) else {}

    state["metric_loop_state"] = copy.deepcopy(loop_state)
    state["ml_improvement_primary_metric_name"] = str(target.get("name") or "").strip()
    state["ml_improvement_primary_metric_source"] = str(target.get("source") or "").strip()
    state["ml_improvement_higher_is_better"] = _resolve_metric_loop_higher_is_better(
        str(target.get("name") or ""),
        metric_target=target,
        loop_target=target,
        primary_metric_state=_load_primary_metric_state(state),
    )
    min_delta = _coerce_float(target.get("min_delta"))
    if min_delta is not None:
        state["ml_improvement_min_delta"] = float(min_delta)
    state["ml_improvement_round_count"] = int(round_payload.get("round_id") or state.get("ml_improvement_round_count", 0) or 0)
    state["ml_improvement_current_round_id"] = int(round_payload.get("round_id") or state.get("ml_improvement_current_round_id", 0) or 0)
    state["ml_improvement_rounds_allowed"] = int(round_payload.get("rounds_allowed") or state.get("ml_improvement_rounds_allowed", 1) or 1)
    state["ml_improvement_patience"] = int(round_payload.get("patience") or state.get("ml_improvement_patience", 2) or 2)
    state["ml_improvement_no_improve_streak"] = int(round_payload.get("no_improve_streak") or state.get("ml_improvement_no_improve_streak", 0) or 0)

    round_baseline_value = _coerce_float(round_baseline.get("metric_value"))
    incumbent_value = _coerce_float(incumbent.get("metric_value"))
    best_value = _coerce_float(best_observed.get("metric_value"))
    if round_baseline_value is not None:
        state["ml_improvement_round_baseline_metric"] = float(round_baseline_value)
        state["ml_improvement_baseline_metric"] = float(round_baseline_value)
    if isinstance(round_baseline.get("metrics_payload"), dict):
        state["ml_improvement_round_baseline_metrics"] = copy.deepcopy(round_baseline.get("metrics_payload") or {})
        state["ml_improvement_baseline_metrics"] = copy.deepcopy(round_baseline.get("metrics_payload") or {})
    if incumbent_value is not None:
        state["ml_improvement_incumbent_metric"] = float(incumbent_value)
    if best_value is not None:
        state["ml_improvement_best_metric"] = float(best_value)
    best_label = str(best_observed.get("label") or "").strip()
    if best_label:
        state["ml_improvement_best_label"] = best_label
    if _coerce_nonnegative_int(best_observed.get("round_id"), default=0) > 0:
        state["ml_improvement_best_round"] = _coerce_nonnegative_int(best_observed.get("round_id"), default=0)
    if round_baseline.get("review_verdict"):
        state["ml_improvement_baseline_review_verdict"] = str(round_baseline.get("review_verdict"))
    if isinstance(controller.get("continue_round"), bool):
        state["ml_improvement_continue"] = bool(controller.get("continue_round"))
    if isinstance(controller.get("active"), bool):
        state["ml_improvement_round_active"] = bool(controller.get("active"))
    if controller.get("review_mode"):
        state["ml_improvement_review_mode"] = str(controller.get("review_mode"))
    if controller.get("force_finalize_reason") is not None:
        state["ml_improvement_force_finalize_reason"] = str(controller.get("force_finalize_reason") or "")
    if artifacts.get("output_paths"):
        state["ml_improvement_output_paths"] = list(artifacts.get("output_paths") or [])
    if artifacts.get("snapshot_dir"):
        state["ml_improvement_snapshot_dir"] = str(artifacts.get("snapshot_dir"))
    if final_entry.get("label"):
        final_label = str(final_entry.get("label"))
        state["ml_improvement_kept"] = "improved" if final_label == "candidate" else final_label
    elif selection.get("selected_label"):
        selection_label = str(selection.get("selected_label"))
        state["ml_improvement_kept"] = "improved" if selection_label == "candidate" else selection_label
def _resolve_metric_payload(
    metrics_report: Dict[str, Any] | None,
    metric_name: str | None,
    *,
    source_hint: str = "",
) -> Dict[str, Any]:
    metric_name = str(metric_name or "").strip()
    payload = metrics_report if isinstance(metrics_report, dict) else {}
    if not payload:
        return {}
    resolved = metric_eval_resolve_metric_value(payload, metric_name)
    if not isinstance(resolved, dict) or resolved.get("value") is None:
        return {}
    source = str(source_hint or payload.get("source") or "metrics.resolve_metric")
    matched_key = str(resolved.get("matched_key") or metric_name).strip()
    resolved_name = str(
        resolved.get("metric_name")
        or resolved.get("matched_key")
        or metric_name
        or ""
    ).strip()
    return {
        "name": resolved_name or metric_name,
        "canonical_name": str(
            resolved.get("canonical_name")
            or _metric_canonical_name(resolved_name or metric_name)
        ),
        "value": float(resolved.get("value")),
        "matched_key": matched_key,
        "score": int(resolved.get("score", 0) or 0),
        "source": source,
    }


def _build_primary_metric_state(
    state: Dict[str, Any],
    metrics_report: Dict[str, Any] | None,
    weights_report: Dict[str, Any] | None,
    objective_type: str | None,
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> Dict[str, Any]:
    payload = metrics_report if isinstance(metrics_report, dict) else {}
    if isinstance(payload, dict):
        normalized_metrics = _normalize_metrics_report_payload(payload)
        if isinstance(normalized_metrics, dict) and normalized_metrics:
            payload = normalized_metrics
    weights_payload = weights_report if isinstance(weights_report, dict) else {}
    target = _resolve_contract_metric_target(state if isinstance(state, dict) else {}, contract if isinstance(contract, dict) else {})
    target_name = str(target.get("name") or "").strip()
    target_canonical_name = str(target.get("canonical_name") or _metric_canonical_name(target_name))
    resolved_primary = _resolve_metric_payload(
        payload,
        target_name,
        source_hint=str(payload.get("source") or "metrics.resolve_metric") if isinstance(payload, dict) else "metrics.resolve_metric",
    )

    candidates = _collect_metric_candidates(payload if isinstance(payload, dict) else {}, weights_payload)
    primary: Dict[str, Any] | None = None
    if resolved_primary:
        primary = {
            "name": target_name or resolved_primary.get("name") or resolved_primary.get("matched_key"),
            "canonical_name": resolved_primary.get("canonical_name") or target_canonical_name,
            "value": resolved_primary.get("value"),
            "matched_key": resolved_primary.get("matched_key"),
            "source": resolved_primary.get("source"),
            "ci_lower": None,
            "ci_upper": None,
        }
        matched_key = str(resolved_primary.get("matched_key") or "")
        matched_norm = _normalize_metric_key(matched_key)
        for cand in candidates:
            if not isinstance(cand, dict):
                continue
            cand_name = str(cand.get("name") or "")
            if matched_key and (
                _metric_name_matches(matched_key, cand_name)
                or _normalize_metric_key(cand_name) == matched_norm
            ):
                primary["ci_lower"] = _coerce_float(cand.get("ci_lower"))
                primary["ci_upper"] = _coerce_float(cand.get("ci_upper"))
                break
    elif target_name:
        for cand in candidates:
            if not isinstance(cand, dict):
                continue
            cand_name = str(cand.get("name") or "").strip()
            cand_value = _coerce_float(cand.get("value"))
            if not cand_name or cand_value is None:
                continue
            if not _metric_name_matches(target_name, cand_name):
                continue
            primary = {
                "name": target_name,
                "canonical_name": target_canonical_name or _metric_canonical_name(cand_name),
                "value": float(cand_value),
                "matched_key": cand_name,
                "source": str(payload.get("source") or "metrics.normalized") if isinstance(payload, dict) else "metrics.normalized",
                "ci_lower": _coerce_float(cand.get("ci_lower")),
                "ci_upper": _coerce_float(cand.get("ci_upper")),
            }
            break
    else:
        heuristic_primary = _pick_primary_metric_candidate(candidates, objective_type or "unknown")
        if isinstance(heuristic_primary, dict):
            primary_value = _coerce_float(heuristic_primary.get("value"))
            if primary_value is not None:
                primary = {
                    "name": str(heuristic_primary.get("name") or target_name or ""),
                    "canonical_name": _metric_canonical_name(heuristic_primary.get("name") or target_name),
                    "value": float(primary_value),
                    "matched_key": str(heuristic_primary.get("name") or ""),
                    "source": str(payload.get("source") or "metrics.normalized") if isinstance(payload, dict) else "metrics.normalized",
                    "ci_lower": _coerce_float(heuristic_primary.get("ci_lower")),
                    "ci_upper": _coerce_float(heuristic_primary.get("ci_upper")),
                }

    if not isinstance(primary, dict) or not _is_number(primary.get("value")):
        return {}

    baseline = None
    primary_canonical = str(primary.get("canonical_name") or "")
    for cand in candidates:
        if not isinstance(cand, dict) or not cand.get("is_baseline"):
            continue
        cand_name = str(cand.get("name") or "")
        cand_canonical = _metric_canonical_name(cand_name)
        if primary_canonical and cand_canonical and primary_canonical == cand_canonical:
            baseline = cand
            break
    if baseline is None:
        baseline = next((cand for cand in candidates if isinstance(cand, dict) and cand.get("is_baseline")), None)

    baseline_value = _coerce_float(baseline.get("value")) if isinstance(baseline, dict) else None
    higher_is_better = target.get("higher_is_better")
    if not isinstance(higher_is_better, bool):
        higher_is_better = _metric_higher_is_better(str(primary.get("name") or target_name))

    return {
        "target_metric_name": target_name or primary.get("name"),
        "target_metric_canonical_name": target_canonical_name or primary_canonical,
        "target_metric_source": str(target.get("source") or "unavailable"),
        "primary_metric_name": primary.get("name"),
        "primary_metric_canonical_name": primary_canonical,
        "primary_metric_value": float(primary.get("value")),
        "primary_metric_source": str(primary.get("source") or "metrics.normalized"),
        "primary_metric_path": str(primary.get("matched_key") or primary.get("name") or ""),
        "higher_is_better": bool(higher_is_better),
        "baseline_metric_name": baseline.get("name") if isinstance(baseline, dict) else None,
        "baseline_value": baseline_value,
        "lift": _calc_lift(baseline_value, primary.get("value"), bool(higher_is_better)) if baseline_value is not None else None,
        "ci_lower": _coerce_float(primary.get("ci_lower")),
        "ci_upper": _coerce_float(primary.get("ci_upper")),
        "eval_signature": _build_eval_signature(objective_type, evaluation_spec, contract),
    }


def _resolve_contract_metric_target(state: Dict[str, Any], contract: Dict[str, Any]) -> Dict[str, Any]:
    candidates: List[Tuple[str, Any]] = []
    if isinstance(contract, dict):
        candidates.append(("contract.validation_requirements", contract.get("validation_requirements")))
        candidates.append(("contract.evaluation_spec", contract.get("evaluation_spec")))
        candidates.append(("contract.root", contract))
    if isinstance(state, dict):
        candidates.append(("state.evaluation_spec", state.get("evaluation_spec")))
        eval_spec = state.get("evaluation_spec")
        if isinstance(eval_spec, dict):
            candidates.append(("state.evaluation_spec.validation_requirements", eval_spec.get("validation_requirements")))
    for source, entry in candidates:
        resolved = _resolve_metric_from_entry(entry, source)
        if isinstance(resolved, dict) and resolved.get("name"):
            return resolved
    return {"name": None, "canonical_name": "", "higher_is_better": None, "source": "unavailable"}


def _resolve_contract_primary_metric_name(state: Dict[str, Any], contract: Dict[str, Any]) -> str | None:
    resolved = _resolve_contract_metric_target(state, contract)
    metric_name = resolved.get("name")
    if isinstance(metric_name, str) and metric_name.strip():
        return metric_name.strip()
    return None


def _metric_name_matches(expected: str, candidate: str) -> bool:
    expected_norm = _normalize_metric_key(expected)
    candidate_norm = _normalize_metric_key(candidate)
    expected_canonical = _metric_canonical_name(expected)
    candidate_canonical = _metric_canonical_name(candidate)
    if not expected_norm or not candidate_norm:
        return False
    return (
        expected_norm == candidate_norm
        or expected_norm in candidate_norm
        or candidate_norm in expected_norm
        or (
            bool(expected_canonical)
            and bool(candidate_canonical)
            and expected_canonical == candidate_canonical
        )
    )


def _extract_primary_metric_for_board(
    state: Dict[str, Any],
    metrics_report: Dict[str, Any],
) -> Dict[str, Any]:
    if isinstance(metrics_report, dict):
        normalized_metrics = _normalize_metrics_report_payload(metrics_report)
        if isinstance(normalized_metrics, dict) and normalized_metrics:
            metrics_report = normalized_metrics
    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    metric_target = _resolve_contract_metric_target(state, contract)
    contract_metric = str(metric_target.get("name") or "").strip()
    contract_canonical_name = str(metric_target.get("canonical_name") or _metric_canonical_name(contract_metric))

    metric_state = _load_primary_metric_state(state)
    if isinstance(metric_state, dict) and metric_state:
        primary_name = str(metric_state.get("primary_metric_name") or "")
        primary_canonical_name = str(
            metric_state.get("primary_metric_canonical_name") or _metric_canonical_name(primary_name)
        )
        target_canonical_name = str(
            metric_state.get("target_metric_canonical_name") or _metric_canonical_name(metric_state.get("target_metric_name"))
        )
        if (
            not contract_metric
            or _metric_name_matches(contract_metric, primary_name)
            or (contract_canonical_name and contract_canonical_name in {primary_canonical_name, target_canonical_name})
        ):
            value = _coerce_float(metric_state.get("primary_metric_value"))
            if value is not None:
                return {
                    "name": contract_metric or primary_name,
                    "canonical_name": contract_canonical_name or primary_canonical_name,
                    "value": float(value),
                    "baseline_value": _coerce_float(metric_state.get("baseline_value")),
                    "matched_key": str(metric_state.get("primary_metric_path") or ""),
                    "source": str(metric_state.get("primary_metric_source") or "primary_metric_state"),
                }

    snapshot = state.get("primary_metric_snapshot")
    if isinstance(snapshot, dict) and snapshot and (
        not contract_metric
        or _metric_name_matches(str(contract_metric), str(snapshot.get("primary_metric_name") or ""))
    ):
        return {
            "name": snapshot.get("primary_metric_name") or contract_metric,
            "canonical_name": str(
                snapshot.get("primary_metric_canonical_name")
                or snapshot.get("canonical_name")
                or _metric_canonical_name(snapshot.get("primary_metric_name") or contract_metric)
            ),
            "value": snapshot.get("primary_metric_value"),
            "baseline_value": snapshot.get("baseline_value"),
            "matched_key": snapshot.get("primary_metric_path") or snapshot.get("matched_key"),
            "source": str(snapshot.get("primary_metric_source") or snapshot.get("source") or "primary_metric_snapshot"),
        }

    weights_path = _resolve_declared_artifact_path_from_state(
        state,
        "weights.json",
        kind="weights",
    )
    weights_report = _load_json_safe(weights_path) if weights_path else {}
    if not isinstance(weights_report, dict):
        weights_report = {}

    candidates = _collect_metric_candidates(metrics_report if isinstance(metrics_report, dict) else {}, weights_report)
    if contract_metric:
        resolved_primary = _resolve_metric_payload(
            metrics_report if isinstance(metrics_report, dict) else {},
            contract_metric,
            source_hint=str((metrics_report or {}).get("source") or "metrics.resolve_metric"),
        )
        if resolved_primary:
            return {
                "name": contract_metric,
                "canonical_name": str(resolved_primary.get("canonical_name") or contract_canonical_name),
                "value": float(resolved_primary.get("value")),
                "baseline_value": None,
                "matched_key": str(resolved_primary.get("matched_key") or ""),
                "source": str(resolved_primary.get("source") or "metrics.resolve_metric"),
            }
        for cand in candidates:
            if not isinstance(cand, dict):
                continue
            cand_name = str(cand.get("name") or "")
            if not _metric_name_matches(contract_metric, cand_name):
                continue
            value = _coerce_float(cand.get("value"))
            if value is None:
                continue
            return {
                "name": cand_name or contract_metric,
                "canonical_name": _metric_canonical_name(cand_name or contract_metric),
                "value": float(value),
                "matched_key": cand_name or contract_metric,
                "source": str((metrics_report or {}).get("source") or "metrics.normalized"),
            }
        direct_value = _extract_primary_metric(
            metrics_report if isinstance(metrics_report, dict) else {},
            contract_metric,
        )
        if direct_value is None:
            raw_metrics, raw_metrics_path = _load_declared_json_artifact_from_state(
                state,
                "metrics.json",
                kind="metrics",
            )
            if isinstance(raw_metrics, dict):
                direct_value = _extract_primary_metric(raw_metrics, contract_metric)
        if direct_value is not None:
            return {
                "name": contract_metric,
                "canonical_name": contract_canonical_name,
                "value": float(direct_value),
                "matched_key": contract_metric,
                "source": str((metrics_report or {}).get("source") or f"{raw_metrics_path}.direct_scan"),
            }
        return {
            "name": contract_metric,
            "canonical_name": contract_canonical_name,
            "value": None,
            "source": "contract.primary_metric_missing",
        }

    evaluation_spec = contract.get("evaluation_spec") if isinstance(contract.get("evaluation_spec"), dict) else {}
    objective_type = (
        (evaluation_spec.get("objective_type") if isinstance(evaluation_spec, dict) else None)
        or (state.get("selected_strategy") or {}).get("analysis_type")
        or "unknown"
    )
    primary = _pick_primary_metric_candidate(candidates, str(objective_type))
    if isinstance(primary, dict):
        value = _coerce_float(primary.get("value"))
        if value is not None:
            return {
                "name": primary.get("name"),
                "value": float(value),
                "source": str((metrics_report or {}).get("source") or "metrics.normalized"),
            }

    model_perf = metrics_report.get("model_performance") if isinstance(metrics_report.get("model_performance"), dict) else {}
    for key in ("normalized_gini", "auc", "accuracy", "f1", "rmse", "mae", "r2"):
        val = model_perf.get(key)
        if isinstance(val, dict):
            val = val.get("mean")
        if isinstance(val, (int, float)):
            return {
                "name": key,
                "value": float(val),
                "source": str((metrics_report or {}).get("source") or "metrics.model_performance"),
            }
    return {"name": None, "value": None, "source": "unavailable"}


def _build_review_board_facts(state: Dict[str, Any]) -> Dict[str, Any]:
    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    metrics_report = _resolve_metrics_report_for_facts(state if isinstance(state, dict) else {})
    if not isinstance(metrics_report, dict):
        metrics_report = {}
    alignment_check, _alignment_path = _load_declared_json_artifact_from_state(
        state,
        "alignment_check.json",
    )
    if not isinstance(alignment_check, dict):
        alignment_check = {}
    oc_report = _resolve_output_contract_report_for_facts(state if isinstance(state, dict) else {})
    artifact_issues = _extract_contract_artifact_issues(oc_report)
    visual_reqs = (
        contract.get("artifact_requirements", {}).get("visual_requirements")
        if isinstance(contract.get("artifact_requirements"), dict)
        else {}
    )
    if not isinstance(visual_reqs, dict):
        visual_reqs = {}
    model_perf = metrics_report.get("model_performance")
    model_perf_compact: Dict[str, Any] = {}
    if isinstance(model_perf, dict):
        for key, value in model_perf.items():
            if isinstance(value, (int, float, str, bool)) and len(model_perf_compact) < 15:
                model_perf_compact[str(key)] = value

    # Determine runtime status from the *current* execution outcome.
    # Prior to this fix, residual error text from earlier failed attempts
    # (stored in last_gate_context.traceback, heavy_runner_error_context, etc.)
    # could cause _resolve_authoritative_runtime_text to return non-empty text
    # even after a successful retry, producing a phantom FAILED_RUNTIME that
    # blocked the review board from approving the iteration.
    #
    # The authoritative signal for "did the latest execution succeed?" is the
    # combination of execution_error, sandbox_failed and the current
    # execution_output.  We only fall through to the deeper heuristic search
    # when the latest execution itself signals a problem.
    _latest_exec_error = bool(state.get("execution_error"))
    _latest_sandbox_failed = bool(state.get("sandbox_failed"))
    _latest_output_has_failure = _has_runtime_failure_marker(state.get("execution_output"))

    if not _latest_exec_error and not _latest_sandbox_failed and not _latest_output_has_failure:
        # Latest execution completed cleanly — ignore residual text from
        # previous failed attempts that may still linger in the state.
        runtime_status = "OK"
    else:
        authoritative_runtime = _resolve_authoritative_runtime_text(state=state)
        runtime_status = "FAILED_RUNTIME" if (
            _latest_sandbox_failed
            or bool(authoritative_runtime)
            or _latest_output_has_failure
        ) else "OK"
    gate_context = state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
    return {
        "contract": {
            "source": state.get("execution_contract_source") or "execution_contract",
            "signature": state.get("execution_contract_signature"),
            "min_signature": state.get("execution_contract_min_signature"),
            "version": contract.get("contract_version"),
            "snapshot_path": state.get("execution_contract_snapshot_path"),
        },
        "runtime": {
            "status": runtime_status,
            "runtime_fix_terminal": bool(state.get("runtime_fix_terminal")),
            "runtime_fix_count": int(state.get("runtime_fix_count", 0) or 0),
            "sandbox_failed": bool(state.get("sandbox_failed")),
        },
        "metrics": {
            "primary": _extract_primary_metric_for_board(state, metrics_report),
            "model_performance": model_perf_compact,
        },
        "alignment": _summarize_alignment_requirements(alignment_check),
        "output_contract": {
            "overall_status": str(oc_report.get("overall_status") or "").lower() if isinstance(oc_report, dict) else "",
            "missing_required_artifacts": artifact_issues.get("missing_paths", []),
            "schema_issues": artifact_issues.get("schema_issues", []),
        },
        "visual_requirements": {
            "enabled": bool(visual_reqs.get("enabled")),
            "required": bool(visual_reqs.get("required")),
            "expected_items": len(visual_reqs.get("items") or []) if isinstance(visual_reqs.get("items"), list) else 0,
            "visuals_missing_signal": bool(state.get("visuals_missing")),
        },
        "pipeline": {
            "review_verdict_before_board": state.get("review_verdict"),
            "failed_gates": gate_context.get("failed_gates", []),
            "required_fixes": gate_context.get("required_fixes", []),
            "hard_failures": state.get("hard_failures", []),
        },
    }


def _build_code_review_diagnostics(
    *,
    runtime_failure_detected: bool,
    runtime_terminal: bool,
    execution_output: str,
    output_contract_report: Dict[str, Any] | None,
    artifact_index: List[Dict[str, Any]] | None,
) -> Dict[str, Any]:
    oc_report = output_contract_report if isinstance(output_contract_report, dict) else {}
    missing_outputs = [str(path) for path in (oc_report.get("missing") or []) if path]
    blockers: List[str] = []
    if runtime_failure_detected:
        blockers.append("runtime_failure")
    if str(oc_report.get("overall_status") or "").lower() == "error":
        blockers.append("output_contract_error")
    if missing_outputs:
        blockers.append("contract_required_artifacts_missing")
    return {
        "runtime_status": "FAILED_RUNTIME" if runtime_failure_detected else "OK",
        "runtime_fix_terminal": bool(runtime_terminal),
        "execution_output_tail": str(execution_output or "")[-1200:],
        "output_contract_overall_status": str(oc_report.get("overall_status") or "").lower(),
        "output_contract_missing": missing_outputs,
        "artifact_index": artifact_index if isinstance(artifact_index, list) else [],
        "hard_blockers": blockers,
    }


def _apply_review_consistency_guard(
    result: Dict[str, Any] | None,
    diagnostics: Dict[str, Any] | None,
    *,
    actor: str,
) -> Dict[str, Any]:
    """Attach deterministic blocker context without overriding the LLM verdict."""
    packet: Dict[str, Any] = dict(result or {})
    blockers = [str(x) for x in ((diagnostics or {}).get("hard_blockers") or []) if x]
    if not blockers:
        return packet

    blocker_text = ", ".join(blockers[:6])
    note = (
        f"{str(actor or 'reviewer').upper()}_CONTEXT_GUARD: deterministic blockers detected "
        f"outside the reviewer packet ({blocker_text}). LLM verdict preserved for board adjudication."
    )
    return _attach_review_consistency_signal(
        packet,
        signal_key="deterministic_blockers",
        note=note,
        source=f"{str(actor or 'reviewer').lower()}_context_guard",
        hard_blockers=blockers,
    )


def _harmonize_review_packets_with_final_eval(
    reviewer_packet: Dict[str, Any] | None,
    qa_packet: Dict[str, Any] | None,
    *,
    eval_raw_status: str,
    eval_feedback: str,
    eval_failed_gates: List[str] | None,
    eval_required_fixes: List[str] | None,
) -> tuple[Dict[str, Any], Dict[str, Any], List[str]]:
    """
    Keep reviewer/QA packets aligned with the evaluator without rewriting LLM verdicts.
    Final evaluator discrepancies are attached as advisory context for the board.
    """
    trigger_statuses = {"NEEDS_IMPROVEMENT", "REJECTED", "FAIL", "FAILED", "ERROR", "CRASH"}
    status_norm = str(eval_raw_status or "").strip().upper()
    if status_norm not in trigger_statuses:
        return dict(reviewer_packet or {}), dict(qa_packet or {}), []

    advisory_fixes = [str(item) for item in (eval_required_fixes or []) if item][:5]
    advisory_gates = [str(item) for item in (eval_failed_gates or []) if item][:5]
    eval_feedback_trimmed = str(eval_feedback or "").strip()
    blocking_eval = any(_looks_blocking_retry_signal(item) for item in (advisory_gates + advisory_fixes))
    if not blocking_eval and eval_feedback_trimmed:
        blocking_eval = _looks_blocking_retry_signal(eval_feedback_trimmed)
    notes: List[str] = []

    def _patch_packet(packet: Dict[str, Any], label: str) -> Dict[str, Any]:
        patched = dict(packet or {})
        status = str(patched.get("status") or "").strip().upper()
        failed = [str(item) for item in (patched.get("failed_gates") or []) if item]
        hard = [str(item) for item in (patched.get("hard_failures") or []) if item]
        if status != "APPROVED" or failed or hard:
            return patched

        message = (
            f"{label.upper()}_CROSS_REVIEW_ALIGNMENT: result_evaluator reported unresolved issues "
            "outside the clean reviewer packet. LLM verdict preserved for board adjudication."
        )
        if eval_feedback_trimmed:
            message = f"{message} evaluator_feedback={eval_feedback_trimmed[:320]}"
        notes.append(
            f"{label}: preserved {status} while attaching evaluator_alignment signal from {status_norm}"
        )
        return _attach_review_consistency_signal(
            patched,
            signal_key="evaluator_alignment",
            note=message,
            source="result_evaluator",
            failed_gates=advisory_gates,
            required_fixes=advisory_fixes,
            evaluator_status=status_norm,
            blocking_eval=blocking_eval,
        )

    return _patch_packet(dict(reviewer_packet or {}), "reviewer"), _patch_packet(dict(qa_packet or {}), "qa_reviewer"), notes


_GATE_TEXT_STOPWORDS = {
    "a",
    "an",
    "and",
    "as",
    "at",
    "by",
    "for",
    "from",
    "in",
    "into",
    "of",
    "on",
    "or",
    "the",
    "to",
    "with",
}


def _normalize_gate_match_text(value: Any) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").strip().lower()).strip()


def _gate_text_tokens(value: Any) -> set[str]:
    tokens: set[str] = set()
    normalized = _normalize_gate_match_text(value)
    for token in normalized.split():
        if token in _GATE_TEXT_STOPWORDS:
            continue
        if len(token) <= 2 and token not in {"cv", "lb", "id", "oof"}:
            continue
        tokens.add(token)
    return tokens


def _gate_failure_language_detected(text: Any) -> bool:
    value = _normalize_gate_match_text(text)
    if not value:
        return False
    patterns = (
        r"\bfailed\b",
        r"\bfailure\b",
        r"\bviolat\w*\b",
        r"\breject\w*\b",
        r"\binstead of\b",
        r"\brather than\b",
        r"\bdid not\b",
        r"\bdoes not\b",
        r"\bnot implemented\b",
        r"\bmissing\b",
        r"\bmismatch\b",
        r"\bwithout\b",
        r"\bignor\w*\b",
        r"\bbypass\w*\b",
        r"\bwrong\b",
    )
    return any(re.search(pattern, value) for pattern in patterns)


def _collect_active_hard_gate_specs(contract: Dict[str, Any] | None) -> List[Dict[str, Any]]:
    merged: List[Dict[str, Any]] = []
    seen: set[str] = set()
    sources = []
    if isinstance(contract, dict):
        sources.extend([get_qa_gates(contract) or [], get_reviewer_gates(contract) or []])
    for gate_list in sources:
        for gate in gate_list:
            if not isinstance(gate, dict):
                continue
            name = str(gate.get("name") or gate.get("id") or gate.get("gate") or "").strip()
            if not name:
                continue
            if str(gate.get("severity") or "HARD").strip().upper() != "HARD":
                continue
            key = name.lower()
            if key in seen:
                continue
            seen.add(key)
            params = gate.get("params") if isinstance(gate.get("params"), dict) else {}
            merged.append({"name": name, "severity": "HARD", "params": params})
    return merged

_FEEDBACK_FRAGMENT_SPLIT_RE = re.compile(r"(?<=[\.\!\?])\s+|\n+")


def _split_feedback_fragments(text: Any) -> List[str]:
    raw = str(text or "").replace("\r", "\n").strip()
    if not raw:
        return []
    fragments: List[str] = []
    seen: set[str] = set()
    for block in _FEEDBACK_FRAGMENT_SPLIT_RE.split(raw):
        candidate = str(block or "").strip(" -\t")
        if not candidate:
            continue
        normalized = _normalize_gate_match_text(candidate)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        fragments.append(candidate)
    return fragments[:40] if fragments else [raw[:500]]


def _collect_review_packet_text_fragments(packet: Dict[str, Any] | None) -> List[str]:
    if not isinstance(packet, dict):
        return []
    fragments: List[str] = []
    for key in ("feedback",):
        value = packet.get(key)
        if isinstance(value, str) and value.strip():
            fragments.extend(_split_feedback_fragments(value))
    for key in ("warnings", "required_fixes", "failed_gates", "hard_failures"):
        values = packet.get(key)
        if not isinstance(values, list):
            continue
        for item in values:
            text = str(item or "").strip()
            if text:
                fragments.extend(_split_feedback_fragments(text))
    evidence = packet.get("evidence")
    if isinstance(evidence, list):
        for item in evidence:
            if isinstance(item, dict):
                for key in ("claim", "source"):
                    text = str(item.get(key) or "").strip()
                    if text:
                        fragments.extend(_split_feedback_fragments(text))
            else:
                text = str(item or "").strip()
                if text:
                    fragments.extend(_split_feedback_fragments(text))
    deduped: List[str] = []
    seen: set[str] = set()
    for fragment in fragments:
        normalized = _normalize_gate_match_text(fragment)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        deduped.append(fragment)
    return deduped[:40]


def _gate_match_fragments(gate_spec: Dict[str, Any]) -> List[str]:
    fragments: List[str] = []
    name = str(gate_spec.get("name") or "").strip()
    if name:
        fragments.append(name)
    params = gate_spec.get("params") if isinstance(gate_spec.get("params"), dict) else {}
    for key, value in params.items():
        if isinstance(value, str) and value.strip():
            fragments.append(value.strip())
            fragments.append(f"{key} {value}".strip())
        elif isinstance(value, (int, float, bool)):
            fragments.append(f"{key} {value}")
    deduped: List[str] = []
    seen: set[str] = set()
    for fragment in fragments:
        normalized = _normalize_gate_match_text(fragment)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        deduped.append(normalized)
    return deduped


def _packet_implied_hard_gate_failures(
    packet: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> List[str]:
    if not isinstance(packet, dict) or not isinstance(contract, dict):
        return []
    hard_gate_specs = _collect_active_hard_gate_specs(contract)
    if not hard_gate_specs:
        return []
    packet_fragments = _collect_review_packet_text_fragments(packet)
    if not packet_fragments:
        return []

    normalized_packet_fragments = [
        (_normalize_gate_match_text(fragment), _gate_text_tokens(fragment))
        for fragment in packet_fragments
    ]
    implied: List[str] = []
    for gate_spec in hard_gate_specs:
        gate_name = str(gate_spec.get("name") or "").strip()
        if not gate_name:
            continue
        gate_fragments = _gate_match_fragments(gate_spec)
        gate_token_sets = [tokens for tokens in (_gate_text_tokens(fragment) for fragment in gate_fragments) if len(tokens) >= 2]
        for normalized_fragment, fragment_tokens in normalized_packet_fragments:
            if not normalized_fragment or not _gate_failure_language_detected(normalized_fragment):
                continue
            if any(gate_fragment and gate_fragment in normalized_fragment for gate_fragment in gate_fragments):
                implied.append(gate_name)
                break
            if not fragment_tokens:
                continue
            matched = False
            for gate_tokens in gate_token_sets:
                overlap = fragment_tokens & gate_tokens
                if len(overlap) >= 2:
                    implied.append(gate_name)
                    matched = True
                    break
            if matched:
                break
    return list(dict.fromkeys([name for name in implied if name]))


def _enforce_review_packet_contract_consistency(
    packet: Dict[str, Any] | None,
    *,
    contract: Dict[str, Any] | None,
    actor: str,
) -> Dict[str, Any]:
    normalized = dict(packet) if isinstance(packet, dict) else {}
    if not normalized or not isinstance(contract, dict):
        return normalized

    explicit_status = _normalize_review_status(str(normalized.get("status") or ""))
    explicit_failed = [item for item in (normalized.get("failed_gates") or []) if item]
    explicit_hard = [item for item in (normalized.get("hard_failures") or []) if item]

    implied_failures = _packet_implied_hard_gate_failures(normalized, contract)
    if explicit_status in {"APPROVED", "APPROVE_WITH_WARNINGS"} and not explicit_failed and not explicit_hard and not implied_failures:
        return normalized
    if not implied_failures:
        return normalized
    if explicit_failed or explicit_hard or explicit_status in {"REJECTED", "NEEDS_IMPROVEMENT"}:
        return normalized

    consistency_note = (
        f"{str(actor or 'reviewer').upper()}_CONTRACT_CONSISTENCY: text/evidence implies "
        f"possible HARD gate tension(s): {', '.join(implied_failures[:6])}. "
        "LLM verdict preserved; board should adjudicate the conflict."
    )
    return _attach_review_consistency_signal(
        normalized,
        signal_key="contract_consistency",
        note=consistency_note,
        source=f"{str(actor or 'reviewer').lower()}_contract_consistency",
        implied_hard_gate_failures=implied_failures,
    )


_RUN_FACTS_BLOCK_RE = re.compile(
    r"=== RUN_FACTS_PACK_JSON \(read-only\) ===.*?=== END RUN_FACTS_PACK_JSON ===",
    re.DOTALL,
)

_STEWARD_FACTS_BLOCK_RE = re.compile(
    r"=== STEWARD_FACTS \(deterministic, source-of-truth\) ===.*?=== END STEWARD_FACTS ===",
    re.DOTALL,
)


def _minimal_agent_context_enabled() -> bool:
    raw = os.getenv("AGENT_MINIMAL_CONTEXT_MODE", "1")
    return str(raw).strip().lower() not in {"0", "false", "no", "off"}


def _strip_run_facts_blocks(text: str) -> str:
    if not isinstance(text, str) or not text:
        return ""
    cleaned = _RUN_FACTS_BLOCK_RE.sub("", text)
    cleaned = _STEWARD_FACTS_BLOCK_RE.sub("", cleaned)
    return cleaned.strip()


def _build_senior_summary_context(state: Dict[str, Any]) -> str:
    base = _strip_run_facts_blocks(str((state or {}).get("data_summary", "") or ""))
    return _prepend_dataset_semantics_summary(base, state if isinstance(state, dict) else {})


def _build_steward_facts_block(state: Dict[str, Any]) -> str:
    if not isinstance(state, dict):
        return ""
    profile = state.get("profile") if isinstance(state.get("profile"), dict) else None
    if not profile and isinstance(state.get("dataset_profile"), dict):
        profile = state.get("dataset_profile")
    if not profile:
        profile_path = _abs_in_work(os.getcwd(), "data/dataset_profile.json")
        loaded_profile = _load_json_safe(profile_path)
        if isinstance(loaded_profile, dict):
            profile = loaded_profile
    profile = profile if isinstance(profile, dict) else {}
    dataset_semantics = state.get("dataset_semantics") if isinstance(state.get("dataset_semantics"), dict) else {}
    dataset_training_mask = (
        state.get("dataset_training_mask")
        if isinstance(state.get("dataset_training_mask"), dict)
        else {}
    )
    column_sets = state.get("column_sets") if isinstance(state.get("column_sets"), dict) else {}
    data_profile = state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {}
    rows = profile.get("rows")
    cols = profile.get("cols")
    try:
        rows = int(rows)
    except Exception:
        rows = None
    try:
        cols = int(cols)
    except Exception:
        cols = None
    compute_hints = profile.get("compute_hints") if isinstance(profile.get("compute_hints"), dict) else {}
    primary_target = str(dataset_semantics.get("primary_target") or "").strip()
    split_candidates = dataset_semantics.get("split_candidates") if isinstance(dataset_semantics.get("split_candidates"), list) else []
    id_candidates = dataset_semantics.get("id_candidates") if isinstance(dataset_semantics.get("id_candidates"), list) else []
    training_rows_rule = str(dataset_training_mask.get("training_rows_rule") or "").strip()
    scoring_rows_rule = str(dataset_training_mask.get("scoring_rows_rule") or "").strip()
    target_analysis = dataset_semantics.get("target_analysis") if isinstance(dataset_semantics.get("target_analysis"), dict) else {}

    missing_frac = profile.get("missing_frac") if isinstance(profile.get("missing_frac"), dict) else {}
    missing_alerts = []
    for col_name, frac in missing_frac.items():
        try:
            frac_val = float(frac)
        except Exception:
            continue
        if frac_val <= 0:
            continue
        missing_alerts.append((str(col_name), frac_val))
    missing_alerts.sort(key=lambda item: item[1], reverse=True)

    constants_count = 0
    selectors = column_sets.get("selectors") if isinstance(column_sets.get("selectors"), dict) else {}
    for key in ("constant_like", "constant", "drop_candidates", "stable_zero"):
        value = selectors.get(key)
        if isinstance(value, list):
            constants_count += len([x for x in value if isinstance(x, str) and x.strip()])

    associations = (
        data_profile.get("feature_target_associations")
        if isinstance(data_profile.get("feature_target_associations"), list)
        else []
    )
    top_assoc: List[str] = []
    for item in associations[:5]:
        if not isinstance(item, dict):
            continue
        col = str(item.get("column") or "").strip()
        score = item.get("score")
        method = str(item.get("method") or "").strip()
        if not col:
            continue
        if isinstance(score, (int, float)):
            top_assoc.append(f"{col}({round(float(score), 4)} via {method or 'association'})")
        else:
            top_assoc.append(f"{col}({method or 'association'})")

    lines: List[str] = ["=== STEWARD_FACTS (deterministic, source-of-truth) ==="]
    if rows is not None and cols is not None:
        lines.append(f"- Shape: {rows} rows x {cols} cols")
    if primary_target:
        lines.append(f"- Target: {primary_target}")
    if training_rows_rule:
        lines.append(f"- Training rows rule: {training_rows_rule}")
    if scoring_rows_rule:
        lines.append(f"- Scoring rows rule: {scoring_rows_rule}")
    if split_candidates:
        lines.append(f"- Split candidates: {', '.join(str(c) for c in split_candidates[:8])}")
    if id_candidates:
        lines.append(f"- ID candidates: {', '.join(str(c) for c in id_candidates[:8])}")
    if isinstance(target_analysis, dict):
        imbalance = target_analysis.get("class_imbalance_ratio")
        if imbalance is not None:
            lines.append(f"- Target imbalance ratio: {imbalance}")
        partial_label = target_analysis.get("partial_label_detected")
        if partial_label is not None:
            lines.append(f"- Partial label detected: {bool(partial_label)}")
    if missing_alerts:
        top_missing = ", ".join(f"{c}={round(v,4)}" for c, v in missing_alerts[:5])
        lines.append(f"- Top missingness: {top_missing}")
    if constants_count > 0:
        lines.append(f"- Constant/drop-candidate columns signaled: {constants_count}")
    if top_assoc:
        lines.append(f"- Top feature-target associations: {', '.join(top_assoc)}")
    if compute_hints:
        scale = compute_hints.get("scale_category")
        mem_mb = compute_hints.get("estimated_memory_mb")
        cv_ok = compute_hints.get("cross_validation_feasible")
        dl_ok = compute_hints.get("deep_learning_feasible")
        lines.append(
            f"- Compute hints: scale={scale}, estimated_memory_mb={mem_mb}, cv_feasible={cv_ok}, dl_feasible={dl_ok}"
        )
    lines.append("=== END STEWARD_FACTS ===")
    return "\n".join(lines)


def _build_agent_feedback_context(state: Dict[str, Any], agent_label: str) -> str:
    gate = state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
    failed_gates = [str(g) for g in (gate.get("failed_gates") or []) if g]
    required_fixes = [str(x) for x in (gate.get("required_fixes") or []) if x]
    lines = [
        "ITERATION_FEEDBACK_CONTEXT:",
        f"- agent: {agent_label}",
        f"- iteration_count: {int(state.get('iteration_count', 0) or 0)}",
    ]
    review_verdict = state.get("review_verdict")
    if review_verdict:
        lines.append(f"- last_review_verdict: {review_verdict}")
    review_feedback = str(state.get("review_feedback") or "").strip()
    if review_feedback:
        lines.append("- last_review_feedback:")
        lines.append(review_feedback[:2400])
    if failed_gates:
        lines.append("- failed_gates:")
        lines.extend([f"  - {g}" for g in failed_gates[:20]])
    if required_fixes:
        lines.append("- required_fixes:")
        lines.extend([f"  - {fx}" for fx in required_fixes[:20]])
    runtime_error = str(state.get("execution_error_message") or state.get("error_message") or "").strip()
    if runtime_error:
        lines.append("- runtime_error:")
        lines.append(runtime_error[:1800])
    return "\n".join(lines).strip()


def _prepend_dataset_semantics_summary(text: str, state: Dict[str, Any]) -> str:
    if not isinstance(state, dict):
        return text
    facts_block = _build_steward_facts_block(state)
    summary = state.get("dataset_semantics_summary")
    column_sets_summary = state.get("column_sets_summary")
    column_manifest_summary = state.get("column_manifest_summary")
    data_atlas_summary = state.get("data_atlas_summary")
    combined = facts_block or ""
    if summary:
        combined = f"{combined}\n{summary}" if combined else summary
    if column_sets_summary:
        combined = f"{combined}\n{column_sets_summary}" if combined else column_sets_summary
    if column_manifest_summary:
        combined = f"{combined}\n{column_manifest_summary}" if combined else column_manifest_summary
    if data_atlas_summary:
        combined = f"{combined}\n{data_atlas_summary}" if combined else data_atlas_summary
    if not combined:
        return text
    if text:
        return f"{combined}\n\n{text}"
    return combined


def _resolve_steward_evidence_bundle(
    csv_path: str,
    dialect_payload: Dict[str, Any],
    header_cols: List[str],
    requested: List[Dict[str, Any]],
) -> Dict[str, Any]:
    evidence_items: List[Dict[str, Any]] = []
    for req in requested:
        if not isinstance(req, dict):
            continue
        kind = str(req.get("kind") or "").strip().lower()
        column = str(req.get("column") or "").strip()
        if not kind or not column or column not in header_cols:
            continue
        try:
            if kind == "missingness":
                item = scan_missingness(csv_path, dialect_payload, column)
                evidence_items.append({"kind": kind, "column": column, "result": item})
            elif kind == "uniques":
                max_unique = int(req.get("max_unique") or 20)
                item = scan_uniques(csv_path, dialect_payload, column, max_unique=max(5, min(max_unique, 100)))
                evidence_items.append({"kind": kind, "column": column, "result": item})
            elif kind == "column_profile":
                miss = scan_missingness(csv_path, dialect_payload, column)
                uniq = scan_uniques(csv_path, dialect_payload, column, max_unique=20)
                evidence_items.append(
                    {
                        "kind": kind,
                        "column": column,
                        "result": {
                            "missingness": miss,
                            "uniques": uniq,
                        },
                    }
                )
        except Exception as err:
            evidence_items.append(
                {
                    "kind": kind,
                    "column": column,
                    "error": str(err),
                }
            )
    return {
        "requested_count": len(requested),
        "resolved_count": len(evidence_items),
        "items": evidence_items,
    }

_ABORT_EVENT = threading.Event()

def _normalize_path_posix(path: str) -> str:
    try:
        return Path(path).as_posix()
    except Exception:
        return str(path).replace("\\", "/")


def _hash_text(text: str) -> str:
    if not text:
        return ""
    return hashlib.sha256(text.encode("utf-8", errors="replace")).hexdigest()[:12]


def _apply_static_autofixes(code: str) -> tuple[str, List[Dict[str, Any]]]:
    if not code:
        return code, []
    fixes: List[Dict[str, Any]] = []
    updated = code

    def _autofix_nested_dict_assignments(text: str) -> tuple[str, int]:
        bases = ["stats", "cleaning_stats", "manifest_stats", "quality_stats", "validation_stats"]
        base_pattern = "|".join(re.escape(base) for base in bases)
        pattern = re.compile(
            rf"(?P<base>\b(?:{base_pattern})\b)\s*\[\s*(?P<key>'[^']+'|\"[^\"]+\")\s*\]\s*"
            rf"\[\s*(?P<inner>'[^']+'|\"[^\"]+\")\s*\]\s*="
        )
        base_inits = {
            base
            for base in bases
            if re.search(rf"\b{re.escape(base)}\s*=\s*(\{{\s*\}}|dict\(\)|defaultdict\(\s*dict\s*\))", text)
        }
        lines = text.splitlines()
        changed = False
        count = 0
        for idx, line in enumerate(lines):
            match = pattern.search(line)
            if not match:
                continue
            base = match.group("base")
            if base not in base_inits:
                continue
            key = match.group("key")
            if "setdefault" in line:
                continue
            if re.search(rf"{base}\.setdefault\(\s*{re.escape(key)}\s*,", text):
                continue
            if re.search(rf"{base}\s*\[\s*{re.escape(key)}\s*\]\s*=", text):
                continue
            replacement = f"{base}.setdefault({key}, {{}})[{match.group('inner')}] ="
            lines[idx] = pattern.sub(replacement, line, count=1)
            changed = True
            count += 1
        if not changed:
            return text, 0
        return "\n".join(lines), count

    for pattern, replacement, label in [
        (r"\bnp\.bool\b", "np.bool_", "np.bool->np.bool_"),
    ]:
        before_hash = _hash_text(updated)
        updated, count = re.subn(pattern, replacement, updated)
        if count:
            fixes.append(
                {
                    "rule": label,
                    "count": int(count),
                    "before_hash": before_hash,
                    "after_hash": _hash_text(updated),
                  }
              )
    before_hash = _hash_text(updated)
    updated, nested_count = _autofix_nested_dict_assignments(updated)
    if nested_count:
        fixes.append(
            {
                "rule": "nested_dict_setdefault",
                "count": int(nested_count),
                "before_hash": before_hash,
                "after_hash": _hash_text(updated),
            }
        )
    if "json.dump(" in updated and "_json_dump_patched" not in updated:
        json_patch = (
            "import json\n"
            "def _json_default(obj):\n"
            "    try:\n"
            "        import numpy as np\n"
            "    except Exception:\n"
            "        np = None\n"
            "    try:\n"
            "        import pandas as pd\n"
            "    except Exception:\n"
            "        pd = None\n"
            "    if np is not None:\n"
            "        if isinstance(obj, (np.integer,)):\n"
            "            return int(obj)\n"
            "        if isinstance(obj, (np.floating,)):\n"
            "            return float(obj)\n"
            "        if isinstance(obj, (np.bool_,)):\n"
            "            return bool(obj)\n"
            "        if isinstance(obj, (np.ndarray,)):\n"
            "            return obj.tolist()\n"
            "    if pd is not None and isinstance(obj, pd.Series):\n"
            "        return obj.tolist()\n"
            "    if obj is None:\n"
            "        return None\n"
            "    raise TypeError(f\"Object of type {type(obj)} is not JSON serializable\")\n"
            "\n"
            "_json_dump_original = json.dump\n"
            "def _json_dump_patched(obj, fp, **kwargs):\n"
            "    kwargs.setdefault(\"default\", _json_default)\n"
            "    return _json_dump_original(obj, fp, **kwargs)\n"
            "json.dump = _json_dump_patched\n"
        )
        before_hash = _hash_text(updated)
        updated = json_patch + "\n" + updated
        fixes.append(
            {
                "rule": "json_dump_default_patch",
                "count": 1,
                "before_hash": before_hash,
                "after_hash": _hash_text(updated),
            }
        )
    return updated, fixes


def _collect_violation_snippets(code: str, violations: List[str], max_lines: int = 12) -> List[str]:
    if not code or not violations:
        return []
    tokens: List[str] = []
    for violation in violations:
        if "np.bool" in violation:
            tokens.append("np.bool")
        matches = re.findall(r"'([^']+)'", str(violation))
        for match in matches:
            if match and match not in tokens:
                tokens.append(match)
    if not tokens:
        return []
    lines = code.splitlines()
    snippets: List[str] = []
    for idx, line in enumerate(lines, start=1):
        if any(tok in line for tok in tokens):
            snippets.append(f"L{idx}: {line.strip()}")
            if len(snippets) >= max_lines:
                break
    return snippets


def _persist_output_contract_report(
    state: Dict[str, Any],
    reason: str | None = None,
    path: str = "data/output_contract_report.json",
) -> Dict[str, Any]:
    """
    Persist output contract report with real compliance checking.
    
    Includes:
      - Required outputs presence (backward compatible: present/missing/summary)
      - Artifact requirements schema validation (artifact_requirements_report)
      - Overall status derivation
    """
    from src.utils.output_contract import build_output_contract_report
    
    contract = state.get("execution_contract", {}) if isinstance(state, dict) else {}

    if not isinstance(contract, dict) or not contract:
        normalized_reason = str(reason or "execution_contract_unavailable").strip() or "execution_contract_unavailable"
        report = {
            "present": [],
            "missing": [],
            "missing_optional": [],
            "summary": "Contract unavailable; output contract could not be evaluated.",
            "artifact_requirements_report": {
                "status": "error",
                "files_report": {
                    "present": [],
                    "missing": [],
                    "missing_optional": [],
                    "summary": "Contract unavailable; required files were not evaluated.",
                },
                "row_count_report": {
                    "checked": [],
                    "mismatches": [],
                    "errors": [],
                    "summary": "Contract unavailable; row-count validation was not evaluated.",
                },
                "scored_rows_report": {
                    "exists": False,
                    "applicable": False,
                    "present_columns": [],
                    "missing_columns": [],
                    "missing_any_of_groups": [],
                    "matched_any_of_groups": [],
                    "missing_any_of_groups_with_severity": [],
                    "summary": "Contract unavailable; scored_rows validation was not evaluated.",
                },
                "summary": "Contract unavailable; artifact requirements were not evaluated.",
            },
            "overall_status": "error",
            "reason": normalized_reason,
        }
    else:
        # Build comprehensive report using the unified helper
        report = build_output_contract_report(
            contract=contract,
            work_dir=".",  # Current working directory
            reason=reason,
        )
    
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        dump_json(path, report)
    except Exception:
        pass
    return report


def _refresh_output_contract_state(
    state: Dict[str, Any],
    *,
    reason: str,
) -> Dict[str, Any]:
    contract = state.get("execution_contract") if isinstance(state, dict) else {}
    if not isinstance(contract, dict) or not contract:
        current = state.get("output_contract_report") if isinstance(state, dict) else {}
        return dict(current) if isinstance(current, dict) else {}

    report = _persist_output_contract_report(state, reason=reason)
    if isinstance(state, dict) and isinstance(report, dict):
        state["output_contract_report"] = copy.deepcopy(report)
        missing = [str(item).strip() for item in (report.get("missing") or []) if str(item).strip()]
        overall_status = str(report.get("overall_status") or "").strip().lower()
        if not missing and overall_status != "error":
            state["last_successful_output_contract_report"] = copy.deepcopy(report)
    return report if isinstance(report, dict) else {}

def _stage_illustrative_assets(
    source_root: str,
    report_root: str = "report",
    label_col_hint: str | None = None,
    contract: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    staged = {"plots": [], "jsons": [], "csvs": [], "metadata_path": None}
    if not source_root or not os.path.isdir(source_root):
        return staged
    report_root = report_root or "report"
    os.makedirs(report_root, exist_ok=True)
    scored_rows_dest = None
    summary_dest = None
    candidate_jsons: List[Dict[str, str]] = []
    deliverable_lookup: Dict[str, Dict[str, Any]] = {}
    schema_paths: set[str] = set()
    if isinstance(contract, dict):
        # V4.1: Use artifact_requirements only (no legacy artifact_schemas)
        artifacts = get_artifact_requirements(contract)
        required_files = artifacts.get("required_files", [])
        if isinstance(required_files, list):
            for path in required_files:
                if path:
                    deliverable_lookup[str(path)] = {"path": str(path), "required": True}
        # V4.1: Use file_schemas from artifact_requirements
        file_schemas = artifacts.get("file_schemas")
        if isinstance(file_schemas, dict):
            schema_paths = {str(path) for path in file_schemas.keys() if path}

    def _score_summary_candidate(rel_path: str, dest_path: str) -> float:
        deliverable = deliverable_lookup.get(rel_path, {})
        kind = str(deliverable.get("kind") or "").lower()
        score = 0.0
        if kind in {"report", "summary", "metrics"}:
            score += 5.0
        if deliverable and deliverable.get("required"):
            score += 3.0
        if rel_path in schema_paths:
            score += 1.0
        try:
            size = os.path.getsize(dest_path)
            if size > 0:
                score += min(size / 2048.0, 4.0)
        except Exception:
            pass
        payload = _load_json_any(dest_path)
        if isinstance(payload, dict):
            keys = list(payload.keys())
            score += min(len(keys), 20) * 0.1
            for tok in ("metrics", "recommendations", "limits", "summary", "results"):
                if tok in payload:
                    score += 0.5
        return score
    for base, _, names in os.walk(source_root):
        for name in names:
            full = os.path.join(base, name)
            rel = os.path.relpath(full, source_root)
            rel_posix = rel.replace("\\", "/")
            lower = rel_posix.lower()
            is_plot = lower.startswith("static/plots/") and lower.endswith((".png", ".jpg", ".jpeg"))
            is_json = lower.startswith(("data/", "reports/")) and lower.endswith(".json")
            is_scored_rows = lower.endswith("/scored_rows.csv") or lower == "scored_rows.csv"
            if not (is_plot or is_json or is_scored_rows):
                continue
            dest = os.path.join(report_root, rel)
            os.makedirs(os.path.dirname(dest), exist_ok=True)
            try:
                shutil.copy2(full, dest)
            except Exception:
                continue
            dest_posix = _normalize_path_posix(dest)
            if is_plot:
                staged["plots"].append(dest_posix)
            elif is_json:
                staged["jsons"].append(dest_posix)
                candidate_jsons.append({"rel": rel_posix, "dest": dest})
            elif is_scored_rows:
                staged["csvs"].append(dest_posix)
                scored_rows_dest = dest

    if candidate_jsons:
        ranked = sorted(
            candidate_jsons,
            key=lambda item: _score_summary_candidate(item["rel"], item["dest"]),
            reverse=True,
        )
        summary_dest = ranked[0]["dest"]

    if summary_dest and scored_rows_dest and label_col_hint:
        try:
            meta = enrich_outputs(
                scored_rows_dest,
                summary_json_path=summary_dest,
                label_col_hint=label_col_hint,
            )
            staged["label_enrichment_meta"] = meta
        except Exception as err:
            print(f"Warning: illustrative label enrichment failed: {err}")

    metadata = {
        "status": "illustrative_only",
        "not_production": True,
        "source_root": _normalize_path_posix(source_root),
        "staged_at": datetime.utcnow().isoformat(),
        "assets": staged,
    }
    try:
        meta_path = os.path.join(report_root, "illustrative_assets.json")
        with open(meta_path, "w", encoding="utf-8") as f_meta:
            json.dump(metadata, f_meta, indent=2, ensure_ascii=False)
        staged["metadata_path"] = _normalize_path_posix(meta_path)
    except Exception:
        staged["metadata_path"] = None
    return staged

def request_abort(reason: str | None = None) -> None:
    _ABORT_EVENT.set()
    if reason:
        print(f"ABORT_REQUESTED: {reason}")

def clear_abort() -> None:
    _ABORT_EVENT.clear()

def abort_requested() -> bool:
    return _ABORT_EVENT.is_set()

def _abort_if_requested(state: Dict[str, Any], stage: str) -> Dict[str, Any] | None:
    if not _ABORT_EVENT.is_set():
        return None
    run_id = state.get("run_id") if isinstance(state, dict) else None
    if run_id:
        log_run_event(run_id, "abort_requested", {"stage": stage})
        try:
            finalize_run(run_id, status_final="CRASH", state=state)
        except Exception:
            pass
        finally:
            exit_run_workspace(state)
    return {
        "error_message": "ABORTED_BY_USER",
        "cleaned_data_preview": "Error: Aborted",
        "budget_counters": state.get("budget_counters", {}) if isinstance(state, dict) else {},
    }

def _extract_manifest_alerts(manifest: Dict[str, Any], derived_columns: List[str]) -> List[str]:
    if not isinstance(manifest, dict):
        return []

    row_counts = manifest.get("row_counts") or {}
    summary_stats = manifest.get("summary_statistics") or {}
    warnings = manifest.get("warnings") or []
    if not isinstance(warnings, list):
        warnings = [warnings]

    cleaned_shape = summary_stats.get("cleaned_shape")
    cleaned_rows = None
    if isinstance(cleaned_shape, (list, tuple)) and cleaned_shape:
        try:
            cleaned_rows = int(cleaned_shape[0])
        except Exception:
            cleaned_rows = None

    def _is_zero(val: Any) -> bool:
        return isinstance(val, (int, float)) and val == 0

    row_candidates = [
        row_counts.get("final"),
        row_counts.get("rows_after"),
        row_counts.get("after"),
        summary_stats.get("rows_processed"),
        cleaned_rows,
    ]

    alerts: List[str] = []
    if any(_is_zero(val) for val in row_candidates):
        alerts.append(f"EMPTY_OUTPUT: row_counts={row_counts} summary_statistics={summary_stats}")

    missing_derived: List[str] = []
    if derived_columns and warnings:
        derived_norm = {_norm_name(col) for col in derived_columns if col}
        for warning in warnings:
            if not isinstance(warning, str):
                continue
            warning_text = warning
            if "Missing columns in raw data" in warning_text or "Missing required columns" in warning_text:
                parsed_cols = _parse_manifest_warning_list(warning_text)
                if parsed_cols:
                    for col in parsed_cols:
                        if _norm_name(col) in derived_norm:
                            missing_derived.append(col)
                else:
                    warning_norm = _norm_name(warning_text)
                    for col in derived_columns:
                        col_norm = _norm_name(col)
                        if col_norm and col_norm in warning_norm:
                            missing_derived.append(col)

    if missing_derived:
        alerts.append(f"MISSING_DERIVED_IN_WARNINGS: {sorted(set(missing_derived))}")

    if alerts and warnings:
        preview = warnings if len(warnings) <= 3 else warnings[:3] + ["..."]
        alerts.append(f"WARNINGS_PREVIEW: {preview}")

    return alerts

def _summarize_row_drop(
    manifest: Dict[str, Any],
    required_cols: List[str],
    min_drop_frac: float = 0.5,
    min_null_increase_frac: float = 0.2,
    initial_override: int | None = None,
    after_override: int | None = None,
) -> Dict[str, Any]:
    if not isinstance(manifest, dict):
        return {}
    row_counts = manifest.get("row_counts") or {}
    try:
        initial = int(
            row_counts.get("initial")
            or row_counts.get("rows_before")
            or row_counts.get("input")
            or row_counts.get("total")
        )
    except Exception:
        initial = None
    try:
        after = int(
            row_counts.get("after_cleaning")
            or row_counts.get("final")
            or row_counts.get("rows_after")
            or row_counts.get("after")
            or row_counts.get("output")
        )
    except Exception:
        after = None

    if initial_override is not None:
        initial = initial_override
    if after_override is not None:
        after = after_override

    if not initial or after is None or initial <= 0:
        return {}
    drop = max(initial - after, 0)
    drop_frac = drop / initial if initial else 0.0
    if drop_frac < min_drop_frac:
        return {}

    norm = normalize_manifest(manifest)
    conversions = norm.get("conversions", {}) or {}
    suspects: List[Dict[str, Any]] = []
    for col in required_cols or []:
        key = str(col).lower()
        conv = conversions.get(key)
        if not isinstance(conv, dict):
            continue
        null_inc = conv.get("null_increase")
        try:
            null_inc_val = float(null_inc)
        except Exception:
            continue
        if null_inc_val <= 0:
            continue
        if initial and null_inc_val / initial < min_null_increase_frac:
            continue
        suspects.append(
            {
                "column": col,
                "null_increase": int(null_inc_val),
                "from_dtype": conv.get("from_dtype"),
                "to_dtype": conv.get("to_dtype"),
                "method": conv.get("method"),
            }
        )

    return {
        "initial": initial,
        "after": after,
        "drop": drop,
        "drop_frac": round(drop_frac, 4),
        "suspects": suspects,
    }

def _count_raw_rows(csv_path: str, encoding: str, sep: str | None = None, decimal: str | None = None) -> int | None:
    try:
        import pandas as pd

        df = pd.read_csv(
            csv_path,
            encoding=encoding,
            sep=sep or ",",
            decimal=decimal or ".",
            usecols=[0],
            low_memory=False,
        )
        return len(df)
    except Exception:
        try:
            with open(csv_path, "r", encoding=encoding, errors="ignore") as f:
                count = sum(1 for _ in f)
            return max(count - 1, 0)
        except Exception:
            return None

def _parse_manifest_warning_list(warning: str) -> List[str]:
    import ast
    if ":" not in warning:
        return []
    list_text = warning.split(":", 1)[1].strip()
    try:
        parsed = ast.literal_eval(list_text)
    except Exception:
        return []
    if isinstance(parsed, (list, tuple)):
        return [str(item) for item in parsed]
    return []

def _find_empty_required_columns(df, required_cols: List[str], threshold: float = 0.98) -> List[Dict[str, Any]]:
    issues = []
    if df is None or not required_cols:
        return issues
    for col in required_cols:
        if col not in df.columns:
            continue
        series = df[col]
        if series.empty:
            continue
        try:
            if series.dtype == object:
                stripped = series.astype(str).str.strip()
                null_like = series.isna() | (stripped == "")
            else:
                null_like = series.isna()
            null_frac = float(null_like.mean()) if len(series) else 0.0
            non_null_count = int((~null_like).sum())
        except Exception:
            null_frac = 0.0
            non_null_count = 0
        if null_frac >= threshold or non_null_count == 0:
            issues.append(
                {
                    "column": col,
                    "null_frac": null_frac,
                    "non_null_count": non_null_count,
                }
            )
    return issues

def _resolve_requirement_meta(contract: Dict[str, Any], col: str) -> Dict[str, Any]:
    """
    V4.1: Resolve metadata for a column used for determining if it is optional.
    Constructs a synthetic requirement dict from V4.1 sources.
    """
    if not isinstance(contract, dict):
        return {}

    norm_col = _norm_name(col)

    # Check optional passthrough (override canonical requirement if explicitly set)
    from src.utils.contract_accessors import get_canonical_columns, get_artifact_requirements
    artifact_reqs = get_artifact_requirements(contract)
    schema = artifact_reqs.get("schema_binding", {})
    optional = schema.get("optional_passthrough_columns", [])
    for c in optional:
        if _norm_name(c) == norm_col:
            return {"name": c, "required": False, "nullable": True}

    # Check V4.1 canonical columns (Strictly required usually)
    canonical = get_canonical_columns(contract)
    for c in canonical:
        if _norm_name(c) == norm_col:
            return {"name": c, "required": True, "nullable": False}

    # V4.1: No legacy data_requirements fallback
    # Default: if not found in canonical, assume it might be optional or extra
    return {}

def _is_optional_requirement(req: Dict[str, Any]) -> bool:
    if not isinstance(req, dict):
        return True # If semantics not found, don't block
    if req.get("required") is False:
        return True
    if req.get("nullable") is True:
        return True
    return False
    if req.get("optional") is True:
        return True
    return False

def _sample_raw_null_stats(
    csv_path: str,
    dialect: Dict[str, Any],
    raw_cols: List[str],
    nrows: int = 500,
) -> Dict[str, Dict[str, Any]]:
    stats: Dict[str, Dict[str, Any]] = {}
    sample_df = sample_raw_columns(csv_path, dialect, raw_cols, nrows=nrows, dtype=str)
    if sample_df is None or getattr(sample_df, "empty", False):
        return stats
    for col in raw_cols:
        if col not in sample_df.columns:
            continue
        series = sample_df[col]
        try:
            raw_str = series.astype(str).str.strip()
            null_like = series.isna() | raw_str.eq("") | raw_str.str.lower().isin(["nan", "null", "none"])
            null_frac = float(null_like.mean()) if len(series) else 0.0
            stats[col] = {
                "null_frac": null_frac,
                "non_null_frac": float(1.0 - null_frac),
                "sample_rows": int(len(series)),
            }
        except Exception:
            stats[col] = {}
    return stats

def _build_required_sample_context(
    csv_path: str,
    dialect: Dict[str, Any],
    required_cols: List[str],
    norm_map: Dict[str, str],
    max_rows: int = 50,
    max_examples: int = 6,
) -> str:
    if not csv_path or not required_cols:
        return ""
    raw_cols = []
    canon_to_raw: Dict[str, str] = {}
    for col in required_cols:
        normed = _norm_name(col)
        raw = norm_map.get(normed)
        if raw:
            canon_to_raw[col] = raw
            raw_cols.append(raw)
    if not raw_cols:
        return ""
    sample_df = sample_raw_columns(csv_path, dialect, raw_cols, nrows=max_rows, dtype=str)
    if sample_df is None or getattr(sample_df, "empty", False):
        return ""

    def _pattern_stats(series) -> Dict[str, float]:
        try:
            series = series.dropna().astype(str)
        except Exception:
            return {}
        if series.empty:
            return {}
        sample = series
        percent_like = float(sample.str.contains("%").mean())
        comma_decimal = float(sample.str.contains(r"\d+,\d+").mean())
        dot_decimal = float(sample.str.contains(r"\d+\.\d+").mean())
        numeric_like = float(sample.str.contains(r"^[\s\-\+]*[\d,.\s%]+$").mean())
        whitespace = float(sample.str.contains(r"^\s+|\s+$").mean())
        return {
            "numeric_like_ratio": round(numeric_like, 4),
            "percent_like_ratio": round(percent_like, 4),
            "comma_decimal_ratio": round(comma_decimal, 4),
            "dot_decimal_ratio": round(dot_decimal, 4),
            "whitespace_ratio": round(whitespace, 4),
        }

    samples: Dict[str, Dict[str, Any]] = {}
    for canon, raw in canon_to_raw.items():
        if raw not in sample_df.columns:
            continue
        series = sample_df[raw]
        try:
            if series.dtype == object:
                series = series.astype(str).str.strip()
            values = [v for v in series.dropna().tolist() if str(v).strip() != ""]
        except Exception:
            values = []
        uniq: List[str] = []
        for val in values:
            sval = str(val)
            if sval not in uniq:
                uniq.append(sval)
            if len(uniq) >= max_examples:
                break
        samples[canon] = {
            "raw_column": raw,
            "examples": uniq,
            "pattern_stats": _pattern_stats(series),
        }

    if not samples:
        return ""
    payload = {"sample_rows": int(len(sample_df)), "columns": samples}
    return "RAW_REQUIRED_COLUMN_SAMPLES:\n" + json.dumps(payload, ensure_ascii=True)


def _infer_parsing_hints_from_sample_context(sample_context: str) -> str:
    """
    Builds compact, universal parsing guidance from RAW_REQUIRED_COLUMN_SAMPLES.
    This is intentionally generic: it does not hardcode dataset-specific fixes, it derives hints from patterns.
    """
    if not sample_context:
        return ""
    if "RAW_REQUIRED_COLUMN_SAMPLES:" not in sample_context:
        return ""
    try:
        _, raw_json = sample_context.split("\n", 1)
    except ValueError:
        return ""
    try:
        payload = json.loads(raw_json.strip())
    except Exception:
        return ""
    columns = payload.get("columns") if isinstance(payload, dict) else None
    if not isinstance(columns, dict) or not columns:
        return ""

    hints: List[str] = []
    saw_symbols = False
    saw_multi_dot = False
    saw_multi_comma = False
    saw_percent = False

    for meta in columns.values():
        if not isinstance(meta, dict):
            continue
        examples = meta.get("examples") or []
        for ex in examples:
            s = str(ex)
            if "%" in s:
                saw_percent = True
            if s.count(".") >= 2:
                saw_multi_dot = True
            if s.count(",") >= 2:
                saw_multi_comma = True
            # Anything other than digits, whitespace, separators, sign, parentheses, and percent.
            if re.search(r"[^\d\s,.\-+()%]", s):
                saw_symbols = True

    if saw_symbols:
        hints.append("Strip currency symbols/letters before numeric conversion (keep digits, sign, separators, parentheses, and %).")
    if saw_multi_dot:
        hints.append("Values with multiple '.' are usually thousands separators; remove all '.' (unless you also detect a decimal separator elsewhere).")
    if saw_multi_comma:
        hints.append("Values with multiple ',' are usually thousands separators; remove all ',' and infer decimal by the last separator.")
    if saw_percent:
        hints.append("For percentages: strip '%' and normalize 1–100 to 0–1.")
    hints.append("If raw values are mostly non-null but conversion yields mostly NaN, treat it as a parsing failure and switch to a more permissive sanitizer.")
    hints.append("Add a small parser self-check: parse the provided examples and confirm you do not get all-NaN for required numeric columns.")

    return "DE_PARSING_HINTS:\n- " + "\n- ".join(hints)

def _extract_manifest_row_count(manifest: Dict[str, Any]) -> int | None:
    if not isinstance(manifest, dict):
        return None
    row_counts = manifest.get("row_counts")
    if isinstance(row_counts, dict):
        for key in ("after_cleaning", "final", "output", "cleaned", "rows"):
            value = row_counts.get(key)
            if isinstance(value, (int, float)) and value >= 0:
                return int(value)
    for key in ("row_count", "rows", "n_rows", "cleaned_row_count", "output_row_count"):
        value = manifest.get(key)
        if isinstance(value, (int, float)) and value >= 0:
            return int(value)
    return None

def _estimate_row_count(
    csv_path: str,
    encoding: str = "utf-8",
    sep: str = ",",
    quotechar: str = '"',
    escapechar: str | None = None,
) -> int | None:
    if not csv_path or not os.path.exists(csv_path):
        return None
    if not isinstance(sep, str) or len(sep) != 1:
        sep = ","
    if not isinstance(quotechar, str) or len(quotechar) != 1:
        quotechar = '"'
    if not isinstance(escapechar, str) or len(escapechar) != 1:
        escapechar = None

    encodings = [encoding, "utf-8-sig", "latin-1"]
    tried: set[str] = set()
    for enc in encodings:
        if not enc or enc in tried:
            continue
        tried.add(enc)
        try:
            with open(csv_path, "r", encoding=enc, errors="replace", newline="") as f:
                reader = csv.reader(
                    f,
                    delimiter=sep,
                    quotechar=quotechar,
                    escapechar=escapechar,
                )
                next(reader, None)  # header
                return sum(1 for _ in reader)
        except Exception:
            continue
    return None

def _compute_exact_non_null_ratio(
    csv_path: str,
    dialect: Dict[str, Any],
    column_name: str,
    chunk_size: int = 50000,
) -> float | None:
    if not csv_path or not column_name or not os.path.exists(csv_path):
        return None
    sep = dialect.get("sep") or ","
    decimal = dialect.get("decimal") or "."
    encoding = dialect.get("encoding") or "utf-8"
    total = 0
    non_null = 0
    null_tokens = {"", "na", "n/a", "nan", "null", "none", "nat"}
    try:
        for chunk in pd.read_csv(
            csv_path,
            sep=sep,
            decimal=decimal,
            encoding=encoding,
            usecols=[column_name],
            chunksize=chunk_size,
            dtype=str,
            low_memory=False,
        ):
            if column_name not in chunk.columns:
                continue
            series = chunk[column_name]
            mask = series.isna()
            try:
                lowered = series.astype(str).str.strip().str.lower()
                mask = mask | lowered.isin(null_tokens)
            except Exception:
                pass
            total += int(series.shape[0])
            non_null += int((~mask).sum())
    except Exception:
        return None
    if total <= 0:
        return None
    return float(non_null / total)

def _build_signal_summary_context(
    csv_path: str,
    dialect: Dict[str, Any],
    required_cols: List[str],
    norm_map: Dict[str, str],
    header_cols: List[str],
    dataset_semantics: Dict[str, Any] | None = None,
    manifest_path: str | None = None,
) -> Dict[str, Any]:
    summary: Dict[str, Any] = {}
    manifest = _load_json_safe(manifest_path) if manifest_path else {}
    row_count = _extract_manifest_row_count(manifest) or _estimate_row_count(
        csv_path,
        dialect.get("encoding", "utf-8"),
        str(dialect.get("sep") or ","),
        str(dialect.get("quotechar") or '"'),
        dialect.get("escapechar"),
    )
    if row_count is not None:
        summary["row_count"] = row_count
    if header_cols:
        summary["column_count"] = len(header_cols)
    target_canon = None
    target_raw = None
    if isinstance(dataset_semantics, dict):
        target_analysis = dataset_semantics.get("target_analysis") or {}
        if target_analysis.get("partial_label_detected"):
            target_canon = target_analysis.get("primary_target")
            if target_canon:
                target_norm = _norm_name(str(target_canon))
                target_raw = norm_map.get(target_norm, target_canon if target_canon in header_cols else None)
    if required_cols:
        summary["required_columns"] = required_cols
        summary["required_feature_count"] = len(required_cols)
        if row_count:
            summary["rows_per_required_feature"] = round(row_count / max(len(required_cols), 1), 2)
        raw_cols = []
        canon_to_raw: Dict[str, str] = {}
        for col in required_cols:
            normed = _norm_name(col)
            raw = norm_map.get(normed)
            if raw:
                canon_to_raw[col] = raw
                raw_cols.append(raw)
        sample_df = sample_raw_columns(csv_path, dialect, raw_cols, nrows=200, dtype=str)
        if sample_df is not None and not sample_df.empty:
            stats: Dict[str, Any] = {}
            for canon, raw in canon_to_raw.items():
                if raw not in sample_df.columns:
                    continue
                series = sample_df[raw]
                try:
                    values = series.astype(str)
                    non_null_ratio = float(values.replace("", None).notna().mean())
                    nunique = int(values.dropna().nunique())
                    examples = [str(v) for v in values.dropna().head(3).tolist()]
                except Exception:
                    non_null_ratio = None
                    nunique = None
                    examples = []
                stats[canon] = {
                    "raw_column": raw,
                    "sample_non_null_ratio": non_null_ratio,
                    "sample_nunique": nunique,
                    "sample_examples": examples,
                }
            if stats:
                if target_raw and target_canon:
                    exact_ratio = None
                    exact_total = None
                    exact_missing = None
                    if isinstance(dataset_semantics, dict):
                        target_info = dataset_semantics.get("target_analysis") or {}
                        if isinstance(target_info, dict) and target_info.get("target_null_frac_exact") is not None:
                            exact_ratio = 1.0 - float(target_info.get("target_null_frac_exact"))
                            exact_total = target_info.get("target_total_count_exact")
                            exact_missing = target_info.get("target_missing_count_exact")
                    if exact_ratio is None:
                        exact_ratio = _compute_exact_non_null_ratio(csv_path, dialect, target_raw)
                    if exact_ratio is not None:
                        for canon, payload in stats.items():
                            if payload.get("raw_column") == target_raw or canon == target_canon:
                                payload.pop("sample_non_null_ratio", None)
                                payload["exact_non_null_ratio"] = exact_ratio
                                if exact_total is not None:
                                    payload["exact_total_count"] = exact_total
                                if exact_missing is not None:
                                    payload["exact_missing_count"] = exact_missing
                                break
                        else:
                            summary["target_column_stats"] = {
                                "column": target_canon,
                                "raw_column": target_raw,
                                "exact_non_null_ratio": exact_ratio,
                            }
                            if exact_total is not None:
                                summary["target_column_stats"]["exact_total_count"] = exact_total
                            if exact_missing is not None:
                                summary["target_column_stats"]["exact_missing_count"] = exact_missing
                summary["required_column_sample_stats"] = stats
        required_raw = set(canon_to_raw.values())
        candidate_cols = [col for col in header_cols if col not in required_raw]
        if candidate_cols:
            summary["candidate_column_count"] = len(candidate_cols)
            sample_candidates = candidate_cols[:40]
            candidate_df = sample_raw_columns(csv_path, dialect, sample_candidates, nrows=200, dtype=str)
            if candidate_df is not None and not candidate_df.empty:
                candidate_stats: List[Dict[str, Any]] = []
                for col in sample_candidates:
                    if col not in candidate_df.columns:
                        continue
                    series = candidate_df[col]
                    try:
                        values = series.astype(str)
                        non_null_ratio = float(values.replace("", None).notna().mean())
                        nunique = int(values.dropna().nunique())
                        examples = [str(v) for v in values.dropna().head(3).tolist()]
                    except Exception:
                        non_null_ratio = None
                        nunique = None
                        examples = []
                    likely_id = False
                    try:
                        sample_len = len(values.dropna())
                        if sample_len > 0 and nunique is not None:
                            likely_id = nunique >= max(int(sample_len * 0.9), 25)
                    except Exception:
                        likely_id = False
                    candidate_stats.append(
                        {
                            "column": col,
                            "sample_non_null_ratio": non_null_ratio,
                            "sample_nunique": nunique,
                            "sample_examples": examples,
                            "likely_id": likely_id,
                        }
                    )
                if candidate_stats:
                    summary["candidate_columns"] = candidate_stats
    if target_raw and target_canon:
        has_exact = False
        stats_payload = summary.get("required_column_sample_stats")
        if isinstance(stats_payload, dict):
            for payload in stats_payload.values():
                if isinstance(payload, dict) and "exact_non_null_ratio" in payload:
                    has_exact = True
                    break
        if not has_exact and "target_column_stats" not in summary:
            exact_ratio = _compute_exact_non_null_ratio(csv_path, dialect, target_raw)
            if exact_ratio is not None:
                summary["target_column_stats"] = {
                    "column": target_canon,
                    "raw_column": target_raw,
                    "exact_non_null_ratio": exact_ratio,
                }
    return summary

def _invert_column_roles(column_roles: Dict[str, Any]) -> Dict[str, List[str]]:
    """Build column -> roles mapping from contract column_roles payload."""
    inverted: Dict[str, List[str]] = {}
    if not isinstance(column_roles, dict):
        return inverted
    for role, cols in column_roles.items():
        if not isinstance(cols, list):
            continue
        for col in cols:
            if not col:
                continue
            key = str(col)
            roles = inverted.setdefault(key, [])
            if role not in roles:
                roles.append(str(role))
    return inverted


def _pick_split_column(df: pd.DataFrame, column_roles: Dict[str, Any]) -> str | None:
    if not isinstance(df, pd.DataFrame) or df.empty:
        return None
    candidates: List[str] = []
    if isinstance(column_roles, dict):
        split_cols = column_roles.get("split_indicator")
        if isinstance(split_cols, list):
            candidates.extend([str(c) for c in split_cols if c])
    if "__split" not in candidates:
        candidates.append("__split")
    for cand in candidates:
        if cand in df.columns:
            return cand
    return None


def _build_cleaned_data_summary_min(
    df_clean: pd.DataFrame,
    contract: Dict[str, Any] | None,
    required_columns: List[str] | None,
    data_path: str | None = None,
    max_columns: int = 120,
    outlier_policy: Dict[str, Any] | None = None,
    outlier_report: Dict[str, Any] | None = None,
    cleaning_manifest: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    """
    Build compact cleaned-data facts for ML context without duplicating full profiling.
    The summary is deterministic, small, and derived from DE output + contract decisions.
    """
    contract = contract if isinstance(contract, dict) else {}
    required_columns = [str(col) for col in (required_columns or []) if col]
    column_roles = get_column_roles(contract)
    canonical_columns = get_canonical_columns(contract)
    role_by_column = _invert_column_roles(column_roles if isinstance(column_roles, dict) else {})

    df_cols = [str(c) for c in list(df_clean.columns)]
    df_col_set = set(df_cols)

    # Prioritize contract columns for compact context. Fall back to full columns for narrow datasets.
    priority: List[str] = []
    for seq in (
        required_columns,
        canonical_columns if isinstance(canonical_columns, list) else [],
        list(role_by_column.keys()),
    ):
        for col in seq:
            col_s = str(col)
            if col_s and col_s not in priority:
                priority.append(col_s)
    if len(df_cols) <= max_columns:
        columns_for_summary = list(df_cols)
    else:
        columns_for_summary = [col for col in priority if col in df_col_set]
        for col in df_cols:
            if col in columns_for_summary:
                continue
            columns_for_summary.append(col)
            if len(columns_for_summary) >= max_columns:
                break

    split_column = _pick_split_column(df_clean, column_roles if isinstance(column_roles, dict) else {})
    train_mask = None
    test_mask = None
    train_rows = None
    test_rows = None
    if split_column and split_column in df_clean.columns:
        try:
            split_series = df_clean[split_column].astype(str).str.strip().str.lower()
            train_mask = split_series.eq("train")
            test_mask = split_series.eq("test")
            train_rows = int(train_mask.sum())
            test_rows = int(test_mask.sum())
        except Exception:
            train_mask = None
            test_mask = None
            train_rows = None
            test_rows = None

    objective_type = (
        str(contract.get("objective_type") or "")
        or str((contract.get("objective_analysis") or {}).get("problem_type") or "")
        or str((contract.get("evaluation_spec") or {}).get("objective_type") or "")
    ).strip().lower()

    def _role_dtype_warning(roles: List[str], series: pd.Series) -> str | None:
        if not roles:
            return None
        roles_set = {str(r) for r in roles}
        is_numeric = pd.api.types.is_numeric_dtype(series)
        is_datetime = pd.api.types.is_datetime64_any_dtype(series)
        is_object = pd.api.types.is_object_dtype(series)
        if "temporal_features" in roles_set and not (is_datetime or is_object):
            return "temporal_role_with_non_temporal_dtype"
        if ("numerical_features" in roles_set or "spatial_features" in roles_set) and not is_numeric:
            return "numeric_role_with_non_numeric_dtype"
        if any(r in roles_set for r in ("categorical_features", "id", "split_indicator")) and is_numeric:
            return "categorical_role_with_numeric_dtype"
        if "target" in roles_set and objective_type in {"regression", "forecasting", "time_series"} and not is_numeric:
            return "target_role_with_non_numeric_dtype_for_regression"
        return None

    def _masked_null_frac(series: pd.Series, mask: pd.Series | None) -> float | None:
        if mask is None:
            return None
        try:
            sliced = series[mask]
        except Exception:
            return None
        if sliced.shape[0] == 0:
            return None
        try:
            return round(float(sliced.isna().mean()), 6)
        except Exception:
            return None

    rows_total = int(len(df_clean))
    missing_required = [col for col in required_columns if col not in df_col_set]
    column_summaries: List[Dict[str, Any]] = []
    role_dtype_warnings: List[Dict[str, Any]] = []

    for col in columns_for_summary:
        present = col in df_col_set
        expected_roles = role_by_column.get(col, [])
        summary: Dict[str, Any] = {
            "column_name": col,
            "present": bool(present),
            "dtype_observed": None,
            "null_frac": None,
            "in_train": None,
            "in_test": None,
            "mismatch_with_contract": {
                "expected_in_required_columns": col in required_columns,
                "required_but_missing": bool(col in required_columns and not present),
                "expected_roles": expected_roles,
                "role_dtype_warning": None,
            },
        }
        if present:
            series = df_clean[col]
            try:
                summary["dtype_observed"] = str(series.dtype)
            except Exception:
                summary["dtype_observed"] = None
            try:
                summary["null_frac"] = round(float(series.isna().mean()), 6)
            except Exception:
                summary["null_frac"] = None
            if train_mask is not None:
                summary["in_train"] = {
                    "rows": train_rows,
                    "null_frac": _masked_null_frac(series, train_mask),
                }
            if test_mask is not None:
                summary["in_test"] = {
                    "rows": test_rows,
                    "null_frac": _masked_null_frac(series, test_mask),
                }
            warning = _role_dtype_warning(expected_roles, series)
            if warning:
                summary["mismatch_with_contract"]["role_dtype_warning"] = warning
                role_dtype_warnings.append(
                    {"column": col, "warning": warning, "expected_roles": expected_roles, "dtype": summary["dtype_observed"]}
                )
        column_summaries.append(summary)

    omitted_columns_count = max(0, len(df_cols) - len(columns_for_summary))
    outlier_summary: Dict[str, Any] = {}
    if isinstance(outlier_policy, dict) and outlier_policy:
        enabled_raw = outlier_policy.get("enabled")
        if isinstance(enabled_raw, str):
            enabled = enabled_raw.strip().lower() in {"1", "true", "yes", "on", "enabled"}
        elif enabled_raw is None:
            enabled = bool(
                outlier_policy.get("target_columns")
                or outlier_policy.get("methods")
                or outlier_policy.get("treatment")
            )
        else:
            enabled = bool(enabled_raw)
        outlier_summary = {
            "enabled": bool(enabled),
            "apply_stage": str(outlier_policy.get("apply_stage") or "data_engineer").strip().lower(),
            "target_columns": [str(col) for col in (outlier_policy.get("target_columns") or []) if col],
            "report_present": bool(isinstance(outlier_report, dict) and outlier_report),
        }
        if isinstance(outlier_report, dict) and outlier_report:
            for key in ("status", "columns_touched", "rows_affected", "flags_created"):
                if key in outlier_report:
                    outlier_summary[key] = outlier_report.get(key)
        manifest_outlier = (
            cleaning_manifest.get("outlier_treatment")
            if isinstance(cleaning_manifest, dict) and isinstance(cleaning_manifest.get("outlier_treatment"), dict)
            else None
        )
        if manifest_outlier:
            outlier_summary["manifest_outlier_treatment"] = manifest_outlier

    return {
        "version": "v1",
        "source": "system_after_data_engineer",
        "advisory_only": True,
        "contract_precedence_policy": "if_conflict_use_ml_view_and_execution_contract",
        "data_path": str(data_path or ""),
        "row_count": rows_total,
        "column_count": int(len(df_cols)),
        "split_column": split_column,
        "required_columns": required_columns,
        "missing_required_columns": missing_required,
        "omitted_columns_count": omitted_columns_count,
        "role_dtype_warnings": role_dtype_warnings,
        "column_summaries": column_summaries,
        "outlier_treatment": outlier_summary,
    }


def _build_required_raw_map(
    required_cols: List[str],
    norm_map: Dict[str, str],
) -> Dict[str, str]:
    mapping: Dict[str, str] = {}
    for col in required_cols or []:
        normed = _norm_name(col)
        raw = norm_map.get(normed)
        if raw:
            mapping[col] = raw
    return mapping

def _load_required_columns_artifact(path: str = "data/required_columns.json") -> List[str]:
    """
    Load required input columns from runtime artifact.
    Supports:
    - list[str] payload
    - dict payload with `required_columns` or `columns`
    """
    payload = _load_json_any(path)
    if isinstance(payload, list):
        return [str(col) for col in payload if col]
    if isinstance(payload, dict):
        candidates = payload.get("required_columns")
        if not isinstance(candidates, list):
            candidates = payload.get("columns")
        if isinstance(candidates, list):
            return [str(col) for col in candidates if col]
    return []

def _filter_input_contract(contract: Dict[str, Any]) -> Dict[str, Any]:
    """
    V4.1: Canonical columns ARE inputs. Returns contract as-is.
    No legacy data_requirements filtering needed.
    """
    if not isinstance(contract, dict):
        return {}
    filtered = dict(contract)
    required_cols = _load_required_columns_artifact()
    if required_cols:
        artifact_reqs = filtered.get("artifact_requirements")
        artifact_reqs = dict(artifact_reqs) if isinstance(artifact_reqs, dict) else {}
        clean_cfg = artifact_reqs.get("clean_dataset")
        clean_cfg = dict(clean_cfg) if isinstance(clean_cfg, dict) else {}
        clean_cfg["required_columns"] = required_cols
        artifact_reqs["clean_dataset"] = clean_cfg
        filtered["artifact_requirements"] = artifact_reqs
    return filtered


def build_de_objective(contract: Dict[str, Any]) -> str:
    objective = (
        "Clean dataset to satisfy contract canonical_columns; ensure numeric/date parsing; "
        "produce cleaned_data + manifest."
    )
    if not isinstance(contract, dict):
        return objective
    canonical = get_canonical_columns(contract) or []
    if canonical:
        return f"{objective} Canonical columns count: {len(canonical)}."
    return objective



def _resolve_required_input_columns(contract: Dict[str, Any], strategy: Dict[str, Any]) -> List[str]:
    """V4.1: Prefer explicit required_columns; avoid canonical_columns unless required set is missing."""
    file_required = _load_required_columns_artifact("data/required_columns.json")
    if file_required:
        return file_required
    if contract and isinstance(contract, dict):
        artifact_reqs = contract.get("artifact_requirements") or {}
        clean_cfg = artifact_reqs.get("cleaned_dataset") or artifact_reqs.get("clean_dataset") or {}
        required = clean_cfg.get("required_columns")
        if isinstance(required, list) and required:
            return required
    if contract and isinstance(contract, dict):
        canonical = get_canonical_columns(contract)
        if canonical:
            return canonical
    # Fallback to strategy if contract has no usable columns
    return strategy.get("required_columns", []) if strategy else []


def _resolve_clean_dataset_coverage(contract: Dict[str, Any] | None) -> Dict[str, List[str]]:
    contract = contract if isinstance(contract, dict) else {}
    artifact_reqs = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
    clean_cfg = artifact_reqs.get("cleaned_dataset") or artifact_reqs.get("clean_dataset") or {}
    clean_cfg = clean_cfg if isinstance(clean_cfg, dict) else {}

    required_cols = [str(col) for col in (clean_cfg.get("required_columns") or []) if str(col).strip()]

    optional_cols_raw = clean_cfg.get("optional_passthrough_columns")
    if not isinstance(optional_cols_raw, list):
        schema_binding = clean_cfg.get("schema_binding")
        if isinstance(schema_binding, dict):
            optional_cols_raw = schema_binding.get("optional_passthrough_columns")
    optional_cols = [str(col) for col in (optional_cols_raw or []) if str(col).strip()]

    return {
        "required_columns": list(dict.fromkeys(required_cols)),
        "optional_passthrough_columns": list(dict.fromkeys(optional_cols)),
    }


def _build_contract_operational_dependency_mismatch(
    contract: Dict[str, Any] | None,
    *,
    cleaned_header: List[str] | None,
    column_inventory: List[str] | None = None,
) -> Dict[str, Any]:
    contract = contract if isinstance(contract, dict) else {}
    header_cols = [str(col) for col in (cleaned_header or []) if str(col).strip()]
    dependency_report = collect_contract_operational_dependency_columns(
        contract,
        column_inventory=column_inventory,
    )
    dependencies = [
        str(col)
        for col in (dependency_report.get("all") or [])
        if isinstance(col, str) and col.strip()
    ]
    coverage = _resolve_clean_dataset_coverage(contract)
    required_cols = coverage.get("required_columns", [])
    passthrough_cols = coverage.get("optional_passthrough_columns", [])

    header_norm = {_norm_name(col): col for col in header_cols if _norm_name(col)}
    coverage_norm = {
        _norm_name(col): col
        for col in (required_cols + passthrough_cols)
        if isinstance(col, str) and _norm_name(col)
    }

    missing_in_header: List[str] = []
    uncovered_by_contract: List[str] = []
    actionable_dependencies: List[str] = []
    for col in dependencies:
        norm = _norm_name(col)
        if not norm:
            continue
        is_missing = norm not in header_norm
        is_uncovered = norm not in coverage_norm
        if is_missing:
            missing_in_header.append(col)
        if is_uncovered:
            uncovered_by_contract.append(col)
        if is_missing and is_uncovered:
            actionable_dependencies.append(col)

    return {
        "dependencies": dependencies,
        "required_columns": required_cols,
        "optional_passthrough_columns": passthrough_cols,
        "missing_in_header": missing_in_header,
        "uncovered_by_contract": uncovered_by_contract,
        "actionable_dependencies": actionable_dependencies,
        "should_replan": bool(actionable_dependencies),
    }


def _build_planner_contract_mismatch_payload(
    contract: Dict[str, Any] | None,
    *,
    cleaned_header: List[str] | None,
    column_inventory: List[str] | None = None,
) -> Dict[str, Any]:
    report = _build_contract_operational_dependency_mismatch(
        contract,
        cleaned_header=cleaned_header,
        column_inventory=column_inventory,
    )
    if not report.get("should_replan"):
        return {}
    actionable = [str(col) for col in (report.get("actionable_dependencies") or []) if str(col).strip()]
    return {
        "status": "REJECTED",
        "reason": "planner_contract_mismatch",
        "failed_gates": ["planner_contract_mismatch"],
        "required_fixes": [
            "Repair the execution contract so all operational dependency columns used by task semantics are preserved in cleaned_dataset coverage.",
            "Do not reinterpret these columns as model features unless the planner explicitly decides so.",
        ],
        "evidence": [
            {
                "claim": "Operational dependency columns declared by the contract are missing from the cleaned artifact and are not preserved by cleaned_dataset coverage.",
                "source": "contract_operational_dependency_guard",
            }
        ],
        "report": report,
        "summary": (
            "PLANNER_CONTRACT_MISMATCH: actionable_dependencies="
            + str(actionable[:10])
            + " missing_in_header="
            + str((report.get("missing_in_header") or [])[:10])
            + " uncovered_by_contract="
            + str((report.get("uncovered_by_contract") or [])[:10])
        ),
    }


def _detect_planner_contract_mismatch_for_state(
    state: Dict[str, Any] | None,
    *,
    runtime_text: str | None = None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    if not contract:
        return {}

    if runtime_text is not None:
        runtime_lower = str(runtime_text or "").lower()
        if "missing required input columns" not in runtime_lower and "missing required columns" not in runtime_lower:
            return {}

    data_path = str(state.get("ml_data_path") or "").strip()
    csv_sep = str(state.get("csv_sep") or ",")
    csv_encoding = str(state.get("csv_encoding") or "utf-8")
    header_cols = _read_csv_header(data_path, csv_encoding, csv_sep) if data_path and os.path.exists(data_path) else []
    if not header_cols:
        return {}

    return _build_planner_contract_mismatch_payload(
        contract,
        cleaned_header=header_cols,
        column_inventory=get_canonical_columns(contract),
    )

def _load_constant_columns_from_profile(profile_path: str = "data/data_profile.json") -> List[str]:
    profile = _load_json_safe(profile_path)
    if not isinstance(profile, dict):
        return []
    confidence = str(profile.get("constant_columns_confidence") or "").strip().lower()
    sampling_uncertainty = profile.get("sampling_uncertainty")
    if confidence == "low_sampled":
        return []
    if isinstance(sampling_uncertainty, dict) and sampling_uncertainty.get(
        "is_uncertain_for_column_level_deterministic_inference"
    ):
        return []
    constant_cols = profile.get("constant_columns")
    if not isinstance(constant_cols, list):
        return []
    return [col for col in constant_cols if isinstance(col, str) and col.strip()]

def _filter_missing_required_constants(
    missing_cols: List[str],
    contract: Dict[str, Any],
    constant_cols: List[str],
) -> Tuple[List[str], List[str]]:
    if not missing_cols or not constant_cols:
        return missing_cols, []
    constant_norm = {_norm_name(col) for col in constant_cols if col}
    protected = set()
    for col in contract.get("outcome_columns", []) or []:
        protected.add(_norm_name(col))
    for col in contract.get("decision_columns", []) or []:
        protected.add(_norm_name(col))
    filtered: List[str] = []
    ignored: List[str] = []
    for col in missing_cols:
        normed = _norm_name(col)
        if normed in constant_norm and normed not in protected:
            ignored.append(col)
        else:
            filtered.append(col)
    return filtered, ignored

def _build_translator_run_narrative(
    state: Dict[str, Any],
    run_summary: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    """
    Build a compact, structured narrative of the run for the Business Translator.

    Instead of forcing the translator to parse 15+ raw JSON artifacts, this
    function pre-digests the run state into a ~2KB summary that tells the
    story: what was asked, what happened, what worked, what the result is.
    """
    narrative: Dict[str, Any] = {}

    # 1. Business objective
    contract = state.get("execution_contract")
    if not isinstance(contract, dict):
        contract = _load_json_any("data/execution_contract.json") or {}
    narrative["business_objective"] = (
        state.get("business_objective")
        or contract.get("business_objective")
        or ""
    )

    # 2. Strategy chosen
    strategy = state.get("selected_strategy")
    if isinstance(strategy, dict):
        narrative["strategy"] = {
            "title": strategy.get("title"),
            "hypothesis": strategy.get("hypothesis"),
            "objective_type": strategy.get("objective_type"),
        }

    # 3. Data summary (from steward)
    steward = _load_json_any("data/steward_summary.json") or {}
    if isinstance(steward, dict) and steward:
        narrative["data_summary"] = {
            "summary": str(steward.get("summary") or "")[:600],
            "rows": steward.get("row_count"),
            "columns": steward.get("column_count"),
            "encoding": steward.get("encoding"),
        }

    # 4. Cleaning summary
    manifest = _load_json_any("data/cleaning_manifest.json")
    if isinstance(manifest, dict) and manifest:
        row_counts = manifest.get("row_counts", {})
        narrative["cleaning_summary"] = {
            "rows_before": row_counts.get("before") or row_counts.get("original"),
            "rows_after": row_counts.get("after") or row_counts.get("final"),
            "nulls_handled": manifest.get("nulls_filled_count")
                or manifest.get("null_handling_count"),
        }

    # 5. ML improvement loop — the most important narrative element
    ml_loop: Dict[str, Any] = {}
    run_sum = run_summary if isinstance(run_summary, dict) else {}
    metric_improvement = run_sum.get("metric_improvement")
    if isinstance(metric_improvement, dict):
        ml_loop["baseline_metric"] = metric_improvement.get("baseline_metric")
        ml_loop["final_metric"] = metric_improvement.get("final_metric_reported")
        ml_loop["kept"] = metric_improvement.get("kept")
        ml_loop["metric_name"] = metric_improvement.get("metric_name")

    budget = run_sum.get("budget_counters")
    if isinstance(budget, dict):
        ml_loop["total_ml_attempts"] = budget.get("ml_calls")
        ml_loop["total_reviewer_calls"] = budget.get("reviewer_calls")

    # Round history from state
    round_history = state.get("ml_improvement_round_history")
    if isinstance(round_history, list) and round_history:
        ml_loop["rounds"] = [
            {
                "round": r.get("round_id"),
                "hypothesis": (
                    r.get("hypothesis", {}).get("label")
                    if isinstance(r.get("hypothesis"), dict)
                    else str(r.get("hypothesis") or "")[:80]
                ),
                "baseline": r.get("baseline_metric"),
                "candidate": r.get("candidate_metric"),
                "kept": r.get("kept"),
            }
            for r in round_history
            if isinstance(r, dict)
        ]
    else:
        # Fallback: read compact info from metric_loop_state on disk
        mls = _load_json_any("data/metric_loop_state.json") or {}
        if isinstance(mls, dict) and mls:
            _round = mls.get("round") if isinstance(mls.get("round"), dict) else {}
            _incumbent = mls.get("incumbent") if isinstance(mls.get("incumbent"), dict) else {}
            _best = mls.get("best_observed") if isinstance(mls.get("best_observed"), dict) else {}
            ml_loop["rounds_completed"] = _round.get("round_id")
            ml_loop["rounds_allowed"] = _round.get("rounds_allowed")
            ml_loop["no_improve_streak"] = _round.get("no_improve_streak")
            ml_loop["incumbent_value"] = _incumbent.get("metric_value")
            ml_loop["best_observed_value"] = _best.get("metric_value")
            ml_loop["best_observed_label"] = _best.get("label")

    if ml_loop:
        narrative["ml_loop"] = ml_loop

    # 6. Review verdict and feedback
    narrative["review_verdict"] = state.get("review_verdict")
    review_fb = state.get("review_feedback")
    if isinstance(review_fb, dict):
        narrative["review_feedback"] = {
            "status": review_fb.get("status"),
            "feedback": str(review_fb.get("feedback") or "")[:500],
        }
    elif isinstance(review_fb, str):
        narrative["review_feedback"] = review_fb[:500]

    # 7. Final decision
    narrative["system_decision"] = run_sum.get("run_outcome")
    narrative["failed_gates"] = run_sum.get("failed_gates", [])
    narrative["warnings"] = run_sum.get("warnings", [])

    # 8. Primary metric (authoritative)
    pms = state.get("primary_metric_state")
    if isinstance(pms, dict) and pms:
        narrative["primary_metric"] = {
            "name": pms.get("primary_metric_name"),
            "value": pms.get("primary_metric_value"),
            "source": "primary_metric_state (authoritative)",
        }

    return narrative


def _resolve_contract_deliverables(contract: Dict[str, Any]) -> List[Dict[str, Any]]:
    """
    V4.1 compatible deliverables resolver.
    Returns a list of dicts [{'path': str, 'required': bool, 'kind': str, 'owner': str, ...}]
    """
    from src.utils.contract_accessors import get_deliverables, get_required_outputs

    # Prefer rich deliverables (with kind/owner metadata)
    deliverables = get_deliverables(contract)
    if deliverables:
        return deliverables

    # Fallback: get_required_outputs returns List[str]
    outputs = get_required_outputs(contract)
    if outputs:
        return [{"path": p, "required": True} for p in outputs]

    return []


def _resolve_contract_columns(contract: Dict[str, Any], sources: set[str] | None = None) -> List[str]:
    """V4.1: Use canonical_columns for input, derived_columns for derived. No legacy fallback."""
    if not contract or not isinstance(contract, dict):
        return []

    # If sources contains 'input', valid V4.1 sources are canonical_columns
    if sources and 'input' in sources:
        from src.utils.contract_accessors import get_canonical_columns
        return get_canonical_columns(contract)

    # If asking for 'derived', check derived_columns
    if sources and 'derived' in sources:
        from src.utils.contract_accessors import get_derived_column_names
        return get_derived_column_names(contract)

    # Default: return canonical columns (input columns)
    from src.utils.contract_accessors import get_canonical_columns
    return get_canonical_columns(contract)

def _resolve_allowed_columns_for_gate(
    state: Dict[str, Any],
    contract: Dict[str, Any],
    evaluation_spec: Dict[str, Any] | None = None,
) -> List[str]:
    allowed: List[str] = []
    csv_path = state.get("ml_data_path")
    if isinstance(csv_path, str) and csv_path and os.path.exists(csv_path):
        try:
            import pandas as pd

            csv_sep = state.get("csv_sep", ",")
            csv_decimal = state.get("csv_decimal", ".")
            csv_encoding = state.get("csv_encoding", "utf-8")
            header_df = pd.read_csv(csv_path, nrows=0, sep=csv_sep, decimal=csv_decimal, encoding=csv_encoding)
            allowed.extend([str(col) for col in header_df.columns.tolist() if col])
        except Exception:
            pass

    if isinstance(contract, dict):
        from src.utils.contract_accessors import get_derived_column_names
        derived_cols = get_derived_column_names(contract)
        allowed.extend([str(c) for c in derived_cols if c])
        # V4.1: No legacy data_requirements fallback

    if not allowed:
        profile = state.get("profile") or state.get("dataset_profile")
        if isinstance(profile, dict):
            cols = profile.get("columns")
            if isinstance(cols, list):
                allowed.extend([str(col) for col in cols if col])

    seen: set[str] = set()
    deduped: List[str] = []
    for col in allowed:
        norm = _norm_name(col)
        if not norm or norm in seen:
            continue
        seen.add(norm)
        deduped.append(col)
    return deduped

def _resolve_allowed_patterns_for_gate(contract: Any) -> List[str]:
    """V4.1: Use artifact_requirements.file_schemas only. No legacy fallback."""
    patterns: List[str] = []
    if not isinstance(contract, dict):
        return patterns
    scored_schema = get_declared_file_schema(contract, "scored_rows.csv")
    if isinstance(scored_schema, dict):
        allowed_patterns = scored_schema.get("allowed_name_patterns")
        if isinstance(allowed_patterns, list):
            patterns.extend([str(pat) for pat in allowed_patterns if isinstance(pat, str) and pat.strip()])
    return patterns

def _resolve_contract_columns_for_cleaning(contract: Dict[str, Any], sources: set[str] | None = None) -> List[str]:
    """V4.1: Use canonical_columns for cleaning. No legacy data_requirements."""
    if not contract or not isinstance(contract, dict):
        return []
    # V4.1: Cleaning uses canonical_columns + optional_passthrough_columns from artifact_requirements
    from src.utils.contract_accessors import get_canonical_columns, get_artifact_requirements
    columns = list(get_canonical_columns(contract))
    artifacts = get_artifact_requirements(contract)
    schema_binding = artifacts.get("schema_binding", {})
    if isinstance(schema_binding, dict):
        passthrough = schema_binding.get("optional_passthrough_columns", [])
        if isinstance(passthrough, list):
            columns.extend([str(c) for c in passthrough if c])
    return columns

def _is_glob_pattern(path: str) -> bool:
    if not path:
        return False
    return any(ch in path for ch in ["*", "?", "["]) or path.endswith(("/", "\\"))

_REQUIRED_OUTPUT_EXTENSIONS = {
    ".csv",
    ".json",
    ".png",
    ".pdf",
    ".parquet",
    ".pkl",
    ".pickle",
    ".joblib",
    ".txt",
    ".md",
}


def _looks_like_filesystem_path(value: str) -> bool:
    if not value:
        return False
    text = str(value).strip()
    if not text:
        return False
    lower = text.lower()
    if lower.startswith(("data/", "static/", "artifacts/")):
        return True
    if "/" in text or "\\" in text:
        return True
    _, ext = os.path.splitext(lower)
    return ext in _REQUIRED_OUTPUT_EXTENSIONS


def _normalize_output_path(path: str) -> str:
    """Normalize separators while preserving contract-declared paths."""
    if not path:
        return path
    return str(path).strip().replace("\\", "/").lstrip("/")


def _merge_conceptual_outputs(
    state: Dict[str, Any] | None,
    contract: Dict[str, Any],
    conceptual_outputs: List[str],
) -> None:
    if not conceptual_outputs or not isinstance(state, dict):
        return
    reporting = state.get("reporting_requirements")
    if not isinstance(reporting, dict):
        reporting = {}
    merged: List[str] = []
    seen: set[str] = set()

    def _add_items(items: Any) -> None:
        if not isinstance(items, list):
            return
        for item in items:
            text = str(item).strip()
            if not text:
                continue
            key = text.lower()
            if key in seen:
                continue
            seen.add(key)
            merged.append(text)

    contract_reporting = contract.get("reporting_requirements") if isinstance(contract, dict) else None
    _add_items(reporting.get("conceptual_outputs"))
    if isinstance(contract_reporting, dict):
        _add_items(contract_reporting.get("conceptual_outputs"))
    _add_items(conceptual_outputs)

    reporting["conceptual_outputs"] = merged
    state["reporting_requirements"] = reporting


def _resolve_required_outputs(contract: Dict[str, Any], state: Dict[str, Any] | None = None) -> List[str]:
    """
    Resolve required outputs from V4.1 contract structure.
    Priority:
      1. contract.required_outputs (single source of truth)
      2. evaluation_spec.required_outputs (fallback when contract list is absent/empty)
      3. accessor union (legacy fallback only)
    NO LONGER uses spec_extraction.deliverables (legacy).
    """
    if not isinstance(contract, dict):
        return []

    conceptual_outputs: List[str] = []

    def _split_outputs(values: Any) -> tuple[List[str], List[str]]:
        file_like: List[str] = []
        conceptual_like: List[str] = []
        if isinstance(values, list):
            for item in values:
                if not item:
                    continue
                # Support dict items with "path" key (owner-aware format)
                if isinstance(item, dict):
                    path = item.get("path") or ""
                else:
                    path = str(item)
                if not path:
                    continue
                if _looks_like_filesystem_path(path):
                    file_like.append(_normalize_output_path(path))
                else:
                    conceptual_like.append(path)
        return file_like, conceptual_like

    resolved: List[str] = []
    seen: set[str] = set()

    def _add_output(path: str) -> None:
        if not path:
            return
        normalized = _normalize_output_path(str(path))
        key = normalized.lower()
        if key in seen:
            return
        seen.add(key)
        resolved.append(normalized)

    # Priority 1: contract.required_outputs (canonical)
    has_contract_required_outputs = False
    req_outputs = contract.get("required_outputs")
    if isinstance(req_outputs, list) and req_outputs:
        file_like, conceptual_like = _split_outputs(req_outputs)
        conceptual_outputs.extend(conceptual_like)
        for path in file_like:
            _add_output(path)
        has_contract_required_outputs = bool(file_like)

    # If canonical required_outputs exists, do not widen with eval/accessor outputs.
    # This avoids runtime/view desynchronization and keeps contract as single source of truth.
    if has_contract_required_outputs:
        eval_spec = contract.get("evaluation_spec")
        if isinstance(eval_spec, dict):
            eval_outputs = eval_spec.get("required_outputs")
            if isinstance(eval_outputs, list) and eval_outputs:
                _, conceptual_like = _split_outputs(eval_outputs)
                conceptual_outputs.extend(conceptual_like)
        try:
            accessor_outputs = get_required_outputs(contract)
        except Exception:
            accessor_outputs = []
        if isinstance(accessor_outputs, list):
            for entry in accessor_outputs:
                if not entry:
                    continue
                text = str(entry)
                if not _looks_like_filesystem_path(text):
                    conceptual_outputs.append(text)
        _merge_conceptual_outputs(state, contract, conceptual_outputs)
        return resolved

    # Fallback 1: evaluation_spec.required_outputs
    eval_spec = contract.get("evaluation_spec")
    if isinstance(eval_spec, dict):
        eval_outputs = eval_spec.get("required_outputs")
        if isinstance(eval_outputs, list) and eval_outputs:
            file_like, conceptual_like = _split_outputs(eval_outputs)
            conceptual_outputs.extend(conceptual_like)
            for path in file_like:
                _add_output(path)

    # Fallback 2: accessor union (required_files/required_plots/visual required items)
    try:
        accessor_outputs = get_required_outputs(contract)
    except Exception:
        accessor_outputs = []
    if isinstance(accessor_outputs, list):
        for entry in accessor_outputs:
            if not entry:
                continue
            text = str(entry)
            if _looks_like_filesystem_path(text):
                _add_output(text)
            else:
                conceptual_outputs.append(text)

    _merge_conceptual_outputs(state, contract, conceptual_outputs)
    return resolved


def _extract_output_path_candidate(item: Any) -> str:
    if isinstance(item, str):
        return item
    if isinstance(item, dict):
        for key in ("path", "output", "artifact", "output_path", "file"):
            value = item.get(key)
            if isinstance(value, str) and value.strip():
                return value
    return ""


def _normalize_output_path_list(values: Any) -> List[str]:
    if not isinstance(values, list):
        return []
    normalized: List[str] = []
    seen: set[str] = set()
    for item in values:
        candidate = _extract_output_path_candidate(item)
        if not candidate:
            continue
        path = _normalize_output_path(candidate)
        if not path:
            continue
        key = path.lower()
        if key in seen:
            continue
        seen.add(key)
        normalized.append(path)
    return normalized


def _path_match_variants(path: Any) -> List[str]:
    text = str(path or "").strip()
    if not text:
        return []
    variants: List[str] = []
    primary = _normalize_output_path(text)
    if primary:
        variants.append(primary)
    if os.path.isabs(text):
        try:
            rel = _normalize_output_path(os.path.relpath(text, "."))
            if rel and not rel.startswith("../") and rel not in variants:
                variants.append(rel)
        except Exception:
            pass
    return variants


def _resolve_ml_de_input_exclusions(state: Dict[str, Any] | None) -> set[str]:
    excluded: set[str] = set()
    for item in (CANONICAL_CLEANED_REL, CANONICAL_MANIFEST_REL, "data/cleaned_full.csv"):
        for variant in _path_match_variants(item):
            excluded.add(variant.lower())
    if isinstance(state, dict):
        de_view = state.get("de_view") or (state.get("contract_views") or {}).get("de_view")
        if isinstance(de_view, dict):
            for key in ("output_path", "output_manifest_path", "manifest_path"):
                value = de_view.get(key)
                for variant in _path_match_variants(value):
                    excluded.add(variant.lower())
    return excluded


def _resolve_artifact_requirement_outputs(contract: Dict[str, Any]) -> List[str]:
    artifact_requirements = get_artifact_requirements(contract) if isinstance(contract, dict) else {}
    if not isinstance(artifact_requirements, dict):
        artifact_requirements = {}
    candidates: List[Any] = []
    for key in ("required_outputs", "required_files"):
        values = artifact_requirements.get(key)
        if isinstance(values, list):
            candidates.extend(values)
    return _normalize_output_path_list(candidates)


def _resolve_ml_heavy_runner_required_outputs(
    contract: Dict[str, Any],
    state: Dict[str, Any] | None = None,
) -> List[str]:
    """
    Resolve ML heavy-runner required outputs with a single source of truth:
    1) owner-filtered contract.required_outputs for ml_engineer
    2) canonical required_outputs fallback
    3) artifact_requirements fallback

    DE pipeline inputs (cleaned_data/manifest) are excluded deterministically.
    """
    if not isinstance(contract, dict):
        return []

    owner_filtered: List[str] = []
    try:
        from src.utils.contract_accessors import get_required_outputs_by_owner
        owner_filtered = get_required_outputs_by_owner(contract, "ml_engineer")
    except Exception:
        owner_filtered = []

    candidates_by_priority: List[List[str]] = [
        _normalize_output_path_list(owner_filtered),
        _resolve_required_outputs(contract, state),
        _resolve_artifact_requirement_outputs(contract),
    ]
    excluded = _resolve_ml_de_input_exclusions(state)

    for candidates in candidates_by_priority:
        if not candidates:
            continue
        filtered: List[str] = []
        seen: set[str] = set()
        for path in candidates:
            normalized = _normalize_output_path(path)
            if not normalized:
                continue
            key = normalized.lower()
            if key in excluded or key in seen:
                continue
            seen.add(key)
            filtered.append(normalized)
        if filtered:
            return filtered

    return []


def _apply_ml_reviewer_output_scope(
    contract: Dict[str, Any],
    state: Dict[str, Any] | None,
    reviewer_view: Dict[str, Any] | None,
    evaluation_spec: Dict[str, Any] | None,
) -> tuple[Dict[str, Any], Dict[str, Any] | None]:
    """
    Force reviewer scope to ML-owned outputs only.

    Prevents reviewer/QA feedback loops from asking ML to generate DE artifacts
    (e.g., cleaned_data / cleaning_manifest).
    """
    scoped_outputs = _resolve_ml_heavy_runner_required_outputs(contract, state)
    if not scoped_outputs:
        return (
            dict(reviewer_view) if isinstance(reviewer_view, dict) else {},
            dict(evaluation_spec) if isinstance(evaluation_spec, dict) else evaluation_spec,
        )

    scoped_reviewer_view = dict(reviewer_view) if isinstance(reviewer_view, dict) else {}
    scoped_reviewer_view["required_outputs"] = list(scoped_outputs)
    verification = scoped_reviewer_view.get("verification")
    if isinstance(verification, dict):
        verification = dict(verification)
    else:
        verification = {}
    verification["required_outputs"] = list(scoped_outputs)
    scoped_reviewer_view["verification"] = verification

    scoped_eval_spec: Dict[str, Any] | None
    if isinstance(evaluation_spec, dict):
        scoped_eval_spec = dict(evaluation_spec)
        scoped_eval_spec["required_outputs"] = list(scoped_outputs)
        eval_verification = scoped_eval_spec.get("verification")
        if isinstance(eval_verification, dict):
            eval_verification = dict(eval_verification)
        else:
            eval_verification = {}
        eval_verification["required_outputs"] = list(scoped_outputs)
        scoped_eval_spec["verification"] = eval_verification
    else:
        scoped_eval_spec = evaluation_spec

    return scoped_reviewer_view, scoped_eval_spec


def _resolve_optional_runtime_downloads(contract: Dict[str, Any]) -> List[str]:
    """
    Resolve non-blocking artifacts that should be pulled from sandbox outputs when present.

    These artifacts enrich reviewer/board context but do not gate execution success.
    """
    if not isinstance(contract, dict):
        return []

    resolved: List[str] = []
    seen: set[str] = set()

    def _add_optional(path: Any) -> None:
        text = str(path or "").strip()
        if not text:
            return
        if not _looks_like_filesystem_path(text):
            return
        normalized = _normalize_output_path(text)
        key = normalized.lower()
        if key in seen:
            return
        seen.add(key)
        resolved.append(normalized)

    artifacts = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
    for key in ("optional_outputs", "optional_files"):
        values = artifacts.get(key)
        if isinstance(values, list):
            for item in values:
                if isinstance(item, dict):
                    _add_optional(item.get("path") or item.get("output_path") or item.get("file"))
                else:
                    _add_optional(item)

    return resolved


def _resolve_expected_output_paths(contract: Dict[str, Any], state: Dict[str, Any] | None = None) -> List[str]:
    """V4.1-only: delegates to _resolve_required_outputs."""
    return _resolve_required_outputs(contract, state)


def _purge_execution_outputs(
    required_outputs: List[str],
    keep_outputs: List[str] | None = None,
    preserve_paths: List[str] | None = None,
) -> None:
    protected = {
        "data/cleaned_data.csv",
        "data/cleaned_full.csv",
        "data/cleaning_manifest.json",
        "data/dataset_profile.json",
        "data/steward_summary.json",
        "data/steward_summary.txt",
        "data/column_mapping_summary.json",
        "data/strategy_spec.json",
        "data/plan.json",
        "data/evaluation_spec.json",
        "data/execution_contract.json",
    }
    for path in preserve_paths or []:
        norm = _normalize_output_path(str(path or ""))
        if norm:
            protected.add(norm)
    keep_exact = {
        _normalize_path_posix(path)
        for path in (keep_outputs or [])
        if path and not _is_glob_pattern(path)
    }
    keep_globs = [str(path) for path in (keep_outputs or []) if path and _is_glob_pattern(path)]

    def _should_keep(path: str) -> bool:
        norm = _normalize_path_posix(path)
        if norm in keep_exact:
            return True
        for pattern in keep_globs:
            if fnmatch.fnmatch(norm, pattern):
                return True
        return False
    for path in required_outputs or []:
        if not path or _is_glob_pattern(path):
            continue
        if path in protected:
            continue
        if path.startswith("data/cleaned_"):
            continue
        try:
            if os.path.exists(path):
                os.remove(path)
        except Exception:
            pass
    for extra in [
        "data/metrics.json",
        "data/scored_rows.csv",
        "data/alignment_check.json",
        "data/output_contract_report.json",
        "analysis/leakage_report.json",
        "artifacts/heavy_error.json",
        "artifacts/heavy_status.json",
        "artifacts/heavy_execution_log.txt",
        "artifacts/heavy_model.joblib",
    ]:
        if extra in protected:
            continue
        if _should_keep(extra):
            continue
        try:
            if os.path.exists(extra):
                os.remove(extra)
        except Exception:
            pass
    for folder in ["analysis", "models", os.path.join("static", "plots")]:
        try:
            if not os.path.isdir(folder):
                continue
            for base, _, names in os.walk(folder):
                for name in names:
                    full = os.path.join(base, name)
                    rel = _normalize_path_posix(os.path.relpath(full, "."))
                    if rel in protected or rel.startswith("data/cleaned_"):
                        continue
                    if _should_keep(rel):
                        continue
                    try:
                        os.remove(full)
                    except Exception:
                        pass
            for base, dirs, _ in os.walk(folder, topdown=False):
                for dname in dirs:
                    path = os.path.join(base, dname)
                    try:
                        if os.path.isdir(path) and not os.listdir(path):
                            os.rmdir(path)
                    except Exception:
                        pass
        except Exception:
            pass

def _find_stale_outputs(required_outputs: List[str], start_ts: float) -> List[str]:
    stale: List[str] = []
    if not required_outputs:
        return stale
    threshold = start_ts - 1.0
    protected = {
        "data/cleaned_data.csv",
        "data/cleaned_full.csv",
        "data/cleaning_manifest.json",
        "data/dataset_profile.json",
    }
    for path in required_outputs:
        if not path or _is_glob_pattern(path):
            continue
        if path in protected or path.startswith("data/cleaned_"):
            continue
        if not os.path.exists(path):
            continue
        try:
            if os.path.getmtime(path) < threshold:
                stale.append(path)
        except Exception:
            continue
    return stale

def _infer_artifact_type(path: str, deliverable_kind: str | None = None) -> str:
    if deliverable_kind:
        return str(deliverable_kind)
    lower = str(path or "").lower()
    if "plot" in lower or lower.endswith((".png", ".jpg", ".jpeg", ".svg")):
        return "plot"
    if lower.endswith(".csv"):
        if "pred" in lower or "score" in lower:
            return "predictions"
        if "summary" in lower:
            return "summary"
        return "dataset"
    if lower.endswith(".json"):
        if "weight" in lower:
            return "weights"
        if "metrics" in lower:
            return "metrics"
        if "forecast" in lower:
            return "forecast"
        if "importance" in lower:
            return "feature_importances"
        if "error" in lower or "residual" in lower:
            return "error_analysis"
        if "alignment" in lower or "report" in lower:
            return "report"
        if "insights" in lower:
            return "insights"
        if "strategy_spec" in lower:
            return "strategy_spec"
        if "plan" in lower:
            return "execution_plan"
        return "json"
    if lower.endswith(".md"):
        return "executive_summary"
    return "artifact"

def _infer_produced_by(path: str) -> str:
    lower = str(path or "").lower()
    if "/qa/" in lower or "\\qa\\" in lower or lower.startswith("artifacts/qa/"):
        return "qa_reviewer"
    if "clean" in lower or "cleaning" in lower:
        return "data_engineer"
    if "strategy_spec" in lower:
        return "strategist"
    if "plan" in lower:
        return "execution_planner"
    if "insights" in lower:
        return "results_advisor"
    if "executive_summary" in lower:
        return "business_translator"
    if "alignment" in lower or "report" in lower:
        return "system"
    return "ml_engineer"

def _build_artifact_index(
    paths: List[str],
    deliverables: List[Dict[str, Any]] | None = None,
) -> List[Dict[str, Any]]:
    by_path = {}
    deliverable_lookup: Dict[str, Dict[str, Any]] = {}
    for item in deliverables or []:
        if isinstance(item, dict) and item.get("path"):
            deliverable_lookup[item["path"]] = item
    for path in paths or []:
        if not path:
            continue
        deliverable = deliverable_lookup.get(path) or {}
        artifact_type = _infer_artifact_type(path, deliverable.get("kind"))
        produced_by = _infer_produced_by(path)
        by_path[path] = {
            "artifact_type": artifact_type,
            "path": path,
            "schema_version": "1",
            "produced_by": produced_by,
        }
    return list(by_path.values())

def _merge_artifact_index_entries(
    base: List[Dict[str, Any]],
    additions: List[Dict[str, Any]],
) -> List[Dict[str, Any]]:
    merged: Dict[str, Dict[str, Any]] = {}
    for item in base or []:
        path = item.get("path") if isinstance(item, dict) else None
        if path:
            merged[path] = item
    for item in additions or []:
        path = item.get("path") if isinstance(item, dict) else None
        if path:
            merged[path] = item
    return list(merged.values())


def _extract_runner_reported_artifact_paths(runner_result: Dict[str, Any] | None) -> List[str]:
    if not isinstance(runner_result, dict):
        return []

    candidates: List[str] = []
    downloaded = runner_result.get("downloaded")
    if isinstance(downloaded, dict):
        candidates.extend(str(path) for path in downloaded.keys() if str(path or "").strip())
    elif isinstance(downloaded, list):
        candidates.extend(str(path) for path in downloaded if str(path or "").strip())

    for payload in (
        runner_result.get("status_payload"),
        runner_result.get("error"),
        runner_result.get("error_raw"),
    ):
        if not isinstance(payload, dict):
            continue
        for key in ("uploaded_outputs", "uploaded", "present", "required_outputs_present", "downloaded"):
            values = payload.get(key)
            if isinstance(values, list):
                candidates.extend(str(path) for path in values if str(path or "").strip())

    return _normalize_output_path_list(candidates)


def _persist_runner_artifact_index(
    state: Dict[str, Any] | None,
    runner_result: Dict[str, Any] | None,
    *,
    contract: Dict[str, Any] | None = None,
    extra_paths: List[str] | None = None,
) -> List[Dict[str, Any]]:
    state = state if isinstance(state, dict) else {}
    contract_payload = contract if isinstance(contract, dict) else (
        state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    )

    artifact_paths = _extract_runner_reported_artifact_paths(runner_result)
    if isinstance(extra_paths, list):
        artifact_paths.extend(str(path) for path in extra_paths if str(path or "").strip())
    artifact_paths = _normalize_output_path_list(artifact_paths)
    if not artifact_paths:
        existing = state.get("artifact_index") if isinstance(state.get("artifact_index"), list) else state.get("produced_artifact_index")
        return existing if isinstance(existing, list) else []

    existing_index = state.get("artifact_index")
    if not isinstance(existing_index, list):
        existing_index = state.get("produced_artifact_index")
    if not isinstance(existing_index, list):
        existing_index = _load_json_any("data/produced_artifact_index.json")
    normalized_existing = existing_index if isinstance(existing_index, list) else []
    deliverables = _resolve_contract_deliverables(contract_payload)
    additions = _build_artifact_index(artifact_paths, deliverables if isinstance(deliverables, list) else None)
    merged_index = _merge_artifact_index_entries(normalized_existing, additions)
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/produced_artifact_index.json", merged_index)
    except Exception as idx_err:
        print(f"Warning: failed to persist runner artifact index: {idx_err}")
    state["artifact_index"] = merged_index
    state["produced_artifact_index"] = merged_index
    return merged_index


def _merge_non_empty_policy(base: Dict[str, Any], override: Dict[str, Any]) -> Dict[str, Any]:
    merged = dict(base or {})
    for key, value in (override or {}).items():
        if value is None:
            continue
        if isinstance(value, str) and not value.strip():
            continue
        if isinstance(value, (list, dict)) and len(value) == 0:
            continue
        merged[key] = value
    base_constraints = base.get("constraints") if isinstance(base, dict) else {}
    override_constraints = override.get("constraints") if isinstance(override, dict) else {}
    if isinstance(base_constraints, dict) or isinstance(override_constraints, dict):
        merged["constraints"] = {
            **(base_constraints if isinstance(base_constraints, dict) else {}),
            **(override_constraints if isinstance(override_constraints, dict) else {}),
        }
    if isinstance(override, dict) and isinstance(override.get("plot_spec"), dict) and override.get("plot_spec"):
        merged["plot_spec"] = override["plot_spec"]
    return merged


def _ensure_plot_spec_in_policy(policy: Dict[str, Any], contract: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(policy, dict):
        policy = {}
    plot_spec = policy.get("plot_spec")
    if isinstance(plot_spec, dict):
        enabled = plot_spec.get("enabled", True)
        plots = plot_spec.get("plots")
        if isinstance(plots, list) and plots:
            return policy
        if enabled is False:
            return policy

    visual_reqs = (
        contract.get("artifact_requirements", {}).get("visual_requirements")
        if isinstance(contract.get("artifact_requirements"), dict)
        else {}
    )
    if isinstance(visual_reqs, dict):
        vis_visible = visual_reqs.get("plot_spec") if isinstance(visual_reqs.get("plot_spec"), dict) else None
        if vis_visible:
            policy = dict(policy)
            policy["plot_spec"] = vis_visible
            return policy
        if visual_reqs.get("enabled") is False:
            policy = dict(policy)
            policy["plot_spec"] = {"enabled": False}
            return policy

    policy = dict(policy)
    policy["plot_spec"] = build_plot_spec(contract)
    return policy


def _compact_reporting_policy(policy: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(policy, dict):
        return {}
    plot_spec = policy.get("plot_spec")
    if not isinstance(plot_spec, dict) or not plot_spec:
        return {}
    plots = plot_spec.get("plots") if isinstance(plot_spec.get("plots"), list) else []
    max_plots = plot_spec.get("max_plots")
    if isinstance(max_plots, (int, float)):
        max_plots_val = int(max_plots)
    elif isinstance(max_plots, str) and max_plots.strip().isdigit():
        max_plots_val = int(max_plots.strip())
    else:
        max_plots_val = len(plots)
    return {
        "plot_spec": {
            "enabled": bool(plot_spec.get("enabled", True)),
            "max_plots": max_plots_val,
        }
    }


def _maybe_set_contract_min_policy(contract_min: Dict[str, Any] | None, policy: Dict[str, Any]) -> None:
    if not isinstance(contract_min, dict):
        return
    existing = contract_min.get("reporting_policy")
    if isinstance(existing, dict) and existing:
        return
    compact = _compact_reporting_policy(policy)
    if compact:
        contract_min["reporting_policy"] = compact


def _validate_projected_views_for_execution(
    contract: Dict[str, Any],
    views: Dict[str, Any],
) -> List[str]:
    errors: List[str] = []
    contract = contract if isinstance(contract, dict) else {}

    # ── V5 union validation: the union of all view fields must contain
    # every field declared in any contract section.  This is the only
    # structural check needed because v5 views are direct merges.
    # Detect v5: either direct v5 contract or flattened (has _v5_original)
    _v5_source = None
    if str(contract.get("contract_version", "")).startswith("5") and "shared" in contract:
        _v5_source = contract
    elif isinstance(contract.get("_v5_original"), dict):
        _v5_source = contract["_v5_original"]
    if _v5_source is not None:
        from src.utils.contract_response_schema import V5_AGENT_SECTION_KEYS

        # Collect all fields declared across contract sections
        all_contract_fields: set = set()
        for section_key in ["shared"] + list(V5_AGENT_SECTION_KEYS):
            section = _v5_source.get(section_key)
            if isinstance(section, dict):
                all_contract_fields.update(section.keys())

        # Collect all fields present across all views
        all_view_fields: set = set()
        expected_view_keys = ("de_view", "ml_view", "cleaning_view", "qa_view", "reviewer_view", "translator_view", "results_advisor_view")
        for view_key in expected_view_keys:
            v = views.get(view_key) if isinstance(views, dict) else None
            if not isinstance(v, dict) or not v:
                errors.append(f"{view_key}_missing")
            else:
                all_view_fields.update(v.keys())

        # Every contract field must appear in at least one view
        missing = all_contract_fields - all_view_fields
        if missing:
            errors.append(f"v5_view_union_missing_fields:{','.join(sorted(missing))}")

        return errors

    # Non-v5 contracts: no legacy validation, just return empty errors
    return errors


def _get_view_profile_context(state: Dict[str, Any] | None) -> tuple[Dict[str, Any], Dict[str, Any]]:
    if not isinstance(state, dict):
        return {}, {}
    data_profile = state.get("data_profile") if isinstance(state.get("data_profile"), dict) else {}
    dataset_profile = state.get("dataset_profile") if isinstance(state.get("dataset_profile"), dict) else {}
    if not dataset_profile and isinstance(state.get("profile"), dict):
        dataset_profile = state.get("profile")
    return data_profile, dataset_profile


def _project_contract_views_from_state(
    state: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
    artifact_index: Any,
    *,
    cleaning_code: str | None = None,
) -> Dict[str, Dict[str, Any]]:
    data_profile, dataset_profile = _get_view_profile_context(state)
    return build_contract_views_projection(
        contract if isinstance(contract, dict) else {},
        artifact_index,
        cleaning_code=cleaning_code,
        data_profile=data_profile,
        dataset_profile=dataset_profile,
    )


def _persist_column_resolution_context(
    views: Dict[str, Any],
    *,
    base_dir: str = "data",
    run_bundle_dir: str | None = None,
) -> str:
    context: Dict[str, Any] = {}
    if isinstance(views, dict):
        for key in ("de_view", "cleaning_view"):
            view = views.get(key)
            candidate = view.get("column_resolution_context") if isinstance(view, dict) else None
            if isinstance(candidate, dict) and candidate:
                context = candidate
                break
    if not context:
        return ""
    path = os.path.join(base_dir, "column_resolution_context.json")
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(context, f, indent=2, ensure_ascii=False)
    if run_bundle_dir:
        bundle_path = os.path.join(run_bundle_dir, "column_resolution_context.json")
        os.makedirs(os.path.dirname(bundle_path), exist_ok=True)
        with open(bundle_path, "w", encoding="utf-8") as f:
            json.dump(context, f, indent=2, ensure_ascii=False)
    return path


def _persist_artifact_obligations_context(
    context: Dict[str, Any],
    *,
    base_dir: str = "data",
    run_bundle_dir: str | None = None,
) -> str:
    context = context if isinstance(context, dict) else {}
    if not context:
        return ""
    path = os.path.join(base_dir, "contracts", "support", "data_engineer_artifact_obligations.json")
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(context, f, indent=2, ensure_ascii=False)
    if run_bundle_dir:
        bundle_path = os.path.join(
            run_bundle_dir,
            "contracts",
            "support",
            "data_engineer_artifact_obligations.json",
        )
        os.makedirs(os.path.dirname(bundle_path), exist_ok=True)
        with open(bundle_path, "w", encoding="utf-8") as f:
            json.dump(context, f, indent=2, ensure_ascii=False)
    return path


def _build_contract_views(
    state: Dict[str, Any],
    contract: Dict[str, Any],
    contract_min: Dict[str, Any] | None,
) -> Dict[str, Any]:
    artifact_index = state.get("artifact_index") or []
    if not artifact_index:
        required_outputs = []
        required_outputs = _resolve_required_outputs(contract, state)
        deliverables = _resolve_contract_deliverables(contract)
        artifact_index = _build_artifact_index(required_outputs, deliverables)
    projected_views = _project_contract_views_from_state(state, contract, artifact_index)
    de_view = projected_views.get("de_view") or {}
    ml_view = projected_views.get("ml_view") or {}
    cleaning_view = projected_views.get("cleaning_view") or {}
    qa_view = projected_views.get("qa_view") or {}
    reviewer_view = projected_views.get("reviewer_view") or {}
    translator_view = projected_views.get("translator_view") or {}
    results_advisor_view = projected_views.get("results_advisor_view") or {}
    views = {
        "de_view": de_view,
        "ml_view": ml_view,
        "cleaning_view": cleaning_view,
        "qa_view": qa_view,
        "reviewer_view": reviewer_view,
        "translator_view": translator_view,
        "results_advisor_view": results_advisor_view,
    }
    view_errors = _validate_projected_views_for_execution(contract, views)
    projection_reports: Dict[str, Any] = {}
    artifact_obligations_context = build_data_engineer_artifact_obligations(contract)
    column_resolution_context_path = _persist_column_resolution_context(
        views,
        base_dir="data",
        run_bundle_dir=state.get("run_bundle_dir"),
    )
    artifact_obligations_context_path = _persist_artifact_obligations_context(
        artifact_obligations_context,
        base_dir="data",
        run_bundle_dir=state.get("run_bundle_dir"),
    )
    view_paths = persist_views(
        views,
        base_dir="data",
        run_bundle_dir=state.get("run_bundle_dir"),
    )
    projection_report_paths = persist_view_projection_reports(
        projection_reports,
        base_dir="data",
        run_bundle_dir=state.get("run_bundle_dir"),
    )
    return {
        "contract_views": views,
        "contract_view_paths": view_paths,
        "contract_view_projection_reports": projection_reports,
        "contract_view_projection_report_paths": projection_report_paths,
        "artifact_index": artifact_index,
        "de_view": de_view,
        "ml_view": ml_view,
        "cleaning_view": cleaning_view,
        "qa_view": qa_view,
        "reviewer_view": reviewer_view,
        "translator_view": translator_view,
        "results_advisor_view": results_advisor_view,
        "contract_views_projection_ok": not view_errors,
        "contract_views_projection_errors": view_errors,
        "artifact_obligations_context": artifact_obligations_context,
        "artifact_obligations_context_path": artifact_obligations_context_path,
        "column_resolution_context_path": column_resolution_context_path,
    }

def _deliverable_id_from_path(path: str) -> str:
    base = os.path.basename(str(path)) or str(path)
    cleaned = re.sub(r"[^0-9a-zA-Z]+", "_", base).strip("_").lower()
    return cleaned or "deliverable"

def _infer_deliverable_kind(path: str) -> str:
    from src.utils.contract_accessors import _infer_kind_from_path
    return _infer_kind_from_path(path)

def _should_run_case_alignment(
    contract: Dict[str, Any] | None,
    evaluation_spec: Dict[str, Any] | None = None,
) -> bool:
    if not isinstance(contract, dict):
        contract = {}
    skip_reason = _case_alignment_skip_reason(contract, evaluation_spec)
    if skip_reason:
        return False
    required_outputs = _resolve_required_outputs(contract)
    required_set = {str(p) for p in (required_outputs or []) if p}
    required_basenames = {
        os.path.basename(str(path)).lower()
        for path in required_set
        if str(path).strip()
    }
    requires_outputs = bool(required_basenames.intersection({"scored_rows.csv", "weights.json", "case_summary.csv"}))
    spec_requires = False
    if isinstance(evaluation_spec, dict):
        spec_requires = bool(
            evaluation_spec.get("requires_case_alignment")
            or evaluation_spec.get("case_alignment_required")
            or evaluation_spec.get("requires_row_scoring")
        )
    flags = _resolve_eval_flags(evaluation_spec) if isinstance(evaluation_spec, dict) else {}
    return requires_outputs or spec_requires or bool(flags.get("requires_row_scoring"))

def _case_alignment_skip_reason(
    contract: Dict[str, Any] | None,
    evaluation_spec: Dict[str, Any] | None = None,
) -> str:
    """V4.1: Check case_taxonomy, case_key, case_columns from contract root only."""
    if not isinstance(contract, dict):
        contract = {}
    # V4.1: Use top-level keys only, no spec_extraction
    case_taxonomy = contract.get("case_taxonomy") if isinstance(contract.get("case_taxonomy"), list) else []
    case_key = contract.get("case_key")
    case_columns = contract.get("case_columns")
    if isinstance(evaluation_spec, dict):
        if not case_taxonomy:
            case_taxonomy = evaluation_spec.get("case_taxonomy") if isinstance(evaluation_spec.get("case_taxonomy"), list) else []
        case_key = case_key or evaluation_spec.get("case_key")
        case_columns = case_columns or evaluation_spec.get("case_columns")
    manifest_path = get_clean_manifest_path(contract)
    scored_rows_path = get_declared_artifact_path(contract, "scored_rows.csv")

    def _scored_rows_has_group_signals(scored_path: str = "") -> bool:
        if not scored_path:
            return False
        if not os.path.exists(scored_path):
            return False
        dialect = _load_output_dialect_local(manifest_path)
        header = _read_csv_header(scored_path, dialect.get("encoding", "utf-8"), dialect.get("sep", ","))
        if not header:
            return False
        normed = [_norm_name(col) for col in header]
        has_group = any(any(tok in name for tok in ["case", "group", "segment", "bucket", "cluster"]) for name in normed)
        has_score = any(any(tok in name for tok in ["score", "pred", "prob", "rank"]) for name in normed)
        return bool(has_group and has_score)

    if not case_taxonomy:
        if _scored_rows_has_group_signals(scored_rows_path):
            return ""
        return "case_taxonomy missing or empty"
    if not case_key and not case_columns:
        if _scored_rows_has_group_signals(scored_rows_path):
            return ""
        return "case_key/case_columns missing"
    return ""

def _normalize_required_fixes(items: List[Any] | None) -> List[str]:
    fixes: List[str] = []
    for item in items or []:
        if item is None:
            continue
        if isinstance(item, str):
            cleaned = item.strip()
            if cleaned:
                fixes.append(cleaned)
        else:
            fixes.append(str(item))
    return fixes

