def _build_fix_instructions(required_fixes: List[str]) -> str:
    if not required_fixes:
        return ""
    lines = ["PATCH TARGETS (apply minimal edits):"]
    for fix in required_fixes:
        lines.append(f"- {fix}")
    return "\n".join(lines)


def _extract_contract_artifact_issues(oc_report: Dict[str, Any] | None) -> Dict[str, List[str]]:
    """
    Extract actionable contract artifact issues from output_contract_report.

    Returns:
      {
        "missing_paths": [...],
        "schema_issues": [...],
      }
    """
    missing_paths: List[str] = []
    schema_issues: List[str] = []
    if not isinstance(oc_report, dict):
        return {"missing_paths": missing_paths, "schema_issues": schema_issues}

    def _add_missing(path_like: Any) -> None:
        text = str(path_like or "").strip().replace("\\", "/")
        while text.startswith("./"):
            text = text[2:]
        if not text:
            return
        if text not in missing_paths:
            missing_paths.append(text)

    for path in oc_report.get("missing", []) or []:
        _add_missing(path)

    artifact_report = oc_report.get("artifact_requirements_report")
    if isinstance(artifact_report, dict):
        files_report = artifact_report.get("files_report")
        if isinstance(files_report, dict):
            for path in files_report.get("missing", []) or []:
                _add_missing(path)
        row_count_report = artifact_report.get("row_count_report")
        if isinstance(row_count_report, dict):
            for mismatch in row_count_report.get("mismatches", []) or []:
                if not isinstance(mismatch, dict):
                    continue
                path = str(mismatch.get("path") or "unknown.csv")
                expected = mismatch.get("expected_row_count")
                actual = mismatch.get("actual_row_count")
                schema_issues.append(
                    f"{path} row count mismatch: expected {expected}, got {actual}"
                )
            for issue in row_count_report.get("errors", []) or []:
                if not isinstance(issue, dict):
                    continue
                path = str(issue.get("path") or "unknown.csv")
                detail = str(issue.get("error") or "unknown_error")
                schema_issues.append(
                    f"{path} row count check error: {detail}"
                )

        scored_rows_report = artifact_report.get("scored_rows_report")
        if isinstance(scored_rows_report, dict):
            missing_columns = [str(col) for col in (scored_rows_report.get("missing_columns") or []) if col]
            if missing_columns:
                schema_issues.append(
                    "scored_rows.csv missing required columns: " + ", ".join(missing_columns)
                )
            fail_groups: List[str] = []
            for group in scored_rows_report.get("missing_any_of_groups_with_severity", []) or []:
                if not isinstance(group, dict):
                    continue
                if str(group.get("severity") or "").lower() != "fail":
                    continue
                values = group.get("group") if isinstance(group.get("group"), list) else []
                normalized = [str(v) for v in values if v]
                if normalized:
                    fail_groups.append("[" + ", ".join(normalized) + "]")
            if fail_groups:
                schema_issues.append(
                    "scored_rows.csv missing required any-of groups: " + "; ".join(fail_groups)
                )

    return {"missing_paths": missing_paths, "schema_issues": schema_issues}


_ATTEMPT_LEDGER_MAX_ENTRIES = 160


def _normalize_cycle_phase(raw: Any) -> str:
    token = str(raw or "").strip().lower().replace("-", "_").replace(" ", "_")
    if not token:
        return "other"
    mapping = {
        "baseline": "compliance",
        "bootstrap": "compliance",
        "bootstrap_review": "compliance",
        "compliance_bootstrap": "compliance",
        "retry": "compliance",
        "review_complete": "compliance",
        "metric_improvement": "metric",
        "metric_improvement_round": "metric",
        "optimization": "metric",
        "runtime_fix": "runtime",
        "runtime_failure": "runtime",
    }
    normalized = mapping.get(token, token)
    if normalized in {"compliance", "metric", "runtime", "other"}:
        return normalized
    return "other"


def _normalize_cycle_outcome(raw: Any) -> str:
    token = str(raw or "").strip().lower().replace(" ", "_")
    return token[:64] if token else "unknown"


def _normalize_root_cause_signature(raw: Any) -> str:
    text = str(raw or "").strip().lower().replace("\\", "/")
    if not text:
        return ""
    text = re.sub(r"0x[0-9a-f]+", "0x?", text)
    text = re.sub(r"\bline\s+\d+\b", "line ?", text)
    text = re.sub(r"\b\d+\b", "?", text)
    text = re.sub(r"\s+", " ", text)
    return text[:220]


def _get_attempt_ledger_entries(state: Dict[str, Any] | None) -> List[Dict[str, Any]]:
    if not isinstance(state, dict):
        return []
    raw_entries = state.get("attempt_ledger")
    if not isinstance(raw_entries, list):
        return []
    return [dict(entry) for entry in raw_entries if isinstance(entry, dict)]


def _compute_attempt_phase_counts(entries: List[Dict[str, Any]]) -> Dict[str, int]:
    counts = {"compliance": 0, "metric": 0, "runtime": 0, "other": 0}
    for entry in entries:
        phase = _normalize_cycle_phase(entry.get("phase"))
        counts[phase] = counts.get(phase, 0) + 1
    return counts


def _sync_attempt_ledger_state(state: Dict[str, Any]) -> Dict[str, int]:
    entries = _get_attempt_ledger_entries(state)
    counts = _compute_attempt_phase_counts(entries)
    explicit_total = sum(int(v or 0) for v in counts.values())
    current_total = _coerce_nonnegative_int(state.get("expensive_cycle_count", 0), default=0)
    current_metric = _coerce_nonnegative_int(state.get("metric_iterations", 0), default=0)
    current_runtime = _coerce_nonnegative_int(state.get("runtime_iterations", 0), default=0)
    state["attempt_ledger"] = entries[-_ATTEMPT_LEDGER_MAX_ENTRIES:]
    state["phase_cycle_counts"] = counts
    state["expensive_cycle_count"] = max(current_total, explicit_total)
    state["metric_iterations"] = max(
        current_metric,
        counts.get("metric", 0),
        _coerce_nonnegative_int(state.get("ml_improvement_round_count", 0), default=0),
    )
    state["runtime_iterations"] = max(
        current_runtime,
        counts.get("runtime", 0),
        _coerce_nonnegative_int(state.get("runtime_fix_count", 0), default=0),
    )
    return counts


def _build_attempt_cycle_key(
    *,
    phase: str,
    outcome: str,
    state: Dict[str, Any],
    root_cause: str = "",
    source: str = "",
    cycle_key: str | None = None,
) -> str:
    if cycle_key:
        return str(cycle_key)
    return "|".join(
        [
            phase,
            outcome,
            str(source or ""),
            str(_coerce_nonnegative_int(state.get("iteration_count", 0), default=0)),
            str(_coerce_nonnegative_int(state.get("ml_engineer_attempt", 0), default=0)),
            str(_coerce_nonnegative_int(state.get("execution_attempt", 0), default=0)),
            str(_coerce_nonnegative_int(state.get("ml_improvement_round_count", 0), default=0)),
            root_cause[:120],
        ]
    )


def _append_attempt_cycle(
    state: Dict[str, Any],
    *,
    phase: Any,
    outcome: Any,
    root_cause: Any = "",
    source: str = "",
    details: Dict[str, Any] | None = None,
    cycle_key: str | None = None,
) -> Dict[str, Any]:
    if not isinstance(state, dict):
        return {}
    entries = _get_attempt_ledger_entries(state)
    normalized_phase = _normalize_cycle_phase(phase)
    normalized_outcome = _normalize_cycle_outcome(outcome)
    normalized_root_cause = _normalize_root_cause_signature(root_cause)
    normalized_details = dict(details) if isinstance(details, dict) else {}
    normalized_cycle_key = _build_attempt_cycle_key(
        phase=normalized_phase,
        outcome=normalized_outcome,
        state=state,
        root_cause=normalized_root_cause,
        source=source,
        cycle_key=cycle_key,
    )
    if entries and str(entries[-1].get("cycle_key") or "") == normalized_cycle_key:
        state["attempt_ledger"] = entries[-_ATTEMPT_LEDGER_MAX_ENTRIES:]
        _sync_attempt_ledger_state(state)
        return dict(entries[-1])

    phase_counts = _compute_attempt_phase_counts(entries)
    next_cycle_id = max(
        _coerce_nonnegative_int(state.get("expensive_cycle_count", 0), default=0),
        len(entries),
    ) + 1
    entry = {
        "cycle_id": int(next_cycle_id),
        "phase": normalized_phase,
        "phase_cycle_index": int(phase_counts.get(normalized_phase, 0) + 1),
        "outcome": normalized_outcome,
        "root_cause": normalized_root_cause,
        "source": str(source or ""),
        "iteration_count": _coerce_nonnegative_int(state.get("iteration_count", 0), default=0),
        "ml_engineer_attempt": _coerce_nonnegative_int(state.get("ml_engineer_attempt", 0), default=0),
        "execution_attempt": _coerce_nonnegative_int(state.get("execution_attempt", 0), default=0),
        "runtime_fix_count": _coerce_nonnegative_int(state.get("runtime_fix_count", 0), default=0),
        "round_id": _coerce_nonnegative_int(state.get("ml_improvement_round_count", 0), default=0),
        "review_verdict": str(state.get("review_verdict") or ""),
        "cycle_key": normalized_cycle_key,
    }
    if normalized_details:
        entry["details"] = normalized_details
    entries.append(entry)
    state["attempt_ledger"] = entries[-_ATTEMPT_LEDGER_MAX_ENTRIES:]
    _sync_attempt_ledger_state(state)
    return entry


def _reconcile_latest_attempt_cycle(
    state: Dict[str, Any],
    *,
    phase: Any,
    outcome: Any,
    root_cause: Any = "",
    source: str = "run_result_evaluator",
    details: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    if not isinstance(state, dict):
        return {}
    entries = _get_attempt_ledger_entries(state)
    if not entries:
        return _append_attempt_cycle(
            state,
            phase=phase,
            outcome=outcome,
            root_cause=root_cause,
            source=source,
            details=details,
        )
    current_execution_attempt = _coerce_nonnegative_int(state.get("execution_attempt", 0), default=0)
    target_index: int | None = None
    for idx in range(len(entries) - 1, -1, -1):
        entry = entries[idx]
        if str(entry.get("source") or "") != str(source or ""):
            continue
        if _coerce_nonnegative_int(entry.get("execution_attempt", -1), default=-1) != current_execution_attempt:
            continue
        target_index = idx
        break
    if target_index is None:
        return _append_attempt_cycle(
            state,
            phase=phase,
            outcome=outcome,
            root_cause=root_cause,
            source=source,
            details=details,
        )

    normalized_phase = _normalize_cycle_phase(phase)
    normalized_outcome = _normalize_cycle_outcome(outcome)
    normalized_root_cause = _normalize_root_cause_signature(root_cause)
    entry = dict(entries[target_index])
    entry["phase"] = normalized_phase
    entry["outcome"] = normalized_outcome
    entry["root_cause"] = normalized_root_cause
    entry["cycle_key"] = _build_attempt_cycle_key(
        phase=normalized_phase,
        outcome=normalized_outcome,
        state=state,
        root_cause=normalized_root_cause,
        source=source,
    )
    if isinstance(details, dict) and details:
        merged_details = dict(entry.get("details") or {})
        merged_details.update(details)
        entry["details"] = merged_details
    entries[target_index] = entry
    state["attempt_ledger"] = entries[-_ATTEMPT_LEDGER_MAX_ENTRIES:]
    _sync_attempt_ledger_state(state)
    return entry


def _iteration_budget_snapshot(state: Dict[str, Any]) -> Dict[str, int]:
    entries = _get_attempt_ledger_entries(state)
    phase_counts = _compute_attempt_phase_counts(entries)
    compliance_retries = _coerce_nonnegative_int(state.get("compliance_iterations", 0), default=0)
    metric_rounds = max(
        phase_counts.get("metric", 0),
        _coerce_nonnegative_int(state.get("metric_iterations", 0), default=0),
        _coerce_nonnegative_int(state.get("ml_improvement_round_count", 0), default=0),
    )
    runtime_cycles = max(
        phase_counts.get("runtime", 0),
        _coerce_nonnegative_int(state.get("runtime_iterations", 0), default=0),
        _coerce_nonnegative_int(state.get("runtime_fix_count", 0), default=0),
    )
    explicit_total = _coerce_nonnegative_int(state.get("expensive_cycle_count", 0), default=0)
    phase_total = sum(int(v or 0) for v in phase_counts.values())
    legacy_total = max(
        _coerce_nonnegative_int(state.get("iteration_count", 0), default=0),
        compliance_retries + metric_rounds + runtime_cycles,
    )
    total_cycles = max(explicit_total, phase_total, legacy_total)
    return {
        "total_cycles": int(total_cycles),
        "compliance_retries": int(compliance_retries),
        "metric_rounds": int(metric_rounds),
        "runtime_cycles": int(runtime_cycles),
        "ledger_compliance_cycles": int(phase_counts.get("compliance", 0)),
        "ledger_metric_cycles": int(phase_counts.get("metric", 0)),
        "ledger_runtime_cycles": int(phase_counts.get("runtime", 0)),
    }


def _derive_root_cause_signature(
    state: Dict[str, Any],
    phase: Any,
    *,
    gate_context: Dict[str, Any] | None = None,
    feedback_text: str | None = None,
) -> str:
    normalized_phase = _normalize_cycle_phase(phase)
    if normalized_phase == "runtime":
        runtime_summary = _summarize_runtime_error(
            state.get("last_runtime_error_tail") or state.get("execution_output")
        )
        if isinstance(runtime_summary, dict):
            token = runtime_summary.get("message") or runtime_summary.get("type")
            normalized = _normalize_root_cause_signature(token)
            if normalized:
                return normalized
        runtime_tail = str(state.get("last_runtime_error_tail") or state.get("execution_output") or "").strip()
        if runtime_tail:
            return _normalize_root_cause_signature(runtime_tail.splitlines()[-1])
        return ""

    gate = gate_context if isinstance(gate_context, dict) else (
        state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
    )
    candidate_fields = (
        ("hard_failure", gate.get("hard_failures")),
        ("failed_gate", gate.get("failed_gates")),
        ("required_fix", gate.get("required_fixes")),
    )
    for prefix, values in candidate_fields:
        if not isinstance(values, list):
            continue
        for item in values:
            normalized = _normalize_root_cause_signature(f"{prefix}:{item}")
            if normalized:
                return normalized

    feedback_candidates = [
        feedback_text,
        gate.get("feedback"),
        state.get("review_feedback"),
    ]
    for item in feedback_candidates:
        text = str(item or "").strip()
        if not text:
            continue
        normalized = _normalize_root_cause_signature(text.splitlines()[0])
        if normalized:
            return normalized
    return ""


def _resolve_root_cause_repeat_limit(state: Dict[str, Any], phase: Any) -> int:
    normalized_phase = _normalize_cycle_phase(phase)
    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    policy = contract.get("iteration_policy") if isinstance(contract.get("iteration_policy"), dict) else {}
    phase_key = f"{normalized_phase}_root_cause_repeat_limit"
    env_key = f"{normalized_phase.upper()}_ROOT_CAUSE_REPEAT_LIMIT"
    default_map = {
        "runtime": 2,
        "compliance": 3,
        "metric": 2,
        "other": 3,
    }
    for raw in (
        policy.get(phase_key),
        policy.get("root_cause_repeat_limit"),
        os.getenv(env_key),
        os.getenv("ROOT_CAUSE_REPEAT_LIMIT"),
    ):
        try:
            value = int(raw)
        except Exception:
            continue
        if value > 0:
            return value
    return int(default_map.get(normalized_phase, 3))


def _recent_root_cause_streak(state: Dict[str, Any], phase: Any, root_cause: str) -> int:
    normalized_phase = _normalize_cycle_phase(phase)
    normalized_root_cause = _normalize_root_cause_signature(root_cause)
    if not normalized_root_cause:
        return 0
    entries = _get_attempt_ledger_entries(state)
    streak = 0
    started = False
    for entry in reversed(entries):
        entry_phase = _normalize_cycle_phase(entry.get("phase"))
        if entry_phase != normalized_phase:
            if started:
                break
            continue
        entry_root_cause = _normalize_root_cause_signature(entry.get("root_cause"))
        if not entry_root_cause:
            if started:
                break
            continue
        if entry_root_cause == normalized_root_cause:
            streak += 1
            started = True
            continue
        if started:
            break
        return 0
    return streak


def _should_stop_repeated_root_cause(state: Dict[str, Any], phase: Any, root_cause: str) -> Tuple[bool, int, int]:
    normalized_root_cause = _normalize_root_cause_signature(root_cause)
    if not normalized_root_cause:
        return False, 0, 0
    repeat_limit = _resolve_root_cause_repeat_limit(state, phase)
    if repeat_limit <= 0:
        return False, 0, repeat_limit
    predicted_streak = _recent_root_cause_streak(state, phase, normalized_root_cause) + 1
    return predicted_streak >= repeat_limit, predicted_streak, repeat_limit


def _get_iteration_policy(state: Dict[str, Any]) -> Dict[str, Any] | None:
    contract = state.get("execution_contract") or {}
    policy = contract.get("iteration_policy")
    if not isinstance(policy, dict):
        return None
    compliance_max = policy.get("compliance_bootstrap_max")
    metric_max = policy.get("metric_improvement_max")
    runtime_max = policy.get("runtime_fix_max")
    total_max = policy.get("total_iteration_max")
    if compliance_max is None:
        for alias in ("compliance_retry_limit",):
            if policy.get(alias) is not None:
                compliance_max = policy.get(alias)
                break
    if metric_max is None:
        for alias in ("max_iterations", "max_pipeline_iterations", "max_model_iterations", "max_iter", "max_retries"):
            if policy.get(alias) is not None:
                metric_max = policy.get(alias)
                break
    if runtime_max is None:
        for alias in ("gate_retry_limit", "runtime_retry_limit", "max_runtime_retries", "max_retries"):
            if policy.get(alias) is not None:
                runtime_max = policy.get(alias)
                break
    if total_max is None:
        for alias in ("max_total_iterations", "max_total_retries", "max_iterations_total", "total_retry_limit"):
            if policy.get(alias) is not None:
                total_max = policy.get(alias)
                break
    plateau_window = policy.get("plateau_window")
    plateau_epsilon = policy.get("plateau_epsilon")
    out: Dict[str, Any] = {}
    for key, val in {
        "compliance_bootstrap_max": compliance_max,
        "metric_improvement_max": metric_max,
        "runtime_fix_max": runtime_max,
        "total_iteration_max": total_max,
        "plateau_window": plateau_window,
        "plateau_epsilon": plateau_epsilon,
    }.items():
        if val is None:
            continue
        try:
            if key == "plateau_epsilon":
                out[key] = float(val)
            else:
                out[key] = max(1, int(val))
        except Exception:
            continue
    if out:
        print(
            "ITER_POLICY "
            + f"metric_improvement_max={out.get('metric_improvement_max')} "
            + f"runtime_fix_max={out.get('runtime_fix_max')} "
            + f"total_iteration_max={out.get('total_iteration_max')} "
            + f"plateau_window={out.get('plateau_window')} "
            + f"epsilon={out.get('plateau_epsilon')}"
        )
    return out or None


def _coerce_nonnegative_int(value: Any, default: int = 0) -> int:
    try:
        out = int(value)
    except Exception:
        return int(default)
    if out < 0:
        return int(default)
    return out


def _resolve_total_iteration_limit(
    state: Dict[str, Any],
    policy: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> int:
    """
    Resolve a deterministic hard ceiling for global retry loops.
    Priority:
      1) explicit iteration_policy total cap
      2) derived cap from per-phase budgets
      3) legacy default fallback (6)
    """
    default_cap = _coerce_nonnegative_int(os.getenv("MAX_TOTAL_ITERATIONS_DEFAULT", "6"), default=6)
    if default_cap <= 0:
        default_cap = 6

    if isinstance(policy, dict):
        explicit = _coerce_nonnegative_int(policy.get("total_iteration_max"), default=0)
        if explicit > 0:
            return explicit

        compliance_cap = _coerce_nonnegative_int(policy.get("compliance_bootstrap_max"), default=0)
        metric_cap = _coerce_nonnegative_int(policy.get("metric_improvement_max"), default=0)
        if metric_cap <= 0:
            rounds_allowed = _coerce_nonnegative_int(
                (state.get("ml_improvement_rounds_allowed") if isinstance(state, dict) else None),
                default=0,
            )
            if rounds_allowed > 0:
                metric_cap = rounds_allowed
            else:
                rounds_allowed, _, _ = _metric_improvement_policy(contract if isinstance(contract, dict) else {})
                metric_cap = _coerce_nonnegative_int(rounds_allowed, default=0)
        runtime_cap = _coerce_nonnegative_int(
            policy.get("runtime_fix_max"),
            default=_coerce_nonnegative_int(
                state.get("max_runtime_fix_attempts") if isinstance(state, dict) else None,
                default=0,
            ),
        )

        derived = compliance_cap + metric_cap + runtime_cap
        if derived > 0:
            hard_ceiling = _coerce_nonnegative_int(os.getenv("MAX_TOTAL_ITERATIONS_HARD_CEILING", "24"), default=24)
            if hard_ceiling <= 0:
                hard_ceiling = 24
            derived = min(derived, hard_ceiling)
            return max(1, derived)

    return default_cap

def _classify_iteration_type(
    status: str,
    audit_rejected: bool,
    oc_report: Dict[str, Any] | None,
    feedback: str | None,
) -> str | None:
    if status != "NEEDS_IMPROVEMENT":
        return None
    if audit_rejected:
        return "compliance"
    if isinstance(oc_report, dict):
        oc_overall = str(oc_report.get("overall_status") or "").lower()
        if oc_overall == "error":
            return "compliance"
        artifact_report = oc_report.get("artifact_requirements_report")
        if isinstance(artifact_report, dict):
            artifact_status = str(artifact_report.get("status") or "").lower()
            if artifact_status == "error":
                return "compliance"
        if oc_report.get("missing"):
            return "compliance"
    if feedback and any(token in feedback for token in [
        "CODE_AUDIT_REJECTED",
        "OUTPUT_CONTRACT_MISSING",
        "METRICS_SCHEMA_INCONSISTENT",  # Malformed metrics data = code error, not low metrics
        "BASELINE_CHECK_FAILED",
    ]):
        return "compliance"
    return "metric"

def _looks_blocking_retry_signal(text: Any) -> bool:
    value = str(text or "").strip().lower()
    if not value:
        return False
    blocking_tokens = [
        "runtime",
        "traceback",
        "exception",
        "crash",
        "sandbox",
        "output_contract",
        "contract_required",
        "required_outputs_missing",
        "artifact_missing",
        "missing output",
        "missing artifact",
        "qa_",
        "code_audit",
        "hard_fail",
        "security",
        "decisioning",
        "visual_requirements",
        "schema_inconsistent",
        "alignment_check",
        "segmentation",
        "operational_logic",
        "decisioning",
        "uncertainty",
        "dependency",
        "dialect",
        "static_precheck",
        "syntax",
    ]
    if any(token in value for token in blocking_tokens):
        return True
    if "leakage" in value:
        leakage_positive_markers = [
            "document leakage prevention",
            "exclude post-outcome features",
            "excluding forbidden columns",
            "prevents data leakage",
            "leakage is prevented",
        ]
        if any(marker in value for marker in leakage_positive_markers) and not any(
            marker in value for marker in ["failed", "failure", "violation", "rejected", "hard"]
        ):
            return False
        leakage_blocking_markers = [
            "failed",
            "failure",
            "violat",
            "hard",
            "guard",
            "deterministic",
            "reject",
            "post-outcome",
            "forbidden",
            "target leak",
            "leakage_prevention",
        ]
        if any(marker in value for marker in leakage_blocking_markers):
            return True
    return False

def _is_blocking_retry_reason(
    state: Dict[str, Any] | None,
    gate_context: Dict[str, Any] | None = None,
    board_failed_areas: List[str] | None = None,
    board_required_actions: List[str] | None = None,
) -> bool:
    state = state if isinstance(state, dict) else {}
    gate_context = gate_context if isinstance(gate_context, dict) else (
        state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
    )
    board_failed_areas = board_failed_areas if isinstance(board_failed_areas, list) else []
    board_required_actions = board_required_actions if isinstance(board_required_actions, list) else []

    if state.get("runtime_fix_terminal"):
        return True
    if state.get("sandbox_failed"):
        return True
    if _has_runtime_failure_marker(state.get("execution_output")):
        return True

    last_iter_type = str(state.get("last_iteration_type") or "").strip().lower()
    gate_iter_type = str(gate_context.get("iteration_type") or "").strip().lower()
    if last_iter_type == "compliance" or gate_iter_type == "compliance":
        return True

    hard_failures = [str(x) for x in (gate_context.get("hard_failures") or state.get("hard_failures") or []) if x]
    if hard_failures:
        return True

    oc_report = state.get("output_contract_report") if isinstance(state.get("output_contract_report"), dict) else {}
    if isinstance(oc_report, dict):
        if str(oc_report.get("overall_status") or "").strip().lower() == "error":
            return True
        missing = [str(x) for x in (oc_report.get("missing") or []) if x]
        if missing:
            return True
        artifact_report = oc_report.get("artifact_requirements_report")
        if isinstance(artifact_report, dict):
            if str(artifact_report.get("status") or "").strip().lower() == "error":
                return True

    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    artifact_reqs = contract.get("artifact_requirements") if isinstance(contract.get("artifact_requirements"), dict) else {}
    visual_reqs = artifact_reqs.get("visual_requirements") if isinstance(artifact_reqs.get("visual_requirements"), dict) else {}
    if visual_reqs.get("required") and bool(state.get("visuals_missing")):
        return True

    signals: List[str] = []
    signals.extend([str(x) for x in (gate_context.get("failed_gates") or []) if x])
    signals.extend([str(x) for x in (gate_context.get("required_fixes") or []) if x])
    signals.extend([str(x) for x in hard_failures if x])
    signals.extend([str(x) for x in (board_failed_areas or []) if x])
    signals.extend([str(x) for x in (board_required_actions or []) if x])
    for key in ("feedback", "source"):
        value = gate_context.get(key)
        if value:
            signals.append(str(value))

    return any(_looks_blocking_retry_signal(signal) for signal in signals)

def _normalize_qa_gate_specs(raw_gates: Any) -> List[Dict[str, Any]]:
    if not isinstance(raw_gates, list):
        return []
    normalized: List[Dict[str, Any]] = []
    seen: set[str] = set()
    for gate in raw_gates:
        if isinstance(gate, dict):
            name = gate.get("name") or gate.get("id") or gate.get("gate")
            if not name:
                continue
            severity = gate.get("severity")
            required = gate.get("required")
            if severity is None and required is not None:
                severity = "HARD" if bool(required) else "SOFT"
            severity = str(severity).upper() if severity else "HARD"
            if severity not in {"HARD", "SOFT"}:
                severity = "HARD"
            params = gate.get("params")
            if not isinstance(params, dict):
                params = {}
            key = str(name).lower()
            if key in seen:
                continue
            seen.add(key)
            normalized.append({"name": str(name), "severity": severity, "params": params})
        elif isinstance(gate, str):
            key = gate.strip().lower()
            if not key or key in seen:
                continue
            seen.add(key)
            normalized.append({"name": gate.strip(), "severity": "HARD", "params": {}})
    return normalized

def _merge_qa_gate_specs(*gate_lists: Any) -> List[Dict[str, Any]]:
    merged: List[Dict[str, Any]] = []
    seen: set[str] = set()
    for gates in gate_lists:
        for gate in _normalize_qa_gate_specs(gates):
            name = gate.get("name")
            if not name:
                continue
            key = str(name).lower()
            if key in seen:
                continue
            seen.add(key)
            merged.append(gate)
    return merged


def _normalize_review_gate_phase(raw: Any) -> str:
    token = str(raw or "").strip().lower()
    if not token:
        return "baseline"
    token = token.replace("-", "_").replace(" ", "_")
    if token in {
        "metric",
        "metric_round",
        "metric_improvement",
        "optimization",
        "optimize",
        "candidate_review",
        "improvement",
    }:
        return "metric_round"
    return "baseline"


def _build_phase_scoped_contract(contract: Dict[str, Any] | None, phase: Any) -> Dict[str, Any]:
    contract = contract if isinstance(contract, dict) else {}
    normalized_phase = _normalize_review_gate_phase(phase)
    if normalized_phase != "metric_round":
        return contract

    scoped = copy.deepcopy(contract)
    scoped["qa_gates"] = get_qa_gates_for_phase(contract, normalized_phase)
    scoped["reviewer_gates"] = get_reviewer_gates_for_phase(contract, normalized_phase)
    evaluation_spec = scoped.get("evaluation_spec")
    if isinstance(evaluation_spec, dict):
        scoped_eval = copy.deepcopy(evaluation_spec)
        if "qa_gates" in scoped_eval:
            scoped_eval["qa_gates"] = filter_gate_list_for_phase(
                scoped_eval.get("qa_gates"),
                normalized_phase,
                actor="qa",
            )
        if "gates" in scoped_eval:
            scoped_eval["gates"] = filter_gate_list_for_phase(
                scoped_eval.get("gates"),
                normalized_phase,
                actor="qa",
            )
        if "reviewer_gates" in scoped_eval:
            scoped_eval["reviewer_gates"] = filter_gate_list_for_phase(
                scoped_eval.get("reviewer_gates"),
                normalized_phase,
                actor="reviewer",
            )
        scoped["evaluation_spec"] = scoped_eval
    return scoped


def _build_phase_scoped_evaluation_spec(evaluation_spec: Dict[str, Any] | None, phase: Any) -> Dict[str, Any]:
    scoped = copy.deepcopy(evaluation_spec) if isinstance(evaluation_spec, dict) else {}
    normalized_phase = _normalize_review_gate_phase(phase)
    if normalized_phase != "metric_round" or not scoped:
        return scoped
    if "qa_gates" in scoped:
        scoped["qa_gates"] = filter_gate_list_for_phase(scoped.get("qa_gates"), normalized_phase, actor="qa")
    if "gates" in scoped:
        scoped["gates"] = filter_gate_list_for_phase(scoped.get("gates"), normalized_phase, actor="qa")
    if "reviewer_gates" in scoped:
        scoped["reviewer_gates"] = filter_gate_list_for_phase(
            scoped.get("reviewer_gates"),
            normalized_phase,
            actor="reviewer",
        )
    return scoped

def _evaluate_column_presence_gates(
    qa_gates: List[Dict[str, Any]],
    work_dir: str = ".",
) -> Dict[str, Any]:
    failed_gates: List[str] = []
    hard_failures: List[str] = []
    required_fixes: List[str] = []
    messages: List[str] = []

    if not qa_gates:
        return {
            "failed_gates": failed_gates,
            "hard_failures": hard_failures,
            "required_fixes": required_fixes,
            "messages": messages,
        }

    dialect = get_csv_dialect(work_dir)
    sep = dialect.get("sep", ",") if isinstance(dialect, dict) else ","
    encoding = dialect.get("encoding", "utf-8") if isinstance(dialect, dict) else "utf-8"

    for gate in qa_gates:
        if not isinstance(gate, dict):
            continue
        params = gate.get("params")
        if not isinstance(params, dict):
            continue
        target_file = params.get("target_file") or params.get("target_path") or params.get("file")
        column = params.get("column") or params.get("required_column")
        if not target_file or not column:
            continue
        gate_name = gate.get("name") or gate.get("id") or gate.get("gate")
        if not gate_name:
            continue
        severity = str(gate.get("severity") or "HARD").upper()

        path = target_file
        if work_dir and not os.path.isabs(path):
            path = os.path.join(work_dir, target_file)

        header: List[str] = []
        missing_reason = None
        if not os.path.exists(path):
            missing_reason = f"target_file_not_found={target_file}"
        else:
            try:
                with open(path, "r", encoding=encoding, errors="replace", newline="") as handle:
                    reader = csv.reader(handle, delimiter=sep)
                    header = next(reader, [])
            except Exception as err:
                missing_reason = f"header_read_error={err}"

        if missing_reason:
            msg = f"QA_GATE_{'FAIL' if severity == 'HARD' else 'WARN'}[{gate_name}]: {missing_reason}"
            messages.append(msg)
            if severity == "HARD":
                failed_gates.append(str(gate_name))
                hard_failures.append(str(gate_name))
                required_fixes.append(
                    f"Ensure {target_file} exists and includes column '{column}'."
                )
            continue

        if column not in header:
            msg = f"QA_GATE_FAIL[{gate_name}]: missing column '{column}' in {target_file}"
            messages.append(msg)
            if severity == "HARD":
                failed_gates.append(str(gate_name))
                hard_failures.append(str(gate_name))
            required_fixes.append(
                f"Add column '{column}' to {target_file} as required by QA gate {gate_name}."
            )

    return {
        "failed_gates": failed_gates,
        "hard_failures": hard_failures,
        "required_fixes": required_fixes,
        "messages": messages,
    }

def _normalize_allowed_feature_sets(feature_sets: Any) -> Any:
    """Normalize allowed_feature_sets for consistent comparison.

    If dict: sort each list value and return normalized dict.
    If list: sort and return.
    Otherwise: return as-is.
    """
    if isinstance(feature_sets, dict):
        normalized = {}
        for key, val in feature_sets.items():
            if isinstance(val, list):
                normalized[key] = sorted(val)
            else:
                normalized[key] = val
        return normalized
    elif isinstance(feature_sets, list):
        if all(isinstance(item, str) for item in feature_sets):
            return sorted(feature_sets)
        try:
            return sorted(feature_sets)
        except TypeError:
            return feature_sets
    return feature_sets

def _derive_forbidden_from_allowed(allowed_feature_sets: Any, explicit_forbidden: List[str]) -> List[str]:
    """Derive forbidden features from allowed_feature_sets if explicit list is empty.

    If allowed_feature_sets is a dict with 'forbidden' key, use that.
    Otherwise return explicit_forbidden.
    """
    if explicit_forbidden:
        return sorted(explicit_forbidden)
    if isinstance(allowed_feature_sets, dict):
        forbidden = allowed_feature_sets.get("forbidden", [])
        if isinstance(forbidden, list):
            return sorted(forbidden)
    return []

def _capture_strategy_snapshot(state: Dict[str, Any]) -> Dict[str, Any]:
    """Capture snapshot of strategy and contract for drift detection."""
    strategy = state.get("selected_strategy") or {}
    contract = state.get("execution_contract") or {}

    # Use contract_version with fallback to version
    contract_version = contract.get("contract_version") or contract.get("version")

    # Normalize allowed_feature_sets (handles both dict and list formats)
    raw_allowed = contract.get("allowed_feature_sets", []) or []
    allowed_normalized = _normalize_allowed_feature_sets(raw_allowed)

    # Derive forbidden_features from allowed_feature_sets if not explicitly set
    raw_forbidden = contract.get("forbidden_features", []) or []
    forbidden_normalized = _derive_forbidden_from_allowed(raw_allowed, raw_forbidden)

    return {
        "strategy_title": strategy.get("title"),
        "strategy_id": strategy.get("id") or strategy.get("strategy_id"),
        "contract_version": contract_version,
        "canonical_columns": sorted(contract.get("canonical_columns", []) or []),
        "decision_columns": sorted(contract.get("decision_columns", []) or []),
        "outcome_columns": sorted(contract.get("outcome_columns", []) or []),
        "allowed_feature_sets": allowed_normalized,
        "forbidden_features": forbidden_normalized,
    }

def _validate_strategy_lock(state: Dict[str, Any]) -> tuple[bool, Dict[str, Any]]:
    """
    Validate that strategy/contract has not drifted from initial snapshot.
    Returns (ok, details) where ok=True means no drift detected.
    """
    snapshot = state.get("strategy_lock_snapshot")
    if not snapshot:
        # No snapshot to compare - first iteration, capture it
        return True, {"reason": "no_snapshot_yet"}

    current = _capture_strategy_snapshot(state)
    drifts: List[str] = []

    # Compare key fields
    if snapshot.get("strategy_title") and current.get("strategy_title"):
        if snapshot["strategy_title"] != current["strategy_title"]:
            drifts.append(f"strategy_title: {snapshot['strategy_title']} -> {current['strategy_title']}")

    if snapshot.get("strategy_id") and current.get("strategy_id"):
        if snapshot["strategy_id"] != current["strategy_id"]:
            drifts.append(f"strategy_id: {snapshot['strategy_id']} -> {current['strategy_id']}")

    if snapshot.get("contract_version") and current.get("contract_version"):
        if snapshot["contract_version"] != current["contract_version"]:
            drifts.append(f"contract_version: {snapshot['contract_version']} -> {current['contract_version']}")

    if snapshot.get("canonical_columns") and current.get("canonical_columns"):
        if snapshot["canonical_columns"] != current["canonical_columns"]:
            added = set(current["canonical_columns"]) - set(snapshot["canonical_columns"])
            removed = set(snapshot["canonical_columns"]) - set(current["canonical_columns"])
            if added or removed:
                drifts.append(f"canonical_columns changed: +{list(added)}, -{list(removed)}")

    if snapshot.get("decision_columns") and current.get("decision_columns"):
        if snapshot["decision_columns"] != current["decision_columns"]:
            drifts.append(f"decision_columns changed")

    if snapshot.get("outcome_columns") and current.get("outcome_columns"):
        if snapshot["outcome_columns"] != current["outcome_columns"]:
            drifts.append(f"outcome_columns changed")

    # Compare allowed_feature_sets (normalized - can be dict or list)
    snap_allowed = snapshot.get("allowed_feature_sets")
    curr_allowed = current.get("allowed_feature_sets")
    if snap_allowed and curr_allowed:
        if snap_allowed != curr_allowed:
            drifts.append(f"allowed_feature_sets changed")

    if snapshot.get("forbidden_features") and current.get("forbidden_features"):
        if snapshot["forbidden_features"] != current["forbidden_features"]:
            drifts.append(f"forbidden_features changed")

    if drifts:
        return False, {"drifts": drifts, "snapshot": snapshot, "current": current}

    return True, {"reason": "no_drift"}

def _detect_refscore_alias(execution_output: str, contract: Dict[str, Any]) -> bool:
    """V4.1: Check derived_columns and column_roles for refscore pattern."""
    if not execution_output or not isinstance(contract, dict):
        return False
    derived_target = False

    # V4.1: Check derived_columns for refscore
    from src.utils.contract_accessors import get_derived_column_names, get_column_roles
    derived_cols = get_derived_column_names(contract)
    outcome_roles = get_column_roles(contract).get("outcome", [])

    for col in derived_cols:
        if "refscore" in str(col).lower() and col in outcome_roles:
            derived_target = True
            break

    if not derived_target:
        return False
    alias_patterns = [
        '"RefScore": "Score"',
        "'RefScore': 'Score'",
        "RefScore -> Score",
    ]
    return any(pat in execution_output for pat in alias_patterns)

DEFAULT_RUN_BUDGET = {
    "max_de_calls": 4,
    "max_ml_calls": 12,
    "max_reviewer_calls": 10,
    "max_qa_calls": 10,
    "max_execution_calls": 12,
}

def _ensure_budget_state(state: Dict[str, Any]) -> Dict[str, Any]:
    budget = dict(state.get("run_budget") or {})
    if not budget:
        budget = dict(DEFAULT_RUN_BUDGET)
    counters = dict(state.get("budget_counters") or {})
    for key in ["de_calls", "ml_calls", "reviewer_calls", "qa_calls", "execution_calls"]:
        counters.setdefault(key, 0)
    limit_map = {
        "de_calls": "max_de_calls",
        "ml_calls": "max_ml_calls",
        "reviewer_calls": "max_reviewer_calls",
        "qa_calls": "max_qa_calls",
        "execution_calls": "max_execution_calls",
    }
    for counter_key, limit_key in limit_map.items():
        limit = budget.get(limit_key, DEFAULT_RUN_BUDGET.get(limit_key))
        if limit is None:
            continue
        try:
            if counters.get(counter_key, 0) > int(limit):
                counters[counter_key] = int(limit)
        except Exception:
            continue
    return {"run_budget": budget, "budget_counters": counters}

def _consume_budget(state: Dict[str, Any], counter_key: str, limit_key: str, label: str):
    budget = state.get("run_budget") or DEFAULT_RUN_BUDGET
    counters = dict(state.get("budget_counters") or {})
    limit = budget.get(limit_key, DEFAULT_RUN_BUDGET.get(limit_key))
    used = counters.get(counter_key, 0)
    attempted = used + 1
    if limit is not None and attempted > limit:
        return False, counters, f"BUDGET_EXCEEDED: {label} exceeded {used}/{limit}"
    counters[counter_key] = attempted
    return True, counters, ""

def detect_undefined_names(code: str) -> List[str]:
    """
    AST-based preflight to detect names that are used but never defined/imported.
    Avoids wasting sandbox runs on obvious NameError.
    """
    import ast
    import builtins as _builtins

    try:
        tree = ast.parse(code)
    except Exception:
        return []

    defined: set[str] = set(dir(_builtins)) | {"__name__", "__file__", "__package__", "__spec__", "__doc__", "__cached__"}

    def add_target(target):
        if isinstance(target, ast.Name):
            defined.add(target.id)
        elif isinstance(target, (ast.Tuple, ast.List)):
            for elt in target.elts:
                add_target(elt)

    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            for alias in node.names:
                if alias.asname:
                    defined.add(alias.asname)
                else:
                    # top-level module name
                    defined.add(alias.name.split(".")[0])
        elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            defined.add(node.name)
            for arg in node.args.args + node.args.kwonlyargs:
                defined.add(arg.arg)
            if node.args.vararg:
                defined.add(node.args.vararg.arg)
            if node.args.kwarg:
                defined.add(node.args.kwarg.arg)
        elif isinstance(node, ast.ClassDef):
            defined.add(node.name)
        elif isinstance(node, ast.Lambda):
            for arg in node.args.args + node.args.kwonlyargs:
                defined.add(arg.arg)
            if node.args.vararg:
                defined.add(node.args.vararg.arg)
            if node.args.kwarg:
                defined.add(node.args.kwarg.arg)
        elif isinstance(node, (ast.Assign, ast.AnnAssign, ast.AugAssign)):
            add_target(node.target if hasattr(node, "target") else None)
            if hasattr(node, "targets"):
                for tgt in node.targets:
                    add_target(tgt)
        elif isinstance(node, (ast.For, ast.AsyncFor)):
            add_target(node.target)
        elif isinstance(node, ast.With):
            for item in node.items:
                if item.optional_vars:
                    add_target(item.optional_vars)
        elif isinstance(node, ast.comprehension):
            add_target(node.target)
        elif isinstance(node, ast.ExceptHandler) and node.name:
            defined.add(node.name)

    undefined: set[str] = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Name) and isinstance(node.ctx, ast.Load):
            if node.id not in defined:
                undefined.add(node.id)
    return sorted(undefined)

def manifest_dump_missing_default(code: str) -> bool:
    """
    Detects json.dump calls without default= to guard manifest serialization.
    Returns True if a risky call is found.
    """
    import ast
    if "_safe_dump_json" in code and "json.dump = _safe_dump_json" in code:
        return False
    try:
        tree = ast.parse(code)
    except Exception:
        return False
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            func = node.func
            is_json_dump = False
            if isinstance(func, ast.Attribute) and func.attr == "dump":
                if isinstance(func.value, ast.Name) and func.value.id == "json":
                    is_json_dump = True
            if isinstance(func, ast.Name) and func.id == "dump":
                is_json_dump = True
            if not is_json_dump:
                continue
            kw_args = {kw.arg for kw in node.keywords if kw.arg}
            if "default" not in kw_args:
                return True
    return False

def contains_json_null_literal(code: str) -> bool:
    """
    Detects use of JSON literal `null` in Python code (likely from copied JSON).
    """
    import io
    import tokenize
    try:
        tokens = tokenize.generate_tokens(io.StringIO(code).readline)
    except Exception:
        return False
    for tok in tokens:
        if tok.type == tokenize.NAME and tok.string == "null":
            return True
    return False

def _resolve_eval_flags(evaluation_spec: Dict[str, Any] | None) -> Dict[str, bool]:
    if not isinstance(evaluation_spec, dict) or not evaluation_spec:
        return {
            "requires_target": True,
            "requires_supervised_split": True,
            "requires_time_series_split": False,
            "requires_row_scoring": False,
        }
    objective_type = str(evaluation_spec.get("objective_type") or "").lower()
    requires_target = None
    requires_supervised_split = None
    requires_time_series_split = None
    requires_row_scoring = None
    if isinstance(evaluation_spec, dict):
        requires_target = evaluation_spec.get("requires_target")
        requires_supervised_split = evaluation_spec.get("requires_supervised_split")
        requires_time_series_split = evaluation_spec.get("requires_time_series_split")
        requires_row_scoring = evaluation_spec.get("requires_row_scoring")
    if requires_target is None:
        requires_target = objective_type in {"predictive", "prescriptive", "forecasting"}
    if requires_time_series_split is None:
        requires_time_series_split = objective_type == "forecasting"
    if requires_supervised_split is None:
        requires_supervised_split = bool(requires_target)
    if requires_row_scoring is None:
        requires_row_scoring = False
    return {
        "requires_target": bool(requires_target),
        "requires_supervised_split": bool(requires_supervised_split),
        "requires_time_series_split": bool(requires_time_series_split),
        "requires_row_scoring": bool(requires_row_scoring),
    }

def ml_quality_preflight(
    code: str,
    evaluation_spec: Dict[str, Any] | None = None,
    allowed_columns: List[str] | None = None,
    allowed_patterns: List[str] | None = None,
) -> List[str]:
    """
    Static ML quality checks to prevent QA loops before reviewer/sandbox.
    Returns list of missing gates.
    """
    import ast

    issues: List[str] = []
    code_lower = code.lower()
    if "mapping summary" not in code_lower:
        issues.append("MAPPING_SUMMARY")
    if "calibratedclassifiercv" in code_lower and (
        "feature_importances_" in code_lower or "base_estimator" in code_lower
    ):
        issues.append("CALIBRATED_IMPORTANCE_UNSUPPORTED")

    try:
        tree = ast.parse(code)
    except Exception:
        return ["AST_PARSE_FAILED"]

    def _condition_checks_nunique_guard(test_node: ast.AST) -> bool:
        if not isinstance(test_node, ast.Compare):
            return False
        left = test_node.left
        if not isinstance(left, ast.Call):
            return False
        func = left.func
        if not (isinstance(func, ast.Attribute) and func.attr == "nunique"):
            return False
        comparator_consts = [
            comp
            for comp in test_node.comparators
            if isinstance(comp, ast.Constant) and isinstance(comp.value, (int, float))
        ]
        if not comparator_consts:
            return False
        for op, comp in zip(test_node.ops, comparator_consts):
            if isinstance(op, ast.Eq) and comp.value == 1:
                return True
            if isinstance(op, ast.LtE) and comp.value <= 1:
                return True
            if isinstance(op, ast.Lt) and comp.value <= 2:
                return True
        return False

    def _if_has_value_error_raise(body_nodes) -> bool:
        for node in body_nodes:
            if isinstance(node, ast.Raise):
                exc = node.exc
                if isinstance(exc, ast.Call) and isinstance(exc.func, ast.Name) and exc.func.id == "ValueError":
                    return True
            for child in ast.walk(node):
                if isinstance(child, ast.Raise):
                    exc = child.exc
                    if isinstance(exc, ast.Call) and isinstance(exc.func, ast.Name) and exc.func.id == "ValueError":
                        return True
        return False

    has_variance_guard = False
    for node in ast.walk(tree):
        if isinstance(node, ast.If):
            if _condition_checks_nunique_guard(node.test) and _if_has_value_error_raise(node.body):
                has_variance_guard = True
                break
    if not has_variance_guard:
        issues.append("TARGET_VARIANCE_GUARD")

    def _is_df_feature_cols_subscript(node: ast.AST) -> bool:
        if isinstance(node, ast.Subscript):
            if isinstance(node.value, ast.Name) and node.value.id == "df":
                sl = node.slice
                if isinstance(sl, ast.Name) and sl.id == "feature_cols":
                    return True
                if isinstance(sl, ast.Tuple) and len(sl.elts) >= 2:
                    return any(isinstance(e, ast.Name) and e.id == "feature_cols" for e in sl.elts)
            if isinstance(node.value, ast.Attribute):
                # df.loc[:, feature_cols]
                if isinstance(node.value.value, ast.Name) and node.value.value.id == "df" and node.value.attr == "loc":
                    sl = node.slice
                    if isinstance(sl, ast.Tuple) and len(sl.elts) >= 2:
                        return any(isinstance(e, ast.Name) and e.id == "feature_cols" for e in sl.elts)
        return False

    def _drop_excludes_target(call: ast.Call, target_names: set[str]) -> bool:
        if not isinstance(call.func, ast.Attribute):
            return False
        if call.func.attr != "drop":
            return False
        if not isinstance(call.func.value, ast.Name) or call.func.value.id != "df":
            return False
        targets = set(target_names) | {"target", "y", "target_col"}
        # keywords
        for kw in call.keywords:
            if kw.arg != "columns":
                continue
            if isinstance(kw.value, ast.List):
                for elt in kw.value.elts:
                    if isinstance(elt, ast.Name) and elt.id in targets:
                        return True
                    if isinstance(elt, ast.Constant) and isinstance(elt.value, str) and elt.value.lower() in targets:
                        return True
        # positional args
        for arg in call.args:
            if isinstance(arg, ast.List):
                for elt in arg.elts:
                    if isinstance(elt, ast.Name) and elt.id in targets:
                        return True
                    if isinstance(elt, ast.Constant) and isinstance(elt.value, str) and elt.value.lower() in targets:
                        return True
        return False

    target_names: set[str] = set()
    has_target_assignment = False
    has_x_from_feature_cols = False
    has_drop_target = False
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            # target assignment
            for tgt in node.targets:
                if isinstance(tgt, ast.Name) and tgt.id in {"y", "target", "y_train", "target_series"}:
                    has_target_assignment = True
                    target_names.add(tgt.id)
            # X assignment
            if any(isinstance(t, ast.Name) and t.id in {"X", "x"} for t in node.targets):
                if _is_df_feature_cols_subscript(node.value):
                    has_x_from_feature_cols = True
                if isinstance(node.value, ast.Call) and _drop_excludes_target(node.value, target_names):
                    has_drop_target = True
        elif isinstance(node, ast.Call):
            if _drop_excludes_target(node, target_names):
                has_drop_target = True

    has_target_exclusion = has_target_assignment and (has_x_from_feature_cols or has_drop_target)
    if not has_target_exclusion:
        issues.append("TARGET_NOT_IN_X")

    has_high_card_filter = False
    for node in ast.walk(tree):
        if isinstance(node, ast.Compare):
            left = node.left
            comps = [left] + list(node.comparators)
            if any(isinstance(op, (ast.Gt, ast.GtE)) for op in node.ops):
                for comp in comps:
                    if isinstance(comp, ast.Call):
                        func = comp.func
                        if isinstance(func, ast.Attribute) and func.attr == "nunique":
                            has_high_card_filter = True
                            break
        if has_high_card_filter:
            break

    if not (has_x_from_feature_cols or has_high_card_filter):
        issues.append("HIGH_CARDINALITY_HANDLING")

    cv_markers = [
        "cross_val_score",
        "cross_validate",
        "kfold",
        "stratifiedkfold",
        "groupkfold",
        "timeseriessplit",
        "stratifiedgroupkfold",
    ]
    if "train_test_split" in code_lower and not any(marker in code_lower for marker in cv_markers):
        issues.append("CROSS_VALIDATION_REQUIRED")

    flags = _resolve_eval_flags(evaluation_spec)
    if not flags["requires_target"]:
        issues = [
            issue
            for issue in issues
            if issue not in {"TARGET_NOT_IN_X", "TARGET_VARIANCE_GUARD", "CROSS_VALIDATION_REQUIRED", "TIME_SERIES_SPLIT_REQUIRED"}
        ]
    if not flags["requires_supervised_split"]:
        issues = [
            issue
            for issue in issues
            if issue not in {"CROSS_VALIDATION_REQUIRED", "TIME_SERIES_SPLIT_REQUIRED"}
        ]
    if flags["requires_time_series_split"]:
        has_time_series_split = (
            "timeseriessplit" in code_lower
            or ("train_test_split" in code_lower and "shuffle=false" in code_lower)
            or "rolling" in code_lower
            or "expanding" in code_lower
        )
        if not has_time_series_split:
            issues.append("TIME_SERIES_SPLIT_REQUIRED")
        issues = [issue for issue in issues if issue != "CROSS_VALIDATION_REQUIRED"]

    def _has_symbol(names: set[str]) -> bool:
        for node in ast.walk(tree):
            if isinstance(node, ast.Name) and node.id in names:
                return True
            if isinstance(node, ast.Attribute) and node.attr in names:
                return True
        return False

    def _scored_rows_has_delta() -> bool:
        for node in ast.walk(tree):
            if not isinstance(node, ast.Subscript):
                continue
            target = node.value
            if isinstance(target, ast.Name):
                name = target.id
            elif isinstance(target, ast.Attribute):
                name = target.attr
            else:
                name = None
            if name not in {"scored_rows", "scored_df", "scores_df"}:
                continue
            slice_node = node.slice
            if isinstance(slice_node, ast.Constant) and isinstance(slice_node.value, str):
                if "delta" in slice_node.value.lower():
                    return True
        return False

    baseline_required = True
    if flags["requires_target"] and baseline_required:
        if not _has_symbol({"DummyClassifier", "DummyRegressor"}):
            issues.append("BASELINE_REQUIRED")

    if flags["requires_target"] or flags["requires_supervised_split"]:
        # Enhanced NaN hygiene check: Detect sklearn models without imputation
        has_imputer = _has_symbol({"SimpleImputer", "KNNImputer", "IterativeImputer"})
        has_nan_robust_model = _has_symbol({"HistGradientBoostingClassifier", "HistGradientBoostingRegressor"})
        has_dropna = ".dropna(" in code

        # If using models that DON'T handle NaN natively and NO imputation/dropna found
        if not (has_imputer or has_nan_robust_model or has_dropna):
            issues.append("IMPUTER_REQUIRED")

    # CRITICAL: Check for dialect loading from the declared cleaning manifest
    # ML Engineer MUST read output_dialect before loading data
    has_load_dialect_function = "def load_dialect" in code
    has_manifest_read = (
        any(token in code_lower for token in ["cleaning_manifest", "manifest_path", "output_manifest"])
        and ("json.load" in code or "pd.read_json" in code)
    )
    has_dialect_extraction = "output_dialect" in code and "manifest" in code_lower

    # Check if pd.read_csv is called with dialect parameters
    has_read_csv_with_dialect = False
    if "pd.read_csv" in code or "pandas.read_csv" in code:
        # Check if sep= and decimal= are used (not just hardcoded defaults)
        read_csv_calls = code.split("pd.read_csv")
        for call in read_csv_calls[1:]:  # Skip the first split (before first read_csv)
            # Look for sep= and decimal= in the next 200 characters
            snippet = call[:200]
            has_sep = "sep=" in snippet and "sep=sep" in snippet.replace(" ", "")
            has_decimal = "decimal=" in snippet and "decimal=decimal" in snippet.replace(" ", "")
            if has_sep or has_decimal:
                has_read_csv_with_dialect = True
                break

    # If data loading exists but no dialect loading, flag it
    if ("pd.read_csv" in code or "pandas.read_csv" in code):
        if not (has_load_dialect_function or (has_manifest_read and has_dialect_extraction) or has_read_csv_with_dialect):
            issues.append("DIALECT_LOADING_MISSING")

    if allowed_columns:
        unknown_cols = _detect_unknown_columns(code, allowed_columns, allowed_patterns)
        if unknown_cols:
            issues.append("UNKNOWN_COLUMNS_REFERENCED")
        forbidden_assignments = _detect_forbidden_df_assignments(code, allowed_columns, allowed_patterns)
        if forbidden_assignments:
            issues.append("DF_COLUMN_ASSIGNMENT_FORBIDDEN")

    if _detect_synthetic_data(code):
        issues.append("SYNTHETIC_DATA_DETECTED")
    if _detect_dataframe_literal_overwrite(code):
        issues.append("DATAFRAME_LITERAL_OVERWRITE")
    if _scored_rows_has_delta():
        issues.append("SCORED_ROWS_SCHEMA_VIOLATION")

    return issues

def _detect_synthetic_data(code: str) -> bool:
    import ast

    if not code:
        return False
    try:
        tree = ast.parse(code)
    except Exception:
        return False

    if _detect_dataframe_literal_overwrite(code):
        return True

    def _call_name(call_node: ast.Call) -> str:
        try:
            return ast.unparse(call_node.func)
        except Exception:
            if isinstance(call_node.func, ast.Name):
                return call_node.func.id
            if isinstance(call_node.func, ast.Attribute):
                return call_node.func.attr
        return ""

    def _is_random_call(call_node: ast.Call) -> bool:
        name = _call_name(call_node).lower()
        if name.startswith("np.random.") or name.startswith("numpy.random."):
            # Resampling indices for bootstrap/CV is NOT synthetic data generation.
            allowed_suffixes = (
                ".choice",
                ".randint",
                ".permutation",
                ".shuffle",
                ".default_rng",
                ".seed",
            )
            if any(name.endswith(suffix) for suffix in allowed_suffixes):
                return False
            return True
        if name.startswith("random.") or name == "random":
            return True
        return False

    def _is_faker_call(call_node: ast.Call) -> bool:
        name = _call_name(call_node).lower()
        return name.endswith("faker") or ".faker" in name

    def _is_sklearn_make_call(call_node: ast.Call) -> bool:
        name = _call_name(call_node).lower()
        make_names = {
            "make_classification",
            "make_regression",
            "make_blobs",
            "make_moons",
            "make_circles",
        }
        if any(name.endswith(item) for item in make_names):
            return True
        if "sklearn.datasets.make_" in name or ".datasets.make_" in name:
            return True
        return False

    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            if _is_random_call(node) or _is_faker_call(node) or _is_sklearn_make_call(node):
                return True
    return False

def _detect_dataframe_literal_overwrite(code: str) -> bool:
    import ast

    if not code:
        return False
    try:
        tree = ast.parse(code)
    except Exception:
        return False

    target_names = {"df", "data", "dataset", "cleaned_df", "scored_df"}

    def _is_dataframe_literal(node: ast.AST) -> bool:
        if not isinstance(node, ast.Call):
            return False
        func = node.func
        is_df = False
        if isinstance(func, ast.Attribute) and func.attr == "DataFrame":
            if isinstance(func.value, ast.Name) and func.value.id in {"pd", "pandas"}:
                is_df = True
        if isinstance(func, ast.Name) and func.id == "DataFrame":
            is_df = True
        if not is_df:
            return False
        if node.args:
            arg0 = node.args[0]
            if isinstance(arg0, (ast.Dict, ast.List, ast.Tuple)):
                return True
        for kw in node.keywords:
            if kw.arg == "data" and isinstance(kw.value, (ast.Dict, ast.List, ast.Tuple)):
                return True
        return False

    for node in ast.walk(tree):
        if isinstance(node, (ast.Assign, ast.AnnAssign)):
            targets = node.targets if hasattr(node, "targets") else [node.target]
            for tgt in targets:
                if isinstance(tgt, ast.Name) and tgt.id in target_names:
                    if _is_dataframe_literal(node.value):
                        return True
    return False

def _extract_named_string_list(code: str, names: List[str]) -> List[str]:
    import ast

    if not code or not names:
        return []
    try:
        tree = ast.parse(code)
    except Exception:
        return []
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            if not any(isinstance(t, ast.Name) and t.id in names for t in node.targets):
                continue
            if isinstance(node.value, ast.List):
                values: List[str] = []
                for elt in node.value.elts:
                    if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                        values.append(elt.value)
                return values
    return []

def _extract_column_references(code: str) -> List[str]:
    import ast

    if not code:
        return []
    try:
        tree = ast.parse(code)
    except Exception:
        return []

    list_vars: Dict[str, List[str]] = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign) and len(node.targets) == 1:
            target = node.targets[0]
            if not isinstance(target, ast.Name):
                continue
            if isinstance(node.value, (ast.List, ast.Tuple)):
                values: List[str] = []
                for elt in node.value.elts:
                    if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                        values.append(elt.value)
                if values:
                    list_vars[target.id] = values

    refs: set[str] = set()

    def _collect_from_slice(slice_node: ast.AST) -> None:
        if isinstance(slice_node, ast.Constant) and isinstance(slice_node.value, str):
            refs.add(slice_node.value)
            return
        if isinstance(slice_node, ast.Name) and slice_node.id in list_vars:
            refs.update(list_vars[slice_node.id])
            return
        if isinstance(slice_node, (ast.List, ast.Tuple)):
            for elt in slice_node.elts:
                if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                    refs.add(elt.value)
                elif isinstance(elt, ast.Name) and elt.id in list_vars:
                    refs.update(list_vars[elt.id])

    for node in ast.walk(tree):
        if not isinstance(node, ast.Subscript):
            continue
        target = node.value
        if isinstance(target, ast.Attribute) and target.attr == "loc":
            if not (isinstance(target.value, ast.Name) and target.value.id == "df"):
                continue
            slice_node = node.slice
            if isinstance(slice_node, ast.Tuple) and len(slice_node.elts) >= 2:
                _collect_from_slice(slice_node.elts[1])
            continue
        if isinstance(target, ast.Attribute) and target.attr == "iloc":
            continue
        if isinstance(target, ast.Name) and target.id == "df":
            _collect_from_slice(node.slice)

    return sorted(refs)

def _detect_unknown_columns(
    code: str,
    allowed_columns: List[str],
    allowed_patterns: List[str] | None = None,
) -> List[str]:
    if not code or not allowed_columns:
        return []
    import re

    allowed_pattern_list = [str(pat) for pat in (allowed_patterns or []) if isinstance(pat, str) and pat.strip()]

    def _pattern_name(name: str) -> str:
        return re.sub(r"[^0-9a-zA-Z]+", "_", str(name).lower()).strip("_")

    allowed_norm = {_norm_name(col) for col in allowed_columns if col}
    refs = _extract_column_references(code)
    unknown: set[str] = set()
    for col in refs:
        if not col:
            continue
        norm = _norm_name(col)
        if norm in allowed_norm:
            continue
        if allowed_pattern_list:
            target = _pattern_name(col)
            matched = False
            for pattern in allowed_pattern_list:
                try:
                    if re.search(pattern, target):
                        matched = True
                        break
                except re.error:
                    continue
            if matched:
                continue
        unknown.add(col)
    return sorted(unknown)

def _detect_forbidden_df_assignments(
    code: str,
    allowed_columns: List[str],
    allowed_patterns: List[str] | None = None,
) -> List[str]:
    if not code or not allowed_columns:
        return []
    import ast

    try:
        tree = ast.parse(code)
    except Exception:
        return []

    allowed_norm = {_norm_name(col) for col in allowed_columns if col}
    list_vars: Dict[str, List[str]] = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign) and len(node.targets) == 1:
            target = node.targets[0]
            if not isinstance(target, ast.Name):
                continue
            if isinstance(node.value, (ast.List, ast.Tuple)):
                values: List[str] = []
                for elt in node.value.elts:
                    if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                        values.append(elt.value)
                if values:
                    list_vars[target.id] = values

    def _collect_from_slice(slice_node: ast.AST) -> List[str]:
        cols: List[str] = []
        if isinstance(slice_node, ast.Constant) and isinstance(slice_node.value, str):
            cols.append(slice_node.value)
            return cols
        if isinstance(slice_node, ast.Name) and slice_node.id in list_vars:
            cols.extend(list_vars[slice_node.id])
            return cols
        if isinstance(slice_node, (ast.List, ast.Tuple)):
            for elt in slice_node.elts:
                if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                    cols.append(elt.value)
                elif isinstance(elt, ast.Name) and elt.id in list_vars:
                    cols.extend(list_vars[elt.id])
        return cols

    assigned_cols: set[str] = set()

    for node in ast.walk(tree):
        if isinstance(node, (ast.Assign, ast.AnnAssign, ast.AugAssign)):
            targets = node.targets if isinstance(node, ast.Assign) else [node.target]
            for tgt in targets:
                if not isinstance(tgt, ast.Subscript):
                    continue
                target = tgt.value
                if isinstance(target, ast.Name) and target.id == "df":
                    assigned_cols.update(_collect_from_slice(tgt.slice))
                elif isinstance(target, ast.Attribute) and target.attr == "loc":
                    if isinstance(target.value, ast.Name) and target.value.id == "df":
                        slice_node = tgt.slice
                        if isinstance(slice_node, ast.Tuple) and len(slice_node.elts) >= 2:
                            assigned_cols.update(_collect_from_slice(slice_node.elts[1]))
        elif isinstance(node, ast.Call):
            func = node.func
            if isinstance(func, ast.Attribute) and func.attr == "assign":
                if isinstance(func.value, ast.Name) and func.value.id == "df":
                    for kw in node.keywords:
                        if kw.arg:
                            assigned_cols.add(kw.arg)

    forbidden: set[str] = set()
    for col in assigned_cols:
        if not col:
            continue
        norm = _norm_name(col)
        if norm in allowed_norm:
            continue
        forbidden.add(col)

    return sorted(forbidden)

def dialect_guard_violations(code: str, csv_sep: str, csv_decimal: str, csv_encoding: str, expected_path: str | None = None) -> List[str]:
    """
    AST-based guard to ensure pd.read_csv (first call or the one reading expected_path) sets sep/decimal/encoding.
    Only rejects when keywords are missing or literal strings mismatch the provided dialect.

    Special handling for **kwargs:
    - If the call has **kwargs (keyword with arg=None), missing params do NOT generate violations
      (because **kwargs might supply them at runtime).
    - Literal mismatches still generate violations even with **kwargs present.
    """
    import ast

    violations: List[str] = []
    try:
        tree = ast.parse(code)
    except Exception as parse_err:
        return [f"Could not parse code for dialect guard: {parse_err}"]

    calls: List[ast.Call] = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            func = node.func
            if isinstance(func, ast.Attribute) and func.attr == "read_csv":
                if isinstance(func.value, ast.Name) and func.value.id == "pd":
                    calls.append(node)
            elif isinstance(func, ast.Name) and func.id == "read_csv":
                calls.append(node)

    if not calls:
        return violations

    def _is_expected_path(arg: ast.AST) -> bool:
        if expected_path is None:
            return False
        if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
            return arg.value == expected_path
        return False

    target_call = None
    for call in calls:
        if call.args and _is_expected_path(call.args[0]):
            target_call = call
            break
    if target_call is None:
        target_call = calls[0]

    # Check for **kwargs (keyword with arg=None)
    has_kwargs = any(kw.arg is None for kw in target_call.keywords)

    expected = {
        "sep": csv_sep,
        "decimal": csv_decimal,
        "encoding": csv_encoding,
    }
    raw_kw_map = {kw.arg: kw.value for kw in target_call.keywords if kw.arg}
    kw_map = dict(raw_kw_map)
    if "sep" not in kw_map and "delimiter" in raw_kw_map:
        kw_map["sep"] = raw_kw_map["delimiter"]

    def _normalize_encoding(value: str) -> str:
        return str(value).strip().lower().replace("_", "-")

    def _encoding_matches(expected_value: str, actual_value: str) -> bool:
        exp = _normalize_encoding(expected_value)
        act = _normalize_encoding(actual_value)
        if exp in {"utf-8", "utf8"}:
            return act in {"utf-8", "utf8", "utf-8-sig", "utf8-sig"}
        if exp in {"utf-8-sig", "utf8-sig"}:
            return act in {"utf-8", "utf8", "utf-8-sig", "utf8-sig"}
        return exp == act

    for param, expected_value in expected.items():
        if param not in kw_map:
            # Parameter missing - only violation if no **kwargs to potentially supply it
            if not has_kwargs:
                violations.append(f"pd.read_csv missing {param}= for dialect")
            continue
        val_node = kw_map[param]
        if isinstance(val_node, ast.Constant) and isinstance(val_node.value, str):
            if param == "encoding":
                if not _encoding_matches(expected_value, val_node.value):
                    violations.append(
                        f"pd.read_csv {param} literal '{val_node.value}' does not match expected '{expected_value}'"
                    )
                continue
            if val_node.value != expected_value:
                violations.append(f"pd.read_csv {param} literal '{val_node.value}' does not match expected '{expected_value}'")
        else:
            # Non-literal (variable/expression) accepted
            continue

    seen = set()
    unique = []
    for v in violations:
        if v not in seen:
            seen.add(v)
            unique.append(v)
    return unique

def _infer_de_failure_cause(text: str) -> str:
    if not text:
        return ""
    lower = text.lower()
    if "cannot convert the series to <class 'int'>" in lower or "cannot convert the series to <class 'float'>" in lower:
        return "Attempted int()/float() cast on a pandas Series; compute scalar first (e.g., mask.sum())."
    if "missing required columns" in lower or "mapping failed" in lower:
        return "Required columns not found after canonicalization or alias mapping."
    if "cleaning_plan_not_allowed" in lower or "plan output" in lower:
        return "Model returned a JSON plan instead of executable Python code."
    if "dialect" in lower or "read_csv" in lower:
        return "CSV dialect mismatch (sep/decimal/encoding) or missing dialect params."
    if "parsererror" in lower or "tokenizing data" in lower:
        return "CSV dialect/quoting mismatch; enforce detected sep/decimal/encoding."
    if "nameerror" in lower:
        return "Undefined name referenced in the generated code."
    if "keyerror" in lower and "not in index" in lower:
        return "Column name mismatch after normalization; mapping resolution failed."
    if "list of cases must be same length as list of conditions" in lower:
        return "np.select called with mismatched conditions/choices list lengths."
    if "typeerror" in lower or "ufunc" in lower:
        return "Type conversion missing; numeric ops executed on string/object data."
    if "invalid error value specified" in lower and "to_numeric" in lower:
        return "Invalid pd.to_numeric(errors=...) argument used; only supported values are accepted by current pandas runtime."
    if "cleaning_gate_failed" in lower and ("not converted to float" in lower or "not converted to int" in lower):
        return (
            "Type-cast gate validation is too strict/order-dependent. Cast explicitly to the requested dtype "
            "for the full selector set before validating and before any drop/selection steps."
        )
    if "numpy.bool_" in lower and "not serializable" in lower:
        return "JSON serialization failed due to numpy.bool_ values not handled in _json_default."
    if "json" in lower and "default" in lower:
        return "Manifest json.dump missing default for numpy/pandas types."
    if "syntaxerror" in lower:
        return "Generated code is not valid Python syntax."
    return ""


def _is_python_syntax_error(text: str) -> bool:
    lower = str(text or "").lower()
    markers = (
        "syntaxerror",
        "invalid syntax",
        "unterminated string literal",
        "unterminated triple-quoted string",
        "unexpected eof while parsing",
        "eol while scanning string literal",
        "indentationerror",
        "taberror",
    )
    return any(marker in lower for marker in markers)


def _is_likely_python_statement(line: str) -> bool:
    stripped = str(line or "").strip()
    if not stripped:
        return False
    pattern = re.compile(
        r"^(from\s+\w+|import\s+\w+|def\s+\w+|class\s+\w+|if\s+|for\s+|while\s+|try:|"
        r"except\b|finally:|with\s+|return\b|raise\b|pass\b|break\b|continue\b|@\w+|"
        r"[A-Za-z_]\w*\s*=)"
    )
    if pattern.match(stripped):
        return True
    if stripped.startswith(("(", "[", "{")):
        return True
    return False


def _attempt_de_local_syntax_repair(code: str, error_details: str) -> tuple[str, List[str]]:
    """
    Local, deterministic syntax repair for DE scripts.
    Goal: recover from non-Python preambles/fences without spending an extra LLM call.
    """
    text = str(code or "")
    if not text or not _is_python_syntax_error(error_details):
        return text, []

    lines = text.splitlines()
    notes: List[str] = []
    changed = False

    # Strip/neutralize markdown fence lines if present.
    for idx, raw_line in enumerate(lines):
        if re.match(r"^\s*```", raw_line or ""):
            lines[idx] = ""
            changed = True
            if "removed_markdown_fence_lines" not in notes:
                notes.append("removed_markdown_fence_lines")

    for _ in range(32):
        candidate = "\n".join(lines)
        try:
            ast.parse(candidate)
            return candidate, notes
        except SyntaxError as exc:
            line_no = int(getattr(exc, "lineno", 0) or 0)
            if line_no <= 0 or line_no > len(lines):
                break
            current = lines[line_no - 1]
            stripped = str(current or "").strip()
            if not stripped:
                lines[line_no - 1] = "#"
                changed = True
                notes.append(f"commented_blank_line_{line_no}")
                continue
            if stripped.startswith("#"):
                break
            if stripped.startswith(("- ", "* ")):
                lines[line_no - 1] = re.sub(r"^(\s*)", r"\1# ", current, count=1)
                changed = True
                notes.append(f"commented_bullet_line_{line_no}")
                continue
            if not _is_likely_python_statement(stripped):
                lines[line_no - 1] = re.sub(r"^(\s*)", r"\1# ", current, count=1)
                changed = True
                notes.append(f"commented_prose_line_{line_no}")
                continue
            break

    if changed:
        candidate = "\n".join(lines)
        try:
            ast.parse(candidate)
            return candidate, notes
        except Exception:
            pass
    return text, notes

def _build_de_runtime_diagnosis(error_details: str) -> List[str]:
    if not error_details:
        return []
    lower = error_details.lower()
    lines: List[str] = []
    if "cannot convert the series to <class 'int'>" in lower or "cannot convert the series to <class 'float'>" in lower:
        lines.append(
            "You are calling int()/float() on a pandas Series. For boolean masks use int(mask.sum())."
        )
        lines.append(
            "Avoid int(...).sum(); it casts before summing. Correct: int((...).sum())."
        )
    if "list of cases must be same length as list of conditions" in lower:
        lines.append(
            "np.select raised a length mismatch: number of conditions does not match number of choices (see assign_fec_window)."
        )
    if "numpy.bool_" in lower and "not serializable" in lower:
        lines.append(
            "json.dumps failed because validation_results contains numpy.bool_, which _json_default does not handle."
        )
    if "keyerror" in lower and "not in index" in lower:
        lines.append(
            "KeyError indicates a column name mismatch after renaming/normalization; selection list includes a missing column."
        )
    if "not supported between instances of 'str' and 'int'" in lower or "not supported between instances of 'str' and 'float'" in lower:
        lines.append(
            "Type comparison on object/string data: convert %plazoConsumido (or any percentage string) to numeric before >/< checks; use pd.to_numeric/clean_plazo_consumido and compare the numeric series."
        )
    if "invalid error value specified" in lower and "to_numeric" in lower:
        lines.append(
            "pd.to_numeric received an unsupported errors= value for this pandas runtime; use a valid option and handle exceptions explicitly."
        )
    if "cleaning_gate_failed" in lower and ("not converted to float" in lower or "not converted to int" in lower):
        lines.append(
            "For *_type_cast gates, cast full selector/column sets explicitly (e.g., astype(float)/astype('Int64')) before gate assertions."
        )
        lines.append(
            "Validate conversion over all required columns (or selector expansion), not only a single sampled column."
        )
    if "keyerror" in lower and "'score'" in lower:
        lines.append(
            "KeyError on 'Score' suggests conversion metadata was updated before creating a 'Score' entry or the column mapping for Score did not run."
        )
    return lines


def _tail_lines(text: str, n: int = 20) -> str:
    if not isinstance(text, str) or not text.strip():
        return ""
    lines = [line for line in text.strip().splitlines() if line.strip()]
    if not lines:
        return ""
    return "\n".join(lines[-max(1, int(n)):])


def _build_de_gate_implementation_hints(cleaning_gates: Any) -> List[str]:
    if not isinstance(cleaning_gates, list) or not cleaning_gates:
        return []
    hints: List[str] = []
    for gate in cleaning_gates:
        if not isinstance(gate, dict):
            continue
        name = str(gate.get("name") or "").strip()
        params = gate.get("params") if isinstance(gate.get("params"), dict) else {}
        target_type = str(params.get("target_type") or "").strip().lower()
        if not target_type:
            continue
        ref = str(params.get("column") or params.get("selector") or "gate_scope")
        if target_type in {"float", "int", "integer", "numeric"}:
            hints.append(
                f"{name or 'type_cast_gate'} on {ref}: cast explicitly to {target_type} across the full scope before assertions."
            )
    seen = set()
    deduped: List[str] = []
    for hint in hints:
        if hint in seen:
            continue
        seen.add(hint)
        deduped.append(hint)
    return deduped[:10]


def _merge_de_audit_override(base: str, payload: str) -> str:
    base = base or ""
    payload = payload or ""
    if not payload:
        return base

    max_blocks = 12
    max_chars = 16000

    def _split_blocks(text: str) -> List[str]:
        chunks = re.split(r"\n\s*\n", str(text or "").strip())
        out: List[str] = []
        for raw in chunks:
            block = str(raw or "").strip()
            if block:
                out.append(block)
        return out

    def _block_key(block: str) -> str:
        first = ""
        for line in block.splitlines():
            token = str(line or "").strip()
            if token:
                first = token
                break
        if first:
            first = re.sub(r"\s+", " ", first).strip()
            if ":" in first:
                first = first.split(":", 1)[0].strip()
            normalized = re.sub(r"[^a-zA-Z0-9_]+", "_", first).strip("_").lower()
            if normalized:
                return normalized
        digest = hashlib.sha1(block.encode("utf-8", errors="ignore")).hexdigest()[:12]
        return f"block_{digest}"

    ordered_keys: List[str] = []
    by_key: Dict[str, str] = {}
    for block in _split_blocks(base):
        key = _block_key(block)
        if key in by_key:
            by_key[key] = block
            continue
        ordered_keys.append(key)
        by_key[key] = block
    for block in _split_blocks(payload):
        key = _block_key(block)
        if key in by_key:
            by_key[key] = block
        else:
            ordered_keys.append(key)
            by_key[key] = block

    if len(ordered_keys) > max_blocks:
        ordered_keys = ordered_keys[-max_blocks:]

    blocks: List[str] = [by_key[key] for key in ordered_keys if key in by_key and by_key[key].strip()]
    merged = "\n\n".join(blocks)
    if len(merged) <= max_chars:
        return merged

    # Enforce a bounded prompt context without dropping the most recent blocks.
    trimmed: List[str] = []
    total = 0
    for block in reversed(blocks):
        addition = len(block) + (2 if trimmed else 0)
        if trimmed and total + addition > max_chars:
            break
        trimmed.append(block)
        total += addition
    trimmed = list(reversed(trimmed))
    return "\n\n".join(trimmed)


def _format_gate_failure_evidence(
    gate_results: Any,
    max_items: int = 6,
    max_evidence_len: int = 260,
) -> str:
    if not isinstance(gate_results, list):
        return ""
    lines: List[str] = []
    for gate in gate_results:
        if not isinstance(gate, dict):
            continue
        passed = gate.get("passed")
        issues = gate.get("issues") if isinstance(gate.get("issues"), list) else []
        if passed is not False and not issues:
            continue
        name = str(gate.get("name") or "unknown_gate")
        severity = str(gate.get("severity") or "UNKNOWN")
        issue_text = "; ".join(str(x) for x in issues[:2]) if issues else "Gate reported as failed."
        evidence = gate.get("evidence")
        evidence_text = ""
        if isinstance(evidence, dict):
            compact = json.dumps(evidence, ensure_ascii=True)
            evidence_text = compact if len(compact) <= max_evidence_len else compact[: max_evidence_len - 3] + "..."
        elif evidence:
            compact = str(evidence)
            evidence_text = compact if len(compact) <= max_evidence_len else compact[: max_evidence_len - 3] + "..."
        line = f"- Gate: {name} ({severity}) | Issue: {issue_text}"
        if evidence_text:
            line += f" | Evidence: {evidence_text}"
        lines.append(line)
        if len(lines) >= max_items:
            break
    if not lines:
        return ""
    return "GATE_FAILURE_EVIDENCE:\n" + "\n".join(lines)

def _read_csv_header(csv_path: str, encoding: str, sep: str) -> List[str]:
    try:
        import csv
        with open(csv_path, "r", encoding=encoding, errors="replace") as f:
            reader = csv.reader(f, delimiter=sep)
            return next(reader, [])
    except Exception:
        return []

def _detect_alternate_csv_sep(csv_path: str, encoding: str, current_sep: str) -> str | None:
    try:
        import csv
        with open(csv_path, "r", encoding=encoding, errors="replace") as f:
            header_line = f.readline()
        if not header_line:
            return None
        candidates = [",", ";", "\t", "|"]
        best_sep = None
        best_cols = 1
        for sep in candidates:
            if sep == current_sep:
                continue
            try:
                row = next(csv.reader([header_line], delimiter=sep), [])
            except Exception:
                continue
            if len(row) > best_cols:
                best_cols = len(row)
                best_sep = sep
        if best_cols >= 2:
            return best_sep
    except Exception:
        return None
    return None

def _cleanup_run_artifacts() -> None:
    paths_to_remove = [
        os.path.join("artifacts", "ml_engineer_last.py"),
        os.path.join("artifacts", "ml_engineer_context.json"),
        os.path.join("artifacts", "ml_engineer_context_ops.txt"),
        os.path.join("artifacts", "ml_results_advisor.txt"),
        os.path.join("artifacts", "ml_engineer_failure_explainer.txt"),
        os.path.join("artifacts", "data_engineer_last.py"),
        os.path.join("artifacts", "data_engineer_sandbox_last.log"),
    ]
    for path in paths_to_remove:
        try:
            if os.path.exists(path):
                os.remove(path)
        except Exception:
            pass

    # Clear iteration artifacts
    iter_dir = os.path.join("artifacts", "iterations")
    if os.path.isdir(iter_dir):
        for filename in os.listdir(iter_dir):
            file_path = os.path.join(iter_dir, filename)
            try:
                if os.path.isfile(file_path):
                    os.remove(file_path)
            except Exception:
                pass

    # Clear previous outputs that can contaminate new runs
    data_files = [
        os.path.join("data", "weights.json"),
        os.path.join("data", "case_summary.csv"),
        os.path.join("data", "metrics.json"),
        os.path.join("data", "scored_rows.csv"),
        os.path.join("data", "case_alignment_report.json"),
        os.path.join("data", "output_contract_report.json"),
        os.path.join("data", "execution_contract.json"),
    ]
    for path in data_files:
        try:
            if os.path.exists(path):
                os.remove(path)
        except Exception:
            pass

    # Clear plots from previous runs
    plots_dir = os.path.join("static", "plots")
    if os.path.isdir(plots_dir):
        for filename in os.listdir(plots_dir):
            file_path = os.path.join(plots_dir, filename)
            try:
                if os.path.isfile(file_path):
                    os.remove(file_path)
            except Exception:
                pass

def _load_json_safe(path: str) -> Dict[str, Any]:
    if not path or not os.path.exists(path):
        return {}
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}

def _load_json_any(path: str) -> Any:
    if not path or not os.path.exists(path):
        return None
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def _abs_in_work(work_dir: str, rel: str) -> str:
    return os.path.normpath(os.path.join(work_dir, rel))


def _resolve_work_dir_abs(state: Dict[str, Any] | None) -> str:
    work_dir = ""
    if isinstance(state, dict):
        work_dir = state.get("work_dir_abs") or state.get("work_dir") or ""
    if not work_dir:
        work_dir = "."
    work_dir_abs = os.path.abspath(work_dir)
    if isinstance(state, dict):
        state["work_dir_abs"] = work_dir_abs
    return work_dir_abs


def _verify_run_bundle_contracts(
    run_id: str,
    expected_contract: Dict[str, Any] | None,
    work_dir_abs: str,
) -> None:
    if not run_id or not work_dir_abs:
        return
    run_dir = get_run_dir(run_id) or os.path.join("runs", run_id)
    contracts_dir = os.path.join(run_dir, "contracts")
    contract_path = os.path.join(contracts_dir, "execution_contract.json")
    loaded = _load_json_safe(contract_path)
    expected_title = ""
    if isinstance(expected_contract, dict):
        expected_title = str(expected_contract.get("strategy_title") or "")
    observed_title = str(loaded.get("strategy_title") or "")
    if not expected_title or expected_title == observed_title:
        return
    log_run_event(
        run_id,
        "run_bundle_contract_mismatch",
        {
            "expected_strategy_title": expected_title,
            "observed_strategy_title": observed_title,
            "contracts_path": contract_path,
        },
    )
    copy_run_contracts(
        run_id,
        [
            _abs_in_work(work_dir_abs, "data/execution_contract.json"),
            _abs_in_work(work_dir_abs, "data/execution_contract_diagnostics.json"),
            _abs_in_work(work_dir_abs, "data/evaluation_spec.json"),
            _abs_in_work(work_dir_abs, "data/plan.json"),
        ],
    )

def _resolve_artifact_gate_dialect(state: Dict[str, Any], contract: Dict[str, Any]) -> Dict[str, str]:
    csv_sep = state.get("csv_sep") or None
    csv_decimal = state.get("csv_decimal") or None
    csv_encoding = state.get("csv_encoding") or None
    manifest_path = _resolve_cleaning_manifest_path_from_state(state if isinstance(state, dict) else {})
    if not manifest_path and isinstance(contract, dict):
        manifest_path = get_clean_manifest_path(contract)
    if (not csv_sep or not csv_decimal or not csv_encoding) and manifest_path and os.path.exists(manifest_path):
        manifest = _load_json_safe(manifest_path)
        output_dialect = manifest.get("output_dialect") if isinstance(manifest, dict) else None
        if isinstance(output_dialect, dict):
            if not csv_sep:
                csv_sep = output_dialect.get("sep")
            if not csv_decimal:
                csv_decimal = output_dialect.get("decimal")
            if not csv_encoding:
                csv_encoding = output_dialect.get("encoding")
            if csv_sep and not state.get("csv_sep"):
                state["csv_sep"] = csv_sep
            if csv_decimal and not state.get("csv_decimal"):
                state["csv_decimal"] = csv_decimal
            if csv_encoding and not state.get("csv_encoding"):
                state["csv_encoding"] = csv_encoding
    contract_output_dialect = contract.get("output_dialect", {}) if isinstance(contract, dict) else {}
    return {
        "sep": csv_sep or contract_output_dialect.get("sep") or ",",
        "decimal": csv_decimal or contract_output_dialect.get("decimal") or ".",
        "encoding": csv_encoding or contract_output_dialect.get("encoding") or "utf-8",
    }

def _select_segment_column(columns: List[str], contract: Dict[str, Any] | None = None) -> str | None:
    if not columns:
        return None
    label_hint = None
    if isinstance(contract, dict):
        label_hint = contract.get("segment_label_column")
    if label_hint and label_hint in columns:
        return label_hint
    for candidate in [
        "cluster_id",
        "segment_id",
        "segment",
        "cluster",
        "group_id",
        "group",
        "client_segment",
    ]:
        if candidate in columns:
            return candidate
    for col in columns:
        norm = _norm_name(col)
        if any(tok in norm for tok in ["segment", "cluster", "group"]):
            return col
    return None

def _summarize_segmentation_stats(
    scored_path: str,
    csv_sep: str,
    csv_decimal: str,
    csv_encoding: str,
    contract: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    stats = {
        "n_rows": None,
        "n_segments": None,
        "min_segment_size": None,
        "median_segment_size": None,
        "segment_column": None,
    }
    if not scored_path or not os.path.exists(scored_path):
        return stats
    detected_sep = csv_sep
    columns = _read_csv_header(scored_path, csv_encoding, detected_sep)
    if len(columns) <= 1:
        alt_sep = _detect_alternate_csv_sep(scored_path, csv_encoding, detected_sep)
        if alt_sep:
            detected_sep = alt_sep
            columns = _read_csv_header(scored_path, csv_encoding, detected_sep)
            stats["scored_rows_sep_used"] = detected_sep
    segment_col = _select_segment_column(columns, contract)
    stats["segment_column"] = segment_col
    try:
        stats["n_rows"] = _count_raw_rows(scored_path, csv_encoding, detected_sep, csv_decimal)
    except Exception:
        stats["n_rows"] = None
    if not segment_col:
        return stats
    try:
        import pandas as pd
        df = pd.read_csv(
            scored_path,
            sep=detected_sep,
            decimal=csv_decimal,
            encoding=csv_encoding,
            usecols=[segment_col],
            low_memory=False,
        )
        series = df[segment_col].dropna()
        if not series.empty:
            stats["n_segments"] = int(series.nunique())
            sizes = series.value_counts()
            if not sizes.empty:
                stats["min_segment_size"] = int(sizes.min())
                stats["median_segment_size"] = float(sizes.median())
    except Exception:
        return stats
    return stats

def _count_curve_points(payload: Any) -> int:
    if payload is None:
        return 0
    if isinstance(payload, list):
        if payload and all(isinstance(item, dict) for item in payload):
            return len(payload)
        return sum(_count_curve_points(item) for item in payload)
    if isinstance(payload, dict):
        if "points" in payload and isinstance(payload.get("points"), list):
            return len(payload.get("points"))
        total = 0
        for value in payload.values():
            total += _count_curve_points(value)
        return total
    return 0

def _count_curves(payload: Any) -> int:
    if payload is None:
        return 0
    if isinstance(payload, dict):
        container = payload.get("curves") if isinstance(payload.get("curves"), (dict, list)) else payload
        if isinstance(container, dict):
            return len(container)
        if isinstance(container, list):
            return len(container)
    if isinstance(payload, list):
        return len(payload)
    return 0

def _summarize_pricing_artifacts(
    curves_path: str,
    guide_path: str,
    csv_sep: str,
    csv_decimal: str,
    csv_encoding: str,
) -> Dict[str, Any]:
    summary = {
        "curves_present": None,
        "curves_count": 0,
        "curves_points": 0,
        "guide_rows": None,
        "pct_nan_optimal_price": None,
        "optimal_price_columns": [],
    }
    if curves_path and os.path.exists(curves_path):
        payload = _load_json_any(curves_path)
        summary["curves_count"] = _count_curves(payload)
        summary["curves_points"] = _count_curve_points(payload)
        summary["curves_present"] = bool(summary["curves_count"] or summary["curves_points"])
    if guide_path and os.path.exists(guide_path):
        try:
            import pandas as pd
            header = _read_csv_header(guide_path, csv_encoding, csv_sep)
            target_cols = [c for c in header if "optimal_price" in _norm_name(c)]
            summary["optimal_price_columns"] = target_cols
            df = pd.read_csv(guide_path, sep=csv_sep, decimal=csv_decimal, encoding=csv_encoding)
            summary["guide_rows"] = int(len(df))
            if target_cols:
                sub = df[target_cols]
                nan_frac = float(sub.isna().mean().mean()) if not sub.empty else 1.0
                summary["pct_nan_optimal_price"] = round(nan_frac, 4)
        except Exception:
            return summary
    return summary

def _collect_iteration_diagnostics(state: Dict[str, Any]) -> Dict[str, Any]:
    csv_sep = state.get("csv_sep", ",")
    csv_decimal = state.get("csv_decimal", ".")
    csv_encoding = state.get("csv_encoding", "utf-8")
    contract = state.get("execution_contract", {}) if isinstance(state, dict) else {}
    scored_path = _resolve_declared_artifact_path_from_state(
        state if isinstance(state, dict) else {},
        "scored_rows.csv",
    )
    seg_stats = _summarize_segmentation_stats(scored_path, csv_sep, csv_decimal, csv_encoding, contract)
    n_rows = seg_stats.get("n_rows")
    if n_rows is None:
        fallback_path = str(state.get("ml_data_path") or "").strip()
        if not fallback_path or not os.path.exists(fallback_path):
            fallback_path = get_clean_dataset_output_path(contract) or ""
        if fallback_path and os.path.exists(fallback_path):
            try:
                n_rows = _count_raw_rows(fallback_path, csv_encoding, csv_sep, csv_decimal)
                seg_stats["n_rows"] = n_rows
            except Exception:
                pass
    curves_path = _resolve_declared_artifact_path_from_state(
        state if isinstance(state, dict) else {},
        "price_sensitivity_curves.json",
    )
    guide_path = _resolve_declared_artifact_path_from_state(
        state if isinstance(state, dict) else {},
        "optimal_pricing_guide.csv",
    )
    pricing_stats = _summarize_pricing_artifacts(
        curves_path=curves_path,
        guide_path=guide_path,
        csv_sep=csv_sep,
        csv_decimal=csv_decimal,
        csv_encoding=csv_encoding,
    )
    diagnostics = {}
    diagnostics.update(seg_stats)
    diagnostics.update(pricing_stats)
    diagnostics["curves_generated"] = bool(pricing_stats.get("curves_points") or 0)
    runtime_tail = state.get("last_runtime_error_tail")
    if runtime_tail:
        diagnostics["root_cause"] = str(runtime_tail).strip().splitlines()[-1][:300]
    return diagnostics

def _validate_artifact_content(state: Dict[str, Any]) -> tuple[List[str], Dict[str, Any]]:
    diagnostics = _collect_iteration_diagnostics(state)
    issues: List[str] = []
    curves_path = _resolve_declared_artifact_path_from_state(
        state if isinstance(state, dict) else {},
        "price_sensitivity_curves.json",
    )
    guide_path = _resolve_declared_artifact_path_from_state(
        state if isinstance(state, dict) else {},
        "optimal_pricing_guide.csv",
    )
    if curves_path and os.path.exists(curves_path):
        if diagnostics.get("curves_points", 0) == 0:
            issues.append("price_sensitivity_curves_empty")
    if guide_path and os.path.exists(guide_path):
        if diagnostics.get("guide_rows") == 0:
            issues.append("optimal_pricing_guide_empty")
    pct_nan_opt = diagnostics.get("pct_nan_optimal_price")
    if isinstance(pct_nan_opt, (int, float)) and pct_nan_opt >= 0.99:
        issues.append("optimal_price_all_nan")
    n_rows = diagnostics.get("n_rows")
    n_segments = diagnostics.get("n_segments")
    if isinstance(n_rows, (int, float)) and isinstance(n_segments, (int, float)) and n_rows > 0:
        if n_segments > 0.5 * n_rows:
            issues.append("segmentation_degenerate")
    return issues, diagnostics

def _score_attempt(
    outputs_valid: bool,
    output_contract_report: Dict[str, Any],
    content_issues: List[str],
    artifact_paths: List[str],
    contract: Dict[str, Any] | None = None,
) -> float:
    """Score an attempt for best_attempt selection.

    The score has two components:
    1. Completeness score (0-20 range): outputs valid, artifacts present, no issues.
    2. ML metric bonus (100+ range): the primary metric value from metrics.json,
       scaled so that any metric improvement dominates completeness differences.

    This ensures that a higher-metric attempt is always preferred over a
    lower-metric attempt, even if the lower one has slightly better completeness.
    """
    score = 0.0
    present = output_contract_report.get("present", []) if isinstance(output_contract_report, dict) else []
    missing = output_contract_report.get("missing", []) if isinstance(output_contract_report, dict) else []
    if outputs_valid:
        score += 10.0
    score += float(len(present))
    score += float(len(artifact_paths)) * 0.25
    score -= float(len(missing)) * 2.0
    score -= float(len(content_issues)) * 3.0

    # ML metric bonus: extract primary metric from the declared metrics artifact and add it
    # as a dominant score component.  We use a large multiplier (1000x) so
    # that even a 0.0001 AUC improvement (+0.1 score) overwhelms any
    # completeness difference (~1-2 points).
    try:
        metrics_aliases = {
            "metrics.json",
            "cv_metrics.json",
            "evaluation_metrics.json",
            "evaluation_report.json",
            "evaluation_summary.json",
        }
        metrics_candidates: List[str] = []
        seen_candidates: set[str] = set()

        def _append_candidate(path: Any) -> None:
            normalized = normalize_artifact_path(path)
            if not normalized or normalized in seen_candidates:
                return
            seen_candidates.add(normalized)
            metrics_candidates.append(normalized)

        declared_metrics = get_declared_artifact_path(
            contract if isinstance(contract, dict) else {},
            kind="metrics",
        )
        declared_metrics_norm = normalize_artifact_path(declared_metrics)
        declared_metrics_base = os.path.basename(declared_metrics_norm).lower() if declared_metrics_norm else ""
        for path in artifact_paths or []:
            normalized = normalize_artifact_path(path)
            if not normalized:
                continue
            base = os.path.basename(normalized).lower()
            if declared_metrics_norm and (
                normalized == declared_metrics_norm or (declared_metrics_base and base == declared_metrics_base)
            ):
                _append_candidate(normalized)
            if base in metrics_aliases:
                _append_candidate(normalized)

        metrics_json: Dict[str, Any] = {}
        for metrics_path in metrics_candidates:
            candidate_payload = _load_json_safe(metrics_path)
            if isinstance(candidate_payload, dict) and candidate_payload:
                normalized_payload = _normalize_metrics_report_payload(candidate_payload)
                metrics_json = (
                    normalized_payload
                    if isinstance(normalized_payload, dict) and normalized_payload
                    else candidate_payload
                )
                metrics_json.setdefault("source", metrics_path)
                break
        if isinstance(metrics_json, dict) and metrics_json:
            evaluation_spec = (
                contract.get("evaluation_spec")
                if isinstance(contract, dict) and isinstance(contract.get("evaluation_spec"), dict)
                else {}
            )
            primary_metric_state = _build_primary_metric_state(
                state={"execution_contract": contract or {}, "evaluation_spec": evaluation_spec},
                metrics_report=metrics_json,
                weights_report={},
                objective_type=str(evaluation_spec.get("objective_type") or ""),
                evaluation_spec=evaluation_spec,
                contract=contract or {},
            )
            metric_name = str(
                primary_metric_state.get("primary_metric_name")
                or metrics_json.get("primary_metric_name")
                or metrics_json.get("primary_metric")
                or ""
            ).strip()
            ml_value = _coerce_float(primary_metric_state.get("primary_metric_value"))
            if ml_value is None and metric_name:
                ml_value = _extract_primary_metric(metrics_json, metric_name)
            if ml_value is not None and abs(float(ml_value)) < 1e12:
                higher_is_better = (
                    bool(primary_metric_state.get("higher_is_better"))
                    if isinstance(primary_metric_state.get("higher_is_better"), bool)
                    else bool(_metric_higher_is_better(metric_name or ""))
                )
                if higher_is_better:
                    score += float(ml_value) * 1000.0
                else:
                    score -= float(ml_value) * 1000.0
    except Exception:
        pass  # If metrics unavailable, fall back to completeness-only scoring

    return score

def _snapshot_best_attempt(
    attempt_id: int,
    artifact_paths: List[str],
    output_contract_report: Dict[str, Any],
    artifact_index: List[Dict[str, Any]],
    execution_output: str,
    plots_local: List[str],
    diagnostics: Dict[str, Any] | None = None,
    dest_root: str = os.path.join("artifacts", "best_attempt"),
    contract: Dict[str, Any] | None = None,
) -> str | None:
    if attempt_id < 1:
        return None
    try:
        if os.path.isdir(dest_root):
            shutil.rmtree(dest_root)
        os.makedirs(dest_root, exist_ok=True)
        for path in artifact_paths or []:
            if not path or not os.path.exists(path):
                continue
            rel = path.lstrip("./").replace("\\", "/")
            dest = os.path.join(dest_root, rel)
            os.makedirs(os.path.dirname(dest), exist_ok=True)
            shutil.copy2(path, dest)
        meta = {
            "attempt_id": attempt_id,
            "artifact_index": artifact_index,
            "output_contract_report": output_contract_report,
            "execution_output": execution_output,
            "plots_local": plots_local,
            "diagnostics": diagnostics or {},
        }
        metrics_aliases = {
            "metrics.json",
            "cv_metrics.json",
            "evaluation_metrics.json",
            "evaluation_report.json",
            "evaluation_summary.json",
        }
        metrics_payload: Dict[str, Any] = {}
        metrics_path = ""
        declared_metrics = get_declared_artifact_path(
            contract if isinstance(contract, dict) else {},
            kind="metrics",
        )
        declared_metrics_norm = normalize_artifact_path(declared_metrics)
        declared_metrics_base = os.path.basename(declared_metrics_norm).lower() if declared_metrics_norm else ""
        metrics_candidates: List[str] = []
        seen_candidates: set[str] = set()

        def _append_metrics_candidate(path: Any) -> None:
            normalized = normalize_artifact_path(path)
            if not normalized or normalized in seen_candidates:
                return
            seen_candidates.add(normalized)
            metrics_candidates.append(normalized)

        for path in artifact_paths or []:
            normalized = normalize_artifact_path(path)
            if not normalized:
                continue
            base = os.path.basename(normalized).lower()
            if declared_metrics_norm and (
                normalized == declared_metrics_norm or (declared_metrics_base and base == declared_metrics_base)
            ):
                _append_metrics_candidate(normalized)
            if base in metrics_aliases:
                _append_metrics_candidate(normalized)

        for candidate_path in metrics_candidates:
            candidate_payload = _load_json_safe(candidate_path)
            if isinstance(candidate_payload, dict) and candidate_payload:
                normalized_payload = _normalize_metrics_report_payload(candidate_payload)
                metrics_payload = (
                    normalized_payload
                    if isinstance(normalized_payload, dict) and normalized_payload
                    else candidate_payload
                )
                metrics_payload.setdefault("source", candidate_path)
                metrics_path = candidate_path
                break
        if metrics_payload:
            meta["metrics_payload"] = metrics_payload
        if metrics_path:
            meta["metrics_path"] = metrics_path
        if metrics_payload:
            evaluation_spec = (
                contract.get("evaluation_spec")
                if isinstance(contract, dict) and isinstance(contract.get("evaluation_spec"), dict)
                else {}
            )
            primary_metric_state = _build_primary_metric_state(
                state={"execution_contract": contract or {}, "evaluation_spec": evaluation_spec},
                metrics_report=metrics_payload,
                weights_report={},
                objective_type=str(evaluation_spec.get("objective_type") or ""),
                evaluation_spec=evaluation_spec,
                contract=contract or {},
            )
            if isinstance(primary_metric_state, dict) and primary_metric_state:
                meta["primary_metric_state"] = primary_metric_state
        with open(os.path.join(dest_root, "best_attempt.json"), "w", encoding="utf-8") as f_meta:
            json.dump(meta, f_meta, indent=2, ensure_ascii=False)
        return dest_root
    except Exception:
        return None

def _promote_best_attempt(state: Dict[str, Any]) -> Dict[str, Any]:
    best_dir = state.get("best_attempt_dir")
    if not best_dir or not os.path.isdir(best_dir):
        return {}
    updated: Dict[str, Any] = {}
    try:
        for root, _, files in os.walk(best_dir):
            for name in files:
                if name == "best_attempt.json":
                    continue
                src = os.path.join(root, name)
                rel = os.path.relpath(src, best_dir)
                dest = os.path.join(".", rel)
                os.makedirs(os.path.dirname(dest), exist_ok=True)
                shutil.copy2(src, dest)
        meta_path = os.path.join(best_dir, "best_attempt.json")
        meta = _load_json_any(meta_path)
        if isinstance(meta, dict):
            if meta.get("artifact_index") is not None:
                updated["artifact_index"] = meta.get("artifact_index")
                updated["produced_artifact_index"] = meta.get("artifact_index")
                try:
                    os.makedirs("data", exist_ok=True)
                    dump_json("data/produced_artifact_index.json", meta.get("artifact_index"))
                except Exception:
                    pass
            if meta.get("output_contract_report") is not None:
                updated["output_contract_report"] = meta.get("output_contract_report")
                try:
                    os.makedirs("data", exist_ok=True)
                    dump_json("data/output_contract_report.json", meta.get("output_contract_report"))
                except Exception:
                    pass
            metrics_payload = meta.get("metrics_payload") if isinstance(meta.get("metrics_payload"), dict) else {}
            metrics_path = normalize_artifact_path(meta.get("metrics_path"))
            if metrics_payload:
                updated["metrics_report"] = copy.deepcopy(metrics_payload)
                primary_metric_state = (
                    meta.get("primary_metric_state")
                    if isinstance(meta.get("primary_metric_state"), dict)
                    else {}
                )
                if not primary_metric_state:
                    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
                    evaluation_spec = (
                        contract.get("evaluation_spec")
                        if isinstance(contract, dict) and isinstance(contract.get("evaluation_spec"), dict)
                        else {}
                    )
                    primary_metric_state = _build_primary_metric_state(
                        state={"execution_contract": contract, "evaluation_spec": evaluation_spec},
                        metrics_report=metrics_payload,
                        weights_report={},
                        objective_type=str(evaluation_spec.get("objective_type") or ""),
                        evaluation_spec=evaluation_spec,
                        contract=contract,
                    )
                if isinstance(primary_metric_state, dict) and primary_metric_state:
                    updated["primary_metric_state"] = copy.deepcopy(primary_metric_state)
                    try:
                        os.makedirs("data", exist_ok=True)
                        dump_json("data/metric_state.json", primary_metric_state)
                    except Exception:
                        pass
                metrics_snapshot = _build_metrics_artifact_snapshot(
                    state=state if isinstance(state, dict) else {},
                    role="best_attempt",
                    metrics_payload=metrics_payload,
                    path=metrics_path or "",
                    source=f"best_attempt:{metrics_path}" if metrics_path else "best_attempt",
                    metric_name=(
                        primary_metric_state.get("primary_metric_name")
                        if isinstance(primary_metric_state, dict)
                        else None
                    ),
                    higher_is_better=(
                        primary_metric_state.get("higher_is_better")
                        if isinstance(primary_metric_state, dict)
                        else None
                    ),
                )
                if metrics_snapshot:
                    updated["metrics_artifact_snapshot"] = metrics_snapshot
            if meta.get("execution_output"):
                updated.update(_clear_runtime_blockers())
                updated["execution_output"] = meta.get("execution_output")
                updated["execution_output_stale"] = True
            if meta.get("plots_local") is not None:
                updated["plots_local"] = meta.get("plots_local")
    except Exception:
        return updated
    return updated

def _normalize_alignment_check(
    alignment_check: Dict[str, Any],
    alignment_requirements: List[Any],
) -> tuple[Dict[str, Any], List[str]]:
    issues: List[str] = []
    normalized = dict(alignment_check or {})
    raw_status = normalized.get("status")
    if not raw_status:
        raw_status = normalized.get("overall_status") or normalized.get("overallStatus")
    status = str(raw_status or "").upper()

    requirements_payload = normalized.get("requirements")
    per_req = normalized.get("per_requirement")
    evidence_map = normalized.get("evidence")
    checks_payload = normalized.get("checks") or normalized.get("checklist") or []
    map_schema = False

    def _requirements_from_checks(checks: Any) -> List[Dict[str, Any]]:
        derived: List[Dict[str, Any]] = []
        if not isinstance(checks, list):
            return derived
        for idx, item in enumerate(checks):
            if not isinstance(item, dict):
                continue
            req_id = item.get("id") or item.get("name") or item.get("key") or f"check_{idx}"
            status_val = item.get("status") or item.get("result") or item.get("outcome")
            evidence_val = item.get("evidence") or item.get("notes") or []
            evidence_list: List[str] = []
            if isinstance(evidence_val, list):
                evidence_list = [str(v) for v in evidence_val if v]
            elif isinstance(evidence_val, str) and evidence_val.strip():
                evidence_list = [evidence_val.strip()]
            derived.append(
                {
                    "id": str(req_id),
                    "status": str(status_val or "").upper(),
                    "evidence": evidence_list,
                }
            )
        return derived

    def _requirements_from_map(payload: Dict[str, Any], req_ids: set[str]) -> List[Dict[str, Any]]:
        derived: List[Dict[str, Any]] = []
        for req_id in req_ids:
            entry = payload.get(req_id)
            if not isinstance(entry, dict):
                continue
            status_val = entry.get("status") or entry.get("result") or entry.get("outcome")
            evidence_val = entry.get("evidence") or entry.get("notes") or []
            evidence_list: List[str] = []
            if isinstance(evidence_val, list):
                evidence_list = [str(v) for v in evidence_val if v]
            elif isinstance(evidence_val, str) and evidence_val.strip():
                evidence_list = [evidence_val.strip()]
            derived.append(
                {
                    "id": str(req_id),
                    "status": str(status_val or "").upper(),
                    "evidence": evidence_list,
                }
            )
        return derived

    def _derive_status_from_requirements(reqs: List[Dict[str, Any]]) -> str:
        if not isinstance(reqs, list) or not reqs:
            return "WARN"
        statuses = [str(item.get("status") or "").upper() for item in reqs if isinstance(item, dict)]
        if any(st == "FAIL" for st in statuses):
            return "FAIL"
        if any(st not in {"PASS"} for st in statuses):
            return "WARN"
        return "PASS"

    if not isinstance(requirements_payload, list) and checks_payload:
        requirements_payload = _requirements_from_checks(checks_payload)
        normalized["requirements"] = requirements_payload
    if not isinstance(requirements_payload, list) and alignment_requirements:
        req_ids = {
            str(req.get("id") or req.get("name") or req.get("key") or req.get("requirement_id"))
            for req in alignment_requirements
            if isinstance(req, dict) and (req.get("id") or req.get("name") or req.get("key") or req.get("requirement_id"))
        }
        matching = [key for key in normalized.keys() if key in req_ids and isinstance(normalized.get(key), dict)]
        if matching:
            map_schema = True
            requirements_payload = _requirements_from_map(normalized, req_ids)
            normalized["requirements"] = requirements_payload
            if status not in {"PASS", "WARN", "FAIL"}:
                status = _derive_status_from_requirements(requirements_payload)
    if not alignment_requirements and isinstance(requirements_payload, list):
        alignment_requirements = [{"id": item.get("id"), "required": True} for item in requirements_payload if item.get("id")]

    normalized_reqs: List[Dict[str, Any]] = []
    missing_status = 0
    missing_evidence = 0
    for req in alignment_requirements or []:
        if isinstance(req, str):
            req_id = req.strip()
            req_obj = {"id": req_id, "required": True}
        elif isinstance(req, dict):
            req_id = req.get("id") or req.get("name") or req.get("key") or req.get("requirement_id")
            req_obj = req
        else:
            continue
        if not req_id:
            continue
        if isinstance(req_obj, dict) and req_obj.get("required") is False:
            normalized_reqs.append({"id": req_id, "status": "SKIP", "evidence": []})
            continue
        req_status = None
        req_evidence: List[str] = []
        if isinstance(requirements_payload, list):
            for item in requirements_payload:
                if not isinstance(item, dict):
                    continue
                if item.get("id") == req_id:
                    req_status = str(item.get("status") or item.get("result") or "").upper()
                    evidence_val = item.get("evidence") or item.get("notes") or []
                    if isinstance(evidence_val, list):
                        req_evidence = [str(v) for v in evidence_val if v]
                    elif isinstance(evidence_val, str) and evidence_val.strip():
                        req_evidence = [evidence_val.strip()]
                    break
        if req_status is None and isinstance(per_req, dict):
            raw = per_req.get(req_id)
            if raw is not None:
                req_status = str(raw).upper()
        if not req_evidence and isinstance(evidence_map, dict):
            raw_ev = evidence_map.get(req_id)
            if isinstance(raw_ev, list):
                req_evidence = [str(v) for v in raw_ev if v]
            elif isinstance(raw_ev, str) and raw_ev.strip():
                req_evidence = [raw_ev.strip()]
        if not req_status:
            if map_schema:
                req_status = "WARN"
            else:
                missing_status += 1
                req_status = "MISSING"
        if not req_evidence:
            if not map_schema:
                missing_evidence += 1
        normalized_reqs.append(
            {"id": req_id, "status": req_status, "evidence": req_evidence}
        )

    if missing_status:
        issues.append("alignment_missing_requirement_status")
    if missing_evidence:
        issues.append("alignment_missing_evidence")

    if status not in {"PASS", "WARN", "FAIL"}:
        status = "WARN"
        issues.append("alignment_status_invalid")

    failure_mode = normalized.get("failure_mode")
    if not failure_mode and issues:
        failure_mode = "format"

    normalized["status"] = status
    normalized["failure_mode"] = failure_mode
    normalized["requirements"] = normalized_reqs
    if issues:
        summary = normalized.get("summary") or ""
        issue_text = ", ".join(sorted(set(issues)))
        normalized["summary"] = f"{summary} Alignment issues: {issue_text}".strip()
    return normalized, issues


def _resolve_forbidden_features(
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
) -> List[str]:
    forbidden: set[str] = set()

    def _coerce_list(value: Any) -> List[str]:
        if isinstance(value, list):
            return [str(item) for item in value if item]
        if isinstance(value, str):
            return [value]
        return []

    for source in (contract_min, contract):
        if not isinstance(source, dict):
            continue
        allowed = source.get("allowed_feature_sets") or {}
        if isinstance(allowed, dict):
            forbidden |= set(_coerce_list(allowed.get("forbidden_features")))
            forbidden |= set(_coerce_list(allowed.get("forbidden_for_modeling")))
            forbidden |= set(_coerce_list(allowed.get("audit_only_features")))
        if forbidden:
            break

    if not forbidden:
        roles = get_column_roles(contract_min or contract or {})
        if isinstance(roles, dict):
            forbidden |= set(_coerce_list(roles.get("outcome")))
            forbidden |= set(_coerce_list(roles.get("post_decision_audit_only")))

    return sorted({item for item in forbidden if item})


def _ensure_feature_usage(
    alignment_check: Dict[str, Any],
    code: str,
    contract: Dict[str, Any] | None,
) -> Dict[str, Any]:
    alignment_check = dict(alignment_check or {})
    feature_usage = alignment_check.get("feature_usage")
    if not isinstance(feature_usage, dict):
        feature_usage = {}
    used_features = feature_usage.get("used_features")
    if not isinstance(used_features, list) or not used_features:
        model_features = _extract_named_string_list(code or "", ["MODEL_FEATURES", "model_features"])
        segment_features = _extract_named_string_list(code or "", ["SEGMENT_FEATURES", "segment_features"])
        used_features = list(dict.fromkeys((model_features or []) + (segment_features or [])))
    def _coerce_list(value: Any) -> List[str]:
        if isinstance(value, list):
            return [str(item) for item in value if item]
        if isinstance(value, str):
            return [value]
        return []

    target_columns: List[str] = []
    if isinstance(contract, dict):
        target_columns.extend(_coerce_list(contract.get("outcome_columns") or []))
        target_columns.extend(_coerce_list(contract.get("decision_columns") or []))
    feature_usage.setdefault("excluded_features", [])
    feature_usage.setdefault("reason_exclusions", {})
    feature_usage["used_features"] = used_features or []
    feature_usage["target_columns"] = [col for col in target_columns if col]
    alignment_check["feature_usage"] = feature_usage
    return alignment_check


def _apply_forbidden_feature_gate(
    alignment_check: Dict[str, Any],
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
    code: str,
) -> tuple[Dict[str, Any], List[str]]:
    alignment_check = _ensure_feature_usage(alignment_check, code, contract)
    forbidden = _resolve_forbidden_features(contract, contract_min)
    usage = alignment_check.get("feature_usage") if isinstance(alignment_check.get("feature_usage"), dict) else {}
    used_features = usage.get("used_features") if isinstance(usage, dict) else []
    used_set = {str(item) for item in used_features if item}
    violations = sorted({item for item in forbidden if item in used_set})
    requirements = alignment_check.get("requirements")
    if not isinstance(requirements, list):
        requirements = []
    if violations:
        alignment_check["status"] = "FAIL"
        alignment_check["failure_mode"] = alignment_check.get("failure_mode") or "leakage"
        alignment_check["summary"] = (
            alignment_check.get("summary")
            or "Forbidden features detected in model usage."
        )
        alignment_check["forbidden_features_used"] = violations
        requirements.append(
            {
                "id": "forbidden_features",
                "status": "FAIL",
                "evidence": [f"forbidden_used={violations}"],
            }
        )
    elif used_set:
        requirements.append(
            {
                "id": "forbidden_features",
                "status": "PASS",
                "evidence": ["no_forbidden_features_used"],
            }
        )
    else:
        requirements.append(
            {
                "id": "feature_usage",
                "status": "WARN",
                "evidence": ["feature_usage_missing_or_empty"],
            }
        )
    alignment_check["requirements"] = requirements
    return alignment_check, violations

def _coerce_alignment_requirements(reqs: Any) -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    if not isinstance(reqs, list):
        return out
    for idx, req in enumerate(reqs):
        if isinstance(req, str) and req.strip():
            out.append({"id": req.strip(), "required": True})
            continue
        if isinstance(req, dict):
            req_id = req.get("id") or req.get("name") or req.get("key") or f"custom_{idx}"
            req_obj = dict(req)
            req_obj["id"] = req_id
            if "required" not in req_obj:
                req_obj["required"] = True
            out.append(req_obj)
    return out

def _extract_leakage_columns(payload: Any) -> List[str]:
    cols: List[str] = []
    if isinstance(payload, dict):
        for key in ["columns", "features", "numeric_columns", "leaky_columns"]:
            vals = payload.get(key)
            if isinstance(vals, list):
                for v in vals:
                    if isinstance(v, str):
                        cols.append(v)
        pairs = payload.get("pairs") or payload.get("relations") or payload.get("top_pairs")
        if isinstance(pairs, list):
            for item in pairs:
                if not isinstance(item, dict):
                    continue
                for key in ["column", "feature", "name", "col_a", "col_b", "x", "y"]:
                    val = item.get(key)
                    if isinstance(val, str):
                        cols.append(val)
    elif isinstance(payload, list):
        for item in payload:
            if isinstance(item, str):
                cols.append(item)
            elif isinstance(item, dict):
                for key in ["column", "feature", "name", "col_a", "col_b", "x", "y"]:
                    val = item.get(key)
                    if isinstance(val, str):
                        cols.append(val)
    return cols

def _artifact_alignment_gate(
    cleaned_path: str,
    scored_path: str,
    contract: Dict[str, Any],
    evaluation_spec: Dict[str, Any] | None,
    csv_sep: str,
    csv_decimal: str,
    csv_encoding: str,
) -> List[str]:
    issues: List[str] = []
    if not cleaned_path or not os.path.exists(cleaned_path):
        issues.append(f"cleaned_data_missing:{cleaned_path or '<unset>'}")
        return issues

    try:
        import pandas as pd
        cleaned_df = pd.read_csv(cleaned_path, sep=csv_sep, decimal=csv_decimal, encoding=csv_encoding)
    except Exception as err:
        issues.append(f"cleaned_data_read_failed:{err}")
        return issues

    flags = _resolve_eval_flags(evaluation_spec)
    requires_row_scoring = bool(flags.get("requires_row_scoring"))
    declared_scored_rows_path = normalize_artifact_path(
        get_declared_artifact_path(contract if isinstance(contract, dict) else {}, "scored_rows.csv")
    )
    required_outputs = contract.get("required_outputs", []) if isinstance(contract, dict) else []
    if declared_scored_rows_path and declared_scored_rows_path in (required_outputs or []):
        requires_row_scoring = True
    deliverables = _resolve_contract_deliverables(contract) if isinstance(contract, dict) else []
    if isinstance(deliverables, list):
        for item in deliverables:
            if isinstance(item, dict) and normalize_artifact_path(item.get("path")) == declared_scored_rows_path:
                if bool(item.get("required")):
                    requires_row_scoring = True
                break
            if isinstance(item, str) and normalize_artifact_path(item) == declared_scored_rows_path:
                requires_row_scoring = True
                break

    if not requires_row_scoring:
        return issues

    if not scored_path or not os.path.exists(scored_path):
        issues.append("scored_rows_missing")
        return issues

    try:
        import pandas as pd
        scored_sep = csv_sep
        scored_df = pd.read_csv(scored_path, sep=scored_sep, decimal=csv_decimal, encoding=csv_encoding)
        if scored_df.shape[1] == 1:
            alt_sep = _detect_alternate_csv_sep(scored_path, csv_encoding, scored_sep)
            if alt_sep:
                scored_sep = alt_sep
                scored_df = pd.read_csv(scored_path, sep=scored_sep, decimal=csv_decimal, encoding=csv_encoding)
    except Exception as err:
        issues.append(f"scored_rows_read_failed:{err}")
        return issues

    if scored_df.shape[1] == 1:
        issues.append("scored_rows_dialect_mismatch")
        return issues

    if len(scored_df) != len(cleaned_df):
        issues.append("scored_rows_rowcount_mismatch")

    cleaned_cols = [str(c) for c in cleaned_df.columns]
    scored_cols = [str(c) for c in scored_df.columns]
    cleaned_norm = {_norm_name(c) for c in cleaned_cols}
    scored_norm = {_norm_name(c) for c in scored_cols}
    row_id_candidates = {"row_id", "case_id", "caseid", "id"}
    has_row_id = any(c in row_id_candidates for c in scored_norm)
    has_overlap = bool(cleaned_norm.intersection(scored_norm))
    if not has_row_id and not has_overlap:
        issues.append("scored_rows_missing_row_id_or_overlap")

    def _normalize_schema(raw: Any) -> Dict[str, Dict[str, Any]]:
        normalized: Dict[str, Dict[str, Any]] = {}
        if isinstance(raw, dict):
            for key, value in raw.items():
                if not key:
                    continue
                normalized[str(key)] = value if isinstance(value, dict) else {}
            return normalized
        if isinstance(raw, list):
            for item in raw:
                if not isinstance(item, dict):
                    continue
                path = item.get("path") or item.get("artifact") or item.get("output")
                if not path:
                    continue
                normalized[str(path)] = item
        return normalized

    schema = {}
    if isinstance(contract, dict):
        # V4.1: Use artifact_requirements.file_schemas only, no legacy fallback
        reqs = contract.get("artifact_requirements") or {}
        schema = _normalize_schema(reqs.get("file_schemas"))
    scored_schema = get_declared_file_schema(contract, "scored_rows.csv")
    allowed_extra = scored_schema.get("allowed_extra_columns") if isinstance(scored_schema, dict) else None
    allowed_patterns = scored_schema.get("allowed_name_patterns") if isinstance(scored_schema, dict) else None

    allowed_cols: List[str] = list(cleaned_cols)
    allowed_cols.extend(_resolve_contract_columns(contract, sources={"derived", "output"}))
    if isinstance(scored_schema, dict):
        schema_required = scored_schema.get("required_columns")
        if isinstance(schema_required, list):
            allowed_cols.extend([str(col) for col in schema_required if col])
        schema_recommended = scored_schema.get("recommended_columns")
        if isinstance(schema_recommended, list):
            allowed_cols.extend([str(col) for col in schema_recommended if col])
    # Also read scored_rows_schema directly from artifact_requirements
    # (contract may store schema here instead of / in addition to file_schemas)
    scored_rows_schema_direct = reqs.get("scored_rows_schema") if isinstance(reqs, dict) else None
    if isinstance(scored_rows_schema_direct, dict):
        sr_required = scored_rows_schema_direct.get("required_columns")
        if isinstance(sr_required, list):
            allowed_cols.extend([str(col) for col in sr_required if col])
        sr_recommended = scored_rows_schema_direct.get("recommended_columns")
        if isinstance(sr_recommended, list):
            allowed_cols.extend([str(col) for col in sr_recommended if col])
    decisioning_cols: List[str] = []
    decisioning_req = contract.get("decisioning_requirements", {}) if isinstance(contract, dict) else {}
    decisioning_out = decisioning_req.get("output") if isinstance(decisioning_req, dict) else {}
    required_decisioning = decisioning_out.get("required_columns") if isinstance(decisioning_out, dict) else []
    if isinstance(required_decisioning, list):
        for item in required_decisioning:
            name = None
            if isinstance(item, dict):
                name = item.get("name") or item.get("column")
            elif isinstance(item, str):
                name = item
            if name:
                decisioning_cols.append(str(name))
    if decisioning_cols:
        allowed_cols.extend(decisioning_cols)
    # Legacy spec_extraction removed (covered by _resolve_contract_columns V4.1 + data_requirements)

    if isinstance(evaluation_spec, dict):
        target = evaluation_spec.get("target")
        if isinstance(target, dict) and target.get("name"):
            allowed_cols.append(str(target.get("name")))

    allowed_cols.extend(
        [
            "prediction",
            "pred",
            "predicted",
            "predicted_value",
            "predicted_label",
            "predicted_prob",
            "probability",
            "prob",
            "score",
            "risk_score",
            "rank",
            "ranking",
            "segment",
            "segment_id",
            "cluster",
            "cluster_id",
            "group",
            "group_id",
            "row_id",
            "case_id",
            "caseid",
            "id",
            "expected_value",
            "actual",
            "label",
        ]
    )
    allowed_norm = {_norm_name(col) for col in allowed_cols if col}
    allowed_extra_norm = {_norm_name(col) for col in allowed_extra or [] if col}
    allowed_pattern_list = [str(pat) for pat in (allowed_patterns or []) if isinstance(pat, str) and pat.strip()]

    def _pattern_name(name: str) -> str:
        return re.sub(r"[^0-9a-zA-Z]+", "_", str(name).lower()).strip("_")

    scored_extras = []
    for col in scored_cols:
        norm = _norm_name(col)
        if not norm:
            continue
        if norm in allowed_norm:
            continue
        if norm in allowed_extra_norm:
            continue
        if allowed_pattern_list:
            pattern_target = _pattern_name(col)
            matched = False
            for pattern in allowed_pattern_list:
                try:
                    if re.search(pattern, pattern_target):
                        matched = True
                        break
                except re.error:
                    continue
            if matched:
                continue
        if any(tok in norm for tok in [
            "pred",
            "score",
            "prob",
            "priority",
            "rank",
            "explain",
            "recommended",
            "expected",
            "uncert",
            "confidence",
            "driver",
            "reason",
            "policy",
            "action",
            "decision",
            "segment",
            "review",
            "flag",
            "cluster",
            "group",
            "optimal",
        ]):
            continue
        scored_extras.append(col)
    if scored_extras:
        sample = ", ".join(scored_extras[:5])
        issues.append(f"scored_rows_unknown_columns:{sample}")

    leakage_path = os.path.join("analysis", "leakage_report.json")
    if os.path.exists(leakage_path):
        try:
            with open(leakage_path, "r", encoding="utf-8") as f_leak:
                leakage_payload = json.load(f_leak)
            leak_cols = _extract_leakage_columns(leakage_payload)
            if leak_cols:
                numeric_cols = cleaned_df.select_dtypes(include=["number"]).columns.tolist()
                numeric_norm = {_norm_name(c) for c in numeric_cols}
                leak_unknown = [
                    c for c in leak_cols if _norm_name(c) not in numeric_norm
                ]
                if leak_unknown:
                    sample = ", ".join(leak_unknown[:5])
                    issues.append(f"leakage_report_unknown_columns:{sample}")
        except Exception as leak_err:
            issues.append(f"leakage_report_read_failed:{leak_err}")

    align_path = os.path.join("data", "alignment_check.json")
    if os.path.exists(align_path):
        try:
            align_payload = _load_json_safe(align_path)
            if isinstance(align_payload, dict):
                for key in ["row_count", "input_rows", "n_rows", "dataset_rows", "total_rows"]:
                    val = align_payload.get(key)
                    if isinstance(val, int) and val != len(cleaned_df):
                        issues.append("alignment_check_rowcount_mismatch")
                        break
        except Exception:
            pass

    return issues

def _hash_json(payload: Any) -> str | None:
    if not payload:
        return None
    try:
        data = json.dumps(payload, sort_keys=True, ensure_ascii=True).encode("utf-8")
        return hashlib.sha256(data).hexdigest()
    except Exception:
        return None

def _hash_file(path: str) -> str | None:
    if not path or not os.path.exists(path):
        return None
    try:
        h = hashlib.sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None

def _extract_weights_from_obj(obj: Any) -> Dict[str, float]:
    if not isinstance(obj, dict):
        return {}
    if isinstance(obj.get("weights"), dict):
        return {str(k): float(v) for k, v in obj["weights"].items() if _is_number(v)}
    if isinstance(obj.get("feature_weights"), dict):
        return {str(k): float(v) for k, v in obj["feature_weights"].items() if _is_number(v)}
    weights = obj.get("weights")
    features = obj.get("features")
    if isinstance(weights, list) and isinstance(features, list) and len(weights) == len(features):
        out = {}
        for idx, feat in enumerate(features):
            val = weights[idx]
            if _is_number(val):
                out[str(feat)] = float(val)
        if out:
            return out
    weights = obj.get("optimized_weights")
    features = obj.get("feature_cols") or obj.get("feature_columns")
    if isinstance(weights, list) and isinstance(features, list) and len(weights) == len(features):
        out = {}
        for idx, feat in enumerate(features):
            val = weights[idx]
            if _is_number(val):
                out[str(feat)] = float(val)
        if out:
            return out
    return {}

def _normalize_metrics_from_weights(weights_obj: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(weights_obj, dict):
        return {}
    metrics = weights_obj.get("metrics") if isinstance(weights_obj.get("metrics"), dict) else {}
    spearman = (
        metrics.get("global_spearman_correlation")
        or metrics.get("spearman_correlation")
        or metrics.get("spearman")
    )
    kendall = metrics.get("kendall_correlation") or metrics.get("kendall_tau")
    case_spearman = (
        metrics.get("case_level_spearman_correlation")
        or metrics.get("case_order_spearman")
    )
    ranking_violations = metrics.get("ranking_violations")
    max_weight = metrics.get("max_weight")
    hhi = metrics.get("weight_hhi")
    near_zero = metrics.get("near_zero_weights") or metrics.get("near_zero_weights_count")
    if spearman is None and kendall is None and case_spearman is None and max_weight is None:
        return {}
    report = {
        "global_ranking": {
            "spearman": float(spearman) if _is_number(spearman) else None,
            "spearman_p": metrics.get("global_spearman_p_value") if metrics else None,
            "kendall_tau": float(kendall) if _is_number(kendall) else None,
        },
        "case_level": {
            "spearman": float(case_spearman) if _is_number(case_spearman) else None,
            "adjacent_violations_pct": None,
            "adjacent_violations_count": int(ranking_violations) if _is_number(ranking_violations) else None,
        },
        "weight_concentration": {
            "max_weight": float(max_weight) if _is_number(max_weight) else None,
            "hhi": float(hhi) if _is_number(hhi) else None,
            "weights_near_zero": int(near_zero) if _is_number(near_zero) else None,
        },
        "baseline_comparison": {},
    }
    return report

def _load_output_dialect_local(manifest_path: str = "") -> Dict[str, str]:
    defaults = {"sep": ",", "decimal": ".", "encoding": "utf-8"}
    manifest = _load_json_safe(manifest_path) or {}
    if isinstance(manifest, dict):
        output_dialect = manifest.get("output_dialect") or {}
        if isinstance(output_dialect, dict):
            return {
                "sep": output_dialect.get("sep", defaults["sep"]),
                "decimal": output_dialect.get("decimal", defaults["decimal"]),
                "encoding": output_dialect.get("encoding", defaults["encoding"]),
            }
    return defaults

def _compute_adjacent_violations(ref_series, score_series) -> int:
    import pandas as pd
    df = pd.DataFrame({"ref": ref_series, "score": score_series}).dropna()
    if df.empty:
        return 0
    df = df.sort_values("ref")
    refs = df["ref"].values
    scores = df["score"].values
    violations = 0
    for idx in range(len(scores) - 1):
        if refs[idx + 1] > refs[idx] and scores[idx + 1] < scores[idx]:
            violations += 1
    return int(violations)

def _compute_metrics_from_scored_rows(
    scored_rows_path: str = "",
    case_summary_path: str = "",
    manifest_path: str = "",
    weights_obj: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    if not os.path.exists(scored_rows_path):
        return {}
    try:
        import pandas as pd
    except Exception:
        return {}
    dialect = _load_output_dialect_local(manifest_path)
    try:
        df = pd.read_csv(
            scored_rows_path,
            sep=dialect["sep"],
            decimal=dialect["decimal"],
            encoding=dialect["encoding"],
        )
    except Exception:
        return {}
    def _pick_column(cols: List[str], tokens: List[str], exclude: List[str] | None = None) -> str | None:
        for col in cols:
            norm = _norm_name(col)
            if exclude and any(tok in norm for tok in exclude):
                continue
            if any(tok in norm for tok in tokens):
                return col
        return None

    cols = list(df.columns)
    score_col = _pick_column(cols, ["score", "pred", "prediction", "prob", "probability", "rank"], ["ref", "target"])
    ref_col = _pick_column(cols, ["ref", "reference", "target", "label", "actual", "rank"], [])
    case_col = _pick_column(cols, ["case", "group", "segment", "bucket", "cluster"], [])
    if not score_col or not ref_col:
        return {}

    ref_series = pd.to_numeric(df[ref_col], errors="coerce")
    score_series = pd.to_numeric(df[score_col], errors="coerce")
    spearman = None
    kendall = None
    try:
        spearman = float(ref_series.corr(score_series, method="spearman"))
        kendall = float(ref_series.corr(score_series, method="kendall"))
    except Exception:
        pass

    case_spearman = None
    adjacent_violations = None
    if case_col and case_col in df.columns:
        try:
            case_means = (
                df[[case_col, score_col, ref_col]]
                .copy()
                .groupby(case_col)
                .agg({score_col: "mean", ref_col: "first"})
                .reset_index()
            )
            ref_case = pd.to_numeric(case_means[ref_col], errors="coerce")
            score_case = pd.to_numeric(case_means[score_col], errors="coerce")
            case_spearman = float(ref_case.corr(score_case, method="spearman"))
            adjacent_violations = _compute_adjacent_violations(ref_case, score_case)
        except Exception:
            pass

    weights = _extract_weights_from_obj(weights_obj or {})
    weight_metrics = {
        "max_weight": None,
        "hhi": None,
        "weights_near_zero": None,
    }
    if weights:
        vals = list(weights.values())
        try:
            max_weight = max(vals)
            hhi = sum(v ** 2 for v in vals)
            near_zero = sum(1 for v in vals if v < 0.01)
            weight_metrics = {
                "max_weight": float(max_weight),
                "hhi": float(hhi),
                "weights_near_zero": int(near_zero),
            }
        except Exception:
            pass

    return {
        "global_ranking": {
            "spearman": spearman,
            "spearman_p": None,
            "kendall_tau": kendall,
        },
        "case_level": {
            "spearman": case_spearman,
            "adjacent_violations_pct": None,
            "adjacent_violations_count": int(adjacent_violations) if adjacent_violations is not None else None,
        },
        "weight_concentration": weight_metrics,
        "baseline_comparison": {},
    }

def _is_number(value: Any) -> bool:
    try:
        float(value)
        return True
    except Exception:
        return False

def _infer_objective_signature(code: str) -> Dict[str, Any]:
    if not code:
        return {}
    lower = code.lower()
    optimizer = None
    for opt in ("linprog", "slsqp", "minimize", "cobyla", "trust-constr", "differential_evolution"):
        if opt in lower:
            optimizer = opt
            break
    terms = []
    for token in (
        "case_order_violations",
        "adjacent_refscore_violations",
        "case_spearman",
        "case_level",
        "case_means",
        "kendall",
        "spearman",
        "rank_correlation",
        "violation",
        "penalty",
        "regularization",
    ):
        if token in lower and token not in terms:
            terms.append(token)
    code_hash = hashlib.sha256(code.encode("utf-8", errors="replace")).hexdigest()[:10]
    return {"optimizer": optimizer or "unknown", "terms": terms[:6], "code_hash": code_hash}

def _format_metric_delta(label: str, prev: Any, curr: Any) -> str:
    if prev is None or curr is None:
        return f"{label}: {curr}"
    try:
        delta = float(curr) - float(prev)
        return f"{label}: {prev} -> {curr} (delta {delta:+.4f})"
    except Exception:
        return f"{label}: {prev} -> {curr}"

def _extract_metrics_snapshot(metrics_report: Dict[str, Any], weights_report: Dict[str, Any]) -> Dict[str, Any]:
    snapshot: Dict[str, Any] = {}
    if isinstance(metrics_report, dict):
        global_ranking = metrics_report.get("global_ranking", {})
        if isinstance(global_ranking, dict) and _is_number(global_ranking.get("spearman")):
            snapshot["global_spearman"] = float(global_ranking["spearman"])
    if not isinstance(weights_report, dict):
        return snapshot
    propensity = weights_report.get("propensity_model")
    if isinstance(propensity, dict):
        for key in ("auc_cv_mean", "auc_cv_std", "baseline_auc", "improvement_pct"):
            value = propensity.get(key)
            if _is_number(value):
                snapshot[f"propensity_{key}"] = float(value)
        if "calibrated" in propensity:
            snapshot["propensity_calibrated"] = bool(propensity.get("calibrated"))
    price = weights_report.get("price_model")
    if isinstance(price, dict):
        for key in ("mae_cv_mean", "mape_cv_mean", "baseline_mae", "improvement_pct"):
            value = price.get(key)
            if _is_number(value):
                snapshot[f"price_{key}"] = float(value)
        model_type = price.get("model_type")
        if isinstance(model_type, str):
            snapshot["price_model_type"] = model_type
    optimization = weights_report.get("optimization")
    if isinstance(optimization, dict):
        for key in ("total_typologies", "high_value_threshold", "low_value_threshold"):
            value = optimization.get(key)
            if _is_number(value):
                snapshot[f"optimization_{key}"] = float(value)
    return snapshot

def _normalize_metric_key(name: str) -> str:
    return re.sub(r"[^0-9a-zA-Z]+", "", str(name).lower())

def _is_baseline_metric_name(name: str) -> bool:
    key = _normalize_metric_key(name)
    return any(token in key for token in ["baseline", "dummy", "naive", "null", "default"])

_BASELINE_NULL_STRINGS = {"", "na", "n/a", "nan", "null", "none", "nat"}


def _resolve_primary_target_column(
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
) -> str | None:
    if isinstance(evaluation_spec, dict):
        for key in ("target", "target_column", "target_name", "outcome", "label"):
            val = evaluation_spec.get(key)
            if isinstance(val, list) and val:
                val = val[0]
            if isinstance(val, str) and val.strip():
                return val
        outcome_cols = evaluation_spec.get("outcome_columns")
        if isinstance(outcome_cols, list) and outcome_cols:
            if isinstance(outcome_cols[0], str) and outcome_cols[0].strip():
                return outcome_cols[0]
    for source in (contract_min, contract):
        if not isinstance(source, dict):
            continue
        outcome_cols = get_outcome_columns(source)
        if outcome_cols:
            return outcome_cols[0]
        for key in ("target_column", "target", "outcome"):
            val = source.get(key)
            if isinstance(val, str) and val.strip():
                return val
    return None


def _baseline_metric_type(metric_name: str) -> str | None:
    norm = _normalize_metric_key(metric_name)
    if not norm:
        return None
    if "rmsle" in norm:
        return "rmsle"
    if "rmse" in norm:
        return "rmse"
    if "auc" in norm:
        return "auc"
    if "gini" in norm:
        return "gini"
    if "accuracy" in norm or norm.endswith("acc"):
        return "accuracy"
    return None


def _baseline_margin(metric_type: str) -> float:
    if metric_type == "accuracy":
        return 0.02
    if metric_type == "auc":
        return 0.01
    return 1e-4


def _scan_target_for_baseline(
    csv_path: str,
    dialect: Dict[str, Any],
    target_col: str,
    metric_type: str,
    chunksize: int = 200000,
) -> Dict[str, Any]:
    if not csv_path or not target_col or not metric_type:
        return {}
    sep = dialect.get("sep") or ","
    decimal = dialect.get("decimal") or "."
    encoding = dialect.get("encoding") or "utf-8"
    try:
        header = pd.read_csv(csv_path, nrows=0, sep=sep, decimal=decimal, encoding=encoding)
        if target_col not in header.columns:
            return {}
    except Exception:
        return {}

    if metric_type == "auc":
        return {"baseline": 0.5}
    if metric_type == "gini":
        return {"baseline": 0.0}

    try:
        reader = pd.read_csv(
            csv_path,
            usecols=[target_col],
            sep=sep,
            decimal=decimal,
            encoding=encoding,
            dtype="string",
            keep_default_na=False,
            chunksize=max(1, int(chunksize)),
            low_memory=False,
        )
    except Exception:
        return {}

    total_count = 0
    label_counts: Dict[str, int] = {}
    mean = 0.0
    m2 = 0.0

    for chunk in reader:
        if target_col not in chunk.columns:
            continue
        series = chunk[target_col]
        cleaned = series.astype("string").str.strip()
        lowered = cleaned.str.lower()
        missing_mask = series.isna() | (lowered == "") | lowered.isin(_BASELINE_NULL_STRINGS)
        values = cleaned[~missing_mask]
        if values.empty:
            continue

        if metric_type == "accuracy":
            total_count += int(values.shape[0])
            counts = values.value_counts()
            for label, count in counts.items():
                label_counts[str(label)] = label_counts.get(str(label), 0) + int(count)
            continue

        numeric_strings = values
        if decimal and decimal != ".":
            numeric_strings = numeric_strings.str.replace(decimal, ".", regex=False)
        numeric = pd.to_numeric(numeric_strings, errors="coerce").dropna()
        if metric_type == "rmsle":
            numeric = numeric[numeric >= 0]
            if not numeric.empty:
                numeric = numeric.map(math.log1p)
        if numeric.empty:
            continue
        for val in numeric.tolist():
            total_count += 1
            delta = float(val) - mean
            mean += delta / total_count
            delta2 = float(val) - mean
            m2 += delta * delta2

    if metric_type == "accuracy":
        if total_count <= 0 or not label_counts:
            return {}
        baseline = max(label_counts.values()) / total_count
        return {"baseline": float(baseline), "n_rows": int(total_count), "n_classes": len(label_counts)}

    if total_count <= 0:
        return {}
    variance = m2 / total_count if total_count else 0.0
    baseline = math.sqrt(max(variance, 0.0))
    return {"baseline": float(baseline), "n_rows": int(total_count)}


def _evaluate_baseline_sanity_check(
    state: Dict[str, Any],
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
    contract_min: Dict[str, Any] | None,
    primary_metric_snapshot: Dict[str, Any] | None,
) -> Dict[str, Any]:
    snapshot = primary_metric_snapshot if isinstance(primary_metric_snapshot, dict) else {}
    metric_name = snapshot.get("primary_metric_name")
    metric_value = snapshot.get("primary_metric_value")
    if not metric_name or not _is_number(metric_value):
        return {}
    metric_type = _baseline_metric_type(str(metric_name))
    if not metric_type:
        return {}
    target_col = _resolve_primary_target_column(evaluation_spec, contract, contract_min)
    if not target_col:
        return {}
    csv_path = state.get("ml_data_path")
    if not isinstance(csv_path, str) or not csv_path or not os.path.exists(csv_path):
        return {}
    dialect = {
        "sep": state.get("csv_sep") or ",",
        "decimal": state.get("csv_decimal") or ".",
        "encoding": state.get("csv_encoding") or "utf-8",
    }
    baseline_info = _scan_target_for_baseline(csv_path, dialect, target_col, metric_type)
    baseline_value = baseline_info.get("baseline")
    if not _is_number(baseline_value):
        return {}
    margin = _baseline_margin(metric_type)
    higher_is_better = _metric_higher_is_better(str(metric_name))
    if higher_is_better:
        threshold = float(baseline_value) + margin
        failed = float(metric_value) <= threshold
        comparator = "<="
    else:
        threshold = float(baseline_value) - margin
        failed = float(metric_value) >= threshold
        comparator = ">="
    return {
        "failed": failed,
        "metric_name": str(metric_name),
        "metric_value": float(metric_value),
        "baseline_value": float(baseline_value),
        "margin": float(margin),
        "threshold": float(threshold),
        "comparator": comparator,
        "metric_type": metric_type,
        "target_col": target_col,
        "data_path": csv_path,
        "rows_used": baseline_info.get("n_rows"),
    }

def _objective_metric_priority(objective_type: str) -> List[str]:
    objective = str(objective_type or "unknown").lower()
    if "classif" in objective:
        return ["roc_auc", "auc", "f1", "precision", "recall", "accuracy", "pr_auc"]
    if "regress" in objective or "forecast" in objective:
        return ["rmse", "mae", "mape", "smape", "r2", "mse"]
    if "rank" in objective:
        return ["spearman", "kendall", "ndcg", "map", "mrr", "gini"]
    return ["roc_auc", "f1", "rmse", "mae", "r2", "spearman"]

def _coerce_float(value: Any) -> float | None:
    if _is_number(value):
        return float(value)
    return None


def _is_governance_metric_candidate(name: Any) -> bool:
    normalized = _normalize_metric_key(name)
    if not normalized:
        return False
    blocked_tokens = (
        "qagates",
        "reviewergates",
        "submissionschema",
        "outputcontract",
        "alignmentcheck",
        "casealignment",
        "integrityaudit",
        "requiredartifacts",
        "schemaissues",
    )
    return any(token in normalized for token in blocked_tokens)


def _collect_metric_candidates(metrics_report: Dict[str, Any], weights_report: Dict[str, Any]) -> List[Dict[str, Any]]:
    candidates: List[Dict[str, Any]] = []

    def _append_candidate(
        name: str,
        value: Any,
        ci_lower: Any = None,
        ci_upper: Any = None,
    ) -> None:
        metric_name = str(name or "").strip()
        num = _coerce_float(value)
        if not metric_name or num is None or _is_governance_metric_candidate(metric_name):
            return
        candidates.append(
            {
                "name": metric_name,
                "value": num,
                "ci_lower": _coerce_float(ci_lower),
                "ci_upper": _coerce_float(ci_upper),
                "is_baseline": _is_baseline_metric_name(metric_name),
            }
        )

    def _walk_metric_tree(prefix: str, node: Any, depth: int = 0) -> None:
        if depth > 3:
            return
        if isinstance(node, dict):
            # Standard metric containers: {"mean": x} or {"value": x}
            if prefix:
                _append_candidate(prefix, node.get("mean"), node.get("ci_lower"), node.get("ci_upper"))
                _append_candidate(prefix, node.get("value"), node.get("ci_lower"), node.get("ci_upper"))
                metric_alias = node.get("name") or node.get("metric")
                if metric_alias:
                    _append_candidate(str(metric_alias), node.get("value"), node.get("ci_lower"), node.get("ci_upper"))
            # Flatten nested metric trees (e.g., secondary_metrics.MAE, segmentation.by_vendor.n_vendors)
            ignored_keys = {
                "mean",
                "value",
                "name",
                "metric",
                "ci_lower",
                "ci_upper",
                "std",
                "stdev",
                "std_dev",
                "threshold",
                "status",
            }
            for child_key, child_val in node.items():
                if str(child_key) in ignored_keys:
                    continue
                child_prefix = f"{prefix}.{child_key}" if prefix else str(child_key)
                _walk_metric_tree(child_prefix, child_val, depth + 1)
            return
        _append_candidate(prefix, node)

    model_perf = metrics_report.get("model_performance") if isinstance(metrics_report, dict) else {}
    if isinstance(model_perf, dict):
        for key, value in model_perf.items():
            _walk_metric_tree(str(key), value)
    if isinstance(metrics_report, dict):
        generic_metrics = _extract_metric_like_numbers(metrics_report)
        for key, value in generic_metrics.items():
            _append_candidate(str(key), value)
    if isinstance(weights_report, dict):
        for container in ("metrics", "classification", "regression", "propensity_model", "price_model", "optimization"):
            block = weights_report.get(container)
            if not isinstance(block, dict):
                continue
            for key, value in block.items():
                num = _coerce_float(value)
                if num is None:
                    continue
                candidates.append(
                    {
                        "name": str(key),
                        "value": num,
                        "ci_lower": None,
                        "ci_upper": None,
                        "is_baseline": _is_baseline_metric_name(str(key)),
                    }
                )
    return candidates

def _pick_primary_metric_candidate(
    candidates: List[Dict[str, Any]],
    objective_type: str,
) -> Dict[str, Any] | None:
    if not candidates:
        return None
    priority = _objective_metric_priority(objective_type)
    with_ci = [c for c in candidates if c.get("ci_lower") is not None and c.get("ci_upper") is not None]
    search_pool = with_ci if with_ci else candidates
    for token in priority:
        for cand in search_pool:
            if token in _normalize_metric_key(cand.get("name", "")):
                return cand
    return search_pool[0]

def _resolve_validation_requirements(
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> Dict[str, Any]:
    if isinstance(evaluation_spec, dict):
        val = evaluation_spec.get("validation_requirements")
        if isinstance(val, dict):
            return val
    if isinstance(contract, dict):
        val = get_validation_requirements(contract)
        if isinstance(val, dict):
            return val
    return {}

def _build_eval_signature(
    objective_type: str | None,
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> str:
    validation = _resolve_validation_requirements(evaluation_spec, contract)
    method = str(validation.get("method") or "unknown").strip().lower()
    n_folds = validation.get("n_folds") or validation.get("folds")
    n_boot = validation.get("n_bootstrap") or validation.get("n_boot") or validation.get("bootstrap_iterations")
    seed = validation.get("seed") or validation.get("random_state")
    parts = [
        f"objective_type={objective_type or 'unknown'}",
        f"method={method or 'unknown'}",
    ]
    if n_folds is not None:
        parts.append(f"n_folds={n_folds}")
    if n_boot is not None:
        parts.append(f"n_boot={n_boot}")
    if seed is not None:
        parts.append(f"seed={seed}")
    return ";".join(parts)

def _extract_primary_metric_snapshot(
    metrics_report: Dict[str, Any] | None,
    weights_report: Dict[str, Any] | None,
    objective_type: str | None,
    evaluation_spec: Dict[str, Any] | None,
    contract: Dict[str, Any] | None,
) -> Dict[str, Any]:
    primary_state = _build_primary_metric_state(
        state={"evaluation_spec": evaluation_spec or {}, "execution_contract": contract or {}},
        metrics_report=metrics_report if isinstance(metrics_report, dict) else {},
        weights_report=weights_report if isinstance(weights_report, dict) else {},
        objective_type=objective_type,
        evaluation_spec=evaluation_spec,
        contract=contract,
    )
    if not primary_state:
        return {}
    return {
        "primary_metric_name": primary_state.get("primary_metric_name"),
        "primary_metric_canonical_name": primary_state.get("primary_metric_canonical_name"),
        "primary_metric_value": primary_state.get("primary_metric_value"),
        "primary_metric_source": primary_state.get("primary_metric_source"),
        "primary_metric_path": primary_state.get("primary_metric_path"),
        "baseline_metric_name": primary_state.get("baseline_metric_name"),
        "baseline_value": primary_state.get("baseline_value"),
        "lift": primary_state.get("lift"),
        "ci_lower": primary_state.get("ci_lower"),
        "ci_upper": primary_state.get("ci_upper"),
        "higher_is_better": primary_state.get("higher_is_better"),
        "eval_signature": primary_state.get("eval_signature") or _build_eval_signature(objective_type, evaluation_spec, contract),
        "source": primary_state.get("primary_metric_source"),
        "matched_key": primary_state.get("primary_metric_path"),
    }

def _detect_metric_plateau(
    metric_history: List[Dict[str, Any]] | None,
    window: int = 2,
    epsilon: float = 0.01,
) -> tuple[bool, str]:
    history = [item for item in (metric_history or []) if isinstance(item, dict)]
    if len(history) < window:
        return False, ""
    last = history[-1]
    signature = last.get("eval_signature") or "unknown"
    metric_name = last.get("primary_metric_name")
    comparable = []
    for item in history:
        if metric_name and item.get("primary_metric_name") != metric_name:
            continue
        if signature != "unknown" and item.get("eval_signature") != signature:
            continue
        comparable.append(item)
    if len(comparable) < window:
        return False, ""
    recent = comparable[-window:]
    lifts = [item.get("lift") for item in recent]
    if all(isinstance(val, (int, float)) for val in lifts):
        if all(val < epsilon for val in lifts):
            return True, f"lift<{epsilon} for {window} iterations"
    values = []
    ci_pairs = []
    for item in recent:
        val = item.get("primary_metric_value")
        if not isinstance(val, (int, float)):
            return False, ""
        values.append(float(val))
        ci_pairs.append((item.get("ci_lower"), item.get("ci_upper")))
    higher_is_better = True
    if metric_name:
        higher_is_better = _metric_higher_is_better(metric_name)
    any_ci = False
    all_ci_overlap = True
    improvements: List[float] = []
    for idx in range(1, len(values)):
        if higher_is_better:
            delta = values[idx] - values[idx - 1]
        else:
            delta = values[idx - 1] - values[idx]
        improvements.append(delta)
        low1, up1 = ci_pairs[idx - 1]
        low2, up2 = ci_pairs[idx]
        if _is_number(low1) and _is_number(up1) and _is_number(low2) and _is_number(up2):
            any_ci = True
            if max(float(low1), float(low2)) > min(float(up1), float(up2)):
                all_ci_overlap = False
    if improvements and all(delta <= epsilon for delta in improvements):
        if not any_ci or all_ci_overlap:
            return True, f"metric_delta<= {epsilon} across {window} iterations"
    return False, ""

def _append_feedback_history(state: Dict[str, Any], message: str) -> None:
    if not message:
        return
    history = list(state.get("feedback_history", []) or [])
    if message not in history:
        history.append(message)
    state["feedback_history"] = history


def _normalize_review_consistency_signals(signals: Any) -> Dict[str, Any]:
    if not isinstance(signals, dict):
        return {}
    normalized: Dict[str, Any] = {}
    for raw_key, raw_value in signals.items():
        key = str(raw_key or "").strip()
        payload = raw_value if isinstance(raw_value, dict) else {}
        if not key or not payload:
            continue
        signal: Dict[str, Any] = {}
        note = str(payload.get("note") or "").strip()
        if note:
            signal["note"] = _truncate_handoff_text(note, max_len=400)
        source = str(payload.get("source") or "").strip()
        if source:
            signal["source"] = source
        if "preserve_llm_status" in payload:
            signal["preserve_llm_status"] = bool(payload.get("preserve_llm_status"))
        if "blocking_eval" in payload:
            signal["blocking_eval"] = bool(payload.get("blocking_eval"))
        evaluator_status = str(payload.get("evaluator_status") or "").strip()
        if evaluator_status:
            signal["evaluator_status"] = evaluator_status
        for list_key in (
            "implied_hard_gate_failures",
            "hard_blockers",
            "failed_gates",
            "required_fixes",
        ):
            values = _normalize_handoff_items(payload.get(list_key), max_items=12, max_len=220)
            if values:
                signal[list_key] = values
        if signal:
            normalized[key] = signal
    return normalized


def _attach_review_consistency_signal(
    packet: Dict[str, Any] | None,
    *,
    signal_key: str,
    note: str,
    source: str,
    implied_hard_gate_failures: List[str] | None = None,
    hard_blockers: List[str] | None = None,
    failed_gates: List[str] | None = None,
    required_fixes: List[str] | None = None,
    evaluator_status: str = "",
    blocking_eval: bool | None = None,
) -> Dict[str, Any]:
    normalized = dict(packet or {})
    warnings = _normalize_handoff_items(normalized.get("warnings"), max_items=12, max_len=220)
    warning_note = _truncate_handoff_text(note, max_len=220)
    if warning_note and warning_note not in warnings:
        warnings.append(warning_note)
    if warnings:
        normalized["warnings"] = warnings[:12]

    signals = _normalize_review_consistency_signals(normalized.get("consistency_signals"))
    signal_payload = dict(signals.get(signal_key) or {})
    if warning_note:
        signal_payload["note"] = warning_note
    signal_payload["source"] = str(source or signal_key)
    signal_payload["preserve_llm_status"] = True
    if implied_hard_gate_failures:
        signal_payload["implied_hard_gate_failures"] = _normalize_handoff_items(
            implied_hard_gate_failures,
            max_items=10,
            max_len=180,
        )
    if hard_blockers:
        signal_payload["hard_blockers"] = _normalize_handoff_items(
            hard_blockers,
            max_items=10,
            max_len=180,
        )
    if failed_gates:
        signal_payload["failed_gates"] = _normalize_handoff_items(
            failed_gates,
            max_items=10,
            max_len=180,
        )
    if required_fixes:
        signal_payload["required_fixes"] = _normalize_handoff_items(
            required_fixes,
            max_items=10,
            max_len=220,
        )
    if evaluator_status:
        signal_payload["evaluator_status"] = str(evaluator_status)
    if blocking_eval is not None:
        signal_payload["blocking_eval"] = bool(blocking_eval)
    signals[signal_key] = signal_payload
    normalized["consistency_signals"] = signals
    return normalized


def _build_feedback_packet_snapshot(packet: Dict[str, Any] | None) -> Dict[str, Any]:
    packet = packet if isinstance(packet, dict) else {}
    snapshot = {
        "status": str(packet.get("status") or "UNKNOWN"),
        "feedback": _truncate_handoff_text(packet.get("feedback"), max_len=1400),
        "failed_gates": _normalize_handoff_items(packet.get("failed_gates"), max_items=12, max_len=180),
        "required_fixes": _normalize_handoff_items(packet.get("required_fixes"), max_items=12, max_len=220),
        "hard_failures": _normalize_handoff_items(packet.get("hard_failures"), max_items=12, max_len=180),
    }
    warnings = _normalize_handoff_items(packet.get("warnings"), max_items=10, max_len=220)
    if warnings:
        snapshot["warnings"] = warnings
    consistency_signals = _normalize_review_consistency_signals(packet.get("consistency_signals"))
    if consistency_signals:
        snapshot["consistency_signals"] = consistency_signals
    return snapshot


def _normalize_review_packet_for_state(
    packet: Dict[str, Any] | None,
    *,
    default_status: str = "UNKNOWN",
) -> Dict[str, Any]:
    packet = packet if isinstance(packet, dict) else {}
    if not packet and default_status == "UNKNOWN":
        return {}
    normalized = _build_feedback_packet_snapshot(packet)
    status = normalized.get("status") or default_status
    if str(status or "").upper() != "UNKNOWN":
        normalized["status"] = _normalize_review_status(str(status))
    else:
        normalized["status"] = str(default_status or "UNKNOWN")
    normalized["warnings"] = _normalize_handoff_items(packet.get("warnings"), max_items=10, max_len=220)
    normalized["soft_failures"] = _normalize_handoff_items(packet.get("soft_failures"), max_items=12, max_len=180)
    if isinstance(packet.get("qa_gates_evaluated"), list):
        normalized["qa_gates_evaluated"] = _normalize_handoff_items(
            packet.get("qa_gates_evaluated"),
            max_items=20,
            max_len=160,
        )
    if isinstance(packet.get("contract_source_used"), str):
        normalized["contract_source_used"] = str(packet.get("contract_source_used") or "")
    if isinstance(packet.get("improvement_suggestions"), dict):
        normalized["improvement_suggestions"] = packet.get("improvement_suggestions")
    if "retry_worth_it" in packet:
        normalized["retry_worth_it"] = bool(packet.get("retry_worth_it"))
    if isinstance(packet.get("json_parse_trace"), dict):
        normalized["json_parse_trace"] = packet.get("json_parse_trace")
    if isinstance(packet.get("evidence"), list):
        normalized["evidence"] = _normalize_handoff_evidence(packet.get("evidence"), max_items=10)
    return normalized


def _build_ml_feedback_json(
    *,
    source: str,
    status: str,
    feedback: str | None,
    failed_gates: List[str] | None,
    required_fixes: List[str] | None,
    hard_failures: List[str] | None = None,
    review_result: Dict[str, Any] | None = None,
    qa_result: Dict[str, Any] | None = None,
    evidence: List[Dict[str, str]] | None = None,
    repair_hints: List[str] | None = None,
) -> Dict[str, Any]:
    payload = {
        "version": "v1",
        "source": str(source or "unknown"),
        "status": str(status or "UNKNOWN"),
        "summary": _truncate_handoff_text(feedback, max_len=1800),
        "failed_gates": _normalize_handoff_items(failed_gates, max_items=20, max_len=180),
        "required_fixes": _normalize_handoff_items(required_fixes, max_items=20, max_len=220),
        "hard_failures": _normalize_handoff_items(hard_failures, max_items=15, max_len=180),
        "reviewer_packet": _build_feedback_packet_snapshot(review_result),
        "qa_packet": _build_feedback_packet_snapshot(qa_result),
        "evidence": _normalize_handoff_evidence(evidence, max_items=10),
        "repair_hints": _normalize_handoff_items(repair_hints, max_items=2, max_len=220),
    }
    return payload


def _normalize_feedback_record_payload(record: Dict[str, Any] | None) -> Dict[str, Any]:
    if not isinstance(record, dict):
        return {}
    normalized = {
        "agent": str(record.get("agent") or "unknown"),
        "source": str(record.get("source") or "unknown"),
        "status": str(record.get("status") or "UNKNOWN"),
        "iteration": int(record.get("iteration") or 0),
        "feedback": str(record.get("feedback") or ""),
        "failed_gates": [str(x) for x in (record.get("failed_gates") or []) if x],
        "required_fixes": [str(x) for x in (record.get("required_fixes") or []) if x],
        "hard_failures": [str(x) for x in (record.get("hard_failures") or []) if x],
        "runtime_error_tail": str(record.get("runtime_error_tail") or ""),
        "evidence": _normalize_handoff_evidence(record.get("evidence"), max_items=10),
    }
    normalized["failed_gates"] = list(dict.fromkeys(normalized["failed_gates"]))[:20]
    normalized["required_fixes"] = list(dict.fromkeys(normalized["required_fixes"]))[:20]
    normalized["hard_failures"] = list(dict.fromkeys(normalized["hard_failures"]))[:15]
    if len(normalized["feedback"]) > 2400:
        normalized["feedback"] = normalized["feedback"][:2400]
    if len(normalized["runtime_error_tail"]) > 1400:
        normalized["runtime_error_tail"] = normalized["runtime_error_tail"][:1400]
    return normalized


def _build_latest_feedback_record_block(record: Dict[str, Any] | None) -> str:
    normalized = _normalize_feedback_record_payload(record)
    if not normalized:
        return ""
    return "LATEST_ITERATION_FEEDBACK_RECORD_JSON:\n" + json.dumps(normalized, ensure_ascii=True, indent=2)


def _parse_failure_explainer_sections(text: str) -> Dict[str, List[str] | str]:
    parsed: Dict[str, Any] = {
        "where": "",
        "why": "",
        "fixes": [],
        "diagnostics": [],
    }
    raw = str(text or "")
    if not raw.strip():
        return parsed

    for raw_line in raw.splitlines():
        line = str(raw_line or "").strip()
        if not line or ":" not in line:
            continue
        label, value = line.split(":", 1)
        label_norm = str(label or "").strip().upper()
        value_text = str(value or "").strip(" -\t")
        if not value_text:
            continue
        if label_norm == "WHERE" and not parsed["where"]:
            parsed["where"] = value_text
        elif label_norm == "WHY" and not parsed["why"]:
            parsed["why"] = value_text
        elif label_norm == "FIX":
            parsed["fixes"].append(value_text)
        elif label_norm == "DIAGNOSTIC":
            parsed["diagnostics"].append(value_text)

    parsed["fixes"] = list(dict.fromkeys([str(x) for x in parsed["fixes"] if str(x).strip()]))[:6]
    parsed["diagnostics"] = list(dict.fromkeys([str(x) for x in parsed["diagnostics"] if str(x).strip()]))[:4]
    return parsed


def _extract_de_failure_explainer_fix_hints(text: str) -> List[str]:
    parsed = _parse_failure_explainer_sections(text)
    hints: List[str] = []
    for item in parsed.get("fixes") or []:
        hints.append(str(item))
    diagnostics = parsed.get("diagnostics") or []
    if diagnostics:
        hints.append(f"Use this minimal diagnostic if needed: {diagnostics[0]}")
    return list(dict.fromkeys([str(x) for x in hints if str(x).strip()]))[:8]


def _append_de_failure_explainer_context(payload: str, explainer_text: str) -> tuple[str, List[str]]:
    payload_text = str(payload or "")
    explainer = str(explainer_text or "").strip()
    if not explainer:
        return payload_text, []
    payload_text += "\nLLM_FAILURE_EXPLANATION:\n" + explainer
    repair_hints = _extract_de_failure_explainer_fix_hints(explainer)
    if repair_hints:
        payload_text += "\nREPAIR_HINTS:\n- " + "\n- ".join(repair_hints)
    return payload_text, repair_hints


def _set_latest_feedback_record(
    state: Dict[str, Any],
    *,
    agent: str,
    source: str,
    status: str,
    iteration: int,
    feedback: str = "",
    failed_gates: List[str] | None = None,
    required_fixes: List[str] | None = None,
    hard_failures: List[str] | None = None,
    runtime_error_tail: str = "",
    evidence: List[Dict[str, str]] | None = None,
) -> Dict[str, Any]:
    record = _normalize_feedback_record_payload(
        {
            "agent": agent,
            "source": source,
            "status": status,
            "iteration": iteration,
            "feedback": feedback,
            "failed_gates": failed_gates or [],
            "required_fixes": required_fixes or [],
            "hard_failures": hard_failures or [],
            "runtime_error_tail": runtime_error_tail,
            "evidence": evidence or [],
        }
    )
    if not record:
        return {}
    key = "data_engineer_feedback_record" if str(agent).lower() == "data_engineer" else "ml_feedback_record"
    state[key] = record
    return record


def _build_review_progress_tracker(state: Dict[str, Any] | None) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    tracker: Dict[str, Any] = {"available": False}
    metric_history = state.get("metric_history")
    if not isinstance(metric_history, list) or len(metric_history) < 2:
        return tracker
    last_two = [item for item in metric_history if isinstance(item, dict)][-2:]
    if len(last_two) < 2:
        return tracker
    prev, curr = last_two[0], last_two[1]
    prev_name = str(prev.get("primary_metric_name") or "")
    curr_name = str(curr.get("primary_metric_name") or "")
    prev_val = prev.get("primary_metric_value")
    curr_val = curr.get("primary_metric_value")
    if not (prev_name and curr_name and prev_name == curr_name and _is_number(prev_val) and _is_number(curr_val)):
        return tracker
    higher_is_better = _metric_higher_is_better(curr_name)
    delta = float(curr_val) - float(prev_val)
    improved = delta > 0 if higher_is_better else delta < 0
    tracker.update(
        {
            "available": True,
            "metric_name": curr_name,
            "previous_value": float(prev_val),
            "current_value": float(curr_val),
            "delta": delta,
            "higher_is_better": higher_is_better,
            "improved": bool(improved),
        }
    )
    return tracker


def _merge_de_override_with_feedback_record(
    new_state: Dict[str, Any],
    *,
    base_override: str,
    payload: str,
    source: str,
    status: str,
    iteration: int,
    feedback: str,
    failed_gates: List[str] | None = None,
    required_fixes: List[str] | None = None,
    hard_failures: List[str] | None = None,
    runtime_error_tail: str = "",
    evidence: List[Dict[str, str]] | None = None,
) -> None:
    merged = _merge_de_audit_override(base_override, payload)
    de_record = _set_latest_feedback_record(
        new_state,
        agent="data_engineer",
        source=source,
        status=status,
        iteration=int(iteration or 0),
        feedback=str(feedback or ""),
        failed_gates=[str(x) for x in (failed_gates or []) if str(x).strip()],
        required_fixes=[str(x) for x in (required_fixes or []) if str(x).strip()],
        hard_failures=[str(x) for x in (hard_failures or []) if str(x).strip()],
        runtime_error_tail=str(runtime_error_tail or "")[:1400],
        evidence=_normalize_handoff_evidence(evidence, max_items=8),
    )
    if de_record:
        merged = _merge_de_audit_override(merged, _build_latest_feedback_record_block(de_record))
    new_state["data_engineer_audit_override"] = merged

def _normalize_reason_tags(text: str, failed_gates: List[str] | None = None) -> List[str]:
    tags: List[str] = []
    lower = str(text or "").lower()
    gate_tokens = [str(item).lower() for item in (failed_gates or []) if item]
    combined = " ".join([lower] + gate_tokens)
    mapping = [
        ("synthetic", "synthetic"),
        ("df_column_assignment_forbidden", "df_mutation"),
        ("df_column", "df_mutation"),
        ("unknown_columns_referenced", "unknown_columns"),
        ("unknown column", "unknown_columns"),
        ("imputer", "imputer_missing"),
        ("output_contract_missing", "contract_missing_outputs"),
        ("required_outputs_missing", "contract_missing_outputs"),
        ("missing output", "contract_missing_outputs"),
        ("time_series", "time_series_split"),
        ("cross_validation_required", "validation_missing"),
        ("validation_required", "validation_missing"),
        ("alignment", "alignment"),
        ("method_choice", "method_choice"),
        ("data_limited", "data_limited"),
        ("variance guard", "target_variance_guard"),
    ]
    for token, tag in mapping:
        if token in combined and tag not in tags:
            tags.append(tag)
    baseline_missing_patterns = (
        "baseline missing",
        "missing baseline",
        "baseline_check_failed",
        "without baseline",
        "no baseline",
        "dummyclassifier missing",
        "dummyregressor missing",
    )
    if any(pattern in combined for pattern in baseline_missing_patterns) and "baseline_missing" not in tags:
        tags.append("baseline_missing")
    leakage_positive_patterns = (
        "prevents data leakage",
        "prevent data leakage",
        "leakage is prevented",
        "data leakage is prevented",
        "excluding forbidden columns",
        "exclude forbidden columns",
    )
    leakage_negative_patterns = (
        "leakage risk",
        "leakage detected",
        "leakage guard",
        "target leakage",
        "post-outcome",
        "leakage_prevention",
        "target_encoding_leakage_guard",
        "deterministic_target_relation",
    )
    if (
        any(pattern in combined for pattern in leakage_negative_patterns)
        or ("leakage" in combined and _gate_failure_language_detected(combined))
    ) and not any(pattern in combined for pattern in leakage_positive_patterns):
        if "leakage" not in tags:
            tags.append("leakage")
    return tags


def _normalize_review_status(status: str | None) -> str:
    if not status:
        return "APPROVE_WITH_WARNINGS"
    upper = str(status).strip().upper()
    if upper in {"APPROVED", "APPROVE_WITH_WARNINGS", "REJECTED"}:
        return upper
    if upper in {"PASS", "OK", "SUCCESS"}:
        return "APPROVED"
    if upper in {"WARN", "WARNING"}:
        return "APPROVE_WITH_WARNINGS"
    if upper in {"NEEDS_IMPROVEMENT", "FAIL", "FAILED", "REJECT"}:
        return "REJECTED"
    if any(tok in upper for tok in ["REJECT", "FAIL", "ERROR", "CRASH"]):
        return "REJECTED"
    return "APPROVE_WITH_WARNINGS"


def _normalize_review_feedback(feedback: str | None, status: str) -> str:
    text = str(feedback or "").strip()
    if not text:
        return text
    if status in {"APPROVED", "APPROVE_WITH_WARNINGS"}:
        text = re.sub(r"\brejected\b", "resolved", text, flags=re.IGNORECASE)
        text = re.sub(r"\breject\b", "flag", text, flags=re.IGNORECASE)
        text = re.sub(r"\brejection\b", "flag", text, flags=re.IGNORECASE)
    return text


def _normalize_board_status(status: Any) -> str:
    if not status:
        return "APPROVE_WITH_WARNINGS"
    upper = str(status).strip().upper()
    if upper in {"APPROVED", "APPROVE_WITH_WARNINGS", "NEEDS_IMPROVEMENT", "REJECTED"}:
        return upper
    if upper in {"PASS", "OK", "SUCCESS"}:
        return "APPROVED"
    if upper in {"WARN", "WARNING"}:
        return "APPROVE_WITH_WARNINGS"
    if upper in {"FAIL", "FAILED", "REJECT"}:
        return "REJECTED"
    if any(tok in upper for tok in ["REJECT", "FAIL", "ERROR", "CRASH"]):
        return "REJECTED"
    return "APPROVE_WITH_WARNINGS"


def _board_status_to_pipeline(status: Any) -> str:
    normalized = _normalize_board_status(status)
    if normalized in {"NEEDS_IMPROVEMENT", "REJECTED"}:
        return "NEEDS_IMPROVEMENT"
    if normalized == "APPROVED":
        return "APPROVED"
    return "APPROVE_WITH_WARNINGS"


def _has_runtime_failure_marker(output: str | None) -> bool:
    text = str(output or "")
    checks = [
        "Traceback (most recent call last)",
        "HEAVY_RUNNER_ERROR",
        "Sandbox Execution Failed",
        "peer closed connection",
        "incomplete chunked read",
        "Response 404",
    ]
    return any(token in text for token in checks)


def _clear_runtime_blockers() -> Dict[str, Any]:
    return {
        "execution_error": False,
        "execution_output_stale": False,
        "sandbox_failed": False,
        "runtime_fix_terminal": False,
        "runtime_fix_terminal_reason": "",
        "last_runtime_error_tail": None,
        # Clear residual error context from previous failed attempts so that
        # _resolve_authoritative_runtime_text and _build_review_board_facts
        # do not pick up stale tracebacks after a successful retry.
        "heavy_runner_error_context": None,
    }


def _summarize_runtime_error(output: str | None) -> Dict[str, str] | None:
    text = _resolve_authoritative_runtime_text(output)
    if not text:
        return None
    line = text.strip().splitlines()[-1] if text.strip() else ""
    details = _classify_runtime_failure_details(text)
    if "Traceback" in text:
        return {
            "type": "runtime_error",
            "message": line[:300],
            "failure_type": str(details.get("failure_type") or "runtime_error"),
            "repair_focus": str(details.get("repair_focus") or "runtime"),
        }
    if "EXECUTION ERROR" in text or "Sandbox Execution Failed" in text:
        return {
            "type": "execution_error",
            "message": line[:300],
            "failure_type": str(details.get("failure_type") or "runtime_error"),
            "repair_focus": str(details.get("repair_focus") or "runtime"),
        }
    return {
        "type": "error",
        "message": line[:300],
        "failure_type": str(details.get("failure_type") or "runtime_error"),
        "repair_focus": str(details.get("repair_focus") or "runtime"),
    }


def _is_editable_ml_code(previous_code: str | None) -> bool:
    code_text = str(previous_code or "").strip()
    if not code_text:
        return False
    lowered = code_text.lower()
    non_editable_prefixes = ("# generation failed", "# error:")
    if lowered.startswith(non_editable_prefixes):
        return False
    if "pipeline halted due to strategy/contract drift" in lowered:
        return False
    return True


def _should_use_ml_editor_mode(
    previous_code: str | None,
    gate_context: Dict[str, Any] | None,
    iteration_count: int = 0,
) -> bool:
    # Canonical policy: once baseline code exists, every subsequent ML iteration
    # must be editor mode to patch the latest script rather than regenerate.
    if not _is_editable_ml_code(previous_code):
        return False
    if int(iteration_count or 0) >= 1:
        return True

    gate = gate_context if isinstance(gate_context, dict) else {}
    if not gate:
        return False
    source = str(gate.get("source") or "").strip().lower()
    failed = [str(item).strip().lower() for item in (gate.get("failed_gates") or []) if str(item).strip()]
    hard = [str(item).strip().lower() for item in (gate.get("hard_failures") or []) if str(item).strip()]
    feedback_blob = " ".join(
        [
            source,
            " ".join(failed),
            " ".join(hard),
            str(gate.get("feedback") or ""),
            str(gate.get("traceback") or ""),
            str(gate.get("execution_output_tail") or ""),
        ]
    ).lower()
    has_runtime = bool(
        gate.get("runtime_error")
        or "traceback" in feedback_blob
        or "runtime error" in feedback_blob
        or "runtime_failure" in feedback_blob
        or "execution runtime" in source
        or any("runtime" in token for token in failed + hard)
    )
    has_qa = bool(
        "qa" in source
        or any("qa" in token for token in failed + hard)
        or "qa team feedback" in feedback_blob
    )
    return bool(has_runtime or has_qa)


def _classify_ml_memory_phase(failed_gates: List[str] | None, feedback: str | None) -> str:
    tokens = [str(item).strip().lower() for item in (failed_gates or []) if str(item).strip()]
    text = str(feedback or "").lower()
    combined = " ".join(tokens + [text])
    runtime_tokens = [
        "runtime",
        "traceback",
        "exception",
        "timeout",
        "timed out",
        "oom",
        "memoryerror",
        "sandbox",
    ]
    if any(token in combined for token in runtime_tokens):
        return "runtime"
    persistence_tokens = [
        "output_contract",
        "required output",
        "required artifact",
        "missing artifact",
        "alignment_check",
        "scored_rows",
        "metrics.json",
        "persist",
        "serialization",
        "json",
        "file not found",
        "no such file",
        "permission denied",
    ]
    if any(token in combined for token in persistence_tokens):
        return "persistence"
    return "training"


def _extract_gate_names(values: Any) -> List[str]:
    names: List[str] = []
    if not isinstance(values, list):
        return names
    for item in values:
        candidate = ""
        if isinstance(item, dict):
            for key in ("name", "id", "gate", "rule", "check", "label", "title"):
                raw = item.get(key)
                if raw:
                    candidate = str(raw).strip()
                    break
        else:
            candidate = str(item or "").strip()
        if candidate and candidate not in names:
            names.append(candidate)
    return names


def _build_reviewer_evidence_packet(
    state: Dict[str, Any] | None,
    metrics_report: Dict[str, Any] | None,
    oc_report: Dict[str, Any] | None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    metrics_report = metrics_report if isinstance(metrics_report, dict) else {}
    oc_report = oc_report if isinstance(oc_report, dict) else {}

    missing_required = [str(x) for x in (oc_report.get("missing") or []) if x]
    present_outputs = [str(x) for x in (oc_report.get("present") or []) if x]
    perf = metrics_report.get("model_performance")
    perf = perf if isinstance(perf, dict) else {}

    metric_lines: List[str] = []
    preferred_keys = [
        "normalized_gini",
        "roc_auc_mean",
        "auc",
        "accuracy",
        "f1",
        "lift_at_decile_1_mean",
        "pr_auc_mean",
        "brier_score_mean",
        "rmse",
        "mae",
        "r2",
    ]
    for key in preferred_keys:
        if key not in perf:
            continue
        value = perf.get(key)
        if isinstance(value, dict):
            value = value.get("mean")
        if isinstance(value, (int, float)):
            metric_lines.append(f"{key}={float(value):.6g}")
    if not metric_lines:
        primary = _extract_primary_metric_for_board(state, metrics_report)
        primary_name = str(primary.get("name") or "").strip()
        primary_value = primary.get("value")
        if primary_name and isinstance(primary_value, (int, float)):
            metric_lines.append(f"{primary_name}={float(primary_value):.6g}")
    if not metric_lines:
        for cand in _collect_metric_candidates(metrics_report, {}):
            name = str(cand.get("name") or "").strip()
            value = cand.get("value")
            if not name or not isinstance(value, (int, float)):
                continue
            if bool(cand.get("is_baseline")):
                continue
            metric_lines.append(f"{name}={float(value):.6g}")
            if len(metric_lines) >= 6:
                break

    perf_keys = [str(k).lower() for k in perf.keys()]
    has_segmentation = any("segment" in key for key in perf_keys)
    if not has_segmentation:
        seg_block = metrics_report.get("segmentation") if isinstance(metrics_report, dict) else None
        has_segmentation = isinstance(seg_block, dict) and bool(seg_block)
    has_alignment_check = any(
        os.path.basename(str(path or "")).lower() == "alignment_check.json"
        for path in present_outputs
    )
    has_metrics = bool(metric_lines)

    summary_lines = [
        "=== DETERMINISTIC_EVIDENCE ===",
        f"output_contract_missing_required={len(missing_required)}",
    ]
    if present_outputs:
        preview = ", ".join(present_outputs[:5])
        summary_lines.append(f"output_contract_present_preview={preview}")
    if metric_lines:
        summary_lines.append(f"metrics={'; '.join(metric_lines[:6])}")
    if has_segmentation:
        summary_lines.append("segmentation=present")
    if has_alignment_check:
        summary_lines.append("alignment_check=present")
    summary_lines.append("=== END_DETERMINISTIC_EVIDENCE ===")
    summary_text = "\n".join(summary_lines)
    has_structured_evidence = (not missing_required) and has_metrics

    return {
        "has_structured_evidence": has_structured_evidence,
        "summary_text": summary_text,
        "metrics_preview": metric_lines[:6],
        "missing_required": missing_required,
        "has_metrics": has_metrics,
        "has_segmentation": has_segmentation,
        "has_alignment_check": has_alignment_check,
    }


def _feedback_claims_missing_evidence(feedback: str | None, evidence: Dict[str, Any] | None = None) -> bool:
    text = str(feedback or "").lower()
    if not text:
        return False
    tokens = (
        "no_evidence_found",
        "no verificable",
        "no verifiable",
        "not verifiable",
        "insufficient evidence",
    )
    if any(token in text for token in tokens):
        return True

    evidence = evidence if isinstance(evidence, dict) else {}
    has_metrics = bool(evidence.get("has_metrics"))
    has_segmentation = bool(evidence.get("has_segmentation"))
    has_alignment_check = bool(evidence.get("has_alignment_check"))
    missing_required = [str(x) for x in (evidence.get("missing_required") or []) if x]

    claims_missing_artifacts = any(
        token in text
        for token in (
            "required artifact",
            "missing artifact",
            "artifacts are missing",
            "not generated",
            "not found",
        )
    )
    claims_missing_metrics = any(
        token in text
        for token in (
            "not reported",
            "metric is missing",
            "metrics are missing",
            "metrics are not",
            "primary kpi",
            "secondary metrics",
            "no metrics",
        )
    )
    claims_missing_segmentation = ("segment" in text) and any(
        token in text for token in ("missing", "not present", "not reported", "not available", "no segmentation")
    )
    claims_missing_alignment = ("alignment_check" in text) and any(
        token in text for token in ("missing", "not generated", "not found", "not available")
    )

    if claims_missing_artifacts and not missing_required:
        return True
    if claims_missing_metrics and has_metrics:
        return True
    if claims_missing_segmentation and has_segmentation:
        return True
    if claims_missing_alignment and has_alignment_check:
        return True
    return False

def _collect_outputs_state(required_outputs: List[str]) -> Dict[str, List[str]]:
    present: List[str] = []
    missing: List[str] = []
    for path in required_outputs or []:
        if not path or _is_glob_pattern(path):
            continue
        if os.path.exists(path):
            present.append(path)
        else:
            missing.append(path)
    return {"present": present, "missing": missing}

def _truncate_handoff_text(text: Any, max_len: int = 360) -> str:
    value = str(text or "").strip()
    if not value:
        return ""
    compact = re.sub(r"\s+", " ", value)
    if len(compact) <= max_len:
        return compact
    return compact[: max_len - 3] + "..."

def _normalize_handoff_items(values: Any, max_items: int = 10, max_len: int = 180) -> List[str]:
    out: List[str] = []
    if not isinstance(values, list):
        return out
    for value in values:
        text = _truncate_handoff_text(value, max_len=max_len)
        if not text or text in out:
            continue
        out.append(text)
        if len(out) >= max_items:
            break
    return out


def _normalize_handoff_evidence(values: Any, max_items: int = 10) -> List[Dict[str, str]]:
    out: List[Dict[str, str]] = []
    if not isinstance(values, list):
        return out
    for value in values:
        claim = ""
        source = "missing"
        if isinstance(value, dict):
            claim = _truncate_handoff_text(value.get("claim"), max_len=260)
            source = _truncate_handoff_text(value.get("source") or "missing", max_len=220) or "missing"
        else:
            claim = _truncate_handoff_text(value, max_len=260)
        if not claim:
            continue
        item = {"claim": claim, "source": source}
        if item in out:
            continue
        out.append(item)
        if len(out) >= max_items:
            break
    return out


def _merge_reviewer_qa_findings(
    gate_context: Dict[str, Any] | None,
    review_result: Dict[str, Any] | None,
    qa_result: Dict[str, Any] | None,
    eval_result: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    gate_context = gate_context if isinstance(gate_context, dict) else {}
    review_result = review_result if isinstance(review_result, dict) else {}
    qa_result = qa_result if isinstance(qa_result, dict) else {}
    eval_result = eval_result if isinstance(eval_result, dict) else {}

    failed_gates: List[str] = []
    required_fixes: List[str] = []
    hard_failures: List[str] = []
    evidence: List[Dict[str, str]] = []

    for source in (
        gate_context.get("failed_gates"),
        review_result.get("failed_gates"),
        qa_result.get("failed_gates"),
    ):
        for item in _normalize_handoff_items(source, max_items=25, max_len=220):
            if item not in failed_gates:
                failed_gates.append(item)

    for source in (
        gate_context.get("required_fixes"),
        review_result.get("required_fixes"),
        qa_result.get("required_fixes"),
    ):
        for item in _normalize_handoff_items(source, max_items=25, max_len=500):
            if item not in required_fixes:
                required_fixes.append(item)

    for source in (
        gate_context.get("hard_failures"),
        review_result.get("hard_failures"),
        qa_result.get("hard_failures"),
        eval_result.get("hard_failures"),
    ):
        for item in _normalize_handoff_items(source, max_items=20, max_len=240):
            if item not in hard_failures:
                hard_failures.append(item)

    for source in (
        gate_context.get("evidence"),
        review_result.get("evidence"),
        qa_result.get("evidence"),
        eval_result.get("evidence"),
    ):
        for item in _normalize_handoff_evidence(source, max_items=12):
            if item not in evidence:
                evidence.append(item)

    return {
        "failed_gates": failed_gates[:20],
        "required_fixes": required_fixes[:20],
        "hard_failures": hard_failures[:15],
        "evidence": evidence[:12],
    }

def _extract_metric_target_hint(evaluation_spec: Dict[str, Any] | None, contract: Dict[str, Any] | None) -> tuple[float | None, str]:
    sources: List[tuple[str, Dict[str, Any]]] = []
    if isinstance(evaluation_spec, dict):
        sources.append(("evaluation_spec", evaluation_spec))
    if isinstance(contract, dict):
        validation = contract.get("validation_requirements")
        if isinstance(validation, dict):
            sources.append(("validation_requirements", validation))
    key_priority = [
        "target_value",
        "target",
        "benchmark",
        "minimum",
        "min_value",
        "threshold",
        "kpi_target",
    ]
    for prefix, block in sources:
        for key in key_priority:
            value = block.get(key)
            if _is_number(value):
                return float(value), f"{prefix}.{key}"
    for prefix, block in sources:
        gates = block.get("qa_gates")
        if not isinstance(gates, list):
            continue
        for gate in gates:
            if not isinstance(gate, dict):
                continue
            params = gate.get("params")
            if not isinstance(params, dict):
                continue
            for key in ("target", "target_value", "minimum", "threshold", "min_value"):
                value = params.get(key)
                if _is_number(value):
                    gate_name = str(gate.get("name") or "qa_gate")
                    return float(value), f"{prefix}.qa_gates[{gate_name}].params.{key}"
    return None, ""

def _build_retry_context(
    *,
    runtime_tail: str,
    hard_failures: List[str],
    failed_gates: List[str],
    missing_outputs: List[str],
    present_outputs: List[str],
    required_fixes: List[str],
    state: Dict[str, Any],
) -> Dict[str, Any]:
    """
    Build a structured retry_context for targeted error recovery.
    Classifies the error type so downstream agents know exactly what to fix.
    """
    authoritative_runtime = _resolve_authoritative_runtime_text(runtime_tail, state=state)
    runtime_details = _classify_runtime_failure_details(
        authoritative_runtime or runtime_tail,
        missing_outputs=missing_outputs,
    )
    error_type = str(runtime_details.get("failure_type") or "unknown")
    specific_error = str(runtime_details.get("summary") or "")
    blocked_imports: List[str] = []
    runtime_lower = str(authoritative_runtime or runtime_tail or "").lower()
    if not specific_error and failed_gates:
        specific_error = f"Failed gates: {', '.join(failed_gates[:5])}"

    # Extract blocked imports from state if available
    safety_report = state.get("last_safety_scan") if isinstance(state.get("last_safety_scan"), dict) else {}
    if isinstance(safety_report, dict):
        violations = safety_report.get("violations") or safety_report.get("blocked") or []
        if isinstance(violations, list):
            for v in violations:
                name = str(v.get("module") if isinstance(v, dict) else v)
                if name and name not in blocked_imports:
                    blocked_imports.append(name)
    if error_type == "import_error" and not blocked_imports:
        import re as _re
        import_match = _re.search(r"(?:import|module).*?['\"]([^'\"]+)['\"]", runtime_lower)
        if import_match:
            blocked_imports.append(import_match.group(1))

    return {
        "error_type": error_type,
        "specific_error": specific_error,
        "blocked_imports": blocked_imports[:10],
        "missing_outputs": missing_outputs[:10],
        "working_components": present_outputs[:8],
        "repair_focus": str(runtime_details.get("repair_focus") or "runtime"),
        "cost_reduction_required": bool(runtime_details.get("cost_reduction_required")),
        "recommended_actions": [
            str(item) for item in (runtime_details.get("recommended_actions") or []) if str(item).strip()
        ][:5],
        "failed_gates": [
            {"gate": g, "evidence": "see quality_focus for details"}
            for g in failed_gates[:8]
        ],
    }


def _extract_runtime_exception_signature(text: Any) -> Tuple[str, str]:
    lines = [str(line).strip() for line in str(text or "").splitlines() if str(line).strip()]
    for line in reversed(lines):
        if line.lower().startswith("traceback"):
            continue
        if ":" not in line:
            continue
        exc_type, _, message = line.partition(":")
        exc_type = exc_type.strip()
        if not exc_type:
            continue
        compact = exc_type.replace(".", "").replace("_", "")
        if exc_type.endswith("Error") or exc_type.endswith("Exception") or compact.isidentifier():
            return exc_type, message.strip()
    return "", lines[-1] if lines else ""


def _is_wrapper_exception_type(exc_type: Any) -> bool:
    token = re.sub(r"[^A-Za-z0-9_]+", "", str(exc_type or "").strip().upper())
    return token in {
        "",
        "HEAVYRUNNER",
        "LOCALRUNNER",
        "JOBERRORDETAIL",
        "STATUS",
        "EXECUTION",
        "EXECUTIONERROR",
    }


def _score_runtime_text_candidate(text: Any) -> int:
    payload = str(text or "").strip()
    if not payload:
        return -10_000
    score = 0
    if "Traceback (most recent call last)" in payload:
        score += 120
    if "HEAVY_RUNNER_ERROR_CONTEXT:" in payload:
        score += 90
    if "HEAVY_RUNNER_ERROR:" in payload:
        score += 70
    exc_type, _ = _extract_runtime_exception_signature(payload)
    if exc_type and not _is_wrapper_exception_type(exc_type):
        score += 80
    if "AssertionError" in payload:
        score += 30
    if re.search(r"^HEAVY_RUNNER:\s*status=success\b", payload, re.IGNORECASE):
        score -= 150
    score += min(len(payload), 4000) // 120
    return score


def _extract_traceback_tail(text: Any, max_chars: int = 4000) -> str:
    payload = str(text or "").strip()
    if not payload or "Traceback (most recent call last)" not in payload:
        return ""
    idx = payload.rfind("Traceback (most recent call last)")
    if idx < 0:
        return ""
    return payload[idx:][-max_chars:].strip()


def _sanitize_runtime_text_candidate(text: Any) -> str:
    payload = str(text or "").strip()
    if not payload:
        return ""
    candidates: List[str] = []
    traceback_tail = _extract_traceback_tail(payload)
    if traceback_tail:
        candidates.append(traceback_tail)
    for marker in ("HEAVY_RUNNER_ERROR_CONTEXT:", "HEAVY_RUNNER_ERROR:"):
        if marker not in payload:
            continue
        parts = payload.split(marker)
        for part in parts[1:]:
            segment = str(part or "").strip()
            if not segment:
                continue
            tb_segment = _extract_traceback_tail(segment)
            candidates.append(tb_segment or segment[-4000:].strip())
    if not candidates:
        exc_type, _ = _extract_runtime_exception_signature(payload)
        if re.search(r"^HEAVY_RUNNER:\s*status=success\b", payload, re.IGNORECASE) and (
            not exc_type or _is_wrapper_exception_type(exc_type)
        ):
            return ""
        candidates.append(payload[-4000:].strip())
    best = ""
    best_score = -10_000
    for candidate in candidates:
        score = _score_runtime_text_candidate(candidate)
        if score > best_score:
            best = candidate
            best_score = score
    return best


def _resolve_authoritative_runtime_text(
    *texts: Any,
    state: Dict[str, Any] | None = None,
) -> str:
    raw_candidates: List[Any] = list(texts)
    if isinstance(state, dict):
        gate_context = state.get("last_gate_context") if isinstance(state.get("last_gate_context"), dict) else {}
        runtime_error = gate_context.get("runtime_error") if isinstance(gate_context.get("runtime_error"), dict) else {}
        raw_candidates.extend(
            [
                state.get("last_runtime_error_tail"),
                state.get("execution_output"),
                state.get("heavy_runner_error_context"),
                gate_context.get("traceback"),
                gate_context.get("execution_output_tail"),
                runtime_error.get("summary"),
            ]
        )

    best = ""
    best_score = -10_000
    seen: set[str] = set()
    for raw in raw_candidates:
        if isinstance(raw, dict):
            expanded_values = [
                raw.get("stacktrace"),
                raw.get("traceback"),
                raw.get("error"),
                raw.get("message"),
                raw.get("summary"),
            ]
        else:
            expanded_values = [raw]
        for expanded in expanded_values:
            candidate = _sanitize_runtime_text_candidate(expanded)
            if not candidate or candidate in seen:
                continue
            seen.add(candidate)
            score = _score_runtime_text_candidate(candidate)
            if score > best_score:
                best = candidate
                best_score = score
    return best


def _extract_runtime_traceback_line_number(text: Any) -> int | None:
    matches = re.findall(r'File\s+"[^"]+",\s+line\s+(\d+)', str(text or ""))
    if not matches:
        return None
    try:
        return int(matches[-1])
    except Exception:
        return None


def _get_code_line_at(code: Any, line_number: int | None) -> str:
    if not isinstance(line_number, int) or line_number <= 0:
        return ""
    lines = str(code or "").splitlines()
    if 1 <= line_number <= len(lines):
        return lines[line_number - 1].rstrip()
    return ""


def _ast_expr_to_dotted_name(node: ast.AST | None) -> str:
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        parent = _ast_expr_to_dotted_name(node.value)
        if parent:
            return f"{parent}.{node.attr}"
    return ""


def _parse_script_import_aliases(code: Any) -> Dict[str, Dict[str, str]]:
    script = str(code or "")
    if not script.strip():
        return {}
    try:
        tree = ast.parse(script)
    except Exception:
        return {}
    aliases: Dict[str, Dict[str, str]] = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                bound_name = alias.asname or alias.name.split(".")[0]
                module_name = alias.name if alias.asname else alias.name.split(".")[0]
                aliases[bound_name] = {"module": module_name, "attribute": ""}
        elif isinstance(node, ast.ImportFrom) and node.module:
            for alias in node.names:
                bound_name = alias.asname or alias.name
                aliases[bound_name] = {"module": node.module, "attribute": alias.name}
    return aliases


def _collect_constructor_assignments(code: Any) -> Dict[str, List[Dict[str, Any]]]:
    script = str(code or "")
    if not script.strip():
        return {}
    try:
        tree = ast.parse(script)
    except Exception:
        return {}
    assignments: Dict[str, List[Dict[str, Any]]] = {}
    for node in ast.walk(tree):
        call_node = None
        targets: List[ast.AST] = []
        if isinstance(node, ast.Assign):
            call_node = node.value if isinstance(node.value, ast.Call) else None
            targets = list(node.targets or [])
        elif isinstance(node, ast.AnnAssign):
            call_node = node.value if isinstance(node.value, ast.Call) else None
            targets = [node.target]
        if not isinstance(call_node, ast.Call):
            continue
        callee = _ast_expr_to_dotted_name(call_node.func)
        if not callee:
            continue
        for target in targets:
            if isinstance(target, ast.Name):
                assignments.setdefault(target.id, []).append(
                    {
                        "callee": callee,
                        "lineno": int(getattr(node, "lineno", 0) or 0),
                    }
                )
    return assignments


def _collect_call_expressions_for_line(code: Any, line_number: int | None) -> List[str]:
    script = str(code or "")
    if not script.strip() or not isinstance(line_number, int) or line_number <= 0:
        return []
    try:
        tree = ast.parse(script)
    except Exception:
        return []
    expressions: List[str] = []
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        if int(getattr(node, "lineno", 0) or 0) != line_number:
            continue
        dotted = _ast_expr_to_dotted_name(node.func)
        if dotted and dotted not in expressions:
            expressions.append(dotted)
    return expressions[:6]


def _safe_import_module_for_probe(module_name: str) -> Tuple[Any | None, str]:
    token = str(module_name or "").strip()
    if not token:
        return None, ""
    try:
        spec = importlib.util.find_spec(token)
    except Exception:
        return None, ""
    if spec is None:
        return None, ""
    origin = str(getattr(spec, "origin", "") or "")
    origin_norm = os.path.normcase(os.path.abspath(origin)) if origin and origin not in {"built-in", "frozen"} else ""
    project_root = os.path.normcase(os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..")))
    in_project = bool(origin_norm) and origin_norm.startswith(project_root)
    safe_external = ".venv" in origin_norm or "site-packages" in origin_norm
    if in_project and not safe_external:
        return None, origin
    try:
        return importlib.import_module(token), origin
    except Exception:
        return None, origin


def _resolve_probe_object_from_imports(
    dotted_name: str,
    import_aliases: Dict[str, Dict[str, str]],
) -> Tuple[Any | None, str, str]:
    expression = str(dotted_name or "").strip()
    if not expression:
        return None, "", ""
    segments = [segment for segment in expression.split(".") if segment]
    if not segments:
        return None, "", ""

    first = segments[0]
    info = import_aliases.get(first)
    origin = ""
    if info:
        module_obj, origin = _safe_import_module_for_probe(str(info.get("module") or ""))
        if module_obj is None:
            return None, "", origin
        obj = module_obj
        resolved_name = str(info.get("module") or first)
        attribute = str(info.get("attribute") or "").strip()
        if attribute:
            obj = getattr(obj, attribute, None)
            if obj is None:
                return None, "", origin
            resolved_name = f"{resolved_name}.{attribute}"
        remaining = segments[1:]
    else:
        module_obj, origin = _safe_import_module_for_probe(first)
        if module_obj is None:
            return None, "", origin
        obj = module_obj
        resolved_name = first
        remaining = segments[1:]

    for segment in remaining:
        obj = getattr(obj, segment, None)
        if obj is None:
            return None, "", origin
        resolved_name = f"{resolved_name}.{segment}"
    return obj, resolved_name, origin


def _resolve_probe_object_from_expression(
    dotted_name: str,
    import_aliases: Dict[str, Dict[str, str]],
    constructor_assignments: Dict[str, List[Dict[str, Any]]],
    line_number: int | None,
    *,
    depth: int = 0,
) -> Tuple[Any | None, str, str]:
    if depth >= 4:
        return None, "", ""
    expression = str(dotted_name or "").strip()
    if not expression:
        return None, "", ""
    segments = [segment for segment in expression.split(".") if segment]
    if not segments:
        return None, "", ""

    first = segments[0]
    if first in constructor_assignments:
        candidates = [
            item
            for item in (constructor_assignments.get(first) or [])
            if isinstance(item, dict)
            and str(item.get("callee") or "").strip()
            and (
                not isinstance(line_number, int)
                or int(item.get("lineno", 0) or 0) <= int(line_number)
            )
        ]
        if candidates:
            candidate = sorted(candidates, key=lambda item: int(item.get("lineno", 0) or 0))[-1]
            base_obj, resolved_name, origin = _resolve_probe_object_from_expression(
                str(candidate.get("callee") or ""),
                import_aliases,
                constructor_assignments,
                int(candidate.get("lineno", 0) or 0),
                depth=depth + 1,
            )
            if base_obj is not None:
                current = base_obj
                current_name = resolved_name
                for segment in segments[1:]:
                    current = getattr(current, segment, None)
                    if current is None:
                        return None, "", origin
                    current_name = f"{current_name}.{segment}"
                return current, current_name, origin

    return _resolve_probe_object_from_imports(expression, import_aliases)


def _build_candidate_call_site_facts(runtime_output: Any, code: Any) -> List[Dict[str, Any]]:
    line_number = _extract_runtime_traceback_line_number(runtime_output)
    if not isinstance(line_number, int) or line_number <= 0:
        return []
    call_expressions = _collect_call_expressions_for_line(code, line_number)
    if not call_expressions:
        return []
    import_aliases = _parse_script_import_aliases(code)
    constructor_assignments = _collect_constructor_assignments(code)
    facts: List[Dict[str, Any]] = []
    for expression in call_expressions:
        obj, resolved_symbol, origin = _resolve_probe_object_from_expression(
            expression,
            import_aliases,
            constructor_assignments,
            line_number,
        )
        if obj is None:
            continue
        try:
            signature = str(inspect.signature(obj))
        except Exception:
            signature = ""
        if not signature:
            continue
        facts.append(
            {
                "expression": expression,
                "resolved_symbol": resolved_symbol or expression,
                "signature": signature,
                "source": "inspect.signature",
                "origin": origin or None,
            }
        )
        if len(facts) >= 4:
            break
    return facts


def _build_repair_ground_truth(
    *,
    state: Dict[str, Any],
    retry_context: Dict[str, Any] | None,
    runtime_output: Any,
    missing_outputs: List[str] | None,
    present_outputs: List[str] | None,
    failed_gates: List[str] | None,
    required_fixes: List[str] | None,
) -> Dict[str, Any]:
    retry_context = retry_context if isinstance(retry_context, dict) else {}
    runtime_text = str(runtime_output or "").strip()
    error_type = str(retry_context.get("error_type") or "").strip().lower()
    repair_focus = str(retry_context.get("repair_focus") or "").strip().lower()
    specific_error = str(retry_context.get("specific_error") or "").strip()
    exception_type, exception_message = _extract_runtime_exception_signature(runtime_text)
    line_number = _extract_runtime_traceback_line_number(runtime_text)
    generated_code = (
        state.get("generated_code")
        or state.get("last_generated_code")
        or state.get("last_successful_generated_code")
        or ""
    )
    failing_line = _get_code_line_at(generated_code, line_number)
    keyword_match = re.search(r"unexpected keyword argument ['\"]([^'\"]+)['\"]", runtime_text, re.IGNORECASE)
    attr_match = re.search(
        r"'([^']+)' object has no attribute ['\"]([^'\"]+)['\"]",
        runtime_text,
        re.IGNORECASE,
    )
    missing_arg_match = re.search(
        r"missing\s+\d+\s+required positional argument[s]?:\s*['\"]([^'\"]+)['\"]",
        runtime_text,
        re.IGNORECASE,
    )
    takes_no_kw_match = re.search(
        r"got an unexpected keyword argument ['\"]([^'\"]+)['\"]",
        runtime_text,
        re.IGNORECASE,
    )
    if error_type == "runtime_error" and (
        keyword_match or attr_match or missing_arg_match or takes_no_kw_match
    ):
        error_type = "runtime_api_misuse"
        repair_focus = "runtime"

    candidate_call_sites = _build_candidate_call_site_facts(runtime_text, generated_code)
    verified_facts: List[Dict[str, Any]] = []
    environment_facts: List[Dict[str, Any]] = []
    repair_directives: List[str] = []
    do_not_change: List[str] = []

    if exception_type:
        verified_facts.append({"fact": "exception_type", "value": exception_type, "source": "runtime_traceback"})
    if exception_message:
        verified_facts.append({"fact": "exception_message", "value": exception_message[:280], "source": "runtime_traceback"})
    if isinstance(line_number, int) and line_number > 0:
        verified_facts.append({"fact": "failing_line_number", "value": line_number, "source": "runtime_traceback"})
    if failing_line:
        verified_facts.append({"fact": "failing_line_code", "value": failing_line[:280], "source": "generated_code"})
    if missing_outputs:
        verified_facts.append(
            {
                "fact": "missing_outputs",
                "value": [str(path) for path in (missing_outputs or [])[:8]],
                "source": "output_contract",
            }
        )
    if keyword_match:
        verified_facts.append(
            {
                "fact": "unexpected_keyword_argument",
                "value": keyword_match.group(1),
                "source": "runtime_traceback",
            }
        )
        repair_directives.append(
            "Remove or replace unsupported keyword arguments only after matching the verified callable signature."
        )
    if attr_match:
        verified_facts.append(
            {
                "fact": "missing_attribute",
                "value": {"object_type": attr_match.group(1), "attribute": attr_match.group(2)},
                "source": "runtime_traceback",
            }
        )
        repair_directives.append(
            "Do not assume method/attribute chains. Use the verified object type and available signatures to patch the failing access."
        )
    if missing_arg_match:
        verified_facts.append(
            {
                "fact": "missing_required_argument",
                "value": missing_arg_match.group(1),
                "source": "runtime_traceback",
            }
        )
    for call_site in candidate_call_sites:
        environment_facts.append(
            {
                "fact": "callable_signature",
                "expression": call_site.get("expression"),
                "resolved_symbol": call_site.get("resolved_symbol"),
                "value": call_site.get("signature"),
                "origin": call_site.get("origin"),
                "source": call_site.get("source"),
            }
        )
    for path in (present_outputs or [])[:6]:
        do_not_change.append(f"Keep artifact generation for {path} unchanged unless the failing block directly requires it.")
    if error_type == "runtime_api_misuse":
        do_not_change.append("Do not refactor unrelated modeling logic before the verified failing API call is corrected.")
    if error_type in {"output_missing", "artifact_io"}:
        do_not_change.append("Keep working training logic stable while restoring contract outputs at exact paths.")

    for action in retry_context.get("recommended_actions") or []:
        text = str(action or "").strip()
        if text and text not in repair_directives:
            repair_directives.append(text)
    for fix in required_fixes or []:
        text = str(fix or "").strip()
        if text and text not in repair_directives:
            repair_directives.append(text)
        if len(repair_directives) >= 8:
            break
    for gate in failed_gates or []:
        label = str(gate or "").strip()
        if not label:
            continue
        verified_facts.append({"fact": "failed_gate", "value": label[:180], "source": "review_pipeline"})
        if len([item for item in verified_facts if item.get("fact") == "failed_gate"]) >= 6:
            break

    failure_signature = specific_error or ""
    if exception_type or exception_message:
        failure_signature = ": ".join([part for part in [exception_type, exception_message] if part]).strip()
    failure_signature = failure_signature[:320]
    if not error_type and missing_outputs:
        error_type = "output_missing"
    if not repair_focus and error_type in {"runtime_api_misuse", "runtime_error", "timeout", "oom", "import_error", "shape_or_dtype"}:
        repair_focus = "runtime"
    if not repair_focus and error_type in {"artifact_io", "output_missing"}:
        repair_focus = "persistence"

    if not (error_type or verified_facts or environment_facts or repair_directives):
        return {}
    return {
        "version": "v1",
        "root_cause_type": error_type or "unknown",
        "repair_focus": repair_focus or "runtime",
        "failure_signature": failure_signature or None,
        "verified_facts": verified_facts[:12],
        "environment_facts": environment_facts[:8],
        "repair_directives": repair_directives[:8],
        "candidate_call_sites": candidate_call_sites[:4],
        "do_not_change": do_not_change[:8],
    }


def _extract_repair_scope_targets_from_evidence(
    evidence_focus: List[Dict[str, Any]] | None,
) -> List[str]:
    evidence_focus = evidence_focus if isinstance(evidence_focus, list) else []
    targets: List[str] = []
    for item in evidence_focus:
        if not isinstance(item, dict):
            continue
        source = str(item.get("source") or "").strip()
        if not source:
            continue
        for match in re.finditer(r"script:(\d+)", source, re.IGNORECASE):
            target = f"script_line:{match.group(1)}"
            if target not in targets:
                targets.append(target)
        if len(targets) >= 6:
            break
    return targets[:6]


def _build_repair_scope(
    *,
    repair_focus: str,
    repair_ground_truth: Dict[str, Any] | None,
    required_fixes: List[str] | None,
    failed_gates: List[str] | None,
    evidence_focus: List[Dict[str, Any]] | None,
    must_preserve: List[str] | None,
    missing_outputs: List[str] | None,
    optimization_context: Dict[str, Any] | None = None,
    hypothesis_packet: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    repair_focus = str(repair_focus or "").strip().lower()
    if repair_focus not in {"runtime", "persistence", "compliance"}:
        return {}

    repair_ground_truth = repair_ground_truth if isinstance(repair_ground_truth, dict) else {}
    evidence_focus = evidence_focus if isinstance(evidence_focus, list) else []
    must_preserve = [str(item) for item in (must_preserve or []) if str(item).strip()]
    missing_outputs = [str(item) for item in (missing_outputs or []) if str(item).strip()]
    optimization_context = optimization_context if isinstance(optimization_context, dict) else {}
    hypothesis_packet = hypothesis_packet if isinstance(hypothesis_packet, dict) else {}
    phase = "compliance_runtime" if repair_focus in {"runtime", "compliance"} else "contract_persistence"

    editable_targets: List[str] = []
    protected_regions: List[str] = []
    active_findings: List[str] = []
    invariants: List[str] = [
        "Use the full script as context, but treat unrelated regions as frozen by default.",
        "Keep business objective, strategy lock, contract paths, and split rules unchanged.",
        "Do not widen scope unless new verified runtime evidence directly implicates another block.",
    ]

    for fact in repair_ground_truth.get("verified_facts") or []:
        if not isinstance(fact, dict):
            continue
        name = str(fact.get("fact") or "").strip().lower()
        value = fact.get("value")
        if name == "failing_line_number" and isinstance(value, int) and value > 0:
            target = f"failing_block_near_line:{value}"
            if target not in editable_targets:
                editable_targets.append(target)
        elif name == "missing_outputs" and isinstance(value, list) and value:
            target = "artifact_writers:" + ",".join([str(path) for path in value[:4]])
            if target not in editable_targets:
                editable_targets.append(target)
        elif name == "failed_gate":
            text = str(value or "").strip()
            if text and text not in active_findings:
                active_findings.append(text)
        elif name in {"unexpected_keyword_argument", "missing_attribute", "missing_required_argument"}:
            text = f"{name}:{value}"
            if text not in active_findings:
                active_findings.append(text)

    for call_site in repair_ground_truth.get("candidate_call_sites") or []:
        if not isinstance(call_site, dict):
            continue
        expression = str(call_site.get("expression") or "").strip()
        if expression:
            target = f"call_site:{expression}"
            if target not in editable_targets:
                editable_targets.append(target)
        if len(editable_targets) >= 6:
            break

    for target in _extract_repair_scope_targets_from_evidence(evidence_focus):
        if target not in editable_targets:
            editable_targets.append(target)
        if len(editable_targets) >= 6:
            break

    for fix in required_fixes or []:
        text = str(fix or "").strip()
        if text and text not in active_findings:
            active_findings.append(text)
        if len(active_findings) >= 8:
            break

    if repair_focus in {"runtime", "compliance"}:
        protected_regions.extend(
            [
                "training_strategy_and_model_family",
                "feature_selection_and_cv_logic_unless_directly_implicated",
                "data_loading_and_split_semantics_unless_directly_implicated",
            ]
        )
    else:
        protected_regions.extend(
            [
                "training_strategy_and_metric_logic",
                "validated_runtime_blocks_unless_output_persistence_requires_touching_them",
            ]
        )
    if must_preserve:
        protected_regions.extend(must_preserve[:4])
    if missing_outputs:
        invariants.append(
            "If you touch output-writing logic, regenerate only the missing contract artifacts at exact paths: "
            + ", ".join(missing_outputs[:4])
            + "."
        )
    active_hypothesis = (
        optimization_context.get("active_hypothesis")
        if isinstance(optimization_context.get("active_hypothesis"), dict)
        else {}
    )
    active_technique = _extract_hypothesis_technique(hypothesis_packet) or str(
        ((active_hypothesis.get("hypothesis") or {}).get("technique") if isinstance(active_hypothesis, dict) else "")
        or ""
    ).strip()
    if active_technique:
        invariants.append(
            "Metric-improvement hypothesis '"
            + active_technique
            + "' is deferred while repair-first is active; restore incumbent runtime/contract behavior before touching optimization logic."
        )
    contract_lock = (
        optimization_context.get("contract_lock")
        if isinstance(optimization_context.get("contract_lock"), dict)
        else {}
    )
    for key in ("model_family", "cv_protocol", "target_columns", "split_column", "required_outputs"):
        value = contract_lock.get(key)
        if value in (None, "", [], {}):
            continue
        text = f"optimization_contract_lock:{key}={value}"
        if text not in protected_regions:
            protected_regions.append(text)

    return {
        "version": "v1",
        "phase": phase,
        "scope_policy": "patch_only",
        "reviewer_guided": True,
        "editable_targets": editable_targets[:6],
        "protected_regions": protected_regions[:8],
        "active_findings": active_findings[:8],
        "must_preserve_invariants": invariants[:8],
        "widen_scope_rule": "Only widen edit scope if new verified runtime evidence directly implicates another block.",
    }


def _classify_runtime_failure_details(
    output: Any,
    *,
    missing_outputs: List[str] | None = None,
) -> Dict[str, Any]:
    text = _resolve_authoritative_runtime_text(output) or str(output or "").strip()
    lower = text.lower()
    last_line = text.splitlines()[-1].strip() if text else ""
    failure_type = "runtime_error"
    repair_focus = "runtime"
    cost_reduction_required = False
    recommended_actions: List[str] = []
    exception_type, exception_message = _extract_runtime_exception_signature(text)
    has_explicit_runtime_exception = bool(exception_type) and not _is_wrapper_exception_type(exception_type)

    timeout_tokens = (
        "timeout",
        "timed out",
        "time limit",
        "deadline exceeded",
        "exceeded 7200",
        "exceeded 3600",
        "script exceeded",
    )
    oom_tokens = (
        "out of memory",
        "oom",
        "memoryerror",
        "cannot allocate memory",
        "killed process",
        "memory pressure",
    )
    import_tokens = ("modulenotfounderror", "importerror")
    io_tokens = (
        "filenotfounderror",
        "no such file",
        "permission denied",
        "json serialization",
        "to_csv",
        "write artifact",
    )
    api_misuse_tokens = (
        "unexpected keyword argument",
        "has no attribute",
        "missing 1 required positional argument",
        "missing 2 required positional arguments",
        "takes no keyword arguments",
        "got multiple values for argument",
    )
    assertion_tokens = (
        "assertionerror",
        "row count mismatch",
        "expected_row_count",
        "contract requires",
    )
    security_tokens = (
        "security violation",
        "security violations",
        "not allowed",
        "sandbox",
        "forbidden call",
    )
    shape_tokens = (
        "shape mismatch",
        "length mismatch",
        "inconsistent numbers of samples",
        "could not convert",
        "valueerror",
        "typeerror",
    )

    if any(token in lower for token in timeout_tokens):
        failure_type = "timeout"
        repair_focus = "runtime"
        cost_reduction_required = True
        recommended_actions = [
            "Reduce compute cost within the current runtime budget before changing strategy.",
            "Keep the current model family/contract outputs stable while cutting seeds, trials, folds, or iterations only as needed.",
            "Rerun and confirm all contract artifacts are produced before resuming metric optimization.",
        ]
    elif _is_memory_pressure_error(text) or any(token in lower for token in oom_tokens):
        failure_type = "oom"
        repair_focus = "runtime"
        cost_reduction_required = True
        recommended_actions = [
            "Reduce memory footprint before retrying the same modeling approach.",
            "Prefer bounded batch/feature/seed settings over broader replanning.",
            "Verify all required artifacts are produced after the resource fix.",
        ]
    elif any(token in lower for token in import_tokens):
        failure_type = "import_error"
        repair_focus = "runtime"
        recommended_actions = [
            "Use only runtime-compatible dependencies and imports allowed by the contract.",
            "Replace unavailable imports with declared fallbacks before changing model logic.",
        ]
    elif any(token in lower for token in api_misuse_tokens):
        failure_type = "runtime_api_misuse"
        repair_focus = "runtime"
        recommended_actions = [
            "Verify the failing callable signature, accepted arguments, and return type against the installed environment before editing.",
            "Patch only the failing API usage first and keep the broader modeling strategy stable.",
            "Regenerate required artifacts only after the verified runtime API issue is resolved.",
        ]
    elif any(token in lower for token in security_tokens):
        failure_type = "security_violation"
        repair_focus = "compliance"
        recommended_actions = [
            "Remove or replace prohibited sandbox/file-system operations first.",
            "Patch only the compliance-blocking code path before changing any healthy training or scoring logic.",
            "Regenerate required artifacts only after the compliance blocker is cleared.",
        ]
    elif "assertionerror" in lower or (
        has_explicit_runtime_exception
        and str(exception_type).strip() == "AssertionError"
    ) or any(token in lower for token in assertion_tokens):
        failure_type = "runtime_contract_assertion"
        repair_focus = "runtime"
        recommended_actions = [
            "Fix the failing contract assertion or subset-selection logic before any further optimization work.",
            "Use contract row rules and artifact schemas as the source of truth for the failing assertion.",
            "Regenerate required artifacts only after the assertion-causing logic is corrected.",
        ]
    elif any(token in lower for token in io_tokens):
        failure_type = "artifact_io"
        repair_focus = "persistence"
        recommended_actions = [
            "Fix artifact writing/serialization/path handling first.",
            "Preserve valid training logic unless the contract explicitly requires a modeling change.",
        ]
    elif any(token in lower for token in shape_tokens):
        failure_type = "shape_or_dtype"
        repair_focus = "runtime"
        recommended_actions = [
            "Fix shape/dtype/root-cause issues before further optimization changes.",
            "Preserve the broader pipeline and contract outputs while patching the failing block.",
        ]
    elif missing_outputs and not has_explicit_runtime_exception:
        failure_type = "output_missing"
        repair_focus = "persistence"
        recommended_actions = [
            "Regenerate missing contract outputs at the exact required paths.",
            "Keep the rest of the pipeline stable while restoring artifact completeness.",
        ]
    else:
        recommended_actions = [
            "Fix the runtime root cause first and keep the rest of the pipeline stable.",
            "Regenerate required artifacts after the runtime issue is resolved.",
        ]

    summary = last_line or text[:320]
    if failure_type == "output_missing" and missing_outputs:
        summary = "Missing outputs: " + ", ".join([str(path) for path in (missing_outputs or [])[:5]])
    return {
        "failure_type": failure_type,
        "repair_focus": repair_focus,
        "cost_reduction_required": cost_reduction_required,
        "summary": summary[:500],
        "recommended_actions": recommended_actions[:5],
    }


def _resolve_repair_first_focus(
    *,
    retry_context: Dict[str, Any] | None,
    failed_gates: List[str] | None,
    hard_failures: List[str] | None,
    missing_outputs: List[str] | None,
) -> str:
    retry_context = retry_context if isinstance(retry_context, dict) else {}
    retry_focus = str(retry_context.get("repair_focus") or "").strip().lower()
    retry_error_type = str(retry_context.get("error_type") or "").strip().lower()
    retry_specific = str(retry_context.get("specific_error") or "").strip().lower()
    runtime_markers = ("runtime", "traceback", "exception", "timeout", "sandbox", "memory", "oom")
    if retry_error_type in {
        "timeout",
        "oom",
        "import_error",
        "shape_or_dtype",
        "runtime_api_misuse",
        "runtime_contract_assertion",
    }:
        return "runtime"
    if retry_error_type == "security_violation":
        return "compliance"
    if retry_error_type == "runtime_error" and any(token in retry_specific for token in runtime_markers):
        return "runtime"
    if missing_outputs:
        return "persistence"
    if hard_failures:
        return "compliance"
    if any(_looks_blocking_retry_signal(item) for item in (failed_gates or [])):
        return "compliance"
    if retry_focus in {"runtime", "persistence", "compliance"}:
        return retry_focus
    return ""


def _prune_patch_objectives_for_repair_focus(
    patch_objectives: List[str] | None,
    *,
    focus: str,
    add_defer_note: bool = False,
) -> List[str]:
    items = [str(item) for item in (patch_objectives or []) if str(item).strip()]
    if focus not in {"runtime", "persistence", "compliance"}:
        return items[:8]
    deferred_tokens = (
        "metric-improvement round:",
        "apply the active metric-improvement hypothesis",
        "no_op forbidden",
        "improve primary metric",
    )
    kept: List[str] = []
    removed_optimization = False
    for item in items:
        lower = item.lower()
        if any(token in lower for token in deferred_tokens):
            removed_optimization = True
            continue
        kept.append(item)
        if len(kept) >= 6:
            break
    if add_defer_note and removed_optimization:
        note = (
            "Defer the active metric-improvement hypothesis until "
            + focus
            + " blockers are cleared and required outputs are stable."
        )
        if note not in kept:
            kept.append(note)
    return kept[:8] if kept else items[:6]


def _apply_repair_first_handoff(
    handoff: Dict[str, Any] | None,
    *,
    repair_focus: str,
    retry_context: Dict[str, Any] | None,
    source: str,
    reason: str,
) -> Dict[str, Any]:
    repaired = copy.deepcopy(handoff) if isinstance(handoff, dict) else {}
    retry_context = copy.deepcopy(retry_context) if isinstance(retry_context, dict) else {}
    if repair_focus not in {"runtime", "persistence", "compliance"}:
        return repaired

    deferred_optimization = (
        dict(repaired.get("deferred_optimization"))
        if isinstance(repaired.get("deferred_optimization"), dict)
        else {}
    )
    optimization_context = (
        repaired.get("optimization_context")
        if isinstance(repaired.get("optimization_context"), dict)
        else {}
    )
    hypothesis_packet = (
        repaired.get("hypothesis_packet")
        if isinstance(repaired.get("hypothesis_packet"), dict)
        else {}
    )
    if not deferred_optimization and (optimization_context or hypothesis_packet):
        active_hypothesis = optimization_context.get("active_hypothesis") if isinstance(optimization_context, dict) else {}
        technique = _extract_hypothesis_technique(hypothesis_packet) or str(
            ((active_hypothesis.get("hypothesis") or {}).get("technique") if isinstance(active_hypothesis, dict) else "")
            or ""
        ).strip()
        deferred_optimization = {
            "reason": reason or f"repair_first:{repair_focus}",
            "resume_condition": (
                "Resume metric optimization only after repair-first blockers are cleared and contract outputs are stable."
            ),
            "active_technique": technique or None,
        }
    optimization_lane = (
        copy.deepcopy(repaired.get("optimization_lane"))
        if isinstance(repaired.get("optimization_lane"), dict)
        else {}
    )
    if optimization_context or hypothesis_packet or deferred_optimization:
        active_hypothesis = optimization_context.get("active_hypothesis") if isinstance(optimization_context, dict) else {}
        technique = _extract_hypothesis_technique(hypothesis_packet) or str(
            ((active_hypothesis.get("hypothesis") or {}).get("technique") if isinstance(active_hypothesis, dict) else "")
            or ""
        ).strip()
        if isinstance(optimization_context, dict):
            optimization_context = dict(optimization_context)
            optimization_context["repair_first_active"] = True
            optimization_context["deferred_hypothesis"] = True
            optimization_context["deferred_hypothesis_reason"] = (
                "Repair-first scope is active; hypothesis stays contextual until runtime/contract blockers are cleared."
            )
            repaired["optimization_context"] = optimization_context
        optimization_lane.update(
            {
                "active": True,
                "resume_after_repair": True,
                "repair_first": True,
                "repair_focus": repair_focus,
                "source": source,
                "active_technique": technique or optimization_lane.get("active_technique"),
            }
        )
    repaired["mode"] = "patch"
    repaired["source"] = source
    repaired["repair_policy"] = {
        "repair_first": True,
        "primary_focus": repair_focus,
        "reason": reason or f"repair_first:{repair_focus}",
    }
    repaired["retry_context"] = retry_context
    if deferred_optimization:
        repaired["deferred_optimization"] = deferred_optimization
    if optimization_lane:
        repaired["optimization_lane"] = optimization_lane
    editor_constraints = (
        dict(repaired.get("editor_constraints"))
        if isinstance(repaired.get("editor_constraints"), dict)
        else {}
    )
    editor_constraints["must_apply_hypothesis"] = False
    editor_constraints["forbid_noop"] = False
    editor_constraints["patch_intensity"] = "surgical" if repair_focus in {"runtime", "compliance"} else "incremental"
    editor_constraints["scope_policy"] = "patch_only"
    editor_constraints["allow_strategy_changes"] = False
    editor_constraints["freeze_unimplicated_regions"] = True
    repaired["editor_constraints"] = editor_constraints
    repair_scope = (
        copy.deepcopy(repaired.get("repair_scope"))
        if isinstance(repaired.get("repair_scope"), dict)
        else {}
    )
    repair_scope["phase"] = "compliance_runtime" if repair_focus in {"runtime", "compliance"} else "contract_persistence"
    repair_scope["scope_policy"] = "patch_only"
    repair_scope["reviewer_guided"] = True
    repair_scope["widen_scope_rule"] = (
        "Only widen edit scope if new verified runtime evidence directly implicates another block."
    )
    repaired["repair_scope"] = repair_scope
    repaired["patch_objectives"] = _prune_patch_objectives_for_repair_focus(
        repaired.get("patch_objectives"),
        focus=repair_focus,
        add_defer_note=bool(deferred_optimization),
    )
    return repaired


def _candidate_optimization_blueprint_paths(state: Dict[str, Any], run_id: str) -> List[str]:
    token = str(run_id or "").strip()
    if not token:
        return []
    rel_parts = ["runs", token, "agents", "model_analyst", "optimization_blueprint.json"]
    rel_path = os.path.join(*rel_parts)
    candidates: List[str] = [rel_path]

    work_dir = state.get("work_dir")
    if isinstance(work_dir, str) and work_dir.strip():
        candidates.append(os.path.join(work_dir, *rel_parts))

    orig_cwd = state.get("orig_cwd")
    if isinstance(orig_cwd, str) and orig_cwd.strip():
        candidates.append(os.path.join(orig_cwd, *rel_parts))
        candidates.append(
            os.path.join(
                orig_cwd,
                "runs",
                token,
                "work",
                *rel_parts,
            )
        )

    project_root = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", ".."))
    candidates.append(os.path.join(project_root, *rel_parts))
    candidates.append(
        os.path.join(
            project_root,
            "runs",
            token,
            "work",
            *rel_parts,
        )
    )

    deduped: List[str] = []
    seen: set[str] = set()
    for raw in candidates:
        if not raw:
            continue
        normalized = os.path.normcase(os.path.normpath(os.path.abspath(raw)))
        if normalized in seen:
            continue
        seen.add(normalized)
        deduped.append(os.path.abspath(raw))
    return deduped


def _load_optimization_blueprint_from_disk(
    state: Dict[str, Any],
    run_id: str,
) -> tuple[Dict[str, Any] | None, str]:
    for candidate_path in _candidate_optimization_blueprint_paths(state, run_id):
        if not os.path.isfile(candidate_path):
            continue
        try:
            with open(candidate_path, "r", encoding="utf-8") as f_bp:
                payload = json.load(f_bp)
        except Exception as exc:
            print(f"BLUEPRINT_RECOVERY_ERROR: path={candidate_path} error={exc}")
            continue
        if isinstance(payload, dict) and payload:
            return payload, candidate_path
    return None, ""


def _persist_optimization_blueprint_to_disk(
    state: Dict[str, Any],
    run_id: str,
    blueprint: Dict[str, Any],
) -> List[str]:
    if not isinstance(blueprint, dict) or not blueprint:
        return []
    saved_paths: List[str] = []
    for candidate_path in _candidate_optimization_blueprint_paths(state, run_id):
        try:
            os.makedirs(os.path.dirname(candidate_path), exist_ok=True)
            with open(candidate_path, "w", encoding="utf-8") as f_bp:
                json.dump(blueprint, f_bp, indent=2, default=str)
            saved_paths.append(candidate_path)
        except Exception as exc:
            print(f"BLUEPRINT_PERSIST_ERROR: path={candidate_path} error={exc}")
    return saved_paths


def _resolve_cached_optimization_blueprint(
    state: Dict[str, Any],
    *,
    run_id: str = "",
) -> Dict[str, Any]:
    if not isinstance(state, dict):
        return {}
    current = state.get("optimization_blueprint")
    if isinstance(current, dict) and current:
        return current

    handoff = state.get("iteration_handoff")
    if isinstance(handoff, dict):
        from_handoff = handoff.get("optimization_blueprint")
        if isinstance(from_handoff, dict) and from_handoff:
            state["optimization_blueprint"] = from_handoff
            return from_handoff

    gate_ctx = state.get("last_gate_context")
    if isinstance(gate_ctx, dict):
        from_gate = gate_ctx.get("optimization_blueprint")
        if isinstance(from_gate, dict) and from_gate:
            state["optimization_blueprint"] = from_gate
            return from_gate

    run_token = str(run_id or state.get("run_id") or "").strip()
    if run_token:
        recovered, recovered_path = _load_optimization_blueprint_from_disk(state, run_token)
        if isinstance(recovered, dict) and recovered:
            state["optimization_blueprint"] = recovered
            print(f"BLUEPRINT_RECOVERY: loaded optimization blueprint from {recovered_path}")
            return recovered
    return {}


def _build_iteration_handoff(
    state: Dict[str, Any] | None,
    status: str | None,
    gate_context: Dict[str, Any] | None,
    oc_report: Dict[str, Any] | None,
    review_result: Dict[str, Any] | None,
    qa_result: Dict[str, Any] | None,
    eval_result: Dict[str, Any] | None = None,
    evaluation_spec: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    state = state if isinstance(state, dict) else {}
    gate_context = gate_context if isinstance(gate_context, dict) else {}
    oc_report = oc_report if isinstance(oc_report, dict) else {}
    review_result = review_result if isinstance(review_result, dict) else {}
    qa_result = qa_result if isinstance(qa_result, dict) else {}
    eval_result = eval_result if isinstance(eval_result, dict) else {}
    contract = state.get("execution_contract") if isinstance(state.get("execution_contract"), dict) else {}
    iteration_count = int(state.get("iteration_count", 0) or 0)
    next_iteration = iteration_count + 1
    normalized_status = str(status or state.get("review_verdict") or "UNKNOWN").upper()

    scoped_required_outputs = _resolve_ml_heavy_runner_required_outputs(contract, state)
    if not scoped_required_outputs:
        scoped_required_outputs = _resolve_required_outputs(contract, state)
    required_outputs = [str(path) for path in (scoped_required_outputs or []) if path]
    present_outputs = _normalize_handoff_items(oc_report.get("present"), max_items=15, max_len=140)
    missing_outputs = _normalize_handoff_items(oc_report.get("missing"), max_items=15, max_len=140)
    if not present_outputs and required_outputs:
        present_outputs = [path for path in required_outputs if path and os.path.exists(path)][:15]
    if not missing_outputs and required_outputs:
        for path in required_outputs:
            if not path or _is_glob_pattern(path):
                continue
            if not os.path.exists(path) and path not in missing_outputs:
                missing_outputs.append(path)
            if len(missing_outputs) >= 15:
                break

    merged_findings = _merge_reviewer_qa_findings(gate_context, review_result, qa_result, eval_result)
    failed_gates = merged_findings.get("failed_gates") or []
    required_fixes = merged_findings.get("required_fixes") or []
    hard_failures = merged_findings.get("hard_failures") or _normalize_handoff_items(
        gate_context.get("hard_failures") or state.get("hard_failures"),
        max_items=10,
        max_len=240,
    )
    evidence_focus = merged_findings.get("evidence") or []
    if not isinstance(evidence_focus, list):
        evidence_focus = []

    authoritative_runtime = _resolve_authoritative_runtime_text(state=state)
    runtime_tail = _truncate_handoff_text(
        authoritative_runtime or state.get("last_runtime_error_tail") or state.get("execution_output"),
        max_len=520,
    )
    execution_output_text = str(state.get("execution_output") or "")
    preflight_failures = extract_preflight_gate_failures(execution_output_text)
    preflight_raw_tail = extract_preflight_gate_tail(execution_output_text, max_chars=700)
    if preflight_failures:
        for fail in preflight_failures[:8]:
            gate_name = str(fail.get("gate") or "").strip().upper()
            if not gate_name:
                continue
            gate_id = f"preflight_gate_{gate_name}"
            if gate_id not in failed_gates:
                failed_gates.append(gate_id)
            detail_text = _truncate_handoff_text(fail.get("detail"), max_len=220)
            claim = f"PRE_FLIGHT_GATES Gate {gate_name}: FAIL"
            if detail_text:
                claim = f"{claim} - {detail_text}"
            evidence_item = {
                "claim": claim,
                "source": "execution_output.pre_flight_gates",
            }
            if evidence_item not in evidence_focus:
                evidence_focus.append(evidence_item)
    reviewer_feedback = _truncate_handoff_text(
        review_result.get("feedback") or gate_context.get("feedback") or state.get("review_feedback"),
        max_len=1200,
    )
    qa_feedback = _truncate_handoff_text(qa_result.get("feedback"), max_len=900)

    metric_snapshot = _load_primary_metric_state(state)
    metric_loop_state = _load_metric_loop_state(state, contract)
    metric_name = str(
        metric_snapshot.get("primary_metric_name")
        or ((metric_loop_state.get("target") or {}).get("name") if isinstance(metric_loop_state.get("target"), dict) else "")
        or ""
    )
    metric_value = metric_snapshot.get("primary_metric_value")
    baseline_value = metric_snapshot.get("baseline_value")
    if not _is_number(metric_value):
        incumbent_payload = metric_loop_state.get("incumbent") if isinstance(metric_loop_state.get("incumbent"), dict) else {}
        metric_value = _coerce_float(incumbent_payload.get("metric_value"))
    if not _is_number(baseline_value):
        round_payload = metric_loop_state.get("round") if isinstance(metric_loop_state.get("round"), dict) else {}
        round_baseline = round_payload.get("baseline") if isinstance(round_payload.get("baseline"), dict) else {}
        baseline_value = _coerce_float(round_baseline.get("metric_value"))
    # If snapshot is missing/incomplete, recover from deterministic facts so handoff
    # preserves metric continuity across iterations.
    if not metric_name or not _is_number(metric_value):
        metrics_report_for_board = _resolve_metrics_report_for_facts(state if isinstance(state, dict) else {})
        if not isinstance(metrics_report_for_board, dict):
            metrics_report_for_board = {}
        primary_for_board = _extract_primary_metric_for_board(
            state if isinstance(state, dict) else {},
            metrics_report_for_board,
        )
        if isinstance(primary_for_board, dict):
            if not metric_name and primary_for_board.get("name"):
                metric_name = str(primary_for_board.get("name"))
            if not _is_number(metric_value):
                metric_value = _coerce_float(primary_for_board.get("value"))
    if not metric_name or not _is_number(metric_value):
        metric_history = state.get("metric_history")
        if isinstance(metric_history, list):
            for item in reversed(metric_history):
                if not isinstance(item, dict):
                    continue
                hist_name = str(item.get("primary_metric_name") or "")
                hist_value = item.get("primary_metric_value")
                if not metric_name and hist_name:
                    metric_name = hist_name
                if not _is_number(metric_value) and _is_number(hist_value):
                    metric_value = float(hist_value)
                if _is_number(item.get("baseline_value")) and not _is_number(baseline_value):
                    baseline_value = float(item.get("baseline_value"))
                if metric_name and _is_number(metric_value):
                    break
    target_value, target_source = _extract_metric_target_hint(
        evaluation_spec if isinstance(evaluation_spec, dict) else {},
        contract,
    )
    higher_is_better = True
    if metric_name:
        higher_is_better = _metric_higher_is_better(metric_name)
    metric_gap = None
    if _is_number(metric_value) and _is_number(target_value):
        metric_gap = (
            float(target_value) - float(metric_value)
            if higher_is_better
            else float(metric_value) - float(target_value)
        )

    must_preserve: List[str] = []
    for path in present_outputs:
        item = f"Preserve artifact generation for {path}"
        if item not in must_preserve:
            must_preserve.append(item)
    last_success = state.get("last_successful_output_contract_report")
    if isinstance(last_success, dict):
        for path in _normalize_handoff_items(last_success.get("present"), max_items=8, max_len=140):
            item = f"Keep previously valid output path {path}"
            if item not in must_preserve:
                must_preserve.append(item)
            if len(must_preserve) >= 8:
                break

    patch_objectives: List[str] = []
    if runtime_tail and ("traceback" in runtime_tail.lower() or "error" in runtime_tail.lower()):
        patch_objectives.append("Fix the runtime root cause first, then keep the rest of the pipeline stable.")
    if missing_outputs:
        patch_objectives.append(
            "Produce all missing contract outputs exactly at the required paths: "
            + ", ".join(missing_outputs[:5])
        )
    for fix in required_fixes:
        if fix not in patch_objectives:
            patch_objectives.append(fix)
        if len(patch_objectives) >= 8:
            break
    if not patch_objectives and failed_gates:
        patch_objectives.append("Resolve failed gates: " + ", ".join(failed_gates[:5]))
    if (
        normalized_status == "NEEDS_IMPROVEMENT"
        and metric_name
        and _is_number(metric_value)
        and not hard_failures
    ):
        metric_msg = f"Improve primary metric {metric_name} from {float(metric_value):.6g}"
        if _is_number(target_value):
            metric_msg += f" toward target {float(target_value):.6g}"
        patch_objectives.append(metric_msg)
    if not patch_objectives:
        patch_objectives.append("Apply reviewer and QA feedback with minimal, targeted code edits.")

    hypothesis_packet = _resolve_metric_round_hypothesis_packet(state)
    hypothesis_action = str(hypothesis_packet.get("action") or "NO_OP").strip().upper()
    hypothesis_technique = str(_extract_hypothesis_technique(hypothesis_packet) or "").strip()

    # Block hypotheses that use techniques explicitly forbidden by HARD contract gates.
    forbidden_contract = _build_phase_scoped_contract(
        contract if isinstance(contract, dict) else {},
        "metric_round" if bool(state.get("ml_improvement_round_active")) else "baseline",
    )
    _forbidden_set = _collect_forbidden_techniques(forbidden_contract)
    _forbidden_match = _technique_matches_forbidden(hypothesis_technique, _forbidden_set)
    if _forbidden_match and hypothesis_action == "APPLY":
        print(
            f"HYPOTHESIS_BLOCKED: technique '{hypothesis_technique}' "
            f"matches forbidden keyword '{_forbidden_match}' — forcing NO_OP"
        )
        hypothesis_action = "NO_OP"
        if isinstance(hypothesis_packet, dict):
            hypothesis_packet["action"] = "NO_OP"
            hypothesis_packet["blocked_reason"] = (
                f"Technique '{hypothesis_technique}' blocked: "
                f"contains forbidden keyword '{_forbidden_match}' from HARD contract gate"
            )

    enforce_apply_hypothesis = bool(
        bool(state.get("ml_improvement_round_active"))
        and hypothesis_action == "APPLY"
        and hypothesis_technique
        and hypothesis_technique.upper() != "NO_OP"
    )
    cached_handoff = state.get("iteration_handoff") if isinstance(state.get("iteration_handoff"), dict) else {}
    optimization_context = (
        state.get("ml_optimization_context")
        if isinstance(state.get("ml_optimization_context"), dict)
        else {}
    )
    if not optimization_context and isinstance(cached_handoff.get("optimization_context"), dict):
        optimization_context = copy.deepcopy(cached_handoff.get("optimization_context") or {})
    if enforce_apply_hypothesis and not optimization_context:
        run_id = str(state.get("run_id") or "")
        tracker_recent = load_recent_experiment_entries(run_id, k=10) if run_id else []
        round_history = state.get("ml_improvement_round_history")
        if not isinstance(round_history, list):
            round_history = []
        loop_metric_snapshot = _build_metric_loop_prompt_snapshot(
            metric_loop_state,
            current_metric_value=metric_value,
            current_metric_name=metric_name,
        )
        optimization_context = {
            "policy": {},
            "metric_snapshot": loop_metric_snapshot,
            "contract_lock": _build_metric_round_contract_lock(contract, required_outputs, metric_name or "unknown"),
            "active_hypothesis": compress_long_lists(hypothesis_packet or {})[0],
            "experiment_tracker_recent": compress_long_lists((tracker_recent or [])[-5:])[0],
            "round_history_recent": compress_long_lists((round_history or [])[-4:])[0],
            "metric_loop_state": metric_loop_state,
        }
    elif isinstance(optimization_context, dict) and optimization_context:
        optimization_context = dict(optimization_context)
        optimization_context["metric_snapshot"] = _build_metric_loop_prompt_snapshot(
            metric_loop_state,
            current_metric_value=metric_value,
            current_metric_name=metric_name,
        )
        if metric_loop_state:
            optimization_context["metric_loop_state"] = metric_loop_state
    optimization_blueprint = _resolve_cached_optimization_blueprint(
        state,
        run_id=str(state.get("run_id") or ""),
    )
    # ── Retry context: structured error classification for targeted retries ──
    retry_context = _build_retry_context(
        runtime_tail=runtime_tail,
        hard_failures=hard_failures,
        failed_gates=failed_gates,
        missing_outputs=missing_outputs,
        present_outputs=present_outputs,
        required_fixes=required_fixes,
        state=state,
    )
    repair_ground_truth = _build_repair_ground_truth(
        state=state,
        retry_context=retry_context,
        runtime_output=authoritative_runtime or runtime_tail,
        missing_outputs=missing_outputs,
        present_outputs=present_outputs,
        failed_gates=failed_gates,
        required_fixes=required_fixes,
    )
    repair_first_focus = _resolve_repair_first_focus(
        retry_context=retry_context,
        failed_gates=failed_gates,
        hard_failures=hard_failures,
        missing_outputs=missing_outputs,
    )
    if enforce_apply_hypothesis and not repair_first_focus:
        enforce_msg = (
            "Metric-improvement round: apply active hypothesis '"
            + hypothesis_technique
            + "' with material edits (NO_OP forbidden)."
        )
        if enforce_msg not in patch_objectives:
            patch_objectives.insert(0, enforce_msg)

    handoff: Dict[str, Any] = {
        "handoff_version": "v1",
        "mode": (
            "optimize"
            if enforce_apply_hypothesis and not repair_first_focus
            else ("patch" if next_iteration > 1 or repair_first_focus else "build")
        ),
        "from_iteration": iteration_count,
        "next_iteration": next_iteration,
        "source": (
            "actor_critic_metric_improvement"
            if enforce_apply_hypothesis and not repair_first_focus
            else "result_evaluator"
        ),
        "contract_focus": {
            "required_outputs": required_outputs[:15],
            "present_outputs": present_outputs,
            "missing_outputs": missing_outputs,
        },
        "quality_focus": {
            "status": normalized_status,
            "failed_gates": failed_gates,
            "required_fixes": required_fixes,
            "hard_failures": hard_failures,
            "evidence": evidence_focus,
        },
        "metric_focus": {
            "primary_metric": metric_name or None,
            "current_value": metric_value if _is_number(metric_value) else None,
            "baseline_value": baseline_value if _is_number(baseline_value) else None,
            "target_value": target_value if _is_number(target_value) else None,
            "target_source": target_source or None,
            "gap_to_target": metric_gap,
            "higher_is_better": higher_is_better,
        },
        "feedback": {
            "reviewer": reviewer_feedback,
            "qa": qa_feedback,
            "runtime_error_tail": runtime_tail,
            "evidence": evidence_focus,
        },
        "must_preserve": must_preserve[:8],
        "patch_objectives": patch_objectives[:8],
        "optimization_focus": optimization_context.get("metric_snapshot")
        if isinstance(optimization_context.get("metric_snapshot"), dict)
        else {},
        "optimization_context": optimization_context if isinstance(optimization_context, dict) else {},
        "optimization_lane": {
            "active": bool(enforce_apply_hypothesis),
            "resume_after_repair": False,
            "repair_first": False,
            "repair_focus": None,
            "source": (
                "actor_critic_metric_improvement"
                if enforce_apply_hypothesis
                else None
            ),
            "active_technique": hypothesis_technique or None,
        } if (optimization_context or hypothesis_packet or enforce_apply_hypothesis) else {},
        "critic_packet": (
            state.get("ml_improvement_critique_packet")
            if isinstance(state.get("ml_improvement_critique_packet"), dict)
            else {}
        ),
        "hypothesis_packet": hypothesis_packet if isinstance(hypothesis_packet, dict) else {},
        "optimization_blueprint": optimization_blueprint if isinstance(optimization_blueprint, dict) else {},
        "editor_constraints": {
            "must_apply_hypothesis": bool(enforce_apply_hypothesis and not repair_first_focus),
            "forbid_noop": bool(enforce_apply_hypothesis and not repair_first_focus),
            "patch_intensity": "aggressive" if enforce_apply_hypothesis and not repair_first_focus else "incremental",
        },
        "retry_context": retry_context,
        "repair_ground_truth": repair_ground_truth if isinstance(repair_ground_truth, dict) else {},
    }
    if repair_first_focus:
        repair_scope = _build_repair_scope(
            repair_focus=repair_first_focus,
            repair_ground_truth=repair_ground_truth,
            required_fixes=required_fixes,
            failed_gates=failed_gates,
            evidence_focus=evidence_focus,
            must_preserve=must_preserve,
            missing_outputs=missing_outputs,
            optimization_context=optimization_context,
            hypothesis_packet=hypothesis_packet,
        )
    else:
        repair_scope = {}

    if repair_first_focus:
        handoff = _apply_repair_first_handoff(
            handoff,
            repair_focus=repair_first_focus,
            retry_context=retry_context,
            source="result_evaluator_repair_first",
            reason=f"repair_first:{repair_first_focus}",
        )
        if repair_scope:
            handoff["repair_scope"] = repair_scope
    if preflight_failures:
        handoff["preflight_gates"] = {
            "fails": preflight_failures[:10],
            "raw_tail": preflight_raw_tail,
        }
    return handoff


def _persist_iteration_handoff_state(state: Dict[str, Any] | None) -> None:
    state = state if isinstance(state, dict) else {}
    handoff = state.get("iteration_handoff")
    if not isinstance(handoff, dict) or not handoff:
        return
    try:
        os.makedirs("data", exist_ok=True)
        dump_json("data/iteration_handoff.json", handoff)
        persisted_paths = ["data/iteration_handoff.json"]

        metric_state = _load_primary_metric_state(state)
        if isinstance(metric_state, dict) and metric_state:
            dump_json("data/metric_state.json", metric_state)
            persisted_paths.append("data/metric_state.json")

        repair_ground_truth = (
            handoff.get("repair_ground_truth")
            if isinstance(handoff.get("repair_ground_truth"), dict)
            else {}
        )
        if repair_ground_truth:
            dump_json("data/repair_ground_truth.json", repair_ground_truth)
            state["repair_ground_truth"] = copy.deepcopy(repair_ground_truth)
            persisted_paths.append("data/repair_ground_truth.json")

        review_stack = state.get("ml_review_stack")
        if isinstance(review_stack, dict) and review_stack:
            updated_stack = copy.deepcopy(review_stack)
            updated_stack["iteration_handoff"] = copy.deepcopy(handoff)
            if metric_state:
                updated_stack["metric_state"] = copy.deepcopy(metric_state)
            if repair_ground_truth:
                updated_stack["repair_ground_truth"] = copy.deepcopy(repair_ground_truth)
            metric_context = (
                dict(updated_stack.get("metric_improvement_context"))
                if isinstance(updated_stack.get("metric_improvement_context"), dict)
                else {}
            )
            metric_context["active"] = bool(state.get("ml_improvement_round_active"))
            review_mode = str(state.get("ml_improvement_review_mode") or "").strip()
            if review_mode:
                metric_context["review_mode"] = review_mode
            elif "review_mode" not in metric_context:
                metric_context["review_mode"] = None
            updated_stack["metric_improvement_context"] = metric_context
            dump_json("data/ml_review_stack.json", updated_stack)
            state["ml_review_stack"] = updated_stack
            persisted_paths.append("data/ml_review_stack.json")

        existing_index = _load_json_any("data/produced_artifact_index.json")
        normalized_existing = existing_index if isinstance(existing_index, list) else []
        additions = _build_artifact_index(persisted_paths, None)
        merged_index = _merge_artifact_index_entries(normalized_existing, additions)
        dump_json("data/produced_artifact_index.json", merged_index)
        state["artifact_index"] = merged_index
        state["produced_artifact_index"] = merged_index
    except Exception as err:
        print(f"Warning: failed to persist current iteration_handoff state: {err}")


def _suggest_next_actions(
    preflight_issues: List[str],
    outputs_missing: List[str],
    reviewer_reasons: List[str],
    qa_reasons: List[str],
) -> List[str]:
    actions: List[str] = []
    issues = [str(item) for item in (preflight_issues or []) if item]
    reasons = set((reviewer_reasons or []) + (qa_reasons or []))
    if outputs_missing:
        actions.append(f"Write required outputs: {outputs_missing[:5]}")
    if "SYNTHETIC_DATA_DETECTED" in issues or "synthetic" in reasons:
        actions.append("Remove synthetic data generation; load only the provided dataset.")
    if "DF_COLUMN_ASSIGNMENT_FORBIDDEN" in issues or "df_mutation" in reasons:
        actions.append("Avoid df column assignments; use Pipeline/ColumnTransformer or separate artifacts.")
    if "UNKNOWN_COLUMNS_REFERENCED" in issues or "unknown_columns" in reasons:
        actions.append("Use only contract/canonical columns; avoid invented names.")
    if "DIALECT_LOADING_MISSING" in issues:
        actions.append("CRITICAL: Define load_dialect() function and read output_dialect from the declared cleaning manifest path before ANY data loading.")
    if "BASELINE_REQUIRED" in issues or "baseline_missing" in reasons:
        actions.append("Add a DummyClassifier/DummyRegressor baseline with metrics.")
    if "IMPUTER_REQUIRED" in issues or "imputer_missing" in reasons:
        actions.append("Include SimpleImputer in preprocessing before modeling.")
    if "validation_missing" in reasons:
        actions.append("Add appropriate validation (CV or time-based split) and report metrics.")
    if "leakage" in reasons:
        actions.append("Exclude post-outcome features and document leakage prevention.")
    if "contract_missing_outputs" in reasons:
        actions.append("Verify all required artifacts are written to contract paths.")
    if not actions:
        actions.append("Apply reviewer feedback and align outputs to the execution contract.")
    return actions[:3]

def _ml_iteration_journal_path(run_id: str, base_dir: str = "runs") -> str:
    run_dir = get_run_dir(run_id)
    if run_dir:
        return os.path.join(run_dir, "report", "governance", "ml_iteration_journal.jsonl")
    base_root = os.path.abspath(base_dir or "runs")
    return os.path.join(base_root, run_id, "report", "governance", "ml_iteration_journal.jsonl")


def _ml_iteration_trace_summary_path(run_id: str, base_dir: str = "runs") -> str:
    journal_path = _ml_iteration_journal_path(run_id, base_dir=base_dir)
    return os.path.join(os.path.dirname(journal_path), "ml_iteration_trace_summary.json")


def _persist_ml_iteration_trace_summary(
    run_id: str,
    entries: List[Dict[str, Any]],
    base_dir: str = "runs",
) -> None:
    if not run_id or not isinstance(entries, list):
        return

    stage_counts: Dict[str, int] = {}
    iterations: set[int] = set()
    metric_round_map: Dict[int, Dict[str, Any]] = {}
    for entry in entries:
        if not isinstance(entry, dict):
            continue
        stage = str(entry.get("stage") or "unknown").strip() or "unknown"
        stage_counts[stage] = int(stage_counts.get(stage, 0) or 0) + 1
        try:
            iterations.add(int(entry.get("iteration_id")))
        except Exception:
            pass
        metric_round = entry.get("metric_round")
        if isinstance(metric_round, dict):
            try:
                round_id = int(metric_round.get("round_id"))
            except Exception:
                round_id = 0
            if round_id > 0:
                metric_round_map[round_id] = {
                    "round_id": round_id,
                    "action": str(metric_round.get("action") or "").strip(),
                    "technique": str(metric_round.get("technique") or "").strip(),
                    "signature": str(metric_round.get("signature") or "").strip(),
                    "delta": metric_round.get("delta"),
                    "kept": str(metric_round.get("kept") or "").strip(),
                    "reason": str(metric_round.get("reason") or "").strip(),
                }

    last_entry = entries[-1] if entries else {}
    outputs_missing = last_entry.get("outputs_missing") if isinstance(last_entry, dict) else []
    outputs_missing = outputs_missing if isinstance(outputs_missing, list) else []
    metric_rounds = [metric_round_map[key] for key in sorted(metric_round_map.keys())]
    summary = {
        "run_id": run_id,
        "updated_at_utc": datetime.now(timezone.utc).isoformat(),
        "journal_relative_path": "report/governance/ml_iteration_journal.jsonl",
        "entries_count": len(entries),
        "stages_count": stage_counts,
        "iterations_observed": sorted(iterations),
        "metric_rounds_count": len(metric_rounds),
        "metric_rounds": metric_rounds[-24:],
        "last_entry": {
            "iteration_id": last_entry.get("iteration_id") if isinstance(last_entry, dict) else None,
            "stage": last_entry.get("stage") if isinstance(last_entry, dict) else None,
            "reviewer_verdict": last_entry.get("reviewer_verdict") if isinstance(last_entry, dict) else None,
            "qa_verdict": last_entry.get("qa_verdict") if isinstance(last_entry, dict) else None,
            "outputs_missing_count": len(outputs_missing),
        },
    }

    summary_path = _ml_iteration_trace_summary_path(run_id, base_dir=base_dir)
    os.makedirs(os.path.dirname(summary_path), exist_ok=True)
    with open(summary_path, "w", encoding="utf-8") as f:
        json.dump(summary, f, indent=2, ensure_ascii=True)

def _append_ml_iteration_journal(
    run_id: str,
    entry: Dict[str, Any],
    written_ids: List[str] | None = None,
    base_dir: str = "runs",
) -> List[str]:
    if not run_id or not isinstance(entry, dict):
        return written_ids or []
    iter_id = entry.get("iteration_id")
    stage = entry.get("stage") or "unknown"
    if iter_id is None:
        return written_ids or []

    def _entry_key(payload: Dict[str, Any], default_stage: str) -> str:
        stage_value = str(payload.get("stage") or default_stage or "unknown")
        iter_value = payload.get("iteration_id")
        try:
            iter_token = str(int(iter_value))
        except Exception:
            iter_token = str(iter_value or "")
        metric_round = payload.get("metric_round")
        round_id = 0
        if isinstance(metric_round, dict):
            try:
                round_id = int(metric_round.get("round_id") or 0)
            except Exception:
                round_id = 0
        if round_id > 0:
            return iter_token + ":" + stage_value + ":r" + str(round_id)
        return iter_token + ":" + stage_value

    known: set[str] = set()
    for item in written_ids or []:
        if isinstance(item, str):
            known.add(item)
        elif isinstance(item, int) or str(item).isdigit():
            known.add(f"{int(item)}:unknown")
    entry_key = _entry_key(entry, stage)
    if entry_key in known:
        return sorted(known)
    path = _ml_iteration_journal_path(run_id, base_dir=base_dir)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    try:
        with open(path, "a", encoding="utf-8") as f:
            f.write(json.dumps(entry, ensure_ascii=True) + "\n")
    except Exception:
        return sorted(known)
    known.add(entry_key)
    entries = _load_ml_iteration_journal(run_id, base_dir=base_dir)
    try:
        _persist_ml_iteration_trace_summary(run_id, entries, base_dir=base_dir)
    except Exception:
        pass
    try:
        log_run_event(
            run_id,
            "ml_iteration_trace",
            {
                "iteration_id": int(entry.get("iteration_id")) if entry.get("iteration_id") is not None else None,
                "stage": stage,
                "reviewer_verdict": entry.get("reviewer_verdict"),
                "qa_verdict": entry.get("qa_verdict"),
                "outputs_missing_count": len(entry.get("outputs_missing") or []),
                "journal_entries_count": len(entries),
            },
        )
    except Exception:
        pass
    return sorted(known)


def _refresh_ml_iteration_trace_summary(
    run_id: str,
    state: Dict[str, Any] | None = None,
    *,
    base_dir: str = "runs",
) -> None:
    if not run_id:
        return
    entries = _load_ml_iteration_journal(run_id, base_dir=base_dir)
    if not isinstance(entries, list):
        entries = []

    observed_round_ids: set[int] = set()
    for item in entries:
        if not isinstance(item, dict):
            continue
        metric_round = item.get("metric_round")
        if not isinstance(metric_round, dict):
            continue
        try:
            round_id = int(metric_round.get("round_id") or 0)
        except Exception:
            round_id = 0
        if round_id > 0:
            observed_round_ids.add(round_id)

    state_payload = state if isinstance(state, dict) else {}
    round_history = (
        state_payload.get("ml_improvement_round_history")
        if isinstance(state_payload.get("ml_improvement_round_history"), list)
        else []
    )
    iteration_id = int(state_payload.get("iteration_count", 0) or 0) + 1
    reviewer_verdict = str(state_payload.get("review_verdict") or "UNKNOWN")
    qa_packet = (
        state_payload.get("qa_last_result")
        if isinstance(state_payload.get("qa_last_result"), dict)
        else {}
    )
    qa_verdict = str(qa_packet.get("status") or "UNKNOWN")

    for record in round_history:
        if not isinstance(record, dict):
            continue
        try:
            round_id = int(record.get("round_id") or 0)
        except Exception:
            round_id = 0
        if round_id <= 0 or round_id in observed_round_ids:
            continue
        hypothesis = record.get("hypothesis") if isinstance(record.get("hypothesis"), dict) else {}
        entries.append(
            {
                "timestamp_utc": datetime.now(timezone.utc).isoformat(),
                "iteration_id": int(iteration_id),
                "stage": "review_complete",
                "reviewer_verdict": reviewer_verdict,
                "qa_verdict": qa_verdict,
                "outputs_missing": [],
                "metric_round": {
                    "round_id": int(round_id),
                    "action": str(hypothesis.get("action") or "").strip(),
                    "technique": str(hypothesis.get("technique") or "").strip(),
                    "signature": str(hypothesis.get("signature") or "").strip(),
                    "delta": record.get("delta"),
                    "kept": str(record.get("kept") or "").strip(),
                    "reason": str(record.get("reason") or "").strip(),
                },
            }
        )
        observed_round_ids.add(round_id)

    _persist_ml_iteration_trace_summary(run_id, entries, base_dir=base_dir)

def _load_ml_iteration_journal(run_id: str, base_dir: str = "runs") -> List[Dict[str, Any]]:
    if not run_id:
        return []
    path = _ml_iteration_journal_path(run_id, base_dir=base_dir)
    if not os.path.exists(path):
        return []
    entries: List[Dict[str, Any]] = []
    try:
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    entries.append(json.loads(line))
                except Exception:
                    continue
    except Exception:
        return []
    return entries

def _normalize_iteration_memory_items(
    items: Any,
    *,
    max_items: int = 8,
    max_len: int = 220,
) -> List[str]:
    return [
        str(item)
        for item in _normalize_handoff_items(items, max_items=max_items, max_len=max_len)
        if str(item).strip()
    ]


def _is_generic_iteration_memory_action(action: str) -> bool:
    text = str(action or "").strip().lower()
    if not text:
        return True
    generic_prefixes = (
        "resolve failed gates:",
        "apply reviewer feedback",
        "apply review_board required actions",
        "apply reviewer and qa feedback",
        "apply the latest review feedback",
    )
    return text.startswith(generic_prefixes)


def _derive_iteration_memory_actions(
    *,
    outputs_missing: List[str] | None,
    handoff_obj: Dict[str, Any] | None,
    reviewer_packet: Dict[str, Any] | None,
    qa_packet: Dict[str, Any] | None,
    fallback_actions: List[str] | None,
) -> List[str]:
    handoff_obj = handoff_obj if isinstance(handoff_obj, dict) else {}
    reviewer_packet = reviewer_packet if isinstance(reviewer_packet, dict) else {}
    qa_packet = qa_packet if isinstance(qa_packet, dict) else {}
    quality_focus = (
        handoff_obj.get("quality_focus")
        if isinstance(handoff_obj.get("quality_focus"), dict)
        else {}
    )
    outputs_missing = [str(item) for item in (outputs_missing or []) if str(item).strip()]
    preferred: List[str] = []
    generic: List[str] = []
    seen: set[str] = set()

    def _push(action: str) -> None:
        item = str(action or "").strip()
        if not item or item in seen:
            return
        seen.add(item)
        if _is_generic_iteration_memory_action(item):
            generic.append(item)
        else:
            preferred.append(item)

    if outputs_missing:
        _push("Write required outputs: " + str(outputs_missing[:5]))

    structured_sources = (
        handoff_obj.get("patch_objectives"),
        quality_focus.get("required_fixes"),
        reviewer_packet.get("required_fixes"),
        qa_packet.get("required_fixes"),
    )
    for source in structured_sources:
        for item in _normalize_iteration_memory_items(source, max_items=8, max_len=240):
            _push(item)
    if not preferred:
        for item in _normalize_iteration_memory_items(fallback_actions, max_items=8, max_len=240):
            _push(item)

    merged = preferred + generic
    if not merged:
        merged = ["Apply reviewer feedback and align outputs to the execution contract."]
    return merged[:4]


def _extract_iteration_memory_blockers(entry: Dict[str, Any] | None) -> List[str]:
    entry = entry if isinstance(entry, dict) else {}
    blockers: List[str] = []
    seen: set[str] = set()

    def _append(prefix: str, values: Any, *, max_items: int = 6, max_len: int = 180) -> None:
        for item in _normalize_iteration_memory_items(values, max_items=max_items, max_len=max_len):
            token = f"{prefix}:{item}"
            if token in seen:
                continue
            seen.add(token)
            blockers.append(token)

    quality_failed = _normalize_iteration_memory_items(entry.get("quality_failed_gates"), max_items=8, max_len=180)
    quality_hard = _normalize_iteration_memory_items(entry.get("quality_hard_failures"), max_items=8, max_len=180)
    if quality_failed:
        _append("quality_gate", quality_failed)
    if quality_hard:
        _append("quality_hard", quality_hard)
    if not blockers:
        _append("reviewer_gate", entry.get("reviewer_failed_gates"))
        _append("qa_gate", entry.get("qa_failed_gates"))
        _append("reviewer_hard", entry.get("reviewer_hard_failures"))
        _append("qa_hard", entry.get("qa_hard_failures"))

    _append("preflight", entry.get("preflight_issues"), max_items=5, max_len=160)
    _append("missing_output", entry.get("outputs_missing"), max_items=5, max_len=160)

    runtime_error = entry.get("runtime_error")
    if isinstance(runtime_error, dict):
        runtime_label = str(runtime_error.get("type") or "").strip()
        runtime_message = str(runtime_error.get("message") or "").strip()
        if runtime_label:
            _append("runtime", [runtime_label], max_items=1, max_len=120)
        elif runtime_message:
            _append("runtime", [runtime_message.splitlines()[0]], max_items=1, max_len=120)

    if not blockers:
        _append("reason", entry.get("reviewer_reasons"), max_items=5, max_len=120)
        _append("reason", entry.get("qa_reasons"), max_items=5, max_len=120)
    return blockers[:8]


def _build_iteration_memory_cautions(blockers: List[str]) -> List[str]:
    cautions: List[str] = []
    blocker_text = " ".join([str(item).lower() for item in (blockers or []) if item])
    if "strategy_followed" in blocker_text:
        cautions.append("Avoid: do not keep the old model family when strategy_followed is still failing.")
    if "leakage_prevention" in blocker_text or "quality_gate:leakage" in blocker_text:
        cautions.append("Avoid: do not use forbidden/post-outcome features or in-fold target encoding.")
    if "target_variance_guard" in blocker_text:
        cautions.append("Avoid: do not train before validating target/cardinality guards.")
    if "output_row_count_consistency" in blocker_text or "missing_output" in blocker_text:
        cautions.append("Avoid: do not bypass output row-count and artifact write checks.")
    return cautions[:3]


def _build_iteration_memory_repeated_blockers(entries: List[Dict[str, Any]], current_blockers: List[str]) -> List[str]:
    if not entries or not current_blockers:
        return []
    repeated: List[Tuple[str, int]] = []
    for blocker in current_blockers:
        blocker_key = str(blocker or "").strip()
        if not blocker_key:
            continue
        streak = 0
        for entry in reversed(entries):
            if blocker_key in _extract_iteration_memory_blockers(entry):
                streak += 1
            elif streak > 0:
                break
        if streak >= 2:
            repeated.append((blocker_key, streak))
    repeated.sort(key=lambda item: (-item[1], item[0]))
    return [f"{name} (x{count})" for name, count in repeated[:4]]


def _build_iteration_memory_metric_outcomes(entries: List[Dict[str, Any]]) -> List[str]:
    outcomes: List[str] = []
    seen: set[str] = set()
    for entry in reversed(entries):
        metric_round = entry.get("metric_round") if isinstance(entry, dict) else {}
        if not isinstance(metric_round, dict) or not metric_round:
            continue
        technique = str(metric_round.get("technique") or "").strip()
        if not technique or technique in seen:
            continue
        seen.add(technique)
        kept = str(metric_round.get("kept") or "").strip() or "pending"
        reason = str(metric_round.get("reason") or "").strip()
        delta = _coerce_float(metric_round.get("delta"))
        summary = technique
        if delta is not None:
            delta_prefix = "+" if delta > 0 else ""
            summary += f" ({delta_prefix}{delta:.6g})"
        summary += f" -> {kept}"
        if reason:
            summary += f" [{reason}]"
        outcomes.append(summary[:220])
        if len(outcomes) >= 3:
            break
    return outcomes


def _build_ml_iteration_memory_block(entries: List[Dict[str, Any]], max_chars: int = 1200) -> str:
    if not entries:
        return ""
    last = entries[-1]
    diagnostics = last.get("iteration_diagnostics") if isinstance(last, dict) else {}
    last_summary = {
        "iteration_id": last.get("iteration_id"),
        "preflight_issues": last.get("preflight_issues"),
        "runtime_error": last.get("runtime_error"),
        "outputs_missing": last.get("outputs_missing"),
        "reviewer_verdict": last.get("reviewer_verdict"),
        "qa_verdict": last.get("qa_verdict"),
        "n_rows": diagnostics.get("n_rows") if isinstance(diagnostics, dict) else None,
        "n_segments": diagnostics.get("n_segments") if isinstance(diagnostics, dict) else None,
        "min_segment_size": diagnostics.get("min_segment_size") if isinstance(diagnostics, dict) else None,
        "median_segment_size": diagnostics.get("median_segment_size") if isinstance(diagnostics, dict) else None,
        "curves_generated": diagnostics.get("curves_generated") if isinstance(diagnostics, dict) else None,
        "curves_points": diagnostics.get("curves_points") if isinstance(diagnostics, dict) else None,
        "guide_rows": diagnostics.get("guide_rows") if isinstance(diagnostics, dict) else None,
        "pct_nan_optimal_price": diagnostics.get("pct_nan_optimal_price") if isinstance(diagnostics, dict) else None,
        "root_cause": diagnostics.get("root_cause") if isinstance(diagnostics, dict) else None,
    }
    current_blockers = _extract_iteration_memory_blockers(last)
    if current_blockers:
        last_summary["current_blockers"] = current_blockers[:5]

    top_failures_list = _build_iteration_memory_repeated_blockers(entries, current_blockers)
    previous_blockers = _extract_iteration_memory_blockers(entries[-2]) if len(entries) >= 2 else []
    resolved_blockers = [item for item in previous_blockers if item not in current_blockers][:3]
    metric_outcomes = _build_iteration_memory_metric_outcomes(entries)
    next_actions = _normalize_iteration_memory_items(last.get("next_actions"), max_items=4, max_len=240)
    caution_lines = _build_iteration_memory_cautions(current_blockers)
    lines = [
        "Last attempt summary: " + json.dumps(last_summary, ensure_ascii=True),
        "Repeated blockers: " + json.dumps(top_failures_list, ensure_ascii=True),
    ]
    if metric_outcomes:
        lines.append("Recent metric outcomes: " + json.dumps(metric_outcomes, ensure_ascii=True))
    if resolved_blockers:
        lines.append("Resolved since last attempt: " + json.dumps(resolved_blockers, ensure_ascii=True))
    for item in next_actions:
        lines.append("NEXT: " + item)
    lines.extend(caution_lines)
    block = "\n".join(lines)
    if len(block) <= max_chars:
        return block
    base_lines = lines[:2]
    trimmed_lines = list(base_lines)
    for extra in lines[2:]:
        candidate = "\n".join(trimmed_lines + [extra])
        if len(candidate) > max_chars:
            break
        trimmed_lines.append(extra)
    block = "\n".join(trimmed_lines)
    if len(block) <= max_chars:
        return block
    summary_line, failures_line = base_lines
    overhead = len(failures_line) + 1
    allowed = max_chars - overhead
    if allowed <= 0:
        return failures_line[:max_chars]
    summary_line = summary_line[:allowed]
    return summary_line + "\n" + failures_line

def _build_ml_iteration_journal_entry(
    state: Dict[str, Any],
    preflight_issues: List[str] | None,
    runtime_error: Dict[str, str] | None,
    outputs_present: List[str],
    outputs_missing: List[str],
    reviewer_verdict: str | None,
    reviewer_reasons: List[str],
    qa_verdict: str | None,
    qa_reasons: List[str],
    next_actions: List[str],
    stage: str,
    reviewer_packet: Dict[str, Any] | None = None,
    qa_packet: Dict[str, Any] | None = None,
    iteration_handoff: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    code = state.get("generated_code") or ""
    code_hash = hashlib.sha256(code.encode("utf-8", errors="replace")).hexdigest()[:12] if code else ""
    iter_id = int(state.get("iteration_count", 0)) + 1
    diagnostics = _collect_iteration_diagnostics(state)
    if runtime_error and isinstance(runtime_error, dict) and runtime_error.get("message"):
        diagnostics.setdefault("root_cause", runtime_error.get("message"))
    stage_value = stage if stage in {"preflight", "runtime_fix", "review_complete"} else "unknown"
    reviewer_packet = reviewer_packet if isinstance(reviewer_packet, dict) else (
        state.get("reviewer_last_result") if isinstance(state.get("reviewer_last_result"), dict) else {}
    )
    qa_packet = qa_packet if isinstance(qa_packet, dict) else (
        state.get("qa_last_result") if isinstance(state.get("qa_last_result"), dict) else {}
    )
    handoff_obj = iteration_handoff if isinstance(iteration_handoff, dict) else (
        state.get("iteration_handoff") if isinstance(state.get("iteration_handoff"), dict) else {}
    )
    def _safe_int(value: Any) -> int:
        try:
            return int(value)
        except Exception:
            return 0
    def _safe_float(value: Any) -> float | None:
        try:
            if value is None:
                return None
            return float(value)
        except Exception:
            return None

    handoff_meta = {
        "source": str(handoff_obj.get("source") or ""),
        "mode": str(handoff_obj.get("mode") or ""),
        "from_iteration": _safe_int(handoff_obj.get("from_iteration")),
        "next_iteration": _safe_int(handoff_obj.get("next_iteration")),
    }
    quality_focus = (
        handoff_obj.get("quality_focus")
        if isinstance(handoff_obj.get("quality_focus"), dict)
        else {}
    )
    quality_failed_gates = _normalize_iteration_memory_items(
        quality_focus.get("failed_gates"),
        max_items=10,
        max_len=180,
    )
    quality_required_fixes = _normalize_iteration_memory_items(
        quality_focus.get("required_fixes"),
        max_items=10,
        max_len=240,
    )
    quality_hard_failures = _normalize_iteration_memory_items(
        quality_focus.get("hard_failures"),
        max_items=10,
        max_len=180,
    )
    patch_objectives = _normalize_iteration_memory_items(
        handoff_obj.get("patch_objectives"),
        max_items=8,
        max_len=240,
    )
    reviewer_failed_gates = _normalize_iteration_memory_items(
        reviewer_packet.get("failed_gates"),
        max_items=8,
        max_len=180,
    )
    reviewer_hard_failures = _normalize_iteration_memory_items(
        reviewer_packet.get("hard_failures"),
        max_items=8,
        max_len=180,
    )
    qa_failed_gates = _normalize_iteration_memory_items(
        qa_packet.get("failed_gates"),
        max_items=8,
        max_len=180,
    )
    qa_hard_failures = _normalize_iteration_memory_items(
        qa_packet.get("hard_failures"),
        max_items=8,
        max_len=180,
    )
    effective_next_actions = _derive_iteration_memory_actions(
        outputs_missing=outputs_missing,
        handoff_obj=handoff_obj,
        reviewer_packet=reviewer_packet,
        qa_packet=qa_packet,
        fallback_actions=next_actions,
    )
    reviewer_trace = reviewer_packet.get("json_parse_trace") if isinstance(reviewer_packet, dict) else {}
    qa_trace = qa_packet.get("json_parse_trace") if isinstance(qa_packet, dict) else {}
    metric_round_info: Dict[str, Any] = {}
    round_history = state.get("ml_improvement_round_history")
    latest_round = round_history[-1] if isinstance(round_history, list) and round_history and isinstance(round_history[-1], dict) else {}
    hypothesis_packet = (
        state.get("ml_improvement_hypothesis_packet")
        if isinstance(state.get("ml_improvement_hypothesis_packet"), dict)
        else {}
    )
    hypothesis_payload = (
        hypothesis_packet.get("hypothesis")
        if isinstance(hypothesis_packet.get("hypothesis"), dict)
        else {}
    )
    latest_hypothesis = latest_round.get("hypothesis") if isinstance(latest_round.get("hypothesis"), dict) else {}
    tracker_context = (
        hypothesis_packet.get("tracker_context")
        if isinstance(hypothesis_packet.get("tracker_context"), dict)
        else {}
    )
    round_id = (
        _safe_int(latest_round.get("round_id"))
        or _safe_int(state.get("ml_improvement_current_round_id"))
        or _safe_int(state.get("ml_improvement_round_count"))
    )
    if round_id > 0 or bool(state.get("ml_improvement_round_active")):
        reason = str(
            latest_round.get("reason")
            or latest_round.get("forced_finalize_reason")
            or state.get("ml_improvement_force_finalize_reason")
            or state.get("stop_reason")
            or ""
        ).strip()
        metric_round_info = {
            "round_id": round_id,
            "action": str(
                latest_hypothesis.get("action")
                or hypothesis_packet.get("action")
                or ""
            ).strip(),
            "technique": str(
                latest_hypothesis.get("technique")
                or hypothesis_payload.get("technique")
                or ""
            ).strip(),
            "signature": str(
                latest_hypothesis.get("signature")
                or tracker_context.get("signature")
                or ""
            ).strip(),
            "delta": _safe_float(latest_round.get("delta")),
            "kept": str(latest_round.get("kept") or state.get("ml_improvement_kept") or "").strip(),
            "reason": reason,
        }
    return {
        "timestamp_utc": datetime.now(timezone.utc).isoformat(),
        "iteration_id": iter_id,
        "stage": stage_value,
        "code_hash": code_hash,
        "preflight_issues": preflight_issues or [],
        "runtime_error": runtime_error,
        "outputs_present": outputs_present,
        "outputs_missing": outputs_missing,
        "reviewer_verdict": reviewer_verdict or "UNKNOWN",
        "reviewer_reasons": reviewer_reasons or [],
        "qa_verdict": qa_verdict or "UNKNOWN",
        "qa_reasons": qa_reasons or [],
        "quality_failed_gates": quality_failed_gates,
        "quality_required_fixes": quality_required_fixes,
        "quality_hard_failures": quality_hard_failures,
        "patch_objectives": patch_objectives,
        "reviewer_failed_gates": reviewer_failed_gates,
        "reviewer_hard_failures": reviewer_hard_failures,
        "qa_failed_gates": qa_failed_gates,
        "qa_hard_failures": qa_hard_failures,
        "next_actions": effective_next_actions,
        "iteration_diagnostics": diagnostics,
        "handoff_meta": handoff_meta,
        "reviewer_packet_status": str(reviewer_packet.get("status") or ""),
        "qa_packet_status": str(qa_packet.get("status") or ""),
        "reviewer_json_repair_used": bool(reviewer_trace.get("used_repair")) if isinstance(reviewer_trace, dict) else False,
        "qa_json_repair_used": bool(qa_trace.get("used_repair")) if isinstance(qa_trace, dict) else False,
        "metric_round": metric_round_info,
    }

def _build_iteration_memory(
    iter_id: int,
    metrics_report: Dict[str, Any],
    case_report: Dict[str, Any],
    weights_report: Dict[str, Any],
    code: str,
    prev_summary: Dict[str, Any] | None,
    advisor_note: str | None,
    diagnostics: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    objective_sig = _infer_objective_signature(code)
    weights = _extract_weights_from_obj(weights_report)
    top_weights = sorted(weights.items(), key=lambda kv: kv[1], reverse=True)[:3]
    metrics_global = (metrics_report or {}).get("global_ranking", {})
    metrics_case = (metrics_report or {}).get("case_level", {})
    case_metrics = (case_report or {}).get("metrics", {})
    metrics_snapshot = _extract_metrics_snapshot(metrics_report, weights_report)
    summary = {
        "iteration_id": iter_id,
        "objective_signature": objective_sig,
        "weights_top": top_weights,
        "metrics_global": metrics_global,
        "metrics_case_level": metrics_case,
        "case_alignment_metrics": case_metrics,
        "failures": case_report.get("failures", []) if isinstance(case_report, dict) else [],
        "metrics_snapshot": metrics_snapshot,
    }
    if diagnostics:
        summary["iteration_diagnostics"] = diagnostics
    if advisor_note:
        summary["advisor_note"] = advisor_note.strip()
    if prev_summary:
        delta_snapshot: Dict[str, Any] = {}
        prev_snapshot = prev_summary.get("metrics_snapshot", {}) if isinstance(prev_summary, dict) else {}
        if isinstance(prev_snapshot, dict):
            for key, curr_val in metrics_snapshot.items():
                prev_val = prev_snapshot.get(key)
                if prev_val is None and curr_val is None:
                    continue
                delta_snapshot[key] = {"prev": prev_val, "curr": curr_val}
        summary["delta"] = {
            "spearman_case_means": {
                "prev": prev_summary.get("case_alignment_metrics", {}).get("spearman_case_means"),
                "curr": case_metrics.get("spearman_case_means"),
            },
            "adjacent_refscore_violations": {
                "prev": prev_summary.get("case_alignment_metrics", {}).get("adjacent_refscore_violations"),
                "curr": case_metrics.get("adjacent_refscore_violations"),
            },
            "global_spearman": {
                "prev": prev_summary.get("metrics_global", {}).get("spearman"),
                "curr": metrics_global.get("spearman"),
            },
        }
        if delta_snapshot:
            summary["delta"]["metrics_snapshot"] = delta_snapshot
    return summary

def _build_edit_instructions(summary: Dict[str, Any]) -> str:
    if not summary:
        return ""
    objective = summary.get("objective_signature", {})
    failures = summary.get("failures", [])
    delta = summary.get("delta", {})
    weights_top = summary.get("weights_top", [])
    lines = ["EDIT THESE BLOCKS (modify previous code; do not rewrite):"]
    if objective:
        terms = ", ".join(objective.get("terms") or [])
        lines.append(
            f"- Objective: optimizer={objective.get('optimizer')} terms=[{terms}] code_hash={objective.get('code_hash')}"
        )
    if weights_top:
        weights_text = ", ".join([f"{k}={v:.4f}" for k, v in weights_top])
        lines.append(f"- Weights(top): {weights_text}")
    metrics_snapshot = summary.get("metrics_snapshot", {})
    if isinstance(metrics_snapshot, dict) and metrics_snapshot:
        snap_items = []
        for key in sorted(metrics_snapshot.keys())[:6]:
            snap_items.append(f"{key}={metrics_snapshot[key]}")
        lines.append(f"- Metrics snapshot: {', '.join(snap_items)}")
    if delta:
        metrics_delta = delta.get("metrics_snapshot", {}) if isinstance(delta, dict) else {}
        extra_metrics = []
        if isinstance(metrics_delta, dict):
            for key in sorted(metrics_delta.keys())[:4]:
                extra_metrics.append(
                    _format_metric_delta(
                        key,
                        metrics_delta.get(key, {}).get("prev"),
                        metrics_delta.get(key, {}).get("curr"),
                    )
                )
        lines.append(
            "- Metric deltas: "
            + "; ".join(
                [
                    _format_metric_delta("spearman_case_means", delta.get("spearman_case_means", {}).get("prev"), delta.get("spearman_case_means", {}).get("curr")),
                    _format_metric_delta("adjacent_refscore_violations", delta.get("adjacent_refscore_violations", {}).get("prev"), delta.get("adjacent_refscore_violations", {}).get("curr")),
                    _format_metric_delta("global_spearman", delta.get("global_spearman", {}).get("prev"), delta.get("global_spearman", {}).get("curr")),
                    *extra_metrics,
                ]
            )
        )
    if failures:
        lines.append(f"- Current failures: {failures}")
    advisor_note = summary.get("advisor_note")
    if advisor_note:
        lines.append(f"- Advisor: {advisor_note}")
    return "\n".join(lines)
def _summarize_case_summary(path: str) -> Dict[str, Any]:
    if not path or not os.path.exists(path):
        return {}
    try:
        import pandas as pd
        df = pd.read_csv(path)
    except Exception:
        return {}
    case_col = "Case" if "Case" in df.columns else ("Caso" if "Caso" in df.columns else None)
    if not case_col:
        return {"rows": int(len(df))}
    try:
        cases = [int(x) for x in df[case_col].dropna().unique().tolist()]
    except Exception:
        cases = []
    missing_cases = [c for c in range(1, 21) if c not in cases] if cases else []
    respects_col = "respects_order" if "respects_order" in df.columns else None
    false_count = 0
    if respects_col:
        try:
            false_count = int((df[respects_col] == False).sum())
        except Exception:
            false_count = 0
    return {
        "rows": int(len(df)),
        "case_count": int(len(cases)),
        "missing_cases": missing_cases,
        "respects_order_false": false_count,
        "case_col": case_col,
    }

def _persist_iteration_artifacts(iter_id: int, state: Dict[str, Any] | None = None) -> Dict[str, str]:
    if not iter_id or iter_id < 1:
        return {}
    import shutil
    os.makedirs(os.path.join("artifacts", "iterations"), exist_ok=True)
    state_obj = state if isinstance(state, dict) else {}
    mappings = {
        "case_alignment_report": ("data/case_alignment_report.json", f"case_alignment_report_iter_{iter_id}.json"),
        "weights": (
            _resolve_declared_artifact_path_from_state(
                state_obj,
                "weights.json",
                kind="weights",
            ),
            f"weights_iter_{iter_id}.json",
        ),
        "metrics": (
            _resolve_declared_artifact_path_from_state(
                state_obj,
                "metrics.json",
                kind="metrics",
            ),
            f"metrics_iter_{iter_id}.json",
        ),
        "case_summary": (
            _resolve_declared_artifact_path_from_state(
                state_obj,
                "case_summary.csv",
            ),
            f"case_summary_iter_{iter_id}.csv",
        ),
        "scored_rows": (
            _resolve_declared_artifact_path_from_state(
                state_obj,
                "scored_rows.csv",
            ),
            f"scored_rows_iter_{iter_id}.csv",
        ),
    }
    saved: Dict[str, str] = {}
    for key, (src, dst_name) in mappings.items():
        if not os.path.exists(src):
            continue
        dst = os.path.join("artifacts", "iterations", dst_name)
        try:
            shutil.copyfile(src, dst)
            saved[key] = dst
        except Exception:
            continue
    return saved
